window.HADITH_CACHE = window.HADITH_CACHE || {};
window.HADITH_CACHE["nasai_10"] = {"5001":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَقُتَيْبَةُ بْنُ سَعِيدٍ عَنْ سُفْيَانَ عَنْ الزُّهْرِيِّ أَنَّهُ سَمِعَ الْقَاسِمَ بْنَ مُحَمَّدٍ يُخْبِرُ عَنْ عَ��ئِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ سَتَّرْتُ بِقِرَامٍ فِيهِ تَمَاثِيلُ فَلَمَّا رَآهُ تَلَوَّنَ وَجْهُهُ ثُمَّ هَتَكَهُ بِيَدِهِ وَقَالَ إِنَّ أَشَدَّ النَّاسِ عَذَابًا يَوْمَ الْقِيَامَةِ الَّذِينَ يُشَبِّهُونَ بِخَلْقِ اللَّهِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dan [Qutaibah bin Sa'id] dari [Sufyan] dari [Az Zuhri] bahwa ia pernah mendengar [Al Qasim bin Muhammad] mengabarkan dari ['Aisyah] isteri Nabi shallallahu 'alaihi wasallam, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam masuk menemuiku, sementara aku telah memasang kain tipis bergambar sebagai satir. Saat beliau melihatnya, wajah beliau memerah seraya mengambil kain tersebut, beliau lalu bersabda: \"Sesungguhnya siksa yang paling pedih pada hari kiamat nanti adalah orang-orang yang menyerupakan ciptaan Allah.\""},"5002":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا خَالِدٌ وَهُوَ ابْنُ الْحَارِثِ قَالَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ النَّضْرِ بْنِ أَنَسٍ قَالَكُنْتُ جَالِسًا عِنْدَ ابْنِ عَبَّاسٍ أَتَاهُ رَجُلٌ مِنْ أَهْلِ الْعِرَاقِ فَقَالَ إِنِّي أُصَوِّرُ هَذِهِ التَّصَاوِيرَ فَمَا تَقُولُ فِيهَا فَقَالَ ادْنُهْ ادْنُهْ سَمِعْتُ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ صَوَّرَ صُورَةً فِي الدُّنْيَا كُلِّفَ يَوْمَ الْقِيَامَةِ أَنْ يَنْفُخَ فِيهَا الرُّوحَ وَلَيْسَ بِنَافِخِهِ","id":"Telah mengabarkan kepada kami [Amru bin Ali] ia berkata; telah menceritakan kepada kami [Khalid] -yaitu Ibnul Harits- ia berkata; telah menceritakan kepada kami [Sa'id bin Abu Arubah] dari [An Nadlr bin Anas] ia berkata, \"Ketika aku sedang duduk-duduk bersama [Ibnu Abbas], datanglah seorang laki-laki dari penduduk Irak kepadanya dan berkata, \"Aku melukis gambar-gambar ini, lalu apa pendapatmu?\" Ibnu Abbas berkata, \"Kemarilah, kemarilah. Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membuat suatu gambar di dunia, maka pada hari kiamat akan dibebankan kepada untuk meniupkan ruh pada gambar tersebut, padahal ia tidak akan bisa.\""},"5003":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَوَّرَ صُورَةً عُذِّبَ حَتَّى يَنْفُخَ فِيهَا الرُّوحَ وَلَيْسَ بِنَافِخٍ فِيهَا","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, 'Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membuat suatu gambar, maka pada hari kiamat ia akan disiksa hingga ia meniupkan ruh pada gambar tersebut, padahal ia tidak akan bisa.\""},"5004":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ عِكْرِمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَوَّرَ صُورَةً كُلِّفَ يَوْمَ الْقِيَامَةِ أَنْ يَنْفُخَ فِيهَا الرُّوحَ وَلَيْسَ بِنَافِخٍ","id":"Telah mengabarkan kepada kami [Amru bin Ali] ia berkata; telah menceritakan kepada kami [Affan] ia berkata; telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Ikrimah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membuat suatu gambar di dunia, maka pada hari kiamat akan dibebankan kepada untuk meniupkan ruh pada gambar tersebut, padahal ia tidak akan bisa.\""},"5005":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَصْحَابَ هَذِهِ الصُّوَرِ الَّذِينَ يَصْنَعُونَهَا يُعَذَّبُونَ يَوْمَ الْقِيَامَةِ يُقَالُ لَهُمْ أَحْيُوا مَا خَلَقْتُمْ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya pemilik gambar-gambar ini, yaitu orang-orang yang telah melukisnya, pada hari kiamat akan dikatakan kepada mereka 'Hidupkanlah apa yang telah kalian ciptakan'.\""},"5006":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَصْحَابَ هَذِهِ الصُّوَرِ يُعَذَّبُونَ يَوْمَ الْقِيَامَةِ وَيُقَالُ لَهُمْ أَحْيُوا مَا خَلَقْتُمْ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Al Laits] dari [Nafi'] dari [Al Qasim] dari ['Aisyah] isteri Nabi shallallahu 'alaihi wasallam, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya pemilik gambar-gambar ini pada hari kiamat akan disiksa, dan dikatakan kepada mereka 'Hidupkanlah apa yang telah kalian ciptakan'.\""},"5007":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ سِمَاكٍ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهَا قَالَتْإِنَّ أَشَدَّ النَّاسِ عَذَابًا يَوْمَ الْقِيَامَةِ الَّذِينَ يُضَاهُونَ اللَّهَ فِي خَلْقِهِ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Abu Awanah] dari [Simak] dari [Al Qasim bin Muhammad] dari ['Aisyah] isteri Nabi shallallahu 'alaihi wasallam, bahwasanya ia berkata, \"Sesungguhnya yang paling keras siksanya pada hari kiamat adalah orang-orang yang menyerupakan ciptaan Allah.\""},"5008":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ ح وَأَنْبَأَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ مُحَمَّدٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ قَالَ حَدَّثَنَا إِسْمَعِيلُ بْنُ زَكَرِيَّا قَالَ حَدَّثَنَا حُصَيْنُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ مُسْلِمِ بْنِ صُبَيْحٍ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ أَشَدِّ النَّاسِ عَذَابًا يَوْمَ الْقِيَامَةِ الْمُصَوِّرُونَ وَقَالَ أَحْمَدُ الْمُصَوِّرِينَ","id":"Telah mengabarkan kepada kami [Ahmad bin Harb] ia berkata; telah menceritakan kepada kami [Abu Awanah] dari [Al A'masy] dari [Muslim]. (dalam jalur lain disebutkan) Telah memberitakan kepada kami [Muhammad bin Yahya bin Muhammad] ia berkata; telah menceritakan kepada kami [Muhammad bin Ash Shabbah] ia berkata; telah menceritakan kepada kami [Isma'il bin Zakariya] ia berkata; telah menceritakan kepada kami [Hushain bin 'Abdurrahman] dari [Muslim bin Shubaih] dari [Masruq] dari [Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya yang paling keras siksanya pada hari kiamat adalah para penggambar.\" Ahmad menyebutkan, \"Yakni tukang gambar.\""},"5009":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ أَبِي بَكْرٍ عَنْ أَبِي إِسْحَقَ عَنْ مُجَاهِدٍ عَنْ أَبِي هُرَيْرَةَ قَالَاسْتَأْذَنَ جِبْرِيلُ عَلَيْهِ السَّلَام عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ادْخُلْ فَقَالَ كَيْفَ أَدْخُلُ وَفِي بَيْتِكَ سِتْرٌ فِيهِ تَصَاوِيرُ فَإِمَّا أَنْ تُقْطَعَ رُءُوسُهَا أَوْ تُجْعَلَ بِسَاطًا يُوطَأُ فَإِنَّا مَعْشَرَ الْمَلَائِكَةِ لَا نَدْخُلُ بَيْتًا فِيهِ تَصَاوِيرُ","id":"Telah mengabarkan kepada kami [Hannad bin As Sari] dari [Abu Bakr] dari [Abu Ishaq] dari [Mujahid] dari [Abu Hurairah] ia berkata, \"Jibril 'Alaihis Salam minta izin untuk masuk menemui Nabi shallallahu 'alaihi wasallam, beliau lalu bersabda: \"Masuklah.\" Jibril ganti berkata, \"Bagaimana aku akan masuk, sementara di rumahmu ada satir yang bergambar (makhluk bernyawa)! Hendaklah engkau potong kepalanya atau engkau jadikan sebagai bantal yang di duduki. Sesungguhnya kami adalah para malaikat yang tidak akan masuk ke dalam rumah yang di dalamnya terdapat gambar.\""},"5010":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ قَزْعَةَ عَنْ سُفْيَانَ بْنِ حَبِيبٍ وَمُعْتَمِرِ بْنِ سُلَيْمَانَ عَنْ أَشْعَثَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُصَلِّي فِي لُحُفِنَاقَالَ سُفْيَانُ مَلَاحِفِنَا","id":"Telah mengabarkan kepada kami [Al Hasan bin Qaza'ah] dari [Sufyan bin Habib] dan [Mu'tamir bin Sulaiman] dari [Asy'ats] dari [Muhammad bin Sirin] dari [Abdullah bin Syaqiq] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam tidak shalat di dalam selimut-selimut kami.\" Sufyan menyebutkan, \"Selimut-selimut kami.\""},"5011":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْمَرٍ قَالَ حَدَّثَنَا حَبَّانُ قَالَ حَدَّثَنَا هَمَّامٌ قَالَ حَدَّثَنَا قَتَادَةُ قَالَ حَدَّثَنَا أَنَسٌأَنَّ نَعْلَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ لَهَا قِبَالَانِ","id":"Telah mengabarkan kepada kami [Muhammad bin Ma'mir] ia berkata; telah menceritakan kepada kami [Habban] ia berkata; telah menceritakan kepada kami [Hammam] ia berkata; telah menceritakan kepada kami [Qatadah] ia berkata; telah menceritakan kepada kami [Anas] berkata, \"Sandal Rasulullah shallallahu 'alaihi wasallam memiliki dua tali.\""},"5012":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا صَفْوَانُ بْنُ عِيسَى قَالَ حَدَّثَنَا هِشَامٌ عَنْ مُحَمَّدٍ عَنْ عَمْرِو بْنِ أَوْسٍ قَالَكَانَ لِنَعْلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِبَالَانِ","id":"Telah mengabarkan kepada kami [Amru bin Ali] ia berkata; telah menceritakan kepada kami [Shafwan bin Isa] ia berkata; telah menceritakan kepada kami [Hisyam] dari [Muhammad] dari [Amru bin Aus] ia berkata, \"Sandal Rasulullah shallallahu 'alaihi wasallam mempunyai dua tali.\""},"5013":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا انْقَطَعَ شِسْعُ نَعْلِ أَحَدِكُمْ فَلَا يَمْشِ فِي نَعْلٍ وَاحِدَةٍ حَتَّى يُصْلِحَهَا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah menceritakan kepada kami [Muhammad bin Ubaid] ia berkata; telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika tali sandal salah seorang dari kalian putus, maka janganlah berjalan dengan satu sandal hingga ia memperbaikinya.\""},"5014":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَخْبَرَنَا أَبُو مُعَاوِيَةَ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي رَزِينٍ قَالَرَأَيْتُ أَبَا هُرَيْرَةَ يَضْرِبُ بِيَدِهِ عَلَى جَبْهَتِهِ يَقُولُ يَا أَهْلَ الْعِرَاقِ تَزْعُمُونَ أَنِّي أَكْذِبُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَشْهَدُ لَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا انْقَطَعَ شِسْعُ نَعْلِ أَحَدِكُمْ فَلَا يَمْشِ فِي الْأُخْرَى حَتَّى يُصْلِحَهَا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah mengabarkan kepada kami [Abu Mu'awiyah] ia berkata; telah menceritakan kepada kami [Al A'masy] dari [Abu Razin] ia berkata, \"Aku pernah melihat [Abu Hurairah] memukul keningnya dengan tangan seraya berkata, \"Wahai penduduk Irak, kalian mengklaim bahwa aku telah berdusta atas nama Rasulullah shallallahu 'alaihi wasallam. Sungguh, aku bersaksi bahwa aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika tali sandal salah seorang dari kalian putus maka janganlah berjalan dengan yang lainnya hingga kalian memperbaikinya.\""},"5015":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْمَرٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عُمَرَ بْنِ أَبِي الْوَزِيرِ أَبُو مُطَرِّفٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ مُوسَى عَنْ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اضْطَجَعَ عَلَى نَطْعٍ فَعَرِقَ فَقَامَتْ أُمُّ سُلَيْمٍ إِلَى عَرَقِهِ فَنَشَّفَتْهُ فَجَعَلَتْهُ فِي قَارُورَةٍ فَرَآهَا النَّبِيُّ صَلَّى ا��لَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا هَذَا الَّذِي تَصْنَعِينَ يَا أُمَّ سُلَيْمٍ قَالَتْ أَجْعَلُ عَرَقَكَ فِي طِيبِي فَضَحِكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Muhammad bin Ma'mar] ia berkata; telah menceritakan kepada kami [Muhammad bin Umar bin Abu Al Wazir Abu Mutharrif] ia berkata; telah menceritakan kepada kami [Muhammad bin Musa] dari [Abdullah bin Abu Thalhah] dari [Anas bin Malik] berkata, \"Pernah Nabi shallallahu 'alaihi wasallam berbaring di atas tikar hingga berkeringat. Lalu Ummu Sulaim bangun dan menyeka keringat beliau dari atas tikar tersebut dan memasukkannya ke dalam botol. Ketika Nabi shallallahu 'alaihi wasallam melihat hal itu, beliau bertanya: \"Wahai Ummu Sulaim, engkau sedang melakukan apa?\" Ummu Sulaim menjawab, \"Aku ingin menjadikan keringatmu sebagai minyak wangiku.\" Nabi shallallahu 'alaihi wasallam pun tersenyum.\""},"5016":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ قُدَامَةَ عَنْ جَرِيرٍ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ سَمُرَةَ بْنِ سَهْمٍ رَجُلٌ مِنْ قَوْمِهِ قَالَنَزَلْتُ عَلَى أَبِي هَاشِمِ بْنِ عُتْبَةَ وَهُوَ طَعِينٌ فَأَتَاهُ مُعَاوِيَةُ يَعُودُهُ فَبَكَى أَبُو هَاشِمٍ فَقَالَ مُعَاوِيَةُ مَا يُبْكِيكَ أَوَجَعٌ يُشْئِزُكَ أَمْ عَلَى الدُّنْيَا فَقَدْ ذَهَبَ صَفْوُهَا قَالَ كُلٌّ لَا وَلَكِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَهِدَ إِلَيَّ عَهْدًا وَدِدْتُ أَنِّي كُنْتُ تَبِعْتُهُ قَالَ إِنَّهُ لَعَلَّكَ تُدْرِكُ أَمْوَالًا تُقْسَمُ بَيْنَ أَقْوَامٍ وَإِنَّمَا يَكْفِيكَ مِنْ ذَلِكَ خَادِمٌ وَمَرْكَبٌ فِي سَبِيلِ اللَّهِ فَأَدْرَكْتُ فَجَمَعْتُ","id":"Telah mengabarkan kepada kami [Muhammad bin Qudamah] dari [Jarir] dari [Manshur] dari [Abu Wail] dari [Samurah bin Sahm] seorang laki-laki dari kaumnya, ia berkata, \"Aku berkunjung ke rumah Hasyim bin Utbah yang ketika itu sedang terluka kena tusukan. Lalu datanglah Mu'awiyah menjenguknya, [Abu Hasyim] pun menangis. Mu'awiyah bertanya, \"Apa yang membuatmu menangis? Apakah karena rasa sakit? Atau karena dunia, padahal tidak ada yang perlu untuk ditangisi darinya?\" Abu Hasyim menjawab, \"Bukan karena itu semua, tetapi karena Rasulullah shallallahu 'alaihi wasallam pernah memberikan satu janji kepadaku. Aku berkeinginan sekiranya aku mengikutinya. Beliau bersabda: \"Barangkali kamu akan memiliki harta yang banyak hingga cukup untuk dibagi-bagikan ke sejumlah kaum, tapi cukuplah bagimu seorang pelayan dan kendaraan di jalan Allah.\" Dan sekarang aku telah mendapatkan dan mengumpulkannya.\""},"5017":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ يَزِيدَ قَالَ حَدَّثَنَا عِيسَى بْنُ يُونُسَ قَالَ حَدَّثَنَا عُثْمَانُ بْنُ حَكِيمٍ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلٍ قَالَكَانَتْ قَبِيعَةُ سَيْفِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ فِضَّةٍ","id":"Telah mengabarkan kepada kami [Imran bin Yazid] ia berkata; telah menceritakan kepada kami [Isa bin Yunus] ia berkata; telah menceritakan kepada kami [Utsman bin Hakim] dari [Abu Umamah bin Sahl] ia berkata, \"Gagang pedang Rasulullah shallallahu 'alaihi wasallam bagian atasnya terbuat dari perak.\""},"5018":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا عَمْرُو بْنُ عَاصِمٍ قَالَ حَدَّثَنَا هَمَّامٌ وَجَرِيرٌ قَالَا حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ قَالَكَانَ نَعْلُ سَيْفِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ فِضَّةٍ وَقَبِيعَةُ سَيْفِهِ فِضَّةٌ وَمَا بَيْنَ ذَلِكَ حِلَقُ فِضَّةٍ","id":"Telah mengabarkan kepada kami [Abu Dawud] ia berkata; telah menceritakan kepada kami [Amru bin Ashim] ia berkata; telah menceritakan kepada kami [Hammam] dan [Jarir] keduanya berkata; telah menceritakan kepada kami [Qatadah] dari [Anas] ia berkata, \"Na'lu (bagian bawah gagang) pedang Rasulullah shallallahu 'alaihi wasallam terbuat dari perak, qabi'ah (bagian atas gagang) pedangnya dari perak dan antara keduanya juga terbuat dari gulungan perak.\""},"5019":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا يَزِيدُ وَهُوَ ابْنُ زُرَيْعٍ عَنْ هِشَامٍ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ أَبِي الْحَسَنِ قَالَكَانَتْ قَبِيعَةُ سَيْفِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ فِضَّةٍ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Yazid] -yakni Ibnu Zurai'- dari [Hisyam] dari [Qatadah] dari [Sa'id bin Abu Al Hasan] ia berkata, \"Qabi'ah (bagian atas gagang) pedang Rasulullah shallallahu 'alaihi wasallam terbuat dari perak.\""},"5020":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا ابْنُ إِدْرِيسَ قَالَ سَمِعْتُ عَاصِمَ بْنَ كُلَيْبٍ عَنْ أَبِي بُرْدَةَ عَنْ عَلِيٍّ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْ اللَّهُمَّ سَدِّدْنِي وَاهْدِنِي وَنَهَانِي عَنْ الْجُلُوسِ عَلَى الْمَيَاثِرِ وَالْمَيَاثِرُ قَسِّيٌّ كَانَتْ تَصْنَعُهُ النِّسَاءُ لِبُعُولَتِهِنَّ عَلَى الرَّحْلِ كَالْقَطَائِفِ مِنْ الْأُرْجُوَانِ","id":"Telah mengabarkan kepada kami [Muhammad Ibnul 'Ala] ia berkata; telah menceritakan kepada kami [Ibnu Idris] ia berkata; Aku mendengar [Ashim bin Kulaib] dari [Abu Burdah] dari [Ali] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Ucapkanlah 'Ya Allah, luruskanlah perkataanku dan berilah aku petunjuk'. Beliau juga melarangku untuk duduk di atas alas pelana yang terbuat dari sutera. Yang dimaksud dengan alas pelana ini adalah kain yang bersulam sutera, biasanya ia dibuat oleh para wanita untuk keluarganya yang diletakkan di atas kendaraan, seperti kain tebal yang ada campuran warna merah.\""},"5021":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ عَنْ سُلَيْمَانَ بْنِ الْمُغِيرَةِ عَنْ حُمَيْدِ بْنِ هِلَالٍ قَالَ قَالَ أَبُو رِفَاعَةَانْتَهَيْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَخْطُبُ فَقُلْتُ يَا رَسُولَ اللَّهِ رَجُلٌ غَرِيبٌ جَاءَ يَسْأَلُ عَنْ دِينِهِ لَا يَدْرِي مَا دِينُهُ فَأَقْبَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَتَرَكَ خُطْبَتَهُ حَتَّى انْتَهَى إِلَيَّ فَأُتِيَ بِكُرْسِيٍّ خِلْتُ قَوَائِمَهُ حَدِيدًا فَقَعَدَ عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلَ يُعَلِّمُنِي مِمَّا عَلَّمَهُ اللَّهُ ثُمَّ أَتَى خُطْبَتَهُ فَأَتَمَّهَا","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dari ['Abdurrahman] dari [Sulaiman Ibnul Mughirah] dari [Humaid bin Hilal] ia berkata; [Abu Rifa'ah] berkata, \"Aku mendapati Rasulullah shallallahu 'alaihi wasallam sedang berkhutbah, aku lalu berkata, \"Wahai Rasulullah, ada seorang laki-laki asing datang untuk belajar tentang agamanya, ia tidak tahu bagaimana dengan agamanya!\" Rasulullah shallallahu 'alaihi wasallam kemudian berpaling dan berhenti dari khutbahnya, hingga beliau berhadapan denganku. Sebuah kursi kemudian diberikan kepada beliau, aku mengira bahwa kaki-kakinya terbuat dari besi. Rasulullah shallallahu 'alaihi wasallam kemudian duduk di atas kursi tersebut dan mulai mengajariku apa-apa yang telah Allah ajarkan kepadanya. Setelah itu beliau meneruskan khutbahnya hingga selesai.\""},"5022":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ مُحَمَّدِ بْنِ سَلَّامٍ قَالَ حَدَّثَنَا إِسْحَقُ الْأَزْرَقُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَوْنِ بْنِ أَبِي جُحَيْفَةَ عَنْ أَبِي جُحَيْفَةَ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْبَطْحَاءِ وَهُوَ فِي قُبَّةٍ حَمْرَاءَ وَعِنْدَهُ أُنَاسٌ يَسِيرُ فَجَاءَهُ بِلَالٌ فَأَذَّنَ فَجَعَلَ يُتْبِعُ فَاهُ هَاهُنَا وَهَاهُنَا","id":"Telah mengabarkan kepada kami ['Abdurrahman bin Muhammad bin Sallam] ia berkata; telah menceritakan kepada kami [Ishaq Al Azraq] ia berkata; telah menceritakan kepada kami [Sufyan] dari [Aun bin Abu Juhaifah] dari [Abu Juhaifah] ia berkata, \"Kami di Bathha (daerah sekitar Makkah) bersama Nabi shallallahu 'alaihi wasallam, waktu itu beliau berada di dalam kemahnya yang berwarna merah, sementara di sisinya hanya ada beberapa orang. Lalu Bilal datang dan mengumandangkan adzan, ia mengikuti gerakan mulutnya ke sini dan ke sini.\""},"5023":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو ح وَأَنْبَأَنَا مُحَمَّدُ بْنُ آدَمَ بْنِ سُلَيْمَانَ عَنْ ابْنِ الْمُبَارَكِ عَنْ سُفْيَانَ بْنِ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عَمْرِو بْنِ أَوْسٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْمُقْسِطِينَ عِنْدَ اللَّهِ تَعَالَى عَلَى مَنَابِرَ مِنْ نُورٍ عَلَى يَمِينِ الرَّحْمَنِ الَّذِينَ يَعْدِلُونَ فِي حُكْمِهِمْ وَأَهْلِيهِمْ وَمَا وَلُوا قَالَ مُحَمَّدٌ فِي حَدِيثِهِ وَكِلْتَا يَدَيْهِ يَمِينٌ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] ia berkata; telah menceritakan kepada kami [Sufyan] dari [Amru]. (dalam jalur lain disebutkan) Telah memberitakan kepada kami [Muhammad bin Adam bin Sulaiman] dari [Ibnul Mubarak] dari [Sufyan bin Uyainah] dari [Amru bin Dinar] dari [Amru bin Aus] dari [Abdullah bin Amru bin Al 'Ash] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya orang-orang yang berlaku adil akan ditempatkan di sisi Allah Ta'ala di atas mimbar-mimbar yang terbuat dari cahaya, di sisi sebelah kanan 'Arrahman. Yaitu, orang-orang yang adil dalam menghukumi mereka, adil dalam keluarga mereka dan dalam mengerjakan tugas mereka.\" Muhammad menyebutkan dalam haditsnya, \"dan kedua tangan-Nya adalah kanan.\""},"5024":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ عُبَيْدِ اللَّهِ عَنْ خَبِيبِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَبْعَةٌ يُظِلُّهُمْ اللَّهُ عَزَّ وَجَلَّ يَوْمَ الْقِيَامَةِ يَوْمَ لَا ظِلَّ إِلَّا ظِلُّهُ إِمَامٌ عَادِلٌ وَشَابٌّ نَشَأَ فِي عِبَادَةِ اللَّهِ عَزَّ وَجَلَّ وَرَجُلٌ ذَكَرَ اللَّهَ فِي خَلَاءٍ فَفَاضَتْ عَيْنَاهُ وَرَجُلٌ كَانَ قَلْبُهُ مُعَلَّقًا فِي الْمَسْجِدِ وَرَجُلَانِ تَحَابَّا فِي اللَّهِ عَزَّ وَجَلَّ وَرَجُلٌ دَعَتْهُ امْرَأَةٌ ذَاتُ مَنْصِبٍ وَجَمَالٍ إِلَى نَفْسِهَا فَقَالَ إِنِّي أَخَافُ اللَّهَ عَزَّ وَجَلَّ وَرَجُلٌ تَصَدَّقَ بِصَدَقَةٍ فَأَخْفَاهَا حَتَّى لَا تَعْلَمَ شِمَالُهُ مَا صَنَعَتْ يَمِينُهُ","id":"Telah mengabarkan kepada kami [Suwaid bin Nash] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Ubaidullah] dari [Khabib bin 'Abdurrahman] dari [Hafsh bin Ashim] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ada tujuh golongan yang akan Allah lindungi pada hari kiamat, di hari yang tidak ada perlindungan selain perlindungan-Nya; imam yang adil, seorang pemuda yang tumbuh dalam peribadatan kepada Allah 'azza wajalla, seorang laki-laki yang berdzikir kepada Allah dalam keheningan kemudian meneteskan air mata, seorang laki-laki yang hatinya selalu terpaut dengan masjid, dua orang laki-laki yang mencintai karena Allah 'azza wajalla, seorang laki-laki yang diajak oleh seorang wanita cantik dan berkedudukan untuk berzina, lalu ia berkata 'sesungguhnya aku takut kepada Allah 'azza wajalla', serta seorang laki-laki yang bersedekah dengan sembunyi-sembunyi hingga tangan kirinya tidak mengetahui apa yang dilakukan oleh tangan kanannya.\""},"5025":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا مَعْمَرٌ عَنْ سُفْيَانَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَبِي بَكْرٍ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا حَكَمَ الْحَاكِمُ فَاجْتَهَدَ فَأَصَابَ فَلَهُ أَجْرَانِ وَإِذَا اجْتَهَدَ فَأَخْطَأَ فَلَهُ أَجْرٌ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] ia berkata; telah menceritakan kepada kami [Abdurrazaq] ia berkata; telah memberitakan kepada kami [Ma'mar] dari [Sufyan] dari [Yahya bin Sa'id] dari [Abu Bakr bin Muhammad bin Amru bin Hazm] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seorang hakim berijtihad kemudian benar maka ia mendapatkan dua pahala, namun jika salah maka ia mendapatkan satu pahala.\""},"5026":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ عَنْ أَبِي عُمَيْسٍ عَنْ سَعِيدِ بْنِ أَبِي بُرْ��َةَ عَنْ أَبِيهِ عَنْ أَبِي مُوسَى قَالَأَتَانِي نَاسٌ مِنْ الْأَشْعَرِيِّينَ فَقَالُوا اذْهَبْ مَعَنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنَّ لَنَا حَاجَةً فَذَهَبْتُ مَعَهُمْ فَقَالُوا يَا رَسُولَ اللَّهِ اسْتَعِنْ بِنَا فِي عَمَلِكَ قَالَ أَبُو مُوسَى فَاعْتَذَرْتُ مِمَّا قَالُوا وَأَخْبَرْتُ أَنِّي لَا أَدْرِي مَا حَاجَتُهُمْ فَصَدَّقَنِي وَعَذَرَنِي فَقَالَ إِنَّا لَا نَسْتَعِينُ فِي عَمَلِنَا بِمَنْ سَأَلَنَا","id":"Telah mengabarkan kepada kami [Amri bin Manshur] ia berkata; telah menceritakan kepada kami [Sulaiman bin Harb] ia berkata; telah menceritakan kepada kami [Umar bin Ali] dari [Abu Umais] dari [Sa'id bin Burdah] dari [Bapaknya] dari [Abu Musa] ia berkata, \"Beberapa orang dari Al Asy'ari datang kepadaku, mereka berkata, \"Ikutlah bersama kami pergi menemui Rasulullah shallallahu 'alaihi wasallam, karena kami mempunyai suatu keperluan.\" Maka, aku pun ikut pergi bersama mereka. Mereka lalu berkata, \"Wahai Rasulullah, perbantukanlah kami untuk mengerjakan tugasmu.\" Abu Musa berkata, \"Aku meminta maaf kepada Rasulullah dengan apa yang mereka katakan, dan aku juga kabarkan kepada beliau bahwa aku tidak mengetahui apa yang menjadi keperluan mereka, beliau mempercayaiku dan memberiku maaf.\" Setelah itu beliau bersabda: \"Kami tidak akan meminta bantuan untuk mengerjakan tugas kami kepada orang-orang yang memintanya.\""},"5027":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ أَنَسًا يُحَدِّثُ عَنْ أُسَيْدِ بْنِ حُضَيْرٍأَنَّ رَجُلًا مِنْ الْأَنْصَارِ جَاءَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَلَا تَسْتَعْمِلُنِي كَمَا اسْتَعْمَلْتَ فُلَانًا قَالَ إِنَّكُمْ سَتَلْقَوْنَ بَعْدِي أَثَرَةً فَاصْبِرُوا حَتَّى تَلْقَوْنِي عَلَى الْحَوْضِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] ia berkata; telah menceritakan kepada kami [Khalid] ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] ia berkata; Aku mendengar [Anas] menceritakan dari [Usaid bin Hudlair], bahwa ada seorang laki-laki datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Tidakkah engkau memperkerjakan aku sebagaimana engkau memperkerjakan si fulan?\" beliau bersabda: \"Sesungguhnya kalian akan melihat atsarah (sifat mengutamakan diri sendiri), maka hendaklah kalian sabar hingga kalian berjumpa dengan aku.\""},"5028":{"ar":"أَخْبَرَنَا مُجَاهِدُ بْنُ مُوسَى قَالَ حَدَّثَنَا إِسْمَعِيلُ عَنْ يُونُسَ عَنْ الْحَسَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَ ح وَأَنْبَأَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ الْحَسَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَسْأَلْ الْإِمَارَةَ فَإِنَّكَ إِنْ أُعْطِيتَهَا عَنْ مَسْأَلَةٍ وُكِلْتَ إِلَيْهَا وَإِنْ أُعْطِيتَهَا عَنْ غَيْرِ مَسْأَلَةٍ أُعِنْتَ عَلَيْهَا","id":"Telah mengabarkan kepada kami [Mujahid bin Musa] ia berkata; telah menceritakan kepada kami [Isma'il] dari [Yunus] dari [Al Hasan] dari ['Abdurrahman bin Samurah]. (dalam jalur lain disebutkan) Telah memberitakan kepada kami [Amru bin Ali] berkata; telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Ibnu Aun] dari [Al Hasan] dari [Abdurrahman bin Samurah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah engkau meminta kekuasaan, karena jika engkau diberi karena permintaan, engkau akan dibiarkan sendiri. Namun jika engkau diberi kekuasaan tidak atas dasar permintaan, maka engkau akan diberi pertolongan dalam menunaikannya.\""},"5029":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ آدَمَ بْنِ سُلَيْمَانَ عَنْ ابْنِ الْمُبَارَكِ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّكُمْ سَتَحْرِصُونَ عَلَى الْإِمَارَةِ وَإِنَّهَا سَتَكُونُ نَدَامَةً وَحَسْرَةً يَوْمَ الْقِيَامَةِ فَنِعْمَتِ الْمُرْضِعَةُ وَبِئْسَتِ الْفَاطِمَةُ","id":"Telah menceritakan kepada kami [Muhammad bin Adam bin Sulaiman] dari [Ibnul Mubarak] dari [Ibnu Abu Dzi`b] dari [Al Maqburi] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Kalian akan berambisi untuk mendapatkan kekuasaan, padahal ia akan menjadi penyesalan dan kerugian pada hari kiamat. Betapa nikmatnya saat menyusu dan betapa susahnya saat disapih.\""},"5030":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي ابْنُ أَبِي مُلَيْكَةَ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ أَخْبَرَهُأَنَّهُ قَدِمَ رَكْبٌ مِنْ بَنِي تَمِيمٍ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو بَكْرٍ أَمِّرْ الْقَعْقَاعَ بْنَ مَعْبَدٍ وَقَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ بَلْ أَمِّرْ الْأَقْرَعَ بْنَ حَابِسٍ فَتَمَارَيَا حَتَّى ارْتَفَعَتْ أَصْوَاتُهُمَا فَنَزَلَتْ فِي ذَلِكَ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تُقَدِّمُوا بَيْنَ يَدَيْ اللَّهِ وَرَسُولِهِ حَتَّى انْقَضَتْ الْآيَةُ وَلَوْ أَنَّهُمْ صَبَرُوا حَتَّى تَخْرُجَ إِلَيْهِمْ لَكَانَ خَيْرًا لَهُمْ }","id":"Telah mengabarkan kepada kami [Al Hasan bin Muhammad] ia berkata; telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] ia berkata; telah mengabarkan kepadaku [Ibnu Abu Mulaikah] dari [Abdullah bin Az Zubair] mengabarkan kepadanya, serombongan dari bani Tamim datang menemui Nabi shallallahu 'alaihi wasallam, Abu Bakar lalu berkata, \"Angkatlah Al Qa'qa' bin Ma'bad.\" Sedangkan Umar radliallahu 'anhu berkata, \"Angkatlah Al Aqra' bin Habis.\" Hingga terjadilah perdebatan antara keduanya hingga suara mereka meninggi. Maka berkenaan dengan hal itu turunlah ayat: '(Hai orang-orang yang beriman, janganlah kamu mendahului Allah dan Rasul-Nya dan bertakwalah kepada Allah) ' hingga akhir ayat, '(Dan kalau sekiranya mereka bersabar sampai kamu keluar menemui mereka sesungguhnya itu lebih baik bagi mereka) '.\""},"5031":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا يَزِيدُ وَهُوَ ابْنُ الْمِقْدَامِ بْنِ شُرَيْحٍ عَنْ شُرَيْحِ بْنِ هَانِئٍ عَنْ أَبِيهِ هَانِئٍأَنَّهُ لَمَّا وَفَدَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمِعَهُ وَهُمْ يَكْنُونَ هَانِئًا أَبَا الْحَكَمِ فَدَعَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ إِنَّ اللَّهَ هُوَ الْحَكَمُ وَإِلَيْهِ الْحُكْمُ فَلِمَ تُكَنَّى أَبَا الْحَكَمِ فَقَالَ إِنَّ قَوْمِي إِذَا اخْتَلَفُوا فِي شَيْءٍ أَتَوْنِي فَحَكَمْتُ بَيْنَهُمْ فَرَضِيَ كِلَا الْفَرِيقَيْنِ قَالَ مَا أَحْسَنَ مِنْ هَذَا فَمَا لَكَ مِنْ الْوُلْدِ قَالَ لِي شُرَيْحٌ وَعَبْدُ اللَّهِ وَمُسْلِمٌ قَالَ فَمَنْ أَكْبَرُهُمْ قَالَ شُرَيْحٌ قَالَ فَأَنْتَ أَبُو شُرَيْحٍ فَدَعَا لَهُ وَلِوَلَدِهِ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Yazid] -yaitu Ibnul Miqdam bin Syuraih- dari [Syuraih bin Hani] dari bapaknya [Hani] berkata, \"Saat ia datang, Rasulullah shallallahu 'alaihi wasallam mendengar para sahabat menjuluki Hani dengan Abul Hakam. Maka Rasulullah shallallahu 'alaihi wasallam memanggilnya dan bersabda kepadanya: \"Sesungguhnya Allah adalah Al Hakam (pembuat hukum) dan kepada-Nya hukum dikembalikan. Lalu kenapa kamu dijuluki dengan Abul Hakam?\" ia menjawab, \"Jika kaumku berselisih dalam suatu masalah mereka mendatangiku untuk minta putusan, lalu aku memberi putusan kepada mereka, dan kedua kelompok dari mereka pun ridla dengan putusanku.\" Beliau bersabda: \"Sungguh baik perbuatan itu! Apakah engkau mempunyai anak?\" ia menjawab, \"Aku mempunyai anak yang bernama Syuraih, Abdullah dan Muslim.\" Beliau bertanya: \"Siapa yang paling tua?\" ia menjawab, \"Syuraih.\" Beliau bersabda: \"Kamu dijuluki dengan Abu Syuraih.\" Beliau kemudian mendoakannya dan juga mendoakan anak-anaknya.\""},"5032":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ قَالَ حَدَّثَنَا حُمَيْدٌ عَنْ الْحَسَنِ عَنْ أَبِي بَكْرَةَ قَالَعَصَمَنِي اللَّهُ بِشَيْءٍ سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا هَلَكَ كِسْرَى قَالَ مَنْ اسْتَخْلَفُوا قَالُوا بِنْتَهُ قَالَ لَنْ يُفْلِحَ قَوْمٌ وَلَّوْا أَمْرَهُمْ امْرَأَةً","id":"Telah mengabarkan kepada kami [Muhammad Ibnul Mutsanna] ia berkata; telah menceritakan kepada kami [Khalid Ibnul Harits] ia berkata; telah menceritakan kepada kami [Humaid] dari [Al Hasan] dari [Abu Bakrah] ia berkata, \"Allah telah memeliharaku dengan sesuatu yang aku dengar dari Rasulullah shallallahu 'alaihi wasallam saat Kisra hancur, beliau bertanya: \"Siapa yang mereka angkat sebagai raja?\" para sahabat menjawab, \"Puterinya.\" Beliau lalu bersabda: \"Tidak akan beruntung suatu kaum yang menyerahkan perkaranya kepada seorang wanita.\""},"5033":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ هَاشِمٍ عَنْ الْوَلِيدِ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ ابْنِ عَبَّاسٍ عَنْ الْفَضْلِ بْنِ عَبَّاسٍأَنَّهُ كَانَ رَدِيفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَدَاةَ النَّحْرِ فَأَتَتْهُ امْرَأَةٌ مِنْ خَثْعَمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ فَرِيضَةَ اللَّهِ عَزَّ وَجَلَّ فِي الْحَجِّ عَلَى عِبَادِهِ أَدْرَكَتْ أَبِي شَيْخًا كَبِيرًا لَا يَسْتَطِيعُ أَنْ يَرْكَبَ إِلَّا مُعْتَرِضًا أَفَأَحُجُّ عَنْهُ قَالَ نَعَمْ حُجِّي عَنْهُ فَإِنَّهُ لَوْ كَانَ عَلَيْهِ دَيْنٌ قَضَيْتِيهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Hasyim] dari [Al Walid] dari [Al Auza'i] dari [Az Zuhri] dari [Sulaiman bin Yasar] dari [Ibnu Abbas] dari [Al Fadll bin Abbas], bahwasanya ia pernah membonceng di belakang Rasulullah shallallahu 'alaihi wasallam di pagi hari pada hari Nahr (kurban). Lalu datanglah seorang wanita kepadanya dan berkata, \"Wahai Rasulullah, sesungguhnya kewajiban haji yang Allah bebankan kepada hamba-hamba-Nya telah datang kepada bapakku di saat umurnya telah senja dan tidak mampu untuk naik kendaraan kecuali dengan digandeng, maka bolehkah aku menghajikan untuknya?\" beliau menjawab: \"Ya, berhajilah untuknya. Sebab jika ia mempunyai hutang kamu pun wajib membayarnya.\""},"5034":{"ar":"أَخْبَرَنِي عَمْرُو بْنُ عُثْمَانَ قَالَ حَدَّثَنَا الْوَلِيدُ عَنْ الْأَوْزَاعِيِّ قَالَ أَخْبَرَنِي ابْنُ شِهَابٍ ح وَأَخْبَرَنِي مَحْمُودُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا عُمَرُ عَنْ الْأَوْزَاعِيِّ حَدَّثَنِي الزُّهْرِيُّ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ أَنَّ ابْنَ عَبَّاسٍ أَخْبَرَهُأَنَّ امْرَأَةً مِنْ خَثْعَمَ اسْتَفْتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْفَضْلُ رَدِيفُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ فَرِيضَةَ اللَّهِ عَزَّ وَجَلَّ فِي الْحَجِّ عَلَى عِبَادِهِ أَدْرَكَتْ أَبِي شَيْخًا كَبِيرًا لَا يَسْتَطِيعُ أَنْ يَسْتَوِيَ عَلَى الرَّاحِلَةِ فَهَلْ يُجْزِئُ قَالَ مَحْمُودٌ فَهَلْ يَقْضِي أَنْ أَحُجَّ عَنْهُ فَقَالَ لَهَا نَعَمْقَالَ أَبُو عَبْد الرَّحْمَنِ وَقَدْ رَوَى هَذَا الْحَدِيثَ غَيْرُ وَاحِدٍ عَنْ الزُّهْرِيِّ فَلَمْ يَذْكُرْ فِيهِ مَا ذَكَرَ الْوَلِيدُ بْنُ مُسْلِمٍ","id":"Telah mengabarkan kepadaku [Amru bin Utsman] ia berkata; telah menceritakan kepada kami [Al Walid] dari [Al Auza'i] ia berkata; telah mengabarkan kepadaku [Ibnu Syihab]. (dalam jalur lain disebutkan) Telah mengabarkan kepadaku [Mahmud bin Khalid] ia berkata; telah menceritakan kepada kami [Umar] dari [Al Auza'i] berkata, telah menceritakan kepadaku [Az Zuhri] dari [Sulaiman bin Yasar] bahwa [Ibnu Abbas] mengabarkan kepadanya, bahwa seorang wanita dari Khats'am meminta fatwa Rasulullah shallallahu 'alaihi wasallam, sementara Al Fadll sedang membonceng di belakang Rasulullah shallallahu 'alaihi wasallam. Wanita itu berkata, \"Wahai Rasulullah, sesungguhnya kewajiban haji yang Allah bebankan kepada hamba-hamba-Nya telah datang kepada bapakku di saat umurnya sudah tua dan tidak lagi tegak saat duduk di atas kendaraan, maka apakah mencukupi?\" Mahmud berkata, \"Maksudnya adalah, apakah sah jika aku menghajikannya?\" lalu beliau berkata kepadanya: \"Ya.\" 'Abdurrahman berkata, \"Hadits ini diriwayatkan dari Az Zuhri tidak hanya oleh seorang saja, namun ia tidak menyebutkan dalam hadits tersebut nama Al Walid bin Muslim.\""},"5035":{"ar":"قَالَ الْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ قَالَكَانَ الْفَضْلُ بْنُ عَبَّاسٍ رَدِيفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَتْهُ امْرَأَةٌ مِنْ خَثْعَمَ تَسْتَفْتِيهِ فَجَعَلَ الْفَضْلُ يَنْظُرُ إِلَيْهَا وَتَنْظُرُ إِلَيْهِ وَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْرِفُ وَجْهَ الْفَضْلِ إِلَى الشِّقِّ الْآخَرِ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ فَرِيضَةَ اللَّهِ عَزَّ وَجَلَّ عَلَى عِبَادِهِ فِي الْحَجِّ أَدْرَكَتْ أَبِي شَيْخًا كَبِيرًا لَا يَسْتَطِيعُ أَنْ يَثْبُتَ عَلَى الرَّاحِلَةِ أَفَأَحُجُّ عَنْهُ قَالَ نَعَمْ وَذَلِكَ فِي حَجَّةِ الْوَدَاعِ","id":"[Al Harits bin Miskin] meriwayatkan dengan jalan membacakan di hadapannya, sementara aku mendengar dari [Ibnul Qasim] berkata, telah menceritakan kepadaku [Malik] dari [Ibnu Syihab] dari [Sulaiman bin Yasar] dari [Abdullah bin Abbas] ia berkata, \"Al Fadll bin Abbas membonceng di belakang Rasulullah shallallahu 'alaihi wasallam, lalu datanglah seorang wanita dari Khats'am kepada beliau untuk meminta fatwa. Al Fadll memandangi wanita itu dan juga sebaliknya hingga Rasulullah shallallahu 'alaihi wasallam memalingkan wajah Al Fadll ke arah lain, wanita itu lalu berkata, \"Wahai Rasulullah, sesungguhnya kewajiban haji yang Allah bebankan kepada hamba-hamba-Nya telah datang kepada bapakku di saat umurnya sudah tua dan tidak lagi sanggup berkendaraan. Maka apakah boleh aku menghajikan untuknya?\" beliau menjawab: \"Ya.\" Kisah itu terjadi saat haji Wada'.\""},"5036":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنِي أَبِي عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ ابْنِ شِهَابٍ أَنَّ سُلَيْمَانَ بْنَ يَسَارٍ أَخْبَرَهُ أَنَّ ابْنَ عَبَّاسٍ أَخْبَرَهُأَنَّ امْرَأَةً مِنْ خَثْعَمَ قَالَتْ يَا رَسُولَ اللَّهِ إِنَّ فَرِيضَةَ اللَّهِ عَزَّ وَجَلَّ فِي الْحَجِّ عَلَى عِبَادِهِ أَدْرَكَتْ أَبِي شَيْخًا كَبِيرًا لَا يَسْتَوِي عَلَى الرَّاحِلَةِ فَهَلْ يَقْضِي عَنْهُ أَنْ أَحُجَّ عَنْهُ قَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ فَأَخَذَ الْفَضْلُ يَلْتَفِتُ إِلَيْهَا وَكَانَتْ امْرَأَةً حَسْنَاءَ وَأَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْفَضْلَ فَحَوَّلَ وَجْهَهُ مِنْ الشِّقِّ الْآخَرِ","id":"Telah mengabarkan kepada kami [Abu Dawud] ia berkata; telah menceritakan kepada kami [Ya'qub bin Ibrahim] ia berkata; telah menceritakan kepadaku [bapakku] dari [Shalih bin Kaisan] dari [Ibnu Syihab] bahwa [Sulaiman bin Yasar] mengabarkan kepadanya, bahwa [Ibnu Abbas] mengabarkan kepadanya, bahwa ada seorang wanita dari Khats'am berkata, \"Wahai Rasulullah, sesungguhnya kewajiban haji yang Allah bebankan kepada hamba-hamba-Nya telah datang kepada bapakku di saat umurnya sudah tua dan tidak lagi sanggup berkendaraan. Maka apakah sah jika aku menghajikan untuknya?\" Rasulullah shallallahu 'alaihi wasallam lalu bersabda kepadanya: \"Ya.\" Al Fadll langsung mencuri panjang kepada wanita itu -ia adalah wanita yang sangat cantik-, sehingga Rasulullah shallallahu 'alaihi wasallam memegang Al Fadll dan memalingkan wajahnya ke arah lain.\""},"5037":{"ar":"أَخْبَرَنَا مُجَاهِدُ بْنُ مُوسَى عَنْ هُشَيْمٍ عَنْ يَحْيَى بْنِ أَبِي إِسْحَقَ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍأَنَّ رَجُلًا سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَبِي أَدْرَكَهُ الْحَجُّ وَهُوَ شَيْخٌ كَبِيرٌ لَا يَثْبُتُ عَلَى رَاحِلَتِهِ فَإِنْ شَدَدْتُهُ خَشِيتُ أَنْ يَمُوتَ أَفَأَحُجُّ عَنْهُ قَالَ أَفَرَأَيْتَ لَوْ كَانَ عَلَيْهِ دَيْنٌ فَقَضَيْتَهُ أَكَانَ مُجْزِئًا قَالَ نَعَمْ قَالَ فَحُجَّ عَنْ أَبِيكَ","id":"Telah mengabarkan kepada kami [Mujahid bin Musa] dari [Husyaim] dari [Yahya bin Abu Ishaq] dari [Sulaiman bin Yasar] dari [Abdullah bin Abbas] berkata, \"Seorang laki-laki bertanya Nabi shallallahu 'alaihi wasallam, \"Sesungguhnya kewajiban haji telah datang kepada bapakku saat umurnya telah tua, dan ia tidak lagi bisa berkendaraan. Jika aku paksakan, maka aku khawatir ia akan meninggal. Apakah aku harus menghajikannya?\" Beliau balik bertanya: \"Bagaimana pendapatmu jika ia mempunyai hutang kemudian engkau bayar, apakah telah mencukupi?\" Laki-laki menjawab, \"Tentu.\" Beliau lantas bersabda: \"Maka berhajilah untuk bapakmu.\""},"5038":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا يَزِيدُ قَالَ حَدَّثَنَا هِشَامٌ عَنْ مُحَمَّدٍ عَنْ يَحْيَى بْنِ أَبِي إِسْحَقَ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ الْفَضْلِ بْنِ الْعَبَّاسِأَنَّهُ كَانَ رَدِيفَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَهُ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ أُمِّي عَجُوزٌ كَبِيرَةٌ إِنْ حَمَلْتُهَا لَمْ تَسْتَمْسِكْ وَإِنْ رَبَطْتُهَا خَشِيتُ أَنْ أَقْتُلَهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرَأَيْتَ لَوْ كَانَ عَلَى أُمِّكَ دَيْنٌ أَكُنْتَ قَاضِيَهُ قَالَ نَعَمْ قَالَ فَحُجَّ عَنْ أُمِّكَ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] ia berkata; telah menceritakan kepada kami [Yazid] ia berkata; telah menceritakan kepada kami [Hisyam] dari [Muhammad] dari [Yahya bin Abu Ishaq] dari [Sulaiman bin Yasar] dari [Al Fadll bin Al Abbas], bahwasanya ia membonceng di belakang Nabi shallallahu 'alaihi wasallam, kemudian datang seorang laki-laki dan berkata, \"Wahai Rasulullah, ibuku telah tua renta, jika aku membawanya (naik haji) ia tidak bisa berpegangan, dan jika diikat maka aku khawatir akan membunuhnya?\" Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Bagaimana menurutmu, jika ibumu mempunyai hutang apakah engkau akan membayarnya?\" Laki-laki itu menjawab, \"Tentu.\" Beliau pun bersabda: \"Maka berhajilah untuk ibumu.\""},"5039":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا الْوَلِيدُ بْنُ نَافِعٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ يَحْيَى بْنِ أَبِي إِسْحَقَ قَالَ سَمِعْتُ سُلَيْمَانَ بْنَ يَسَارٍ يُحَدِّثُهُ عَنْ الْفَضْلِ بْنِ الْعَبَّاسِ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا نَبِيَّ اللَّهِ إِنَّ أَبِي شَيْخٌ كَبِيرٌ لَا يَسْتَطِيعُ الْحَجَّ وَإِنْ حَمَلْتُهُ لَمْ يَسْتَمْسِكْ أَفَأَحُجُّ عَنْهُ قَالَ حُجَّ عَنْ أَبِيكَقَالَ أَبُو عَبْد الرَّحْمَنِ سُلَيْمَانُ لَمْ يَسْمَعْ مِنْ الْفَضْلِ بْنِ الْعَبَّاسِ","id":"Telah mengabarkan kepada kami [Abu Dawud] ia berkata; telah menceritakan kepada kami [Al Walid bin Nafi'] ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Yahya bin Abu Ishaq] ia berkata; Aku mendengar [Sulaiman bin Yasar] menceritakannya dari [Al Fadll bin Al Abbas] ia berkata, \"Seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, sesungguhnya bapakku telah tua renta dan tidak sanggup untuk melaksanakan haji, jika aku mengajaknya ia tidak bisa berpegangan, maka apakah aku boleh menghajikannya?\" beliau bersabda: \"Berhajilah untuk bapakmu.\" Abu 'Abdurrahman berkata, \"Sulaiman belum pernah mendengar dari Al Fadll bin Al Abbas.\""},"5040":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْمَرٍ قَالَ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ زَكَرِيَّا بْنِ إِسْحَقَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ أَبِي الشَّعْثَاءِ عَنْ ابْنِ عَبَّاسٍأَنَّ رَجُلًا جَاءَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ أَبِي شَيْخٌ كَبِيرٌ أَفَأَحُجُّ عَنْهُ قَالَ نَعَمْ أَرَأَيْتَ لَوْ كَانَ عَلَيْهِ دَيْنٌ فَقَضَيْتَهُ أَكَانَ يُجْزِئُ عَنْهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Ma'mar] ia berkata; telah menceritakan kepada kami [Abu 'Ashim] dari [Zakariya bin Ishaq] dari ['Amru bin Dinar] dari [Abu Asy Sya'tsa] dari [Ibnu Abbas] dia berkata; \"Seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam dan berkata, \"Sesungguhnya bapakku telah tua renta, apakah boleh aku menghajikannya?\" beliau menjawab: \"Tentu, bagaimana pendapatmu jika bapakmu mempunyai hutang kemudian engkau membayarnya, apakah itu telah mencukupinya!?\""},"5041":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ عُمَارَةَ هُوَ ابْنُ عُمَيْرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ قَالَأَكْثَرُوا عَلَى عَبْدِ اللَّهِ ذَاتَ يَوْمٍ فَقَالَ عَبْدُ اللَّهِ إِنَّهُ قَدْ أَتَى عَلَيْنَا زَمَانٌ وَلَسْنَا نَقْضِي وَلَسْنَا هُنَالِكَ ثُمَّ إِنَّ اللَّهَ عَزَّ وَجَلَّ قَدَّرَ عَلَيْنَا أَنْ بَلَغْنَا مَا تَرَوْنَ فَمَنْ عَرَضَ لَهُ مِنْكُمْ قَضَاءٌ بَعْدَ الْيَوْمِ فَلْيَقْضِ بِمَا فِي كِتَابِ اللَّهِ فَإِنْ جَاءَ أَمْرٌ لَيْسَ فِي كِتَابِ اللَّهِ فَلْيَقْضِ بِمَا قَضَى بِهِ نَبِيُّهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنْ جَاءَ أَمْرٌ لَيْسَ فِي كِتَابِ اللَّهِ وَلَا قَضَى بِهِ نَبِيُّهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلْيَقْضِ بِمَا قَضَى بِهِ الصَّالِحُونَ فَإِنْ جَاءَ أَمْرٌ لَيْسَ فِي كِتَابِ اللَّهِ وَلَا قَضَى بِهِ نَبِيُّهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا قَضَى بِهِ الصَّالِحُونَ فَلْيَجْتَهِدْ رَأْيَهُ وَلَا يَقُولُ إِنِّي أَخَافُ وَإِنِّي أَخَافُ فَإِنَّ الْحَلَالَ بَيِّنٌ وَالْحَرَامَ بَيِّنٌ وَبَيْنَ ذَلِكَ أُمُورٌ مُشْتَبِهَاتٌ فَدَعْ مَا يَرِيبُكَ إِلَى مَا لَا يَرِيبُكَقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا الْحَدِيثُ جَيِّدٌ جَيِّدٌ","id":"Telah mengabarkan kepada kami [Muhammad Ibnul 'Ala] ia berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Umarah] -yaitu Ibnu Umair- dari ['Abdurrahman bin Yazid] ia berkata, \"Suatu hari banyak orang datang kepada Abdullah (untuk minta fatwa), [Abdullah] lalu berkata, \"Telah datang kepada kita suatu masa, kita bukan seorang hakim dan bukan orang yang ahli dalam bidang itu. Dan Allah telah menentukan bahwa kita akan bertemu dengan (masa itu) sebagaimana yang kalian lihat ini, maka barangsiapa dari kalian diamanahi sebagai hakim setelah hari ini, hendaklah ia menghukumi berdasarkan apa yang ada dalam Kitabullah. Jika ada satu masalah yang tidak ada dalam Kitabullah, hendaklah ia menghukumi sebagaimana Nabi shallallahu 'alaihi wasallam menghukuminya. Jika ada satu masalah yang tidak ada dalam Kitabullah dan Nabi shallallahu 'alaihi wasallam juga belum menghukuminya, hendaklah ia menghukumi sebagaimana orang-orang shalih menghukuminya. Jika ada satu masalah yang tidak ada dalam Kitabullah, Nabi shallallahu 'alaihi wasallam (hadits) dan orang-orang shalih juga belum pernah menghukuminya, hendaklah ia mengerahkan semua pikirannya dan jangan mengatakan 'Sesungguhnya aku takut, sesungguhnya aku takut'. Sebab yang halal telah jelas dan yang haram juga jelas. Sedangkan di antara keduanya terdapat perkara mutasyabihat (meragukan), maka tinggalkanlah yang meragukanmu dan amalkanlah apa yang tidak meragukanmu.\" 'Abdurrahman berkata; \"Hadits ini sanadnya baik sekali.\""},"5042":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ عَلِيِّ بْنِ مَيْمُونٍ قَالَ حَدَّثَنَا الْفِرْيَابِيُّ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ حُرَيْثِ بْنِ ظُهَيْرٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَأَتَى عَلَيْنَا حِينٌ وَلَسْنَا نَقْضِي وَلَسْنَا هُنَالِكَ وَإِنَّ اللَّهَ عَزَّ وَجَلَّ قَدَّرَ أَنْ بَلَغْنَا مَا تَرَوْنَ فَمَنْ عَرَضَ لَهُ قَضَاءٌ بَعْدَ الْيَوْمِ فَلْيَقْضِ فِيهِ بِمَا فِي كِتَابِ اللَّهِ فَإِنْ جَاءَ أَمْرٌ لَيْسَ فِي كِتَابِ اللَّهِ فَلْيَقْضِ بِمَا قَضَى بِهِ نَبِيُّهُ فَإِنْ جَاءَ أَمْرٌ لَيْسَ فِي كِتَابِ اللَّهِ وَلَمْ يَقْضِ بِهِ نَبِيُّهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلْيَقْضِ بِمَا قَضَى بِهِ الصَّالِحُونَ وَلَا يَقُولُ أَحَدُكُمْ إِنِّي أَخَافُ وَإِنِّي أَخَافُ فَإِنَّ الْحَلَالَ بَيِّنٌ وَالْحَرَامَ بَيِّنٌ وَبَيْنَ ذَلِكَ أُمُورٌ مُشْتَبِهَةٌ فَدَعْ مَا يَرِيبُكَ إِلَى مَا لَا يَرِيبُكَ","id":"Telah mengabarkan kepadaku [Muhammad bin Ali bin Maimun] ia berkata; telah menceritakan kepada kami [Al Firyani] ia berkata; telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari ['Umarah bin 'Umair] dari [Huraits bin Zhuhair] dari [Abdullah bin Mas'ud] ia berkata, \"Telah datang kepada kita suatu masa, kita bukan seorang hakim dan bukan seorang yang ahli dalam bidang itu. Dan Allah telah menetapkan bahwa kita akan bertemu dengan (masa itu) sebagaimana yang kalian lihat saat ini, maka barangsiapa dari kalian diamanahi sebagai hakim setelah hari ini, hendaklah ia menghukumi berdasarkan apa yang ada dalam Kitabullah. Jika ada satu masalah yang tidak ada dalam Kitabullah, hendaklah ia menghukumi sebagaimana Nabi-Nya menghukuminya. Jika ada satu masalah yang tidak ada dalam Kitabullah dan Nabi-Nya shallallahu 'alaihi wasallam juga belum menghukuminya, hendaklah ia menghukumi sebagaimana orang-orang shalih menghukuminya. Dan janganlah salah seorang dari kalian mengatakan 'Sesungguhnya aku takut, sesungguhnya aku takut', Sebab yang halal telah jelas dan yang haram juga telah jelas. Sedangkan di antara keduanya adalah perkara musytabihah (meragukan), maka tinggalkanlah yang meragukanmu dan amalkanlah apa yang tidak meragukanmu.\""},"5043":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا أَبُو عَامِرٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الشَّيْبَانِيِّ عَنْ الشَّعْبِيِّ عَنْ شُرَيْحٍأَنَّهُ كَتَبَ إِلَى عُمَرَ يَسْأَلُهُ فَكَتَبَ إِلَيْهِ أَنْ اقْضِ بِمَا فِي كِتَابِ اللَّهِ فَإِنْ لَمْ يَكُنْ فِي كِتَابِ اللَّهِ فَبِسُنَّةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنْ لَمْ يَكُنْ فِي كِتَابِ اللَّهِ وَلَا فِي سُنَّةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاقْضِ بِمَا قَضَى بِهِ الصَّالِحُونَ فَإِنْ لَمْ يَكُنْ فِي كِتَابِ اللَّهِ وَلَا فِي سُنَّةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَقْضِ بِهِ الصَّالِحُونَ فَإِنْ شِئْتَ فَتَقَدَّمْ وَإِنْ شِئْتَ فَتَأَخَّرْ وَلَا أَرَى التَّأَخُّرَ إِلَّا خَيْرًا لَكَ وَالسَّلَامُ عَلَيْكُمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Basyar] ia berkata; telah menceritakan kepada kami [Abu Amir] ia berkata; telah menceritakan kepada kami [Sufyan] dari [Asy Syaibani] dari [Asy Sya'bi] dari [Syuraih] bahwa ia pernah menulis kepada [Umar] untuk minta fatwa. Maka Umar menulis balasan kepadanya agar ia menghukumi sebagaimana yang ada dalam Kitabullah. Jika dalam Kitabullah tidak ada, hendaklah dengan sunah Rasulullah shallallahu 'alaihi wasallam. Jika dalam Kitabullah dan sunah Rasulullah shallallahu 'alaihi wasallam tidak ada, hendaklah ia memutuskan hukum berdasarkan ketetapan yang telah ditetapkan oleh orang-orang shalih. Jika tidak ditemukan dalam Kitabullah, tidak pula dalam sunah Rasulullah shallallahu 'alaihi wasallam dan orang-orang shalih juga tidak memutuskan ketetapan hukumnya, jika engkau berkenan silahkan engkau maju (berijtihad dan memberi jawaban), dan jika berkenan silahkan engkau mundur (diam). Dan aku tidak melihat mengundurkan diri (diam) kecuali suatu kebaikan untukmu. Wassalamu 'alaikum.\""},"5044":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ قَالَ أَنْبَأَنَا الْفَضْلُ بْنُ مُوسَى عَنْ سُفْيَانَ بْنِ سَعِيدٍ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَتْ مُلُوكٌ بَعْدَ عِيسَى ابْنِ مَرْيَمَ عَلَيْهِ الصَّلَاة وَالسَّلَامُ بَدَّلُوا التَّوْرَاةَ وَالْإِنْجِيلَ وَكَانَ فِيهِمْ مُؤْمِنُونَ يَقْرَءُونَ التَّوْرَاةَ قِيلَ لِمُلُوكِهِمْ مَا نَجِدُ شَتْمًا أَشَدَّ مِنْ شَتْمٍ يَشْتِمُونَّا هَؤُلَاءِ إِنَّهُمْ يَقْرَءُونَ{ وَمَنْ لَمْ يَحْكُمْ بِمَا أَنْزَلَ اللَّهُ فَأُولَئِكَ هُمْ الْكَافِرُونَ }وَهَؤُلَاءِ الْآيَاتِ مَعَ مَا يَعِيبُونَّا بِهِ فِي أَعْمَالِنَا فِي قِرَاءَتِهِمْ فَادْعُهُمْ فَلْيَقْرَءُوا كَمَا نَقْرَأُ وَلْيُؤْمِنُوا كَمَا آمَنَّا فَدَعَاهُمْ فَجَمَعَهُمْ وَعَرَضَ عَلَيْهِمْ الْقَتْلَ أَوْ يَتْرُكُوا قِرَاءَةَ التَّوْرَاةِ وَالْإِنْجِيلِ إِلَّا مَا بَدَّلُوا مِنْهَا فَقَالُوا مَا تُرِيدُونَ إِلَى ذَلِكَ دَعُونَا فَقَالَتْ طَائِفَةٌ مِنْهُمْ ابْنُوا لَنَا أُسْطُوَانَةً ثُمَّ ارْفَعُونَا إِلَيْهَا ثُمَّ اعْطُونَا شَيْئًا نَرْفَعُ بِهِ طَعَامَنَا وَشَرَابَنَا فَلَا نَرِدُ عَلَيْكُمْ وَقَالَتْ طَائِفَةٌ مِنْهُمْ دَعُونَا نَسِيحُ فِي الْأَرْضِ وَنَهِيمُ وَنَشْرَبُ كَمَا يَشْرَبُ الْوَحْشُ فَإِنْ قَدَرْتُمْ عَلَيْنَا فِي أَرْضِكُمْ فَاقْتُلُونَا وَقَالَتْ طَائِفَةٌ مِنْهُمْ ابْنُوا لَنَا دُورًا فِي الْفَيَافِي وَنَحْتَفِرُ الْآبَارَ وَنَحْتَرِثُ الْبُقُولَ فَلَا نَرِدُ عَلَيْكُمْ وَلَا نَمُرُّ بِكُمْ وَلَيْسَ أَحَدٌ مِنْ الْقَبَائِلِ إِلَّا وَلَهُ حَمِيمٌ فِيهِمْ قَالَ فَفَعَلُوا ذَلِكَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَرَهْبَانِيَّةً ابْتَدَعُوهَا مَا كَتَبْنَاهَا عَلَيْهِمْ إِلَّا ابْتِغَاءَ رِضْوَانِ اللَّهِ فَمَا رَعَوْهَا حَقَّ رِعَايَتِهَا }وَالْآخَرُونَ قَالُوا نَتَعَبَّدُ كَمَا تَعَبَّدَ فُلَانٌ وَنَسِيحُ كَمَا سَاحَ فُلَانٌ وَنَتَّخِذُ دُورًا كَمَا اتَّخَذَ فُلَانٌ وَهُمْ عَلَى شِرْكِهِمْ لَا عِلْمَ لَهُمْ بِإِيمَانِ الَّذِينَ اقْتَدَوْا بِهِ فَلَمَّا بَعَثَ اللَّهُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَبْقَ مِنْهُمْ إِلَّا قَلِيلٌ انْحَطَّ رَجُلٌ مِنْ صَوْمَعَتِهِ وَجَاءَ سَائِحٌ مِنْ سِيَاحَتِهِ وَصَاحِبُ الدَّيْرِ مِنْ دَيْرِهِ فَآمَنُوا بِهِ وَصَدَّقُوهُ فَقَالَ اللَّهُ تَبَارَكَ وَتَعَالَى{ يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ وَآمِنُوا بِرَسُولِهِ يُؤْتِكُمْ كِفْلَيْنِ مِنْ رَحْمَتِهِ }أَجْرَيْنِ بِإِيمَانِهِمْ بِعِيسَى وَبِالتَّوْرَاةِ وَالْإِنْجِيلِ وَبِإِيمَانِهِمْ بِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَتَصْدِيقِهِمْ قَالَ يَجْعَلْ لَكُمْ نُورًا تَمْشُونَ بِهِ الْقُرْآنَ وَاتِّبَاعَهُمْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ{ لِئَلَّا يَعْلَمَ أَهْلُ الْكِتَابِ }يَتَشَبَّهُونَ بِكُمْ{ أَنْ لَا يَقْدِرُونَ عَلَى شَيْءٍ مِنْ فَضْلِ اللَّهِ }الْآيَةَ","id":"Telah mengabarkan kepada kami [Al Husain bin Huraits] ia berkata; telah memberitakan kepada kami [Al Fadl bin Musa] dari [Sufyan bin Sa'id] dari ['Atha` bin As Sa`ib] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata; \"Raja-raja setelah Nabi Isa bin Maryam 'Alaihi Ash Shalatu was Salam mengubah Kitab Taurat dan Injil, padahal di tengah-tengah mereka ada orang-orang yang membaca Kitab Taurat. Lalu dikatakan kepada raja-raja itu; \"Kita tidak mendapatkan celaan yang lebah buruk dari celaan mereka. Mereka membaca: ' Barangsiapa yang tidak memutuskan menurut apa yang diturunkan Allah, maka mereka itu adalah orang-orang yang kafir'. Ayat-ayat itu mereka baca untuk mencela perbuatan kita, maka ajaklah mereka agar mereka membaca sebagaimana yang kita baca, dan beriman sebagaimana yang kita imani.\" Raja-raja itu lalu mengajak orang-orang yang membaca Taurat (orang-orang yang beriman), kemudian mengumpulkan dan menawarkan kepada mereka; (memilih untuk) dibunuh atau mereka meninggalkan bacaan Taurat dan Injil mereka, kecuali jika mereka mau membaca Taurat dan Injil sebagaimana bacaan yang telah mereka ubah. Orang-orang yang beriman berkata; \"Apa yang kalian inginkan dengan tawaran itu? Biarkanlah kami.\" Lalu sekelompok dari mereka berkata; \"Bangunkanlah sebuah menara untuk kami, lalu naikkan kami ke atasnya, berikan kepada kami suatu alat yang dengannya kami dapat menaikkan makanan dan minuman kami hingga kami tidak melewati (mengganggu) kalian.\" Sebagian dari mereka juga berkata; \"Biarkanlah kami berpencar di bumi sampai kami kehausan dan minum sebagaimana binatang minum, jika kalian mendapati kami berada di wilayah kalian, maka bunuhlah kami.\" Sebagian lagi berkata; \"Bangunkan kami sebuah rumah (biara) di padang sahara, maka kami akan menggali sumur dan menanam sayuran, kami tidak akan melintasi atau menemui kalian lagi.\" Dan tidak ada satu kabilah pun kecuali telah disiapkan air yang mendidih oleh raja-raja tersebut. Ibnu Abbas berkata; \"Ketika mereka melakukan hal itu, Allah 'azza wajalla menurunkan ayat: ' Dan mereka mengada-adakan rahbaniyyah padahal kami tidak mewajibkannya kepada mereka tetapi (mereka sendirilah yang mengada-adakannya) untuk mencari keridhaan Allah, lalu mereka tidak memeliharanya dengan pemeliharaan yang semestinya'. Sedangkan yang lain berkata; \"Kami akan beribadah sebagaimana Fulan beribadah. Kami akan berpetualang sebagaimana Fulan berpetualang. Kami akan membangun rumah sebagaimana Fulan membagun rumah.\" Mereka tetap dalam kemusyrikan, dan mereka tidak mempunyai pengetahuan tentang keimanan orang-orang yang mereka jadikan tauladan. Ketika Allah mengutus Nabi shallallahu 'alaihi wasallam, mereka (orang-orang yang beriman) tidak tersisa kecuali hanya sedikit saja. Seorang laki-laki akan turun dari tempat peribadatannya, para petualang akan datang dari tempat petualangannya, pemilik rumah (biara) akan keluar dari dalam rumahnya, lalu mereka akan beriman dan membenarkan kenabiannya (Muhammad). Allah Tabaraka Wa Ta'ala lalu berfirman: ' Hai orang-orang yang beriman (kepada para rasul), bertakwalah kepada Allah dan berimanlah kepada Rasul-Nya, niscaya Allah memberikan rahmat-Nya kepadamu dua bagian'. Dua bagian (kebaikan) itu adalah keimanan mereka kepada Isa, Taurat dan Injil, serta keimanan mereka kepada Muhammad shallallahu 'alaihi wasallam dan pembenaran mereka kepadanya. Ibnu Abbas melanjutkan; \"Allah menjadikan cahaya bagi mereka, dengannya mereka dapat mengamalkan Al-Qur'an dan mengikuti sunnah Nabi shallallahu 'alaihi wasallam.\" Selanjutnya Allah berfirman: ' Kami terangkan yang demikian itu) supaya ahli Kitab mengetahui', mereka menyerupai kalian '(bahwa mereka tiada mendapat sedikitpun) '.\""},"5045":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ قَالَ حَدَّثَنِي أَبِي عَنْ زَيْنَبَ بِنْتِ أَبِي سَلَمَةَ عَنْ أُمِّ سَلَمَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّكُمْ تَخْتَصِمُونَ إِلَيَّ وَإِنَّمَا أَنَا بَشَرٌ وَلَعَلَّ بَعْضَكُمْ أَلْحَنُ بِحُجَّتِهِ مِنْ بَعْضٍ فَمَنْ قَضَيْتُ لَهُ مِنْ حَقِّ أَخِيهِ شَيْئًا فَلَا يَأْخُذْهُ فَإِنَّمَا أَقْطَعُهُ بِهِ قِطْعَةً مِنْ النَّارِ","id":"Telah mengabarkan kepada kami ['Amru bin Ali] ia berkata; telah menceritakan kepada kami [Yahya] ia berkata; telah menceritakan kepada kami [Hisyam bin 'Urwah] ia berkata; telah menceritakan kepadaku [Ayahku] dari [Zainab binti Abu Salamah] dari [Ummu Salamah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalian mengadukan permasalahan kepadaku, padahal aku hanyalah manusia biasa, barangkali sebagian dari kalian lebih fasih dalam mengemukakan argumentnya dari sebagian yang lain. Maka barangsiapa yang aku beri putusan dengan mengorbankan hak saudaranya, janganlah kalian ambil, sebab dengan begitu berarti aku telah memercikkan untuknya api neraka.\""},"5046":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ بَكَّارِ بْنِ رَاشِدٍ قَالَ حَدَّثَنَا عَلِيُّ بْنُ عَيَّاشٍ قَالَ حَدَّثَنَا شُعَيْبٌ قَالَ حَدَّثَنِي أَبُو الزِّنَادِ مِمَّا حَدَّثَهُ عَبْدُ الرَّحْمَنِ الْأَعْرَجُ مِمَّا ذَكَرَ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يُحَدِّثُ بِهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَقَالَ بَيْنَمَا امْرَأَتَانِ مَعَهُمَا ابْنَاهُمَا جَاءَ الذِّئْبُ فَذَهَبَ بِابْنِ إِحْدَاهُمَا فَقَالَتْ هَذِهِ لِصَاحِبَتِهَا إِنَّمَا ذَهَبَ بِابْنِكِ وَقَالَتْ الْأُخْرَى إِنَّمَا ذَهَبَ بِابْنِكِ فَتَحَاكَمَتَا إِلَى دَاوُدَ عَلَيْهِ السَّلَام فَقَضَى بِهِ لِلْكُبْرَى فَخَرَجَتَا إِلَى سُلَيْمَانَ بْنِ دَاوُدَ فَأَخْبَرَتَاهُ فَقَالَ ائْتُونِي بِالسِّكِّينِ أَشُقُّهُ بَيْنَهُمَا فَقَالَتْ الصُّغْرَى لَا تَفْعَلْ يَرْحَمُكَ اللَّهُ هُوَ ابْنُهَا فَقَضَى بِهِ لِلصُّغْرَىقَالَ أَبُو هُرَيْرَةَ وَاللَّهِ مَا سَمِعْتُ بِالسِّكِّينِ قَطُّ إِلَّا يَوْمَئِذٍ مَا كُنَّا نَقُولُ إِلَّا الْمُدْيَةَ","id":"Telah mengabarkan kepada kami [Imran bin Bakkar bin Rasyid] ia berkata; telah menceritakan kepada kami [Ali bin Ayyasy] ia berkata; telah menceritakan kepada kami [Syi'aib] ia berkata; telah menceritakan kepadaku [Abu Az Zinad] dari apa-apa yang diceritakan oleh ['Abdurrahman Al A'raj] dari apa-apa yang ia ceritakan, bahwa ia mendengar [Abu Hurairah] menceritakan hadits tersebut dari Rasulullah shallallahu 'alaihi wasallam, ia berkata; Beliau bersabda: \"Ketika dua orang wanita sedang bersama bayi mereka, seekor serigala datang dan membawa bayi salah seorang dari mereka. salah seorang dari keduanya berkata; \"Serigala itu pergi dengan membawa bayimu!\" Kemudian yang lain berkata; \"Tidak, tetapi serigala itu pergi dengan membawa bayimu!\" maka keduanya pergi untuk berhukum kepada Nabi Dawud 'Alaihis Salam, lalu Nabi Dawud memberi putusan bahwa bayi yang ada itu adalah bayi wanita yang lebih tua. Kemudian keduanya pergi menemui Nabi Sulaiman bin Dawud dan mengabarkan kepadanya tentang persoalan tersebut. Nabi Sulaiman lantas berkata; \"Berilah aku pisau kecil hingga aku dapat membelahnya untuk kalian berdua.\" Wanita yang lebih muda berkata; \"Jangan engkau lakukan, semoga Allah merahmatimu. Itu adalah bayiku.\" Maka Sulaiman pun memutuskan bahwa bayi tersebut adalah milik wanita yang lebih muda.\" Abu Hurairah berkata, \"Demi Allah, aku tidak pernah mendengar kata Sikkin (pisau) kecuali hari ini, kami tidak menyebutnya kecuali dengan mudyah (pisau).\""},"5047":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا شُعَيْبُ بْنُ اللَّيْثِ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ عَجْلَانَ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ خَرَجَتْ امْرَأَتَانِ مَعَهُمَا صَبِيَّانِ لَهُمَا فَعَدَا الذِّئْبُ عَلَى إِحْدَاهُمَا فَأَخَذَ وَلَدَهَا فَأَصْبَحَتَا تَخْتَصِمَانِ فِي الصَّبِيِّ الْبَاقِي إِلَى دَاوُدَ عَلَيْهِ السَّلَام فَقَضَى بِهِ لِلْكُبْرَى مِنْهُمَا فَمَرَّتَا عَلَى سُلَيْمَانَ فَقَالَ كَيْفَ أَمْرُكُمَا فَقَصَّتَا عَلَيْهِ فَقَالَ ائْتُونِي بِالسِّكِّينِ أَشُقُّ الْغُلَامَ بَيْنَهُمَا فَقَالَتْ الصُّغْرَى أَتَشُقُّهُ قَالَ نَعَمْ فَقَالَتْ لَا تَفْعَلْ حَظِّي مِنْهُ لَهَا قَالَ هُوَ ابْنُكِ فَقَضَى بِهِ لَهَا","id":"Telah menceritakan kepada kami [Ar Rabi' bin Sulaiman] ia berkata; telah menceritakan kepada kami [Syu'aib bin Al Laits] ia berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu 'Ajlan] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Dua orang wanita keluar dengan membawa anak mereka masing-masing, lalu seekor serigala mengambil anak salah seorang dari mereka. Lalu mereka mengadu kepada Nabi Dawud 'Alaihis Salam tentang perselisihan mereka terhadap anak yang masih tersisa. Dan Nabi Dawud memberi putusan bahwa anak itu milik wanita yang umurnya lebih tua. Keduanya lalu melewati Nabi Sulaiman, Nabi Sulaiman bertanya, \"Apa masalah kalian?\" akhirnya keduanya mengisahkan masalah tersebut kepadanya, Nabi Sulaiman lalu berkata, \"Berilah aku sebilah pisau, aku dapat membelahnya untuk kalian berdua.\" Maka wanita yang lebih muda berkata, \"Engkau akan membelahnya!\" Nabi Sulaiman menjawab, \"Benar.\" Wanita itu berkata lagi, \"Jangan engkau lakukan, bagianku akan aku berikan kepadanya.\" Nabi Sulaiman kemudian berkata, \"Anak itu adalah milikmu.\" Maka Nabi Sulaiman memberi putusan bahwa anak tersebut milik wanita yang lebih muda.\""},"5048":{"ar":"أَخْبَرَنَا الْمُغِيرَةُ بْنُ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا مِسْكِينُ بْنُ بُكَيْرٍ قَالَ حَدَّثَنَا شُعَيْبُ بْنُ أَبِي حَمْزَةَ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَرَجَتْ امْرَأَتَانِ مَعَهُمَا وَلَدَاهُمَا فَأَخَذَ الذِّئْبُ أَحَدَهُمَا فَاخْتَصَمَتَا فِي الْوَلَدِ إِلَى دَاوُدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَضَى بِهِ لِلْكُبْرَى مِنْهُمَا فَمَرَّتَا عَلَى سُلَيْمَانَ عَلَيْهِ السَّلَام فَقَالَ كَيْفَ قَضَى بَيْنَكُمَا قَالَتْ قَضَى بِهِ لِلْكُبْرَى قَالَ سُلَيْمَانُ أَقْطَعُهُ بِنِصْفَيْنِ لِهَذِهِ نِصْفٌ وَلِهَذِهِ نِصْفٌ قَالَتْ الْكُبْرَى نَعَمْ اقْطَعُوهُ فَقَالَتْ الصُّغْرَى لَا تَقْطَعْهُ هُوَ وَلَدُهَا فَقَضَى بِهِ لِلَّتِي أَبَتْ أَنْ يَقْطَعَهُ","id":"Telah mengabarkan kepada kami [Al Mughirah bin 'Abdurrahman] ia berkata; telah menceritakan kepada kami [Miskin bin Bukair] ia berkata; telah menceritakan kepada kami [Syu'aib bin Abu Hamzah] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Dua orang wanita keluar dengan membawa anak mereka masing-masing, lalu seekor serigala mengambil anak salah seorang dari keduanya. Maka keduanya mengadukan kepada Nabi Dawud 'Alaihis Salam tentang setatus anak yang masih tersisa. Lalu Nabi Dawud memutuskan bahwa anak itu adalah milik wanita yang lebih tua. Kemudian mereka mendatangi Nabi Sulaiman, ia lalu bertanya, \"bagaimana Nabi Dawud memberi putusan untuk kalian?\" Wanita yang umurnya lebih muda berkata, \"Dia memberi putusan bahwa anak itu milik wanita yang umurnya lebih tua.\" Nabi Sulaiman berkata, \"Aku akan membelahnya menjadi dua bagian, untuk yang ini separuh dan untuk yang ini separuh.\" Wanita yang lebih tua berkata, \"Ya, silahkan potong.\" Sementara yang muda berkata, \"Jangan engkau potong, biarlah anak itu menjadi miliknya.\" Maka Sulaiman memberi putusan bahwa anak itu untuk wanita yang menolak agar anak itu dipotong.\""},"5049":{"ar":"أَخْبَرَنَا زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ حَمَّادٍ قَالَ حَدَّثَنَا بِشْرُ بْنُ السَّرِيِّ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ مَعْمَرٍ ح وَأَنْبَأَنَا أَحْمَدُ بْنُ عَلِيِّ بْنِ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ مَعِينٍ قَالَ حَدَّثَنَا هِشَامُ بْنُ يُوسُفَ وَعَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَبَعَثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَالِدَ بْنَ الْوَلِيدِ إِلَى بَنِي جَذِيمَةَ فَدَعَاهُمْ إِلَى الْإِسْلَامِ فَلَمْ يُحْسِنُوا أَنْ يَقُولُوا أَسْلَمْنَا فَجَعَلُوا يَقُولُونَ صَبَأْنَا وَجَعَلَ خَالِدٌ قَتْلًا وَأَسْرًا قَالَ فَدَفَعَ إِلَى كُلِّ رَجُلٍ أَسِيرَهُ حَتَّى إِذَا أَصْبَحَ يَوْمُنَا أَمَرَ خَالِدُ بْنُ الْوَلِيدِ أَنْ يَقْتُلَ كُلُّ رَجُلٍ مِنَّا أَسِيرَهُ قَالَ ابْنُ عُمَرَ فَقُلْتُ وَاللَّهِ لَا أَقْتُلُ أَسِيرِي وَلَا يَقْتُلُ أَحَدٌ وَقَالَ بِشْرٌ مِنْ أَصْحَابِي أَسِيرَهُ قَالَ فَقَدِمْنَا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذُكِرَ لَهُ صُنْعُ خَالِدٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَفَعَ يَدَيْهِ اللَّهُمَّ إِنِّي أَبْرَأُ إِلَيْكَ مِمَّا صَنَعَ خَالِدٌ قَالَ زَكَرِيَّا فِي حَدِيثِهِ فَذُكِرَ وَفِي حَدِيثِ بِشْرٍ فَقَالَ اللَّهُمَّ إِنِّي أَبْرَأُ إِلَيْكَ مِمَّا صَنَعَ خَالِدٌ مَرَّتَيْنِ","id":"Telah mengabarkan kepada kami [Zakaria bin Yahya] ia berkata; telah menceritakan kepada kami [Abdul A'la bin Hammad] ia berkata; telah menceritakan kepada kami [Bisyr bin As Sari] ia berkata; telah menceritakan kepada kami [Abdullah Ibnul Mubarak] dari [Ma'mar]. (dalam riwayat lain disebutkan) telah memberitakan kepada kami [Ahmad bin Ali bin Sa'id] ia berkata; telah menceritakan kepada kami [Yahya bin Ma'in] ia berkata; telah menceritakan kepada kami [Hisyam bin Yusuf] dan [Abdurrazaq] dari [Ma'mar] dari [Az Zuhri] dari [Salim] dari [bapaknya] ia berkata, \"Nabi shallallahu 'alaihi wasallam mengutus Khalid bin Walid kepada bani Jadzimah, ia menyeru mereka untuk masuk Islam, namun mereka tidak berlaku baik dengan mengatakan 'kami masuk Islam', dan mereka justeru mengatakan 'kami pindah agama'. Sehingga hal itulah yang menjadikan Khalid membunuh dan menawan. Ibnu Umar berkata, \"Khalid menyerahkan kepada setiap pasukan untuk memperlakukan tawanannya, hingga ketika pada suatu pagi hari Khalid Ibnul Walid memerintahkan setiap kita untuk membunuh tawanannya.\" Ibnu Umar berkata, \"Aku berkata, \"Demi Allah, aku tidak akan membunuh tawananku, dan tidak seorang pun, Bisyr menyebutkan, \"dari sahabatku yang akan membunuh tawanannya.\" Ibnu Umar berkata, \"Kami kemudian datang menemui Nabi shallallahu 'alaihi wasallam, dan apa yang dilakukan oleh Khalid itu diceritakan kepada beliau, maka Nabi shallallahu 'alaihi wasallam pun mengangkat tangan dan mengucapkan: \"Ya Allah, aku berlepas diri dari tindakan yang dilakukan oleh Khalid.\" Zakariya menyebutkan dalam haditsnya, \"Lalu disebutkan.\" Sementara dalam hadits Bisyr disebutkan, \"Beliau bersabda: \"Ya Allah, aku serahkan kepada-Mu apa yang telah dilakukan oleh Khalid. Beliau ucapkan dua kali.\""},"5050":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ قَالَكَتَبَ أَبِي وَكَتَبْتُ لَهُ إِلَى عُبَيْدِ اللَّهِ بْنِ أَبِي بَكْرَةَ وَهُوَ قَاضِي سِجِسْتَانَ أَنْ لَا تَحْكُمَ بَيْنَ اثْنَيْنِ وَأَنْتَ غَضْبَانُ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَحْكُمْ أَحَدٌ بَيْنَ اثْنَيْنِ وَهُوَ غَضْبَانُ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Abu Awanah] dari [Abdul Malik bin Umair] dari ['Abdurrahman bin Abu Bukair] ia berkata, \" [Bapakku] menulis surat -dan aku yang menuliskan untuknya- kepada Ubaidullah bin Abu Bakrah, seorang hakim di Sijistan. Yang isinya; janganlah kamu memutuskan antara dua orang sementara kamu dalam keadaan marah, sesungguhnya aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah seseorang memberi putusan di antara dua orang sementara ia dalam keadaan marah.\""},"5051":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى وَالْحَارِثُ بْنُ مِسْكِينٍ عَنْ ابْنِ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ بْنُ يَزِيدَ وَاللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ أَنَّ عُرْوَةَ بْنَ الزُّبَيْرِ حَدَّثَهُ أَنَّ عَبْدَ اللَّهِ بْنَ الزُّبَيْرِ حَدَّثَهُ عَنْ الزُّبَيْرِ بْنِ الْعَوَّامِأَنَّهُ خَاصَمَ رَجُلًا مِنْ الْأَنْصَارِ قَدْ شَهِدَ بَدْرًا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي شِرَاجِ الْحَرَّةِ كَانَا يَسْقِيَانِ بِهِ كِلَاهُمَا النَّخْلَ فَقَالَ الْأَنْصَارِيُّ سَرِّحْ الْمَاءَ يَمُرُّ عَلَيْهِ فَأَبَى عَلَيْهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْقِ يَا زُبَيْرُ ثُمَّ أَرْسِلْ الْمَاءَ إِلَى جَارِكَ فَغَضِبَ الْأَنْصَارِيُّ وَقَالَ يَا رَسُولَ اللَّهِ أَنْ كَانَ ابْنَ عَمَّتِكَ فَتَلَوَّنَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ يَا زُبَيْرُ اسْقِ ثُمَّ احْبِسْ الْمَاءَ حَتَّى يَرْجِعَ إِلَى الْجَدْرِ فَاسْتَوْفَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلزُّبَيْرِ حَقَّهُ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْلَ ذَلِكَ أَشَارَ عَلَى الزُّبَيْرِ بِرَأْيٍ فِيهِ السَّعَةُ لَهُ وَلِلْأَنْصَارِيِّ فَلَمَّا أَحْفَظَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأَنْصَارِيُّ اسْتَوْفَى لِلزُّبَيْرِ حَقَّهُ فِي صَرِيحِ الْحُكْمِقَالَ الزُّبَيْرُ لَا أَحْسَبُ هَذِهِ الْآيَةَ أُنْزِلَتْ إِلَّا فِي ذَلِكَ{ فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ حَتَّى يُحَكِّمُوكَ فِيمَا شَجَرَ بَيْنَهُمْ }وَأَحَدُهُمَا يَزِيدُ عَلَى صَاحِبِهِ فِي الْقِصَّةِ","id":"Telah mengabarkan kepada kami [Yunus bin Abdul A'la] dan [Al Harits bin Miskin] dari [Ibnu Wahb] ia berkata; telah mengabarkan kepadaku [Yunus bin Yazid] dan [Al Laits bin Sa'd] dari [Ibnu Syihab] bahwa ['Urwah Ibnu Az Zubair] menceritakan kepadanya, bahwa [Abdullah bin Az Zubair] menceritakan kepadanya, bahwa [Az Zubair bin 'Awwam] pernah berselisih dengan seorang laki-laki Anshar yang pernah ikut perang badar bersama Rasulullah shallallahu 'alaihi wasallam dalam masalah mata air harrah yang biasa mereka gunakan untuk mengairi kebun kurma mereka. Laki-laki Anshar itu berkata; \"Biarkanlah air itu mengalir.\" Namun Az Zubair menolaknya. Rasulullah shallallahu 'alaihi wasallam kemudian berkata kepada Az Zubair: \"Wahai Zubair, airilah kebunmu. Setelah itu berikanlah kepada tetanggamu.\" Orang Anshar itu marah dan berkata; \"Wahai Rasulullah, apakah karena ia anak pamanmu?\" maka menjadi merahlah wajah Rasulullah shallallahu 'alaihi wasallam, beliau kemudian bersabda: \"Wahai Zubair, airilah kebunmu. Setelah itu tahanlah airnya hingga ia kembali ke dalam tanah.\" Lantas Rasulullah shallallahu 'alaihi wasallam memenuhi haknya Zubair. Padahal sebelum itu, Rasulullah shallallahu 'alaihi wasallam memberi isyarat kepada Zubair untuk berlaku fleksibel baik untuknya maupun untuk laki-laki Anshar itu. Ketika laki-laki Anshar itu marah kepada Rasulullah shallallahu 'alaihi wasallam, beliau hanya memenuhi haknya Zubair dalam putusannya.\" Az Zubair berkata; \"Aku tidak berpendapat kecuali ayat ini hanya turun berkenaan dengan kasus itu: ' Maka demi Tuhanmu, mereka (pada hakekatnya) tidak beriman hingga mereka menjadikan kamu hakim terhadap perkara yang mereka perselisihkan.\" QS An Nisa`; 65"},"5052":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ قَالَ أَنْبَأَنَا يُونُسُ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ كَعْبٍ عَنْ أَبِيهِأَنَّهُ تَقَاضَى ابْنَ أَبِي حَدْرَدٍ دَيْنًا كَان�� عَلَيْهِ فَارْتَفَعَتْ أَصْوَاتُهُمَا حَتَّى سَمِعَهُمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي بَيْتِهِ فَخَرَجَ إِلَيْهِمَا فَكَشَفَ سِتْرَ حُجْرَتِهِ فَنَادَى يَا كَعْبُ قَالَ لَبَّيْكَ يَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ضَعْ مِنْ دَيْنِكَ هَذَا وَأَوْمَأَ إِلَى الشَّطْرِ قَالَ قَدْ فَعَلْتُ قَالَ قُمْ فَاقْضِهِ","id":"Telah mengabarkan kepada kami [Abu Dawud] ia berkata; telah menceritakan kepada kami [Utsman bin Umar] ia berkata; telah memberitakan kepada kami [Yunus] dari [Az Zuhri] dari [Abdullah bin Ka'b] dari [Ayahnya] bahwa ia pernah meminta pembayaran hutang kepada Ibnu Abu Hadrad, suara keduanya meninggi hingga Rasulullah shallallahu 'alaihi wasallam mendengarnya dari dalam rumah. Beliau kemudian keluar menemui keduanya seraya membuka kain penutup kamarnya, beliau berseru: \"Wahai Ka'b!\" Ka'b menjawab, \"Aku penuhi panggilanmu wahai Rasulullah shallallahu 'alaihi wasallam.\" beliau bersabda: \"Bebaskanlah sebagian dari hutangmu.\" Beliau memberi isyarat setengahnya. Ka'b menjawab, \"Aku telah lakukan itu.\" Beliau bersabda (kepada Ibnu Abu Hardad): \"Berdiri dan bayarlah.\""},"5053":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ مَنْصُورِ بْنِ جَعْفَرٍ قَالَ حَدَّثَنَا مُبَشِّرُ بْنُ عَبْدِ اللَّهِ بْنِ رَزِينٍ قَالَ حَدَّثَنَا سُفْيَانُ بْنُ حُسَيْنٍ عَنْ أَبِي بِشْرٍ جَعْفَرِ بْنِ إِيَاسٍ عَنْ عَبَّادِ بْنِ شُرَحْبِيلَ قَالَقَدِمْتُ مَعَ عُمُومَتِي الْمَدِينَةَ فَدَخَلْتُ حَائِطًا مِنْ حِيطَانِهَا فَفَرَكْتُ مِنْ سُنْبُلِهِ فَجَاءَ صَاحِبُ الْحَائِطِ فَأَخَذَ كِسَائِي وَضَرَبَنِي فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْتَعْدِي عَلَيْهِ فَأَرْسَلَ إِلَى الرَّجُلِ فَجَاءُوا بِهِ فَقَالَ مَا حَمَلَكَ عَلَى هَذَا فَقَالَ يَا رَسُولَ اللَّهِ إِنَّهُ دَخَلَ حَائِطِي فَأَخَذَ مِنْ سُنْبُلِهِ فَفَرَكَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا عَلَّمْتَهُ إِذْ كَانَ جَاهِلًا وَلَا أَطْعَمْتَهُ إِذْ كَانَ جَائِعًا ارْدُدْ عَلَيْهِ كِسَاءَهُ وَأَمَرَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِوَسْقٍ أَوْ نِصْفِ وَسْقٍ","id":"Telah mengabarkan kepada kami [Al Husain bin Manshur bin Ja'far] ia berkata; telah menceritakan kepada kami [Mubasysyir bin Abdullah bin Razin] ia berkata; telah menceritakan kepada kami [Sufyan bin Husain] dari [Abu Bisyr Ja'far bin Iyas] dari [Abbad bin Syurahbil] ia berkata, \"Aku bersama bibi-bibiku datang ke Madinah, lalu aku masuk ke salah satu kebun di sana dan aku goyang-goyang dahannya (agar buahnya jatuh). Kemudian pemiliknya datang, lalu memegang baju dan memukulku. Maka aku datang menemui Rasulullah shallallahu 'alaihi wasallam meminta perlindungan kepadanya, hingga beliau mengutus utusan untuk menemui laki-laki pemilik kebun itu. Tidak lama kemudian, utusan itu kembali dengan membawa pemilik kebun ke hadapan Nabi. Beliau bertanya: \"Apa yang membuatmu melakukan perbuatan ini?\" laki-laki itu menjawab; \"Wahai Rasulullah, orang itu masuk ke dalam kebunku, ia memegang dahan dan menggoyang-goyangnya!\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kenapa kamu tidak memberitahukannya saat dia bodoh (tidak tahu), dan kenapa kamu tidak memberinya makan saat ia lapar. Kembalikanlah baju miliknya!\" Rasulullah shallallahu 'alaihi wasallam kemudian memerintahkan pemilik kebun itu untuk memberiku satu wasaq atau setengahnya.\" "},"5054":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ أَنْبَأَنَا عَبْدُ الرَّحْمَنِ بْنُ الْقَاسِمِ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ أَبِي هُرَيْرَةَ وَزَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ أَنَّهُمَا أَخْبَرَاهُأَنَّ رَجُلَيْنِ اخْتَصَمَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَحَدُهُمَا اقْضِ بَيْنَنَا بِكِتَابِ اللَّهِ وَقَالَ الْآخَرُ وَهُوَ أَفْقَهُهُمَا أَجَلْ يَا رَسُولَ اللَّهِ وَأْذَنْ لِي فِي أَنْ أَتَكَلَّمَ قَالَ إِنَّ ابْنِي كَانَ عَسِيفًا عَلَى هَذَا فَزَنَى بِامْرَأَتِهِ فَأَخْبَرُونِي أَنَّ عَلَى ابْنِي الرَّجْمَ فَافْتَدَيْتُ بِمِائَةِ شَاةٍ وَبِجَارِيَةٍ لِي ثُمَّ إِنِّي سَأَلْتُ أَهْلَ الْعِلْمِ فَأَخْبَرُونِي أَنَّمَا عَلَى ابْنِي جَلْدُ مِائَةٍ وَتَغْرِيبُ عَامٍ وَإِنَّمَا الرَّجْمُ عَلَى امْرَأَتِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ لَأَقْضِيَنَّ بَيْنَكُمَا بِكِتَابِ اللَّهِ أَمَّا غَنَمُكَ وَجَارِيَتُكَ فَرَدٌّ إِلَيْكَ وَجَلَدَ ابْنَهُ مِائَةً وَغَرَّبَهُ عَامًا وَأَمَرَ أُنَيْسًا أَنْ يَأْتِيَ امْرَأَةَ الْآخَرِ فَإِنْ اعْتَرَفَتْ فَارْجُمْهَا فَاعْتَرَفَتْ فَرَجَمَهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] ia berkata; telah memberitakan kepada kami ['Abdurrahman Ibnul Qasim] dari [Malik] dari [Ibnu Syihab] dari [Ubaidullah bin Abdullah bin Utbah] dari [Abu Hurairah] dan [Zaid bin Khalid Al Juhani] keduanya mengabarkan kepadanya, bahwa dua orang laki-laki yang berselisih mengadu kepada Rasulullah shallallahu 'alaihi wasallam. Salah seorang dari keduanya berkata; \"Hukumilah antara kami berdua sesuai dengan Kitabullah, \" yang lain berkata -dan ini yang lebih fakih di antara mereka berdua-, \"Benar, ya Rasulullah. Tapi izinkanlah aku untuk berbicara, laki-laki itu pun berkata; \"Sesungguhnya anakku adalah seorang buruh yang bekerja untuk orang ini, lalu anakku berzina dengan isterinya. Orang-orang mengabariku bahwa hukuman bagi anakku adalah rajam. Maka aku menebusnya dengan seratus ekor kambing dan seorang budak wanita milikku. Setelah itu aku bertanya kepada ahli ilmu, mereka mengabariku bahwa hukuman bagi anakku adalah cambuk seratus kali dan diasingkan selama satu tahun. Sementara hukuman rajam untuk isterinya.\" Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Demi Dzat yang jiwaku ada dalam tangan-Nya, sungguh aku akan menghukumi kalian dengan Kitabullah. Kambing dan budak itu akan dikembalikan lagi kepadamu.\" Kemudian beliau mencambuk anaknya seratus kali dan mengasingkannya selama satu tahun. Lalu beliau memerintahkan Unais agar membawa wanita itu: \"Jika ia mengaku maka rajamlah.\" Wanita itu pun mengaku dan akhirnya dirajam.\""},"5055":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي هُرَيْرَةَ وَزَيْدِ بْنِ خَالِدٍ وَشِبْلٍ قَالُواكُنَّا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ إِلَيْهِ رَجُلٌ فَقَالَ أَنْشُدُكَ بِاللَّهِ إِلَّا مَا قَضَيْتَ بَيْنَنَا بِكِتَابِ اللَّهِ فَقَامَ خَصْمُهُ وَكَانَ أَفْقَهَ مِنْهُ فَقَالَ صَدَقَ اقْضِ بَيْنَنَا بِكِتَابِ اللَّهِ قَالَ قُلْ قَالَ إِنَّ ابْنِي كَانَ عَسِيفًا عَلَى هَذَا فَزَنَى بِامْرَأَتِهِ فَافْتَدَيْتُ مِنْهُ بِمِائَةِ شَاةٍ وَخَادِمٍ وَكَأَنَّهُ أُخْبِرَ أَنَّ عَلَى ابْنِهِ الرَّجْمَ فَافْتَدَى مِنْهُ ثُمَّ سَأَلْتُ رِجَالًا مِنْ أَهْلِ الْعِلْمِ فَأَخْبَرُونِي أَنَّ عَلَى ابْنِي جَلْدُ مِائَةٍ وَتَغْرِيبُ عَامٍ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ لَأَقْضِيَنَّ بَيْنَكُمَا بِكِتَابِ اللَّهِ عَزَّ وَجَلَّ أَمَّا الْمِائَةُ شَاةٍ وَالْخَادِمُ فَرَدٌّ عَلَيْكَ وَعَلَى ابْنِكَ جَلْدُ مِائَةٍ وَتَغْرِيبُ عَامٍ اغْدُ يَا أُنَيْسُ عَلَى امْرَأَةِ هَذَا فَإِنْ اعْتَرَفَتْ فَارْجُمْهَا فَغَدَا عَلَيْهَا فَاعْتَرَفَتْ فَرَجَمَهَا","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Ubaidullah bin Abdullah] dari [Abu Hurairah] dan [Zaid bin Khalid] dan [Syibl] mereka berkata; \"Ketika kami sedang di sisi Nabi shallallahu 'alaihi wasallam, seorang laki-laki bangkit ke arah beliau dan berkata: \"Aku bersumpah kepada Allah atas diri baginda, kecuali jika engkau hukumi antara kami berdua dengan Kitabullah!\" lalu laki-laki yang menjadi seterunya berdiri dan berkata -dan ia lebih fakih di antara keduanya, \"Benar, hukumilah antara kami sesuai dengan Kitabullah.\" Beliau bersabda: \"Katakanlah.\" Laki-laki itu berkata, \"Sesungguhnya anakku adalah seorang buruh yang berkerja untuk orang ini, lalu anakku berzina dengan isterinya, dan aku telah menebusnya dengan seratus ekor kambing dan seorang budak. -seakan ia diberi kabar bahwa hukuman bagi anaknya adalah rajam hingga ia pun menebusnya- Kemudian aku bertanya seorang laki-laki dari ahli ilmu, mereka kemudian mengabariku bahwa hukuman bagi anakku adalah cambuk seratus kali dan diasingkan selama satu tahun. Rasulullah shallallahu 'alaihi wasallam kemudian bersabda kepada laki-laki itu: \"Demi Dzat yang jiwaku ada dalam tangan-Nya, sungguh akan aku menghukumi kalian sesuai dengan Kitabullah 'azza wajalla. Adapun seratus kambing dan seorang budak, maka itu akan dikembalikan kepadamu. Dan anakmu akan dicambuk seratus kali dan diasingkan selama satu tahun. Wahai Unais, besok temuilah isteri orang ini, jika ia mengaku maka rajamlah.\" Keesokan harinya ia pergi menemui wanita itu, dan wanita itu pun mengakuinya hingga Unais merajamnya.\""},"5056":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ أَحْمَدَ الْكَرْمَانِيُّ قَالَ حَدَّثَنَا أَبُو الرَّبِيعِ قَالَ حَدَّثَنَا حَمَّادٌ قَالَ حَدَّثَنَا يَحْيَى عَنْ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حُنَيْفٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِامْرَأَةٍ قَدْ زَنَتْ فَقَالَ مِمَّنْ قَالَتْ مِنْ الْمُقْعَدِ الَّذِي فِي حَائِطِ سَعْدٍ فَأَرْسَلَ إِلَيْهِ فَأُتِيَ بِهِ مَحْمُولًا فَوُضِعَ بَيْنَ يَدَيْهِ فَاعْتَرَفَ فَدَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِإِثْكَالٍ فَضَرَبَهُ وَرَحِمَهُ لِزَمَانَتِهِ وَخَفَّفَ عَنْهُ","id":"Telah mengabarkan kepada kami [Al Hasan bin Ahmad Al Karmani] ia berkata; telah menceritakan kepada kami [Abu Ar Rabi'] ia berkata; telah menceritakan kepada kami [Hammad] ia berkata; telah menceritakan kepada kami [Yahya] dari [Abu Umamah bin Sahl bin Hunaif] berkata, \"Pernah dihadapkan seorang wanita yang telah berzina kepada Nabi shallallahu 'alaihi wasallam, beliau lalu bertanya: \"Dengan siapa?\" Wanita itu menjawab, \"Dengan seorang laki-laki lumpuh yang ada di kebun milik Sa'd.\" Beliau kemudian mengutus utusan untuk menjemput laki-laki itu, maka laki-laki itu dihadapkan kepada beliau dengan digendong, dan ia mengakui perbuatannya. Rasulullah shallallahu 'alaihi wasallam lalu minta untuk diambilkan tandan kurma yang buahnya rusak, kemudian beliau memukulnya. Namun beliau merasa kasihan karena kelumpuhannya hingga hukumannya diringankan.\""},"5057":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا أَبُو حَازِمٍ قَالَ سَمِعْتُ سَهْلَ بْنَ سَعْدٍ السَّاعِدِيَّ يَقُولُوَقَعَ بَيْنَ حَيَّيْنِ مِنْ الْأَنْصَارِ كَلَامٌ حَتَّى تَرَامَوْا بِالْحِجَارَةِ فَذَهَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُصْلِحَ بَيْنَهُمْ فَحَضَرَتْ الصَّلَاةُ فَأَذَّنَ بِلَالٌ وَانْتُظِرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاحْتُبِسَ فَأَقَامَ الصَّلَاةَ وَتَقَدَّمَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ فَجَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ يُصَلِّي بِالنَّاسِ فَلَمَّا رَآهُ النَّاسُ صَفَّحُوا وَكَانَ أَبُو بَكْرٍ لَا يَلْتَفِتُ فِي الصَّلَاةِ فَلَمَّا سَمِعَ تَصْفِيحَهُمْ الْتَفَتَ فَإِذَا هُوَ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرَادَ أَنْ يَتَأَخَّرَ فَأَشَارَ إِلَيْهِ أَنْ اثْبُتْ فَرَفَعَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ يَعْنِي يَدَيْهِ ثُمَّ نَكَصَ الْقَهْقَرَى وَتَقَدَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى فَلَمَّا قَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّلَاةَ قَالَ مَا مَنَعَكَ أَنْ تَثْبُتَ قَالَ مَا كَانَ اللَّهُ لِيَرَى ابْنَ أَبِي قُحَافَةَ بَيْنَ يَدَيْ نَبِيِّهِ ثُمَّ أَقْبَلَ عَلَى النَّاسِ فَقَالَ مَا لَكُمْ إِذَا نَابَكُمْ شَيْءٌ فِي صَلَاتِكُمْ صَفَّحْتُمْ إِنَّ ذَلِكَ لِلنِّسَاءِ مَنْ نَابَهُ شَيْءٌ فِي صَلَاتِهِ فَلْيَقُلْ سُبْحَانَ اللَّهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] ia berkata; telah menceritakan kepada kami [Sufyan] ia berkata; telah menceritakan kepada kami [Abu Hazim] ia berkata; Aku mendengar [Sahl bin Sa'd As Sa'idi] berkata; \"Pernah terjadi pertengkaran antara dua kelompok kaum Anshar hingga mereka saling lempar batu. Nabi shallallahu 'alaihi wasallam kemudian pergi untuk mendamaikan mereka. Ketika waktu shalat tiba, Bilal mengumandangkan adzan, ketika Rasulullah shallallahu 'alaihi wasallam ditungu-tunggu namun tidak datang karena tertahan (dalam acara perdamaian). Bilal kemudian mengumandangkan iqamah sementara Abu Bakar radliallahu 'anhu maju ke depan. Setelah itu Nabi shallallahu 'alaihi wasallam datang dan Abu Bakar masih mengimami shalat. Ketika orang-orang melihat kehadiran beliau, mereka membuat barisan sementara Abu Bakar tetap dalam kondisinya dan tidak berpaling ke belakang. Namun ketika Abu Bakar mendengar suara tashfih (tepukan tangan) orang-orang, iapun menoleh ke belakang, dan ternyata Rasulullah shallallahu 'alaihi wasallam telah datang. Ia ingin mundur ke belakang namun Rasulullah berisyarat agar ia tetap berada di depan. Abu Bakar radliallahu 'anhu lalu mengangkat, yakni tangannya kemudian mundur perlahan. Maka Rasulullah shallallahu 'alaihi wasallam pun maju ke depan untuk mengimami shalat. Setelah Rasulullah shallallahu 'alaihi wasallam selesai shalat, beliau bersabda: \"Apa yang menghalangimu untuk tetap di depan?\" Abu Bakar menjawab; \"Apa mungkin Allah akan melihat Abu Quhafah sementara di sisinya ada Nabi-Nya!\" beliau kemudian menghadap ke arah orang banyak dan bersabda: \"Kenapa jika terjadi sesuatu dalam shalat kalian menepuk tangan? Sesungguhnya menepuk itu adalah bagi wanita, maka barangsiapa terjadi sesuatu dalam shalatnya hendaklah mengucapkan 'Subhanallah'.\""},"5058":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا شُعَيْبُ بْنُ اللَّيْثِ عَنْ أَبِيهِ عَنْ جَعْفَرِ بْنِ رَبِيعَةَ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ الْأَنْصَارِيِّ عَنْ كَعْبِ بْنِ مَالِكٍأَنَّهُ كَانَ لَهُ عَلَى عَبْدِ اللَّهِ بْنِ أَبِي حَدْرَدٍ الْأَسْلَمِيِّ يَعْنِي دَيْنًا فَلَقِيَهُ فَلَزِمَهُ فَتَكَلَّمَا حَتَّى ارْتَفَعَتْ الْأَصْوَاتُ فَمَرَّ بِهِمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا كَعْبُ فَأَشَارَ بِيَدِهِ كَأَنَّهُ يَقُولُ النِّصْفَ فَأَخَذَ نِصْفًا مِمَّا عَلَيْهِ وَتَرَكَ نِصْفًا","id":"Telah mengabarkan kepada kami [Ar Rabi' bin Sulaiman] ia berkata; telah menceritakan kepada kami [Syu'aib bin Al Laits] dari [Ayahnya] dari [Ja'far bin Rabi'ah] dari ['Abdurrahman Al A'raj] dari [Abdullah bin Ka'b bin Malik Al Anshari] dari [Ka'b bin Malik] bahwa ia pernah mempunyai tanggungan yang harus dibayar oleh Abdullah bin Abu Hadrad Al Aslami, yakni hutang. Ka'b bin Malik kemudian menemuinya dan minta pembayaran, keduanya berbicara hingga suaranya meninggi. Lalu Rasulullah shallallahu 'alaihi wasallam melintasi keduanya, beliau bersabda: \"Wahai Ka'b, beliau berisyarat dengan tangannya, seakan beliau mengatakan: \"Setengah.\" Ka'b lalu membebaskan setengah dan meminta pembayaran setengahnya.\""},"5059":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عَوْفٍ قَالَ حَدَّثَنِي حَمْزَةُ أَبُو عُمَرَ الْعَائِذِيُّ قَالَ حَدَّثَنَا عَلْقَمَةُ بْنُ وَائِلٍ عَنْ وَائِلٍ قَالَشَهِدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ جَاءَ بِالْقَاتِلِ يَقُودُهُ وَلِيُّ الْمَقْتُولِ فِي نِسْعَةٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِوَلِيِّ الْمَقْتُولِ أَتَعْفُو قَالَ لَا قَالَ فَتَأْخُذُ الدِّيَةَ قَالَ لَا قَالَ فَتَقْتُلُهُ قَالَ نَعَمْ قَالَ اذْهَبْ بِهِ فَلَمَّا ذَهَبَ فَوَلَّى مِنْ عِنْدِهِ دَعَاهُ فَقَالَ أَتَعْفُو قَالَ لَا قَالَ فَتَأْخُذُ الدِّيَةَ قَالَ لَا قَالَ فَتَقْتُلُهُ قَالَ نَعَمْ قَالَ اذْهَبْ بِهِ فَلَمَّا ذَهَبَ فَوَلَّى مِنْ عِنْدِهِ دَعَاهُ فَقَالَ أَتَعْفُو قَالَ لَا قَالَ فَتَأْخُذُ الدِّيَةَ قَالَ لَا قَالَ فَتَقْتُلُهُ قَالَ نَعَمْ قَالَ اذْهَبْ بِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ ذَلِكَ أَمَا إِنَّكَ إِنْ عَفَوْتَ عَنْهُ يَبُوءُ بِإِثْمِهِ وَإِثْمِ صَاحِبِكَ فَعَفَا عَنْهُ وَتَرَكَهُ فَأَنَا رَأَيْتُهُ يَجُرُّ نِسْعَتَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Basyar] ia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Auf] ia berkata; telah menceritakan kepadaku [Hamzah Abu Umar Al 'Aidzi] ia berkata; telah menceritakan kepada kami [Alqamah bin Wa'il] dari [Wa`il] ia berkata, \"Aku menyaksikan Rasulullah shallallahu 'alaihi wasallam mendatangi seorang pembunuh yang dituntun oleh keluarga terbunuh dalam keadaan terikat. Rasulullah shallallahu 'alaihi wasallam bertanya kepada wali korban itu: \"Apakah kamu akan memaafkannya?\" ia menjawab; \"Tidak.\" Beliau bertanya lagi: \"Apakah engkau akan minta tebusan?\" ia menjawab, \"Tidak.\" Beliau bertanya: \"Apakah engkau akan membunuhnya?\" ia menjawab; \"Ya.\" Beliau bersabda: \"Pergi dan bawalah dia.\" Ketika wali korban itu telah pergi dari sisinya, beliau memanggilnya kembali. Beliau lalu bertanya: \"Apakah kamu akan memaafkannya?\" ia menjawab, \"Tidak.\" Beliau bertanya lagi: \"Apakah engkau akan minta tebusan?\" ia menjawab, \"Tidak.\" Beliau bertanya: \"Apakah engkau akan membunuhnya?\" ia menjawab, \"Ya.\" Beliau bersabda: \"Pergi dan bawalah dia.\" Ketika wali korban itu telah pergi dari sisinya, beliau memanggilnya kembali. Beliau lalu bertanya: \"Apakah kamu akan memaafkannya?\" ia menjawab, \"Tidak.\" Beliau bertanya lagi: \"Apakah engkau akan minta tebusan?\" ia menjawab, \"Tidak.\" Beliau bertanya: \"Apakah engkau akan membunuhnya?\" ia menjawab, \"Ya.\" Beliau bersabda: \"Pergi dan bawalah dia.\" Maka di saat itulah Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya engkau memaafkannya, maka ia akan pergi dengan membawa dosanya dan dosa sahabatmu.\" Orang itu akhirnya memaafkan si pembunuh dan membiarkannya. Dan sungguh, aku melihatnya melepas tali yang mengikatnya.\""},"5060":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ أَنَّهُ حَدَّثَهُ أَنَّ عَبْدَ اللَّهِ بْنَ الزُّبَيْرِ حَدَّثَهُأَنَّ رَجُلَا مِنْ الْأَنْصَارِ خَاصَمَ الزُّبَيْرَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي شِرَاجِ الْحَرَّةِ الَّتِي يَسْقُونَ بِهَا النَّخْلَ فَقَالَ الْأَنْصَارِيُّ سَرِّحْ الْمَاءَ يَمُرُّ فَأَبَى عَلَيْهِ فَاخْتَصَمُوا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْقِ يَا زُبَيْرُ ثُمَّ أَرْسِلْ الْمَاءَ إِلَى جَارِكَ فَغَضِبَ الْأَنْصَارِيُّ فَقَالَ يَا رَسُولَ اللَّهِ أَنْ كَانَ ابْنَ عَمَّتِكَ فَتَلَوَّنَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ يَا زُبَيْرُ اسْقِ ثُمَّ احْبِسْ الْمَاءَ حَتَّى يَرْجِعَ إِلَى الْجَدْرِقَالَ الزُّبَيْرُ إِنِّي أَحْسَبُ أَنَّ هَذِهِ الْآيَةَ نَزَلَتْ فِي ذَلِكَ{ فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ }الْآيَةَ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari ['Urwah] Bahwasanya ia menceritakan kepadanya, bahwa [Abdullah bin Az Zubair] menceritakan kepadanya, bahwa ada seorang laki-laki Anshar yang berselisih dengan Az Zubair mengadu kepada Rasulullah shallallahu 'alaihi wasallam, yakni dalam masalah mata air Al Harrah yang biasa mereka gunakan untuk mengairi pohon kurma. Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Wahai Zubair, airilah (kebun milikmu), setelah itu alirkanlah air itu untuk tetanggamu.\" Laki-laki Anshar itu pun marah, ia lalu berkata, \"Wahai Rasulullah, apakah karena ia anak pamanmu!\" Maka menjadi merahlah wajah Rasulullah shallallahu 'alaihi wasallam, beliau kemudian bersabda: \"Wahai Zubair, airilah (kebunmu), setelah itu tahanlah hingga airnya kembali ke dalam tanah.\" Az Zubair berkata, \"Aku kira ayat ini turun berkenaan dengan peristiwa itu: ' Maka demi Tuhanmu, mereka (pada hakekatnya) tidak beriman.\" QS An Nisa`; 65."},"5061":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الْوَهَّابِ قَالَ حَدَّثَنَا خَالِدٌ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ زَوْجَ بَرِيرَةَ كَانَ عَبْدًا يُقَالُ لَهُ مُغِيثٌ كَأَنِّي أَنْظُرُ إِلَيْهِ يَطُوفُ خَلْفَهَا يَبْكِي وَدُمُوعُهُ تَسِيلُ عَلَى لِحْيَتِهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْعَبَّاسِ يَا عَبَّاسُ أَلَا تَعْجَبْ مِنْ حُبِّ مُغِيثٍ بَرِيرَةَ وَمِنْ بُغْضِ بَرِيرَةَ مُغِيثًا فَقَالَ لَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ رَاجَعْتِيهِ فَإِنَّهُ أَبُو وَلَدِكِ قَالَتْ يَا رَسُولَ اللَّهِ أَتَأْمُرُنِي قَالَ إِنَّمَا أَنَا شَفِيعٌ قَالَتْ فَلَا حَاجَةَ لِي فِيهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basyar] ia berkata; telah menceritakan kepada kami [Abdul Wahhab] ia berkata; telah menceritakan kepada kami [Khalid] dari [Ikrimah] dari [Ibnu Abbas] berkata; \"Suami Barirah adalah seorang budak bernama Mughits. Seakan aku pernah melihatnya selalu berputar-putar di belakangnya (Barirah) sambil menangis hingga air matanya membanjiri janggutnya. Nabi shallallahu 'alaihi wasallam lalu bersabda: \"Wahai Ibnu Abbas, tidakkah kamu ta'ajub dengan kecintaan Mughits kepada Barirah, dan kebencian Barirah kepada Mughits?\" Setelah itu Nabi shallallahu 'alaihi wasallam bertanya kepada Barirah: \"Sekiranya engkau kembali padanya, maka sungguh ia adalah ayah dari anakmu.\" Barirah berkata; \"Wahai Rasulullah, apakah itu perintah untukku?\" beliau menjawab: \"Aku hanya pemersatu.\" Barirah berkata; \"Aku sudah tidak butuh itu (rujuk) lagi.\""},"5062":{"ar":"أَخْبَرَنَا عَبْدُ الْأَعْلَى بْنُ وَاصِلِ بْنِ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا مُحَاضِرُ بْنُ الْمُوَرِّعِ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ عَطَاءٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَأَعْتَقَ رَجُلٌ مِنْ الْأَنْصَارِ غُلَامًا لَهُ عَنْ دُبُرٍ وَكَانَ مُحْتَاجًا وَكَانَ عَلَيْهِ دَيْنٌ فَبَاعَهُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِثَمَانِ مِائَةِ دِرْهَمٍ فَأَعْطَاهُ فَقَالَ اقْضِ دَيْنَكَ وَأَنْفِقْ عَلَى عِيَالِكَ","id":"Telah mengabarkan kepada kami [Abdul A'la bin Washil bin Abdul A'la] ia berkata; telah menceritakan kepada kami [Muhadlir Ibnul Muwadli'] ia berkata; telah menceritakan kepada kami [Al A'masy] dari [Salamah bin Kuhail] dari ['Atha] dari [Jabir bin Abdullah] ia berkata, \"Seorang laki-laki Anshar memerdekakan budak miliknya saat hendak meninggal. Ia sangat miskin dan tengah terlilit hutang. Lalu ia menjualnya kepada Rasulullah shallallahu 'alaihi wasallam dengan harga delapan ratus dirham. Beliau kemudian memberikan uang pembayarannya dan bersabda: \"Bayar hutangmu dan nafkahilah keluargamu.\""},"5063":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ قَالَ حَدَّثَنَا الْعَلَاءُ عَنْ مَعْبَدِ بْنِ كَعْبٍ عَنْ أَخِيهِ عَبْدِ اللَّهِ بْنِ كَعْبٍ عَنْ أَبِي أُمَامَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اقْتَطَعَ حَقَّ امْرِئٍ مُسْلِمٍ بِيَمِينِهِ فَقَدْ أَوْجَبَ اللَّهُ لَهُ النَّارَ وَحَرَّمَ عَلَيْهِ الْجَنَّةَ فَقَالَ لَهُ رَجُلٌ وَإِنْ كَانَ شَيْئًا يَسِيرًا يَا رَسُولَ اللَّهِ قَالَ وَإِنْ كَانَ قَضِيبًا مِنْ أَرَاكٍ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] ia berkata; telah menceritakan kepada kami [Isma'il] ia berkata; telah menceritakan kepada kami [Al 'Ala] dari [Ma'bad bin Ka'b] dari saudaranya [Abdullah bin Ka'b] dari [Abu 'Umamah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengambil hak saudaranya dengan sumpah (palsu), maka Allah akan mewajibkannya masuk neraka dan mengharamkan surga baginya.\" Seorang laki-laki lalu bertanya kepada beliau; \"Meskipun itu sesuatu yang remeh?\" beliau menjawab: \"Meskipun sebatang kayu siwak.\""},"5064":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا وَكِيعٌ قَالَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْجَاءَتْ هِنْدٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ أَبَا سُفْيَانَ رَجُلٌ شَحِيحٌ وَلَا يُنْفِقُ عَلَيَّ وَوَلَدِي مَا يَكْفِينِي أَفَآخُذُ مِنْ مَالِهِ وَلَا يَشْعُرُ قَالَ خُذِي مَا يَكْفِيكِ وَوَلَدِكِ بِالْمَعْرُوفِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Waki'] ia berkata; telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [Ayahnya] dari ['Aisyah] ia berkata; \"Hindun datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, Abu Sufyan adalah seorang laki-laki yang pelit, ia tidak memberi nafkah yang cukup kepadaku dan juga anakku. Apakah boleh aku mengambil uangnya tanpa sepengetahuannya?\" beliau menjawab: \"Ambillah apa yang mencukupi untuk kamu dan anakmu dengan ma'ruf.\""},"5065":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ مَنْصُورِ بْنِ جَعْفَرٍ قَالَ حَدَّثَنَا مُبَشِّرُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا سُفْيَانُ بْنُ حُسَيْنٍ عَنْ جَعْفَرِ بْنِ إِيَاسٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ وَكَانَ عَامِلًا عَلَى سِجِسْتَانَ قَالَ كَتَبَ إِلَيَّ أَبُو بَكْرَةَ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَقْضِيَنَّ أَحَدٌ فِي قَضَاءٍ بِقَضَاءَيْنِ وَلَا يَقْضِي أَحَدٌ بَيْنَ خَصْمَيْنِ وَهُوَ غَضْبَانُ","id":"Telah mengabarkan kepada kami [Al Husain bin Manshur bin Ja'far] ia berkata; telah menceritakan kepada kami [Mubasysyir bin Abdullah] ia berkata; telah menceritakan kepada kami [Sufyan bin Husain] dari [Ja'far bin Iyas] dari ['Abdurrahman bin Abu Bakrah] -ia adalah seorang pegawai di Sijistan- ia berkata; \" [Abu Bakrah] menulis surat kepadaku, ia mengatakan, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah seseorang memberi keputusan dengan dua putusan, dan janganlah seseorang memberi putusan antara dua orang sementara ia dalam keadaan marah.\""},"5066":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا وَكِيعٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ زَيْنَبَ بِنْتِ أُمِّ سَلَمَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّكُمْ تَخْتَصِمُونَ إِلَيَّ وَإِنَّمَا أَنَا بَشَرٌ وَلَعَلَّ بَعْضَكُمْ أَلْحَنُ بِحُجَّتِهِ مِنْ بَعْضٍ فَإِنَّمَا أَقْضِي بَيْنَكُمَا عَلَى نَحْوِ مَا أَسْمَعُ فَمَنْ قَضَيْتُ لَهُ مِنْ حَقِّ أَخِيهِ شَيْئًا فَإِنَّمَا أَقْطَعُ لَهُ قِطْعَةً مِنْ النَّارِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah menceritakan kepada kami [Waki'] dari [Hisyam bin Urwah] dari [Ayahnya] dari [Zainab binti Ummu Salamah] dari [Ummu Salamah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalian mengadukan permasalahan kepadaku, padahal aku hanyalah manusia biasa. Dan mungkin salah seorang dari kalian lebih fasih dalam memberikan argumennya dari yang lain, aku memberi putusan kepada kalian hanyalah sebatas informasi yang aku dengar, maka barangsiapa yang aku beri putusan dengan mengorbankan hak saudaranya, janganlah ia mengambilnya, sebab dengan begitu aku telah memercikkan api neraka kepadanya.\""},"5067":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ ح وَأَنْبَأَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنِي ابْنُ جُرَيْجٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَبْغَضَ الرِّجَالِ إِلَى اللَّهِ الْأَلَدُّ الْخَصِمُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah menceritakan kepada kami [Waki'] ia berkata; telah menceritakan kepada kami [Ibnu Juraij]. (dalam jalur lain disebutkan) telah memberitakan kepada kami [Muhammad bin Manshur] ia berkata; telah menceritakan kepada kami [Sufyan] ia berkata; telah menceritakan kepadaku [Ibnu Juraij] dari [Ibnu Mulaikah] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang paling dibenci Allah adalah orang yang keras kepala dan suka membantah.\""},"5068":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الْأَعْلَى قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ أَبِي بُرْدَةَ عَنْ أَبِيهِ عَنْ أَبِي مُوسَىأَنَّ رَجُلَيْنِ اخْتَصَمَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي دَابَّةٍ لَيْسَ لِوَاحِدٍ مِنْهُمَا بَيِّنَةٌ فَقَضَى بِهَا بَيْنَهُمَا نِصْفَيْنِ","id":"Telah mengabarkan kepada kami [Amru bin Ali] ia berkata; telah menceritakan kepada kami [Abdul A'la] ia berkata; telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Sa'id bin Abu Burdah] dari [Bapaknya] dari [Abu Musa] berkata, \"Dua orang laki-laki mengadukan kepada Nabi shallallahu 'alaihi wasallam berkenaan dengan hewan tunggangan yang keduanya tidak mempunyai bukti, beliau lalu memberi putusan bahwa hewan itu milik mereka berdua.\""},"5069":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ سَعِيدِ بْنِ مَسْرُوقٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي زَائِدَةَ عَنْ نَافِعِ بْنِ عُمَرَ عَنْ ابْنِ أَبِي مُلَيْكَةَ قَالَكَانَتْ جَارِيَتَانِ تَخْرُزَانِ بِالطَّائِفِ فَخَرَجَتْ إِحْدَاهُمَا وَيَدُهَا تَدْمَى فَزَعَمَتْ أَنَّ صَاحِبَتَهَا أَصَابَتْهَا وَأَنْكَرَتْ الْأُخْرَى فَكَتَبْتُ إِلَى ابْنِ عَبَّاسٍ فِي ذَلِكَ فَكَتَبَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى أَنَّ الْيَمِينَ عَلَى الْمُدَّعَى عَلَيْهِ وَلَوْ أَنَّ النَّاسَ أُعْطُوا بِدَعْوَاهُمْ لَادَّعَى نَاسٌ أَمْوَالَ نَاسٍ وَدِمَاءَهُمْ فَادْعُهَا وَاتْلُ عَلَيْهَا هَذِهِ الْآيَةَ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا أُولَئِكَ لَا خَلَاقَ لَهُمْ فِي الْآخِرَةِ }حَتَّى خَتَمَ الْآيَةَ فَدَعَوْتُهَا فَتَلَوْتُ عَلَيْهَا فَاعْتَرَفَتْ بِذَلِكَ فَسَرَّهُ","id":"Telah mengabarkan kepada kami [Ali bin Sa'id bin Masruq] ia berkata; telah menceritakan kepada kami [Yahya bin Abu Zaidah] dari [Nafi' bin Umar] dari [Ibnu Abu Mulaikah] ia berkata, \"Dua orang wanita masuk ke dalam gua di wilayah Tha'if. Lalu salah seorang dari keduanya keluar dengan tangan terluka. Maka ia menyangka bahwa temannya yang telah melukainya, namun temannya mengingkari. Aku lalu menulis surat kepada Ibnu Abbas berkenaan dengan masalah tersebut, [Ibnu Abbas] membalas; Rasulullah shallallahu 'alaihi wasallam pernah memberi putusan, bahwa sumpah itu bagi orang yang dituduh (terdakwa). Sebab jika manusia dibiarkan memberikan dakwaan, maka mereka akan mendakwa harta dan nyawa orang banyak. Oleh karena itu panggillah wanita itu dan bacakanlah ayat ini kepadanya: ' Sesungguhnya orang-orang yang menukar janji (nya dengan) Allah dan sumpah-sumpah mereka dengan harga yang sedikit, mereka itu tidak mendapat bahagian (pahala) di akhirat' QS Ali Imran; 77 hingga akhir ayat. Kemudian aku memanggil wanita tersebut dan aku bacakan ayat itu kepadanya, akhirnya ia mengakuinya.\""},"5070":{"ar":"أَخْبَرَنَا سَوُّارُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا مَرْحُومُ بْنُ عَبْدِ الْعَزِيزِ عَنْ أَبِي نَعَامَةَ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَ قَالَ مُعَاوِيَةُ رَضِيَ اللَّهُ عَنْهُإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ عَلَى حَلْقَةٍ يَعْنِي مِنْ أَصْحَابِهِ فَقَالَ مَا أَجْلَسَكُمْ قَالُوا جَلَسْنَا نَدْعُو اللَّهَ وَنَحْمَدُهُ عَلَى مَا هَدَانَا لِدِينِهِ وَمَنَّ عَلَيْنَا بِكَ قَالَ آللَّهُ مَا أَجْلَسَكُمْ إِلَّا ذَلِكَ قَالُوا آللَّهُ مَا أَجْلَسَنَا إِلَّا ذَلِكَ قَالَ أَمَا إِنِّي لَمْ أَسْتَحْلِفْكُمْ تُهَمَةً لَكُمْ وَإِنَّمَا أَتَانِي جِبْرِيلُ عَلَيْهِ السَّلَام فَأَخْبَرَنِي أَنَّ اللَّهَ عَزَّ وَجَلَّ يُبَاهِي بِكُمْ الْمَلَائِكَةَ","id":"Telah mengabarkan kepada kami [Sawwur bin Abdullah] ia berkata; telah menceritakan kepada kami [Marhum bin Abdul Aziz] dari [Abu Na'amah] dari [Abu Utsman An Nahdi] dari [Abu Sa'id Al Khudri] ia berkata; [Mu'awiyah] radliallahu 'anhu berkata, \"Rasulullah shallallahu 'alaihi wasallam keluar menemui serombongan orang, yakni para sahabatnya. Beliau lalu bertanya: \"Apa yang membuat kalian duduk?\" para sahabat menjawab; \"Kami duduk untuk berdoa kepada Allah dan memuji-Nya atas petunjuk yang Dia berikan hingga kami memeluk agama-Nya. Serta memberikan kepada kami karunia dengan perantaramu.\" Beliau bertanya lagi; \"Demi Allah, apakah hanya itu yang menjadikan kalian duduk berkumpul?\" para sahabat menjawab; \"Demi Allah, kami tidak duduk berkumpul di sini kecuali hanya untuk itu.\" Beliau bersabda: \"Sungguh, aku tidak akan meminta kalian bersumpah untuk menghilangkan keraguan, namun Jibril Alaihis Salam datang kepadaku, ia mengabarkan bahwa Allah 'azza wajalla membanggakan kalian di hadapan para malaikatnya.\""},"5071":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَفْصٍ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ صَفْوَانَ بْنِ سُلَيْمٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى عِيسَى ابْنُ مَرْيَمَ عَلَيْهِ السَّلَام رَجُلًا يَسْرِقُ فَقَالَ لَهُ أَسَرَقْتَ قَالَ لَا وَاللَّهِ الَّذِي لَا إِلَهَ إِلَّا هُوَ قَالَ عِيسَى عَلَيْهِ السَّلَام آمَنْتُ بِاللَّهِ وَكَذَّبْتُ بَصَرِي","id":"Telah mengabarkan kepada kami [Ahmad bin Hafsh] ia berkata; telah menceritakan kepadaku [Bapakku] ia berkata; telah menceritakan kepadaku [Ibrahim bin Thahman] dari [Musa bin 'Uqbah] dari [Shafwan bin Sulaim] dari ['Atha` bin Yasar] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Isa putera Maryam 'Alaihis Salam melihat seorang laki-laki tengah mencuri, lalu ia berkata kepada laki-laki pencuri itu, \"Apakah kamu mencuri?\" ia menjawab, \"Tidak, demi Allah yang tidak ada Tuhan selain Dia.\" Isa 'Alaihis Salam berkata, \"Aku beriman kepada Allah dan berdusta kepada mataku.\""},"5072":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي حَفْصُ بْنُ مَيْسَرَةَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ مُعَاذِ بْنِ عَبْدِ اللَّهِ بْنِ خُبَيْبٍ عَنْ أَبِيهِ قَالَكُنْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي طَرِيقِ مَكَّةَ فَأَصَبْتُ خُلْوَةً مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَنَوْتُ مِنْهُ فَقَالَ قُلْ فَقُلْتُ مَا أَقُولُ قَالَ قُلْ قُلْتُ مَا أَقُولُ قَالَ قُلْ أَعُوذُ بِرَبِّ الْفَلَقِ حَتَّى خَتَمَهَا ثُمَّ قَالَ قُلْ أَعُوذُ بِرَبِّ النَّاسِ حَتَّى خَتَمَهَا ثُمَّ قَالَ مَا تَعَوَّذَ النَّاسُ بِأَفْضَلَ مِنْهُمَا","id":"Telah mengabarkan kepada kami [Yunus bin Abdul A'la] ia berkata; telah menceritakan kepada kami [Ibnu Wahb] ia berkata; telah mengabarkan kepadaku [Hafsh bin Maisarah] dari [Zaid bin Aslam] dari [Mu'adz bin Khubaib] dari [Ayahnya] ia berkata; \"Aku bersama Rasulullah shallallahu 'alaihi wasallam berada di jalanan Makkah, hingga aku bisa berdua dan lebih dekat dengan Rasulullah shallallahu 'alaihi wasallam. Beliau lalu bersabda: \"Ucapkanlah!\" aku berkata; \"Apa yang harus aku ucapkan?\" beliau bersabda: \"Ucapkanlah!\" aku berkata; \"Apa yang harus aku ucapkan?\" beliau bersabda: 'QUL A'UUDZU BIRABBIL FALAQ (Katakanlah: \"Aku berlindung kepada Tuhan Yang Menguasai subuh) ' hingga beliau menyelesaikan bacaannya. Kemudian beliau bersabda lagi: 'QUL A'UUDZU BIRABBINNAAS (Katakanlah: \"Aku berlindung kepada Tuhan (yang memelihara dan menguasai) manusia) ' hingga beliau menyelesaikan bacaannya. Setelah itu beliau bersabda: \"Tidaklah manusia berlindung dengan sesuatu yang lebih utama dari keduanya.\""},"5073":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَلِيٍّ قَالَ حَدَّثَنِي الْقَعْنَبِيُّ عَنْ عَبْدِ الْعَزِيزِ عَنْ عَبْدِ اللَّهِ بْنِ سُلَيْمَانَ عَنْ مُعَاذِ بْنِ عَبْدِ اللَّهِ بْنِ خُبَيْبٍ عَنْ أَبِيهِ عَنْ عُقْبَةَ بْنِ عَامِرٍ الْجُهَنِيِّ قَالَبَيْنَا أَنَا أَقُودُ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَاحِلَتَهُ فِي غَزْوَةٍ إِذْ قَالَ يَا عُقْبَةُ قُلْ فَاسْتَمَعْتُ ثُمَّ قَالَ يَا عُقْبَةُ قُلْ فَاسْتَمَعْتُ فَقَالَهَا الثَّالِثَةَ فَقُلْتُ مَا أَقُولُ فَقَالَ قُلْ هُوَ اللَّهُ أَحَدٌ فَقَرَأَ السُّورَةَ حَتَّى خَتَمَهَا ثُمَّ قَرَأَ قُلْ أَعُوذُ بِرَبِّ الْفَلَقِ وَقَرَأْتُ مَعَهُ حَتَّى خَتَمَهَا ثُمَّ قَرَأَ قُلْ أَعُوذُ بِرَبِّ النَّاسِ فَقَرَأْتُ مَعَهُ حَتَّى خَتَمَهَا ثُمَّ قَالَ مَا تَعَوَّذَ بِمِثْلِهِنَّ أَحَدٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Ali] ia berkata; telah menceritakan kepadaku [Al Qa'nabi] dari [Abdul Aziz] dari [Abdullah bin Sulaiman] dari [Mu'adz bin Abdullah bin Khubaib] dari [Ayahnya] dari ['Uqbah bin Amir Al Juhani] ia berkata; \"Saat aku menuntun kendaraan Rasulullah shallallahu 'alaihi wasallam dalam suatu peperangan, beliau bersabda: \"Wahai 'Uqbah, ucapkanlah!\" aku lalu memasang pendengaranku. Kemudian beliau bersabda: \"Wahai 'Uqbah, ucapkanlah!\" aku lalu memasang pendengaranku. Beliau mengatakan hal itu hingga tiga kali. Maka aku bertanya; \"Apa yang harus aku katakan?\" beliau menjawab: 'QUL HUWAALLAHU AHAD (Katakanlah: \"Dia-lah Allah, Yang Maha Esa) ' beliau lantas membacanya hingga selesai. Kemudian beliau membaca 'QUL A'UUDZU BIRABBIL FALAQ (Katakanlah: \"Aku berlindung kepada Tuhan Yang Menguasai subuh) beliau lantas membacanya hingga selesai. Kemudian beliau membaca 'QUL A'UUDZU BIRABBINNAAS (Katakanlah: \"Aku berlindung kepada Tuhan (yang memelihara dan menguasai) manusia) ' maka aku pun membacanya bersama beliau hingga selesai. Setelah itu beliau bersabda: \"Seseorang tidak akan mendapat sesuatu perlindungan yang setara dengannya (surat-surat tersebut).\""},"5074":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عُثْمَانَ بْنِ حَكِيمٍ قَالَ حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ سُلَيْمَانَ الْأَسْلَمِيُّ عَنْ مُعَاذِ بْنِ عَبْدِ اللَّهِ بْنِ خُبَيْبٍ عَنْ عُقْبَةَ بْنِ عَامِرٍ الْجُهَنِيِّ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْ قُلْتُ وَمَا أَقُولُ قَالَ قُلْ هُوَ اللَّهُ أَحَدٌ قُلْ أَعُوذُ بِرَبِّ الْفَلَقِ قُلْ أَعُوذُ بِرَبِّ النَّاسِ فَقَرَأَهُنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ لَمْ يَتَعَوَّذْ النَّاسُ بِمِثْلِهِنَّ أَوْ لَا يَتَعَوَّذُ النَّاسُ بِمِثْلِهِنَّ","id":"Telah mengabarkan kepada kami [Ahmad bin Utsman bin Hakim] ia berkata; telah menceritakan kepada kami [Khalid bin Makhlad] ia berkata; telah menceritakan kepadaku [Abdullah bin Sulaiman Al Aslami] dari [Mu'adz bin Abdullah bin Khubaib] dari [Uqbah bin Amir Al Juhani] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam berkata kepadaku: \"Katakanlah!\" aku bertanya; \"Apa yang harus aku katakan?\" beliau menjawab: 'QUL HUWAALLAHU AHAD (Katakanlah: \"Dia-lah Allah, Yang Maha Esa), 'QUL A'UUDZU BIRABBIL FALAQ (Katakanlah: \"Aku berlindung kepada Tuhan Yang Menguasai subuh) ' dan 'QUL A'UUDZU BIRABBINNAAS (Katakanlah: \"Aku berlindung kepada Tuhan (yang memelihara dan menguasai) manusia) '.\" Rasulullah shallallahu 'alaihi wasallam kemudian membaca ayat-ayat tersebut, setelah itu beliau bersabda: \"Manusia tidak akan mendapatkan suatu perlindungan yang semisal dengan ayat-ayat tersebut.\""},"5075":{"ar":"أَخْبَرَنِي عَمْرُو بْنُ عُثْمَانَ قَالَ حَدَّثَنَا بَقِيَّةُ قَالَ حَدَّثَنَا بَحِيرُ بْنُ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَأُهْدِيَتْ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَغْلَةٌ شَهْبَاءُ فَرَكِبَهَا وَأَخَذَ عُقْبَةُ يَقُودُهَا بِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِعُقْبَةَ اقْرَأْ قَالَ وَمَا أَقْرَأُ يَا رَسُولَ اللَّهِ قَالَ اقْرَأْ قُلْ أَعُوذُ بِرَبِّ الْفَلَقِ مِنْ شَرِّ مَا خَلَقَ فَأَعَادَهَا عَلَيَّ حَتَّى قَرَأْتُهَا فَعَرَفَ أَنِّي لَمْ أَفْرَحْ بِهَا جِدًّا قَالَ لَعَلَّكَ تَهَاوَنْتَ بِهَا فَمَا قُمْتُ يَعْنِي بِمِثْلِهَا","id":"Telah mengabarkan kepadaku [Amru bin Utsman] ia berkata; telah menceritakan kepada kami [Baqiyyah] ia berkata; telah menceritakan kepada kami [Bahir bin Sa'd] dari [Khalid bin Ma'dan] dari [Jubair bin Nufair] dari ['Uqbah bin Amir] ia berkata, \"Nabi shallallahu 'alaihi wasallam diberi hadiah seekor keledai betina berwarna kelabu, beliau lalu menungganginya sementara 'Uqbah memegangi talinya. Rasulullah shallallahu 'alaihi wasallam kemudian bersabda kepada 'Uqbah: \"Bacalah!\" 'Uqbah bertanya; \"Apa yang harus aku baca ya Rasulullah?\" beliau bersabda: 'QUL A'UUDZU BIRABBIL FALAQ MIN SYARRI MAA KHALAQ (Katakanlah: \"Aku berlindung kepada Tuhan Yang Menguasai subuh dari kejahatan makhluk-Nya) '.\" Beliau terus saja mengulang-ulang untukku hingga aku ikut membacanya. Namun beliau mengetahui bahwa aku kurang begitu semangat, maka beliau bersabda: \"Mungkin karena engkau terlalu meremehkannya. Namun Aku tidak tertarik, yakni dengan surat-surat yang sepertinya.\""},"5076":{"ar":"أَخْبَرَنَا مُوسَى بْنُ حِزَامٍ التِّرْمِذِيُّ قَالَ أَنْبَأَنَا أَبُو أُسَامَةَ عَنْ سُفْيَانَ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِيهِ عَنْ عُقْبَةَ بْنِ عَامِرٍأَنَّهُ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمُعَوِّذَتَيْنِ قَالَ عُقْبَةُ فَأَمَّنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهِمَا فِي صَلَاةِ الْغَدَاةِ","id":"Telah mengabarkan kepada kami [Musa bin Khizam At Turmudzi] ia berkata; telah memberitakan kepada kami [Abu Usamah] dari [Sufyan] dari [Mu'awiyah bin Shalih] dari ['Abdurrahman bin Jubair bin Nufair] dari [Ayahnya] dari ['Uqbah bin Amir] bahwa ia pernah bertanya kepada Nabi shallallahu 'alaihi wasallam tentang Mu'awidzatain. 'Uqbah berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah mengimami kami dalam shalat subuh dengan membaca surat tersebut.\""},"5077":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرٍو قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي مُعَاوِيَةُ بْنُ صَالِحٍ عَنْ ابْنِ الْحَارِثِ وَهُوَ الْعَلَاءُ عَنْ الْقَاسِمِ مَوْلَى مُعَاوِيَةَ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَكُنْتُ أَقُودُ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي السَّفَرِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عُقْبَةُ أَلَا أُعَلِّمُكَ خَيْرَ سُورَتَيْنِ قُرِئَتَا فَعَلَّمَنِي قُلْ أَعُوذُ بِرَبِّ الْفَلَقِ وَ قُلْ أَعُوذُ بِرَبِّ النَّاسِ فَلَمْ يَرَنِي سُرِرْتُ بِهِمَا جِدًّا فَلَمَّا نَزَلَ لِصَلَاةِ الصُّبْحِ صَلَّى بِهِمَا صَلَاةَ الصُّبْحِ لِلنَّاسِ فَلَمَّا فَرَغَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الصَّلَاةِ الْتَفَتَ إِلَيَّ فَقَالَ يَا عُقْبَةُ كَيْفَ رَأَيْتَ","id":"Telah mengabarkan kepada kami [Ahmad bin 'Amru] ia berkata; telah memberitakan kepada kami [Ibnu Wahb] ia berkata; telah mengabarkan kepadaku [Mu'awiyah bin Shalih] dari [Ibnul Harits] -yaitu Al 'Ala`- dari [Al Qasim] mantan budak Mu'awiyah, dari ['Uqbah bin Amir] ia berkata, \"Aku menuntun hewan tunggangan Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan, Rasulullah shallallahu 'alaihi wasallam lalu bersabda kepadaku: \"Wahai 'Uqbah, maukah jika aku ajarkan kepadamu dua surat pilihan untuk dibaca?\" beliau kemudian mengajariku; 'QUL A'UUDZU BIRABBIL FALAQ (Katakanlah: \"Aku berlindung kepada Tuhan Yang Menguasai subuh) ' dan QUL A'UUDZU BIRABBINNAAS (Katakanlah: \"Aku berlindung kepada Tuhan (yang memelihara dan menguasai) manusia) '. Namun, sepertinya beliau tidak melihat tanda kebahagiaan pada diriku dengan diajari dua surat tersebut. Ketika kami singgah untuk shalat subuh, beliau mengimami orang-orang shalat subuh dengan dua ayat tersebut. Seusai shalat, beliau menoleh ke arahku dan bertanya: \"Wahai 'Uqbah, bagaimana menurutmu?\""},"5078":{"ar":"أَخْبَرَنِي مَحْمُودُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا الْوَلِيدُ قَالَ حَدَّثَنِي ابْنُ جَابِرٍ عَنْ الْقَاسِمِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَبَيْنَا أَقُودُ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَقَبٍ مِنْ تِلْكَ النِّقَابِ إِذْ قَالَ أَلَا تَرْكَبُ يَا عُقْبَةُ فَأَجْلَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أَرْكَبْ مَرْكَبَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ أَلَا تَرْكَبُ يَا عُقْبَةُ فَأَشْفَقْتُ أَنْ يَكُونَ مَعْصِيَةً فَنَزَلَ وَرَكِبْتُ هُنَيْهَةً وَنَزَلْتُ وَرَكِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ أَلَا أُعَلِّمُكَ سُورَتَيْنِ مِنْ خَيْرِ سُورَتَيْنِ قَرَأَ بِهِمَا النَّاسُ فَأَقْرَأَنِي قُلْ أَعُوذُ بِرَبِّ الْفَلَقِ وَ قُلْ أَعُوذُ بِرَبِّ النَّاسِ فَأُقِيمَتْ الصَّلَاةُ فَتَقَدَّمَ فَقَرَأَ بِهِمَا ثُمَّ مَرَّ بِي فَقَالَ كَيْفَ رَأَيْتَ يَا عُقْبَةَ بْنَ عَامِرٍ اقْرَأْ بِهِمَا كُلَّمَا نِمْتَ وَقُمْتَ","id":"Telah mengabarkan kepadaku [Mahmud bin Khalid] ia berkata; telah menceritakan kepada kami [Al Walid] ia berkata; telah menceritakan kepadaku [Ibnu Jabir] dari [Al Qasim Abu 'Abdurrahman] dari ['Uqbah bin Amir] ia berkata, \"Ketika aku menuntun hewan tunggangan Rasulullah shallallahu 'alaihi wasallam dalam sebuah lembah, beliau bersabda: \"Tidak maukah jika engkau berkendaraan wahai 'Uqbah?\" Maka aku merasa kurang nyaman untuk berkendaraan di sisi Rasulullah shallallahu 'alaihi wasallam. Kemudian beliau bertanya lagi: \"Tidak maukah engkau berkendaraan wahai 'Uqbah?\" Aku lalu menjadi takut jika penolakanku itu dihitung sebagai perbuatan maksiat. Saat beliau turun aku kemudian naik sebentar dan turun lagi. Setelah itu Rasulullah shallallahu 'alaihi wasallam mengendarainya kembali, kemudian beliau bersabda: \"Tidak inginkah jika aku ajarkan kepadamu dua surat yang bagus untuk dibaca oleh manusia?\" beliau lalu membacakan untukku: 'QUL A'UUDZU BIRABBIL FALAQ (Katakanlah: \"Aku berlindung kepada Tuhan Yang Menguasai subuh) ' dan QUL A'UUDZU BIRABBINNAAS (Katakanlah: \"Aku berlindung kepada Tuhan (yang memelihara dan menguasai) manusia) '. Setelah itu iqamah dikumandangkan dan beliau maju ke depan membaca dua surat tersebut. Ketika lewat di depanku beliau bertanya: \"Wahai 'Uqbah bin Amir, bagaimana menurutmu? Bacalah dua surat tersebut saat engkau akan tidur dan akan bangun.\""},"5079":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ عَجْلَانَ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَكُنْتُ أَمْشِي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا عُقْبَةُ قُلْ فَقُلْتُ مَاذَا أَقُولُ يَا رَسُولَ اللَّهِ فَسَكَتَ عَنِّي ثُمَّ قَالَ يَا عُقْبَةُ قُلْ قُلْتُ مَاذَا أَقُولُ يَا رَسُولَ اللَّهِ فَسَكَتَ عَنِّي فَقُلْتُ اللَّهُمَّ ارْدُدْهُ عَلَيَّ فَقَالَ يَا عُقْبَةُ قُلْ قُلْتُ مَاذَا أَقُولُ يَا رَسُولَ اللَّهِ فَقَالَ قُلْ أَعُوذُ بِرَبِّ الْفَلَقِ فَقَرَأْتُهَا حَتَّى أَتَيْتُ عَلَى آخِرِهَا ثُمَّ قَالَ قُلْ قُلْتُ مَاذَا أَقُولُ يَا رَسُولَ اللَّهِ قَالَ قُلْ أَعُوذُ بِرَبِّ النَّاسِ فَقَرَأْتُهَا حَتَّى أَتَيْتُ عَلَى آخِرِهَا ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ ذَلِكَ مَا سَأَلَ سَائِلٌ بِمِثْلِهِمَا وَلَا اسْتَعَاذَ مُسْتَعِيذٌ بِمِثْلِهِمَا","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu 'Ajlan] dari [Sa'id Al Maqburi] dari ['Uqbah bin Amir] ia berkata, \"Aku pernah berjalan bersama Rasulullah shallallahu 'alaihi wasallam, beliau lalu bersabda: \"Wahai 'Uqbah, ucapkanlah.\" Aku bertanya, \"Apa yang harus aku ucapkan ya Rasulullah?\" beliau diam. Kemudian beliau bersabda: \"Wahai 'Uqbah, ucapkanlah.\" Aku bertanya, \"Apa yang harus aku ucapkan ya Rasulullah?\" beliau diam. Lalu aku berkata, \"Ya Allah, gerakkan beliau hingga ia menjawabku.\" Beliau lalu bersabda: \"Wahai 'Uqbah, ucapkanlah.\" Aku bertanya, \"Apa yang harus aku ucapkan ya Rasulullah?\" beliau lalu bersabda: 'QUL A'UUDZU BIRABBIL FALAQ (Katakanlah: \"Aku berlindung kepada Tuhan Yang Menguasai subuh) ' maka aku pun membacanya hingga akhir ayat. Kemudian beliau bersabda lagi: \"Ucapkanlah.\" Aku bertanya, \"Apa yang harus aku ucapkan ya Rasulullah?\" Beliau bersabda: 'QUL A'UUDZU BIRABBINNAAS (Katakanlah: \"Aku berlindung kepada Tuhan (yang memelihara dan menguasai) manusia) ' maka aku pun membacanya hingga akhir surat. Setelah itu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada seorang peminta pun yang meminta setara dengan itu. Dan tidak perlindungan dari seorang peminta yang setara dengan itu.\""},"5080":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا إِسْمَعِيلُ قَالَ حَدَّثَنَا قَيْسٌ عَنْ عُقْبَةَ بْنِ عَامِرٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُنْزِلَ عَلَيَّ آيَاتٌ لَمْ يُرَ مِثْلُهُنَّ قُلْ أَعُوذُ بِرَبِّ الْفَلَقِ إِلَى آخِرِ السُّورَةِ وَ قُلْ أَعُوذُ بِرَبِّ النَّاسِ إِلَى آخِرِ السُّورَةِ","id":"Telah mengabarkan kepada kami [Muhammad Ibnul Mutsanna] ia berkata; telah menceritakan kepada kami [Yahya] ia berkata; telah menceritakan kepada kami [Isma'il] ia berkata; telah menceritakan kepada kami [Qais] dari ['Uqbah bin Amir] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Telah diturunkan kepadaku beberapa ayat yang tidak akan ditemukan bandingannya; 'QUL A'UUDZU BIRABBIL FALAQ (Katakanlah: \"Aku berlindung kepada Tuhan Yang Menguasai subuh) ' hingga akhir surat dan QUL A'UUDZU BIRABBINNAAS (Katakanlah: \"Aku berlindung kepada Tuhan (yang memelihara dan menguasai) manusia) ' hingga akhir surat.\""},"5081":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنِي بَدَلٌ قَالَ حَدَّثَنَا شَدَّادُ بْنُ سَعِيدٍ أَبُو طَلْحَةَ قَالَ حَدَّثَنَا سَعِيدٌ الْجُرَيْرِيُّ قَالَ حَدَّثَنَا أَبُو نَضْرَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ يَا جَابِرُ قُلْتُ وَمَاذَا أَقْرَأُ بِأَبِي أَنْتَ وَأُمِّي يَا رَسُولَ اللَّهِ قَالَ اقْرَأْ قُلْ أَعُوذُ بِرَبِّ الْفَلَقِ وَ قُلْ أَعُوذُ بِرَبِّ النَّاسِ فَقَرَأْتُهُمَا فَقَالَ اقْرَأْ بِهِمَا وَلَنْ تَقْرَأَ بِمِثْلِهِمَا","id":"Telah mengabarkan kepada kami [Amru bin Ali] ia berkata; telah menceritakan kepada kami [Badal] ia berkata; telah menceritakan kepada kami [Syaddad bin Sa'id Abu Thalhah] ia berkata; telah menceritakan kepada kami [Sa'id Al Jurairi] ia berkata; telah menceritakan kepada kami [Abu Nadlrah] dari [Jabir bin Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Wahai Jabir, bacalah.\" Aku menjawab, \"Wahai Rasulullah, demi bapak dan ibuku sebagai tebusanmu, apa yang harus aku baca?\" beliau menjawab: \"Bacalah: 'QUL A'UUDZU BIRABBIL FALAQ (Katakanlah: \"Aku berlindung kepada Tuhan Yang Menguasai subuh) ' dan QUL A'UUDZU BIRABBINNAAS (Katakanlah: \"Aku berlindung kepada Tuhan (yang memelihara dan menguasai) manusia) '.\" Maka aku pun membaca kedua surat tersebut. Setelah itu beliau bersabda: \"Bacalah keduanya, sekali-kali engkau tidak akan dapat membaca yang lebih baik dari keduanya.\""},"5082":{"ar":"أَخْبَرَنَا يَزِيدُ بْنُ سِنَانٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ أَنْبَأَنَا سُفْيَانُ عَنْ أَبِي سِنَانٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي الْهُذَيْلِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَعَوَّذُ مِنْ أَرْبَعٍ مِنْ عِلْمٍ لَا يَنْفَعُ وَمِنْ قَلْبٍ لَا يَخْشَعُ وَدُعَاءٍ لَا يُسْمَعُ وَنَفْسٍ لَا تَشْبَعُ","id":"Telah mengabarkan kepada kami [Yazid bin Sinan] ia berkata; telah menceritakan kepada kami ['Abdurrahman] ia berkata; telah memberitakan kepada kami [Sufyan] dari [Abu Sinan] dari [Abdullah bin Abu Al Hudzail] dari [Abdullah bin Amru] berkata; \"Nabi shallallahu 'alaihi wasallam selalu berlindung dari empat perkara, yaitu; ilmu yang tidak bermanfaat, hati yang tidak khusyu', doa yang tidak didengar dan jiwa yang tidak pernah merasa puas.\""},"5083":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عُبَيْدُ اللَّهِ قَالَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَقَ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَعَوَّذُ مِنْ الْجُبْنِ وَالْبُخْلِ وَفِتْنَةِ الصَّدْرِ وَعَذَابِ الْقَبْرِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Ubaidullah] ia berkata; telah menceritakan kepada kami [Isra'il] dari [Abu Ishaq] dari ['Amru bin Maimun] dari [Umar] ia berkata; \"Nabi shallallahu 'alaihi wasallam berlindung dari sifat pengecut, kikir, mati sebelum taubat dan siksa kubur.\""},"5084":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ إِسْحَقَ قَالَ حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا سَعْدُ بْنُ أَوْسٍ قَالَ حَدَّثَنِي بِلَالُ بْنُ يَحْيَى أَنَّ شُتَيْرَ بْنَ شَكَلٍ أَخْبَرَهُ عَنْ أَبِيهِ شَكَلِ بْنِ حُمَيْدٍ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا نَبِيَّ اللَّهِ عَلِّمْنِي تَعَوُّذًا أَتَعَوَّذُ بِهِ فَأَخَذَ بِيَدِي ثُمَّ قَالَ قُلْ أَعُوذُ بِكَ مِنْ شَرِّ سَمْعِي وَشَرِّ بَصَرِي وَشَرِّ لِسَانِي وَشَرِّ قَلْبِي وَشَرِّ مَنِيِّي قَالَ حَتَّى حَفِظْتُهَاقَالَ سَعْدٌ وَالْمَنِيُّ مَاؤُهُ","id":"Telah mengabarkan kepada kami [Al Hasan bin Ishaq] ia berkata; telah menceritakan kepada kami [Abu Nu'aim] ia berkata; telah menceritakan kepada kami [Sa'd bin Aus] ia berkata; telah menceritakan kepadaku [Bilal bin Yahya] bahwa [Syutair bin Syakal] mengabarkan kepadanya dari bapaknya [Syakal bin Humaid] ia berkata, \"Aku datang menemui Nabi shallallahu 'alaihi wasallam, lalu aku berkata; \"Wahai Nabi Allah, ajarkanlah aku suatu perlindungan yang bisa aku gunakan untuk berlindung.\" Beliau lalu meraih tanganku dan bersabda: \"Ucapkanlah: A'UUDZU BIKA MIN SYARRI SAM'I WA SYARRI BASHARI, WA SYARRI LISANI, WA SYARRI QALBI, WA SYARRI MANIYYI (Aku berlindung kepada-Mu dari kejelekkan pendengaranku, dari kejelekkan penglihatanku, dari kejelekkan lisanku, dari kejelekkan hatiku dan dari kejelekkan maniku) ' beliau selalu mengucapkannya hingga aku hafal.\" Sa'd berkata; \"Yang dimaksud mani adalah airnya.\""},"5085":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ قَالَ سَمِعْتُ مُصْعَبَ بْنَ سَعْدٍ عَنْ أَبِيهِ قَالَكَانَ يُعَلِّمُنَا خَمْسًا كَانَ يَقُولُ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْعُو بِهِنَّ وَيَقُولُهُنَّ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْبُخْلِ وَأَعُوذُ بِكَ مِنْ الْ��ُبْنِ وَأَعُوذُ بِكَ أَنْ أُرَدَّ إِلَى أَرْذَلِ الْعُمُرِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الدُّنْيَا وَأَعُوذُ بِكَ مِنْ عَذَابِ الْقَبْرِ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] ia berkata; telah menceritakan kepada kami [Khalid] ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Abdul Malik bin Umair] ia berkata; aku mendengar [Mush'ab bin Sa'd] dari [Ayahnya] ia berkata, \"Dia mengajarkan kepada kami lima perkara, katanya; \"Rasulullah shallallahu 'alaihi wasallam biasa mengucapkan dan berdoa dengannya, yaitu; \"ALLAHUMMA INNI A'UUDZU BIKA MINAL BUKHLI, WA A'UUDZU BIKA MINAL JUBNI, WA A'UUDZU BIKA AN URADDA ILAA ARDZALIL 'UMUR WA A'UUDZU BIKA MIN FITNATID DUNYA WA A'UUDZU BIKA MIN ADZAABIL QABRI (Ya Allah, aku berlindung kepada-Mu dari sifat kikir, aku berlindung kepada-Mu dari sifat pengecut, aku berlindung kepada-Mu kepikunan, aku berlindung dari fitnah dunia dan aku berlindung kepada-Mu dari siksa kubur).\""},"5086":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْعَزِيزِ قَالَ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى عَنْ زَكَرِيَّا عَنْ أَبِي إِسْحَقَ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ ابْنِ مَسْعُودٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَعَوَّذُ مِنْ خَمْسٍ مِنْ الْبُخْلِ وَالْجُبْنِ وَسُوءِ الْعُمُرِ وَفِتْنَةِ الصَّدْرِ وَعَذَابِ الْقَبْرِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul Aziz] ia berkata; telah menceritakan kepada kami [Al Fadll bin Musa] dari [Zakariya] dari [Abu Ishaq] dari [Amru bin Maimun] dari [Ibnu Mas'ud] ia berkata; \"Nabi shallallahu 'alaihi wasallam biasa berlindung dari lima hal; yaitu; dari sifat kikir, pengecut, pikun, mati sebelum bertaubat dan dari siksa kubur.\""},"5087":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا حَبَّانُ بْنُ هِلَالٍ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ عَمْرِو بْنِ مَيْمُونٍ الْأَوْدِيِّ قَالَكَانَ سَعْدٌ يُعَلِّمُ بَنِيهِ هَؤُلَاءِ الْكَلِمَاتِ كَمَا يُعَلِّمُ الْمُعَلِّمُ الْغِلْمَانَ وَيَقُولُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَعَوَّذُ بِهِنَّ دُبُرَ الصَّلَاةِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْبُخْلِ وَأَعُوذُ بِكَ مِنْ الْجُبْنِ وَأَعُوذُ بِكَ أَنْ أُرَدَّ إِلَى أَرْذَلِ الْعُمُرِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الدُّنْيَا وَأَعُوذُ بِكَ مِنْ عَذَابِ الْقَبْرِفَحَدَّثْتُ بِهَا مُصْعَبًا فَصَدَّقَهُ","id":"Telah mengabarkan kepada kami [Yahya bin Muhammad] ia berkata; telah menceritakan kepada kami [Habban bin Hilal] ia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Abdul Malik bin 'Umair] dari ['Amru bin Maimun Al Audi] ia berkata; [Sa'd] biasa mengajarkan kepada anak-anaknya lima perkara tersebut sebagaimana seorang guru mengajarkan kepada anak didiknya. Dia berkata; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam biasa berlindung dengannya setiap selesai shalat; \"ALLAHUMMA INNI A'UUDZU BIKA MINAL BUKHLI, WA A'UUDZU BIKA MINAL JUBNI, WA A'UUDZU BIKA AN URADDA ILAA ARDZALIL 'UMUR WA A'UUDZU BIKA MIN FITNATID DUNYA WA A'UUDZU BIKA MIN ADZAABIL QABRI (Ya Allah, aku berlindung kepada-Mu dari sifat kikir, aku berlindung kepada-Mu dari sifat pengecut, aku berlindung kepada-Mu kepikunan, aku berlindung dari fitnah dunia dan aku berlindung kepada-Mu dari siksa kubur).\" Hal itu aku ceritakan kepada [Mush'ab] dan ia pun membenarkannya.\""},"5088":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى عَنْ مُعَاذِ بْنِ هِشَامٍ قَالَ حَدَّثَنَا أَبِي عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْعَجْزِ وَالْكَسَلِ وَالْبُخْلِ وَالْهَرَمِ وَعَذَابِ الْقَبْرِ وَفِتْنَةِ الْمَحْيَا وَالْمَمَاتِ","id":"Telah mengabarkan kepada kami [Muhammad Ibnu Al Mutsanna] dari [Mu'adz bin Hisyam] ia berkata; telah menceritakan kepada kami [Ayahku] dari [Qatadah] dari [Anas] bahwa Nabi Allah shallallahu 'alaihi wasallam mengucapkan: \"ALLAHUMMA INNI A'UUDZU BIKA MINAL 'AJZI WAL KASALI WAL BUKHLI WAL HARAMI WA 'ADZAABIL QABRI WA FITNATIL MAHYAA WAL MAMAATI (Ya Allah, sesungguhnya aku berlindung kepada-Mu dari kelemahan, kemalasan, kikir, pikun, siksa kubur dan fitnah dunia dan setelah mati).\""},"5089":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ الْمُنْذِرِ عَنْ ابْنِ فُضَيْلٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ الْمِنْهَالِ بْنِ عَمْرٍو عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعَوَاتٌ لَا يَدَعُهُنَّ كَانَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْهَمِّ وَالْحَزَنِ وَالْعَجْزِ وَالْكَسَلِ وَالْبُخْلِ وَالْجُبْنِ وَغَلَبَةِ الرِّجَالِ","id":"Telah mengabarkan kepada kami [Ali Ibnul Mundzir] dari [Ibnu Fudlail] ia berkata; telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Al Minhal bin 'Amru] dari [Anas bin Malik] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam mempunyai doa-doa yang tidak pernah lupa untuk membacanya, beliau selalu membaca: \"ALLAHUMMA INNI A'UUDZU BIKA MINAL HAMMI WAL HAZNI WAL 'AJZI WAL KASALI WA BUKHLI, WAL JUBNI WA GHALABATIR RIJAL (Ya Allah, aku berlindung kepada-Mu dari kegelisahan, kesedihan, kelemahan, kemalasan, kebakhilan, sifat pengecut dan penindasan para penguasa).\""},"5090":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَمْرِو بْنِ أَبِي عَمْرٍو عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعَوَاتٌ لَا يَدَعُهُنَّ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْهَمِّ وَالْحَزَنِ وَالْعَجْزِ وَالْكَسَلِ وَالْبُخْلِ وَالْجُبْنِ وَالدَّيْنِ وَغَلَبَةِ الرِّجَالِقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا الصَّوَابُ وَحَدِيثُ ابْنُ فُضَيْلٍ خَطَأٌ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Jarir] dari [Muhammad bin Ishaq] dari [Amru bin Abu Amru] dari [Anas bin Malik] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam mempunyai doa-doa yang tidak pernah ditinggalkan untuk membacanya; \"ALLAHUMMA INNI A'UUDZU BIKA MINAL HAMMI WAL HAZNI WAL 'AJZI WAl KASALI WA BUKHLI, WAL JUBNI WAD DAINI WA GHALABATIR RIJAL (Ya Allah, aku berlindung kepada-Mu dari kegelisahan, kesedihan, kelemahan, kemalasan, kebakhilan, sifat pengecut, hutang dan penindasan para penguasa).\""},"5091":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ قَالَ حَدَّثَنَا بِشْرٌ عَنْ حُمَيْدٍ قَالَ قَالَ أَنَسٌكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْعُو اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْكَسَلِ وَالْهَرَمِ وَالْجُبْنِ وَالْبُخْلِ وَفِتْنَةِ الدَّجَّالِ وَعَذَابِ الْقَبْرِ","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] ia berkata; telah menceritakan kepada kami [Bisyr] dari [Humaid] ia berkata; [Anas] berkata, \"Nabi shallallahu 'alaihi wasallam biasa berdoa dengan do'a: \"ALLAHUMMA INNI A'UUDU BIKA MINAL KASALI WAL HARAMI WAL BUKHLI WA FITNATID DAJALI WA 'ADZAABIL QABRI (Ya Allah, aku berlindung kepadak-Mu dari kemalasan, dari kepikunan, sifat pengecut, kebakhilan, fitnah dajjal dan siksa kubur).\""},"5092":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى الصَّنْعَانِيُّ قَالَ حَدَّثَنَا الْمُعْتَمِرُ عَنْ أَبِيهِ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْعَجْزِ وَالْكَسَلِ وَالْهَرَمِ وَالْبُخْلِ وَالْجُبْنِ وَأَعُوذُ بِكَ مِنْ عَذَابِ الْقَبْرِ وَمِنْ فِتْنَةِ الْمَحْيَا وَالْمَمَاتِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la Ash Shan'ani] ia berkata; telah menceritakan kepada kami [Al Mu'tamir] dari [Ayahnya] dari [Anas] berkata, \"Nabi shallallahu 'alaihi wasallam biasa berdoa: \"ALLAHUMMA INNI A'UUDZU BIKA MINAL 'AJZI WAL KASALI WAL HARAMI WAL BUKHLI WAL JUBNI WA A'UUDZU BIKA MIN 'ADZAABIL QABRI WA MIN FITNAIL MAHYA WAL MAMAATI (Ya Allah, aku berlindung kepada-Mu dari kelemahan, dari kemalasan, dari kepikunan, dari kebakhilan. Dan aku berlindung dari siksa kubur dan fitnah kehidupan dan fitnah setelah mati).\""},"5093":{"ar":"أَخْبَرَنَا أَبُو حَاتِمٍ السِّجِسْتَانِيُّ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ رَجَاءٍ قَالَ حَدَّثَنِي سَعِيدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنِي عَمْرُو بْنُ أَبِي عَمْرٍو مَوْلَى الْمُطَّلِبِ عَنْ عَبْدِ اللَّهِ بْنِ الْمُطَّلِبِ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا دَعَا قَالَ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْهَمِّ وَالْحَزَنِ وَالْعَجْزِ وَالْكَسَلِ وَالْبُخْلِ وَالْجُبْنِ وَضَلَعِ الدَّيْنِ وَغَلَبَةِ الرِّجَالِقَالَ أَبُو عَبْد الرَّحْمَنِ سَعِيدُ بْنُ سَلَمَةَ شَيْخٌ ضَعِيفٌ وَإِنَّمَا أَخْرَجْنَاهُ لِلزِّيَادَةِ فِي الْحَدِيثِ","id":"Telah mengabarkan kepada kami [Abu Hatim As Sijistani] ia berkata; telah menceritakan kepada kami [Abdullah bin Raja] ia berkata; telah menceritakan kepadaku [Sa'id bin Salamah] ia berkata; telah menceritakan kepadaku ['Amru bin Abu 'Amru] -mantan budak Al Muthallib- dari [Abdullah Al Muthallib] dari [Anas bin Malik] dia berkata; \"Jika Rasulullah shallallahu 'alaihi wasallam berdo'a, beliau mengucapkan: \"ALLAHUMMA INNI A'UUDZU MINAL HAMMI WAL HAZANI WAL KASALI WAL BUKHLI WAL JUBNI WA DLALA'ID DAINI WA GHALABATIR RIJALI (Ya Allah, aku berlindung kepada-Mu dari kegelisahan dan kesedihan, kelemahan dan kemalasan, kebakhilan dan sifat pengecut, serta dari himpitan hutang dan penindasan para penguasa) '.\" Abu Abdurrahman berkata; \"Sa'di bin Salamah adalah seorang yang lemah, kami menampilkannya hanya untuk memperlengkap hadits semata.\""},"5094":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ عُثْمَانَ بْنِ أَبِي صَفْوَانَ قَالَ حَدَّثَنِي سَلَمَةُ بْنُ سَعِيدِ بْنِ عَطِيَّةَ وَكَانَ خَيْرَ أَهْلِ زَمَانِهِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكْثَرَ مَا يَتَعَوَّذُ مِنْ الْمَغْرَمِ وَالْمَأْثَمِ قُلْتُ يَا رَسُولَ اللَّهِ مَا أَكْثَرَ مَا تَتَعَوَّذُ مِنْ الْمَغْرَمِ قَالَ إِنَّهُ مَنْ غَرِمَ حَدَّثَ فَكَذَبَ وَوَعَدَ فَأَخْلَفَ","id":"Telah mengabarkan kepadaku [Muhammad bin Utsman bin Abu Shafwan] ia berkata; telah menceritakan kepadaku [Salamah bin Sa'id bin 'Athiah] -ia adalah orang yang paling baik di masanya- ia berkata; telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam paling sering berlindung dari hutang yang tak terbayar dan sesuatu yang menyebabkan dosa. Aku pernah bertanya; \"Wahai Rasulullah, kenapa engkau sering berlindung dari hutang yang tak terbayar?\" beliau menjawab: \"Sebab orang yang berhutang, ia akan banyak berbicara lalu berdusta, berjanji lalu mengingkari.\""},"5095":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ إِسْحَقَ قَالَ أَنْبَأَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا سَعْدُ بْنُ أَوْسٍ قَالَ حَدَّثَنِي بلَالُ بْنُ يَحْيَى أَنَّ شُتَيْرَ بْنَ شَكَلٍ أَخْبَرَهُ عَنْ أَبِيهِ شَكَلِ بْنِ حُمَيْدٍ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا نَبِيَّ اللَّهِ عَلِّمْنِي تَعَوُّذًا أَتَعَوَّذُ بِهِ فَأَخَذَ بِيَدِي ثُمَّ قَالَ قُلْ أَعُوذُ بِكَ مِنْ شَرِّ سَمْعِي وَشَرِّ بَصَرِي وَشَرِّ لِسَانِي وَشَرِّ قَلْبِي وَشَرِّ مَنِيِّي قَالَ حَتَّى حَفِظْتُهَاقَالَ سَعْدٌ وَالْمَنِيُّ مَاؤُهُ خَالَفَهُ وَكِيعٌ فِي لَفْظِهِ","id":"Telah mengabarkan kepada kami [Al Hasan bin Ishaq] ia berkata; telah memberitakan kepada kami [Abu Nu'aim] ia berkata; telah menceritakan kepada kami [Sa'd bin Aus] ia berkata; telah menceritakan kepadaku [Bilal bin Yahya] bahwa [Syutair bin Syakal] mengabarkan kepadanya dari bapaknya [Syakal bin Humaid] ia berkata; \"Aku datang menemui Nabi shallallahu 'alaihi wasallam, lalu aku berkata; \"Wahai Nabiyullah, ajarkanlah aku suatu perlindungan yang bisa aku gunakan untuk berlindung.\" Beliau lalu meraih tanganku dan bersabda: \"Ucapkanlah: A'UUDZU BIKA MIN SYARRI SAM'I WA SYARRI BASHARI, WA SYARRI LISANI, WA SYARRI QALBI, WA SYARRI MANIYYI (Aku berlindung kepada-Mu dari kejelekkan pendengaranku, dari kejelekkan penglihatanku, dari kejelekkan lisanku, dari kejelekkan hatiku dan dari kejelekkan maniku) ' beliau ucapkan hingga aku menghafalnya.\" Sa'd berkata; 'Yang dimaksud mani adalah airnya.' Namun Waki' menyelisihi dalam lafadznya.\""},"5096":{"ar":"أَخْبَرَنَا عُبَيْدُ بْنُ وَكِيعِ بْنِ الْجَرَّاحِ قَالَ حَدَّثَنَا أَبِي عَنْ سَعْدِ بْنِ أَوْسٍ عَنْ بِلَالِ بْنِ يَحْيَى عَنْ شُتَيْرِ بْنِ شَكَلِ بْنِ حُمَيْدٍ عَنْ أَبِيهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ عَلِّمْنِي دُعَاءً أَنْتَفِعُ بِهِ قَالَ قُلْ اللَّهُمَّ عَافِنِي مِنْ شَرِّ سَمْعِي وَبَصَرِي وَلِسَانِي وَقَلْبِي وَمِنْ شَرِّ مَنِيِّي يَعْنِي ذَكَرَهُ","id":"Telah mengabarkan kepada kami ['Ubaid bin Waki' bin Al Jarrah] ia berkata; telah menceritakan kepada kami [Ayahku] dari [Sa'd bin Aus] dari [Bilal bin Yahya] dari [Syutair bin Syakal bin Humaid] dari [Ayahnya] ia berkata; \"Aku berkata; \"Wahai Rasulullah, ajarkanlah aku sebuah doa yang aku bisa ambil manfaatnya.\" Beliau bersabda: 'ALLAHUMMA 'AAFINII MIN SYARRI SAM'I WA BASHARI, WA LISAANI, WA QALBI, WA MIN SYARRI MANIYYI (Ya Allah, selamatkanlah aku dari keburukkan pendengaranku, penglihatan, lisan, hati dan maniku) '. Yakni kemaluannya.\""},"5097":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى عَنْ خَالِدٍ قَالَ حَدَّثَنَا حُمَيْدٌ قَالَسُئِلَ أَنَسٌ وَهُوَ ابْنُ مَالِكٍ عَنْ عَذَابِ الْقَبْرِ وَعَنْ الدَّجَّالِ قَالَ كَانَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْكَسَلِ وَالْهَرَمِ وَالْجُبْنِ وَالْبُخْلِ وَفِتْنَةِ الدَّجَّالِ وَعَذَابِ الْقَبْرِ","id":"Telah mengabarkan kepada kami [Muhammad Ibnul Mutsanna] dari [Khalid] ia berkata; telah menceritakan kepada kami [Humaid] ia berkata; [Anas] -yakni Ibnu Malik- pernah ditanya tentang siksa kubur dan fitnah Dajjal, ia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"ALLAHUMMA INNI A'UUDZU BIKA MINAL KASALI WAL HARAMI WAL BUKHLI WA JUBNI WA FITNAID DAJJALI WA 'ADZAABIL QABRI (Ya Allah, aku berlindung kepada-Mu dari kemalasan, kepikunan, sifat pengecut, kikir, fitnah dajjal dan siksa kubur).\""},"5098":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا مُحَاضِرٌ قَالَ حَدَّثَنَا عَاصِمٌ الْأَحْوَلُ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَلَا أُعَلِّمُكُمْ إِلَّا مَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَلِّمُنَا يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْعَجْزِ وَالْكَسَلِ وَالْبُخْلِ وَالْجُبْنِ وَالْهَرَمِ وَعَذَابِ الْقَبْرِ اللَّهُمَّ آتِ نَفْسِي تَقْوَاهَا وَزَكِّهَا أَنْتَ خَيْرُ مَنْ زَكَّاهَا أَنْتَ وَلِيُّهَا وَمَوْلَاهَا اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ قَلْبٍ لَا يَخْشَعُ وَمِنْ نَفْسٍ لَا تَشْبَعُ وَعِلْمٍ لَا يَنْفَعُ وَدَعْوَةٍ لَا يُسْتَجَابُ لَهَا","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] ia berkata; telah menceritakan kepada kami [Muhadlir] ia berkata; telah menceritakan kepada kami ['Ashim Al Ahwal] dari [Abdullah bin Al Harits] dari [Zaid bin Arqam] ia berkata; \"Aku tidak akan mengajarkan kepada kalian kecuali sesuatu yang Rasulullah shallallahu 'alaihi wasallam ajarkan kepada kami. Beliau mengucapkan: \"ALLAHUMMA INNI A'UUDZU BIKA MINAL 'AJZI WAL KASALI WAL BUKHLI WAL JUBNI WAL HARAMI WA 'ADZAABIL QABRI. ALLAHUMMA AATI NAFSII TAQWAAHAA WA ZAKKIHAA ANTA KHAIRU MAN ZAKKAHAA ANTA WALIYYUHAA WA MAULAAHAA. ALLAHUMMA INNI A'UUDZU BIKA MIN QALBIN LAA YAKHSYA' WA MIN NAFSINN LAA TASYBA' WA 'ILMIN LAA YANFA' WA DA'WATINN LAA YUSTAJAABU LAHAA (Ya Allah, aku berlindung kepada-Mu dari kelemahan, kemalasan, kikir, sifat pengecut, pikun dan siksa kubur. Ya Allah, berikanlah ketakwaan jiwaku, sucikanlah ia karena Engkau adalah sebaik-baik Dzat yang mensucikannya. Engkau adalah Pengatur dan Pemiliknya. Ya Allah, aku berlindung kepada-Mu dari hati yang tidak khusyu', jiwa yang tidak merasa puas, ilmu yang tidak bermanfaat, dan doa yang tidak diijabahi).\""},"5099":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْعَجْزِ وَالْكَسَلِ وَالْبُخْلِ وَالْجُبْنِ وَالْهَرَمِ وَعَذَابِ الْقَبْرِ وَفِتْنَةِ الْمَحْيَا وَالْمَمَاتِ","id":"Telah mengabarkan kepada kami [Amru bin Ali] ia berkata; telah menceritakan kepada kami [Mu'adz bin Hisyam] ia berkata; telah menceritakan kepadaku [Ayahku] dari [Qatadah] dari [Anas] bahwa Nabi Allah shallallahu 'alaihi wasallam bersabda: 'ALLAHUMMA INNI A'UUDZU BIKA MINAL 'AJZI WAL KASALI WAL BUKHLI WAL JUBNI WAL HARAMI WA 'ADZAABIL QABRI WA FITNATIL MAHYAA WAL MAMAATI (Ya Allah, aku berlindung kepada-Mu dari kelemahan, kemalasan, kikir, sifat pengecut, pikun, siksa kubur, fitnah kehidupan dan fitnah setelah mati) '.\""},"5100":{"ar":"أَخْبَرَنَا أَبُو عَاصِمٍ خُشَيْشُ بْنُ أَصْرَمَ قَالَ حَدَّثَنَا حَبَّانُ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ سَعِيدِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْفَقْرِ وَأَعُوذُ بِكَ مِنْ الْقِلَّةِ وَالذِّلَّةِ وَأَعُوذُ بِكَ أَنْ أَظْلِمَ أَوْ أُظْلَمَخَالَفَهُ الْأَوْزَاعِيُّ","id":"Telah mengabarkan kepada kami [Abu Ashim Khusyaisy bin Ashram] ia berkata; telah menceritakan kepada kami [Habban] ia berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Sa'id bin Yasar] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam mengucapkan: \"ALLAHUMMA INNI A'UUDZU BIKA MINAL FAQRI WA A'UUDZU BIKA MINAL QILLATI WADZ DZILLATI WA A'UUDZU BIKA AN AZHLAMA AU UZHLAMA (Ya Allah, aku berlindung kepada-Mu dari kefakiran. Aku berlindung kepada-Mu dari kekurangan dan kehinaan. Dan aku berlindung dari melakukan kezhaliman atau dizhalimi).\" Namun Al Auza'i menyelisihinya."},"5101":{"ar":"قَالَ أَخْبَرَنِي مَحْمُودُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا الْوَلِيدُ عَنْ أَبِي عَمْرٍو هُوَ الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي إِسْحَقُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ قَالَ حَدَّثَنِي جَعْفَرُ بْنُ عِيَاضٍ قَالَ حَدَّثَنِي أَبُو هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعَوَّذُوا بِاللَّهِ مِنْ الْفَقْرِ وَالْقِلَّةِ وَالذِّلَّةِ وَأَنْ تَظْلِمَ أَوْ تُظْلَمَ","id":"Perawi berkata; telah mengabarkan kepadaku [Mahmud bin Khalid] ia berkata; telah menceritakan kepada kami [Al Walid] dari [Abu Amru] -yaitu Al Auza'i- ia berkata; telah menceritakan kepadaku [Ishaq bin Abdullah bin Abu Thalhah] ia berkata; telah menceritakan kepadaku [Ja'far bin Iyadl] ia berkata; telah menceritakan kepadaku [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaklah kalian berlindung kepada Allah dari kefakiran, merasa kurang dan kehinaan, berbuat zhalim atau dizhalimi.\""},"5102":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ إِسْحَقَ عَنْ سَعِيدِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْقِلَّةِ وَالْفَقْرِ وَالذِّلَّةِ وَأَعُوذُ بِكَ أَنْ أَظْلِمَ أَوْ أُظْلَمَ","id":"Telah mengabarkan kepada kami [Ahmad bin Nashr] ia berkata; telah menceritakan kepada kami [Abdu Ash Shamad bin Abdul Warits] ia berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Ishaq] dari [Sa'id bin Yasar] dari [Abu Hurairah] ia berkata; \"Nabi shallallahu 'alaihi wasallam mengucapkan: \"ALLAHUMMA INNI A'UUDZU BIKA MINAL FAQRI WADZ DZILLATI WA A'UUDZU BIKA AN AZHLAMA AU UZHLAMA (Ya Allah, aku berlindung kepada-Mu dari kefakiran, kekurangan dan kehinaan. Dan aku berlindung kepada-Mu dari melakukan kezhaliman atau dizhalimi).\""},"5103":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا عُمَرُ يَعْنِي ابْنَ عَبْدِ الْوَاحِدِ عَنْ الْأَوْزَاعِيِّ قَالَ حَدَّثَنِي إِسْحَقُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي جَعْفَرُ بْنُ عِيَاضٍ قَالَ حَدَّثَنِي أَبُو هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعَوَّذُوا بِاللَّهِ مِنْ الْفَقْرِ وَمِنْ الْقِلَّةِ وَمِنْ الذِّلَّةِ وَأَنْ أَظْلِمَ أَوْ أُظْلَمَ","id":"Telah mengabarkan kepada kami [Mahmud bin Khalid] ia berkata; telah menceritakan kepada kami [Umar yakni Ibnu Abdul Wahid] dari [Al Auza'i] ia berkata; telah menceritakan kepadaku [Ishaq bin Abdullah] ia berkata; telah menceritakan kepadaku [Ja'far bin Iyadl] ia berkata; telah menceritakan kepadaku [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berlindunglah kepada Allah dari kefakiran, merasa kurang, kehinaan, berbuat zhalim atau dizhalimi.\""},"5104":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ حَدَّثَنِي مُوسَى بْنُ شَيْبَةَ عَنْ الْأَوْزَاعِيِّ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ قَالَ حَدَّثَنِي جَعْفَرُ بْنُ عِيَاضٍ أَنَّ أَبَا هُرَيْرَةَ حَدَّثَهُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَعَوَّذُوا بِاللَّهِ مِنْ الْفَقْرِ وَالْقِلَّةِ وَالذِّلَّةِ وَأَنْ تَظْلِمَ أَوْ تُظْلَمَ","id":"Telah mengabarkan kepada kami [Yunus bin Abdul A'la] ia berkata; telah menceritakan kepada kami [Ibnu Wahb] ia berkata; telah menceritakan kepadaku [Musa bin Syaibah] dari [Al Auza'i] dari [Ishaq bin Abdullah bin Abu Thalhah] ia berkata; telah menceritakan kepadaku [Ja'far bin Iyadl] bahwa [Abu Hurairah] menceritakan kepadanya dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Berlindunglah kepada Allah dari kefakiran, kekurangan dan kehinaan, berbuat zhalim atau dizhalimi.\""},"5105":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ قَالَ حَدَّثَنَا عُثْمَانُ يَعْنِي الشَّحَّامَ قَالَ حَدَّثَنَا مُسْلِمٌ يَعْنِي ابْنَ أَبِي بَكْرَةَ أَنَّهُ كَانَ سَمِعَ وَالِدَهُيَقُولُ فِي دُبُرِ الصَّلَاةِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْكُفْرِ وَالْفَقْرِ وَعَذَابِ الْقَبْرِ فَجَعَلْتُ أَدْعُو بِهِنَّ فَقَالَ يَا بُنَيَّ أَنَّى عُلِّمْتَ هَؤُلَاءِ الْكَلِمَاتِ قُلْتُ يَا أَبَتِ سَمِعْتُكَ تَدْعُو بِهِنَّ فِي دُبُرِ الصَّلَاةِ فَأَخَذْتُهُنَّ عَنْكَ قَالَ فَالْزَمْهُنَّ يَا بُنَيَّ فَإِنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْعُو بِهِنَّ فِي دُبُرِ الصَّلَاةِ","id":"Telah mengabarkan kepada kami [Muhammad Ibnul Mutsanna] ia berkata; telah menceritakan kepada kami [Ibnu Abu Adi] ia berkata; telah menceritakan kepada kami [Utsman yaitu Asy Syahham] ia berkata; telah menceritakan kepada kami [Muslim yaitu Ibnu Abu Bakrah] bahwa ia pernah mendengar [Ayahnya] mengucapkan setelah selesai shalat; \"ALLAHUMMA INNI A'UUDZU BIKA MINAL KUFRI WAL FAQRI WA 'ADZAABIL QABRI (Ya Allah, aku berlindung kepada-Mu dari kekafiran, kefakiran dan siksa kubur) '. Lalu aku berdoa dengan doa tersebut. Ayahku lalu bertanya; \"Wahai anakku, dari mana engkau belajar ucapan-ucapan itu?\" Aku menjawab; \"Wahai ayahku, setiap selesai shalat aku mendengarmu membaca itu, maka aku mengamalkan itu darimu!\" Ayahku lalu berkata; \"Wahai anakku, amalkanlah selalu, sebab Nabi shallallahu 'alaihi wasallam selalu membaca doa itu setiap selesai shalat.\""},"5106":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ قَالَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَثِيرًا مَا يَدْعُو بِهَؤُلَاءِ الْكَلِمَاتِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ فِتْنَةِ النَّارِ وَعَذَابِ النَّارِ وَفِتْنَةِ الْقَبْرِ وَعَذَابِ الْقَبْرِ وَشَرِّ فِتْنَةِ الْمَسِيحِ الدَّجَّالِ وَشَرِّ فِتْنَةِ الْفَقْرِ وَشَرِّ فِتْنَةِ الْغِنَى اللَّهُمَّ اغْسِلْ خَطَايَايَ بِمَاءِ الثَّلْجِ وَالْبَرَدِ وَأَنْقِ قَلْبِي مِنْ الْخَطَايَا كَمَا أَنْقَيْتَ الثَّوْبَ الْأَبْيَضَ مِنْ الدَّنَسِ وَبَاعِدْ بَيْنِي وَبَيْنَ خَطَايَايَ كَمَا بَاعَدْتَ بَيْنَ الْمَشْرِقِ وَالْمَغْرِبِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْكَسَلِ وَالْهَرَمِ وَالْمَأْثَمِ وَالْمَغْرَمِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah] ia berkata; telah menceritakan kepada kami [Abu Usamah] ia berkata; telah menceritakan kepada kami [Hisyam bin Urwah] dari [Ayahnya] dari ['Aisyah] ia berkata, \"Doa yang sering dibaca oleh Rasulullah shallallahu 'alaihi wasallam adalah: \"ALLAHUMMA INNI A'UUDZU BIKA MIN FITNATINNARI WA FITNATIL QABRI WA SYARRI FITNATIL MASIIHID DAJJAL WA SYARRI FITNATIL FAQRI WA SYARRI FITNATIL GHINA ALLAHUMMA IGHSIL KHATHAAYAAYA BIMA`ITS TSALJI WA BARADI WA ANTIQI QALBI MINAL KHATHAAYAAYA KAMAA ANQAITA ATS TSAUBAL ABYADLA MINAD DANAS WA BAA'ID BAINII WA BAINA KHATHAAYAAYA KAMAA BAA'ATTA BAINAL MASYRIQI WAL MAGHRIBI ALLAHUMMA INNI A'UUDZU BIKA MINAL KASALI WAL HARAMI WAL MA`TSAMI WAL MAGHRAMI (Ya Allah, aku berlindung kepada-Mu dari fitnah neraka dan siksa neraka, fitnah kubur dan siksa kubur, kejelekkan fitnah Al Masih dajjal, kejelekkan fitnah kafakiran dan kejelekkan fitnah kekayaan. Ya Allah, basuhlah kesalahanku dengan air es dan embun, bersihkan hatiku dari kesalahan sebagaimana Engkau bersihkan kain putih dari kotoran. Jauhkanlah antara aku dan kesalahanku sebagaimana Engkau jauhkan antara timur dan barat. Ya Allah, aku berlindung kepada-Mu dari kemalasan, kepikunan, sebab yang mendatangkan dosa dan hutang yang tidak terbayar).\""},"5107":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَخِيهِ عَبَّادِ بْنِ أَبِي سَعِيدٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْأَرْبَعِ مِنْ عِلْمٍ لَا يَنْفَعُ وَمِنْ قَلْبٍ لَا يَخْشَعُ وَمِنْ نَفْسٍ لَا تَشْبَعُ وَمِنْ دُعَاءٍ لَا يُسْمَعُ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Al Laits] dari [Sa'id bin Abu Sa'id] dari saudaranya [Abbad bin Abu Sa'id] Bahwasanya ia mendengar [Abu Hurairah] berkata; \"Rasulullah shallallahu 'alaihi wasallam selalu mengucapkan: \"ALLAHUMMA INNI A'UUDZU BIKA MINAL ARBA'; MIN 'ILMIN LAA YANFA' WA MIN QALBIN LAA YAKHSYA' WA MIN NAFSIN LAA TASYBA' WA MIN DU'AA`IN LAA YUSMA' (Ya Allah, aku berlindung kepada-Mu dari empat hal; ilmu yang tidak bermanfaat, hati yang tidak khusyu', jiwa yang tidak merasa puas dan dari doa yang tidak didengar).\""},"5108":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ أَنْبَأَنَا ابْنُ إِدْرِيسَ عَنْ ابْنِ عَجْلَانَ عَنْ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْجُوعِ فَإِنَّهُ بِئْسَ الضَّجِيعُ وَأَعُوذُ بِكَ مِنْ الْخِيَانَةِ فَإِنَّهَا بِئْسَتِ الْبِطَانَةُ","id":"Telah mengabarkan kepada kami [Muhammad Ibnul 'Ala] ia berkata; telah memberitakan kepada kami [Ibnu Idris] dari [Ibnu 'Ajlan] dari [Al Maqburi] dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya Allah, aku berlindung kepada-Mu dari kelaparan, sebab ia adalah seburuk-buruk teman tidur. Dan aku berlindung kepada-Mu dari berkhianat, sebab itu adalah seburuk-buruk perkara dalam hati.\""},"5109":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ قَالَ حَدَّثَنَا ابْنُ عَجْلَانَ وَذَكَرَ آخَرَ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْجُوعِ فَإِنَّهُ بِئْسَ الضَّجِيعُ وَمِنْ الْخِيَانَةِ فَإِنَّهَا بِئْسَتِ الْبِطَانَةُ","id":"Telah mengabarkan kepada kami [Muhammad Ibnu Al Mutsanna] ia berkata; telah menceritakan kepada kami [Abdullah bin Idris] ia berkata; telah menceritakan kepada kami [Ibnu 'Ajlan] dan ia menyebutkan orang lain dari [Sa'id bin Abu Sa'id] dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya Allah, aku berlindung kepada-Mu dari kelaparan, sebab ia adalah seburuk-buruk teman tidur. Dan aku berlindung kepada-Mu dari sifat khianat, sebab itu adalah seburuk-buruk perkara dalam hati.\""},"5110":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا خَلَفٌ عَنْ حَفْصٍ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْعُو بِهَذِهِ الدَّعَوَاتِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ عِلْمٍ لَا يَنْفَعُ وَقَلْبٍ لَا يَخْشَعُ وَدُعَاءٍ لَا يُسْمَعُ وَنَفْسٍ لَا تَشْبَعُ ثُمَّ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ هَؤُلَاءِ الْأَرْبَعِ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Khalaf] dari [Hafsh] dari [Anas] ia berkata; \"Nabi shallallahu 'alaihi wasallam biasa berdoa dengan doa-doa berikut: \"ALLAHUMMA INNI A'UUDZU BIKA MIN 'ILMIN LAA YANFA' WA QALBIN LAA YAKHSYA' WA DU'A`IN LAA YUSMA' WA NAFSIN LAA TASYBA' (Ya Allah, aku berlindung kepada-Mu dari ilmu yang tidak bermanfaat, hati yang tidak khusyu', doa yang tidak didengar dan jiwa yang tidak merasa puas) '. Kemudian beliau mengucapkan: \"ALLAHUMMA INNI A'UUDZU BIKA MIN HAULAA`IL ARBA' (Ya Allah, aku berlindung kepada-Mu dari empat perkara tersebut).\""},"5111":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ قَالَ حَدَّثَنَا بَقِيَّةُ قَالَ حَدَّثَنَا ضُبَارَةُ عَنْ دُوَيْدِ بْنِ نَافِعٍ قَالَ قَالَ أَبُو صَالِحٍ قَالَ أَبُو هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْعُو اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الشِّقَاقِ وَالنِّفَاقِ وَسُوءِ الْأَخْلَاقِ","id":"Telah mengabarkan kepada kami [Amru bin Utsman] ia berkata; telah menceritakan kepada kami [Baqiyyah] ia berkata; telah menceritakan kepada kami [Dlubarah] dari [Duwaid bin Nafi'] ia berkata; [Abu Shalih] berkata; [Abu Hurairah] berkata; \"Rasulullah shallallahu 'alaihi wasallam mengucapkan doa: \"ALLAHUMMA INNI A'UUDZU BIKA MINSY SYIQAAQI WAN NIFAAQI WA SUU`IL AKHLAAQI (Ya Allah, aku berlindung kepada-Mu dari perpecahan, kenifakan dan akhlak yang buruk).\""},"5112":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا بَقِيَّةُ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ سُلَيْمَانُ بْنُ سُلَيْمٍ الْحِمْصِيُّ قَالَ حَدَّثَنِي الزُّهْرِيُّ عَنْ عُرْوَةَ هُوَ ابْنُ الزُّبَيْرِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُكْثِرُ التَّعَوُّذَ مِنْ الْمَغْرَمِ وَالْمَأْثَمِ فَقِيلَ لَهُ يَا رَسُولَ اللَّهِ إِنَّكَ تُكْثِرُ التَّعَوُّذَ مِنْ الْمَغْرَمِ وَالْمَأْثَمِ فَقَالَ إِنَّ الرَّجُلَ إِذَا غَرِمَ حَدَّثَ فَكَذَبَ وَوَعَدَ فَأَخْلَفَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Baqiyyah] ia berkata; telah menceritakan kepadaku [Abu Salamah Sulaiman bin Abu Sulaim Al 'Himshi] ia berkata; telah menceritakan kepadaku [Az Zuhri] dari ['Urwah yakni Ibnu Az Zubair] dari ['Aisyah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam memperbanyak minta perlindungan dari hutang yang tidak terbayar dan sebab yang menimbulkan dosa.\" Lalu dikatakan kepada beliau; \"Wahai Rasulullah, kenapa engkau memperbanyak minta perlindungan dari hutang yang tidak terbayar dan sebab yang menimbulkan dosa?\" beliau menjawab: \"Sebab jika seseorang berhutang, ia akan banyak berbicara lalu dusta, dan berjanji lalu mengingkari.\""},"5113":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا حَيْوَةُ وَذَكَرَ آخَرَ قَالَ حَدَّثَنَا سَالِمُ بْنُ غَيْلَانَ التُّجِيبِيُّ أَنَّهُ سَمِعَ دَرَّاجًا أَبَا السَّمْحِ أَنَّهُ سَمِعَ أَبَا الْهَيْثَمِ أَنَّهُ سَمِعَ أَبَا سَعِيدٍ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَعُوذُ بِاللَّهِ مِنْ الْكُفْرِ وَالدَّيْنِ قَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَتَعْدِلُ الدَّيْنَ بِالْكُفْرِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Yazid] ia berkata; telah menceritakan kepada kami [Ayahku] ia berkata; telah menceritakan kepada kami [Haiwah]. Dan ia menyebutkan orang lain; ia berkata; telah menceritakan kepada kami [Salim bin Ghailan At Tujibi] bahwa ia mendengar [Darraj Abu As Samh] bahwa ia mendengar [Abu Al Haitsam] bahwa ia mendengar [Abu Sa'id] berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam mengucapkan: \"A'UUDZU BILLAHI MINAL KUFRI WAD DAINI (Aku berlindung kepada Allah dari kekufuran dan hutang).\" Seorang laki-laki lalu bertanya; \"Wahai Rasulullah, apakah ada hubungannya antara hutang dengan kekufuran?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Ya.\""},"5114":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ يَزِيدَ الْمُقْرِيُّ قَالَ حَدَّثَنَا حَيْوَةُ عَنْ دَرَّاجٍ أَبِي السَّمْحِ عَنْ أَبِي الْهَيْثَمِ عَنْ أَبِي سَعِيدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَعُوذُ بِاللَّهِ مِنْ الْكُفْرِ وَالدَّيْنِ فَقَالَ رَجُلٌ تَعْدِلُ الدَّيْنَ بِالْكُفْرِ قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Basyar] ia berkata; telah menceritakan kepadaku [Abdullah bin Yazid Al Maqburi] ia berkata; telah menceritakan kepada kami [Haiwah] dari [Darraj Abu As Samh] dari [Abu Al Haitsam] dari [Abu Sa'id] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: A'UUDZU BILLAHI MINAL KUFRI WAD DAINI (Aku berlindung kepada Allah dari kekufuran dan hutang).\" Seorang laki-laki lalu bertanya; \"Wahai Rasulullah, apakah antara hutang dengan kekufuran ada hubungannya?\" beliau menjawab: \"Ya.\""},"5115":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ حَدَّثَنِي حُيَيُّ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي أَبُو عَبْدِ الرَّحْمَنِ الْحُبُلِيُّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْعُو بِهَؤُلَاءِ الْكَلِمَاتِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ غَلَبَةِ الدَّيْنِ وَغَلَبَةِ الْعَدُوِّ وَشَمَاتَةِ الْأَعْدَاءِ","id":"Telah mengabarkan kepada kami [Ahmad bin 'Amru bin As Sarh] ia berkata; telah memberitakan kepada kami [Ibnu Abu Wahb] ia berkata; telah menceritakan kepadaku [Huyay bin Abdullah] ia berkata; telah menceritakan kepadaku [Abu 'Abdurrahman Al Hubuli] dari [Abdullah bin 'Amru bin Al Ash] berkata; \"Rasulullah shallallahu 'alaihi wasallam biasa berdoa dengan kalimat-kalimat tersebut: \"ALLAHUMMA INNI A'UUDZU BIKA MIN GHALABATID DAIN WA GHALABATIL 'ADUI WA SYAAMATIL A'DA (Aku berlindung kepada Allah dari lilitan hutang, penindasan musuh dan kebahagiaan musuh).\""},"5116":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا الْقَاسِمُ وَهُوَ ابْنُ يَزِيدَ الْجَرْمِيُّ عَنْ عَبْدِ الْعَزِيزِ أَخْبَرَنِي عَمْرُو بْنُ أَبِي عَمْرٍو عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْهَمِّ وَالْحَزَنِ وَالْكَسَلِ وَالْبُخْلِ وَالْجُبْنِ وَضَلَعِ الدَّيْنِ وَغَلَبَةِ الرِّجَالِ","id":"Telah mengabarkan kepada kami [Ahmad bin Harb] ia berkata; telah menceritakan kepada kami [Al Qasim yaitu Ibnu Yazid Al Jarmi] dari [Abdul Aziz] dia berkata; telah mengabarkan kepadaku ['Amru bin Abu 'Amru] dari [Anas bin Malik] ia berkata; \"Nabi shallallahu 'alaihi wasallam biasa mengucapkan doa: \"ALLAHUMMA INNI A'UUDZU BIKA MINAL HAMMI WAL HAZANI WAL KASALI WAL BUKHLI WAL JUBNI WA DLALA'ID DAINI WA GHALABATIR RIJALI (YA Allah, aku berlindung kepada-Mu dari kegelisahan dan kesedihan, kemalasan dan kebakhilan, sifat pengecut, himpitan hutang dan penindasan para penguasa).\""},"5117":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ عَذَابِ الْقَبْرِ وَفِتْنَةِ النَّارِ وَفِتْنَةِ الْقَبْرِ وَعَذَابِ الْقَبْرِ وَشَرِّ فِتْنَةِ الْمَسِيحِ الدَّجَّالِ وَشَرِّ فِتْنَةِ الْغِنَى وَشَرِّ فِتْنَةِ الْفَقْرِ اللَّهُمَّ اغْسِلْ خَطَايَايَ بِمَاءِ الثَّلْجِ وَالْبَرَدِ وَنَقِّ قَلْبِي مِنْ الْخَطَايَا كَمَا نَقَّيْتَ الثَّوْبَ الْأَبْيَضَ مِنْ الدَّنَسِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْكَسَلِ وَالْهَرَمِ وَالْمَغْرَمِ وَالْمَأْثَمِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah menceritakan kepada kami [Jarir] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari ['Aisyah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam biasa mengucapkan doa: \"ALLAHUMMA INNI A'UUDZU BIKA MIN 'AADZAABIL QABRI WA FITNATIN NAARI WA FITNATIL QABRI WA ADZAABIL QABRI WA SYARRI FITNATIL MASIIHID DAJJAL WA SYARRI FITNATIL GHINA WA SYARRI FITNATIL FAQRI ALLAHUMMA IGHSIL KHATHAAYAAYA BIMA`ITS TSALJI WA BARADI WA ANTIQI QALBI MINAL KHATHAAYAA KAMAA ANQAITA ATS TSAUBAL ABYADLA MINAD DANAS ALLAHUMMA INNI A'UUDZU BIKA MINAL KASALI WAL HARAMI WAL MAGHRAMI WAL MA`TSAMI (Ya Allah, aku berlindung kepada-Mu dari siksa kubur, fitnah neraka, fitnah kubur dan siksa kubur, kejelekkan fitnah Al Masih dajjal, kejelekkan fitnah kekayaan dan fitnah kejelekkan kafakiran. Ya Allah, basuhlah kesalahanku dengan air es dan embun, bersihkan hatiku dari kesalahan sebagaimana Engkau bersihkan kain putih dari kotoran. Ya Allah, aku berlindung kepada-Mu dari kemalasan, kepikunan, hutang yang tidak terbayar dan sebab yang mendatangkan dosa).\""},"5118":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ قَالَ سَمِعْتُ مُصْعَبَ بْنَ سَعْدٍ قَالَكَانَ سَعْدٌ يُعَلِّمُهُ هَؤُلَاءِ الْكَلِمَاتِ وَيَرْوِيهِنَّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْبُخْلِ وَأَعُوذُ بِكَ مِنْ الْجُبْنِ وَأَعُوذُ بِكَ مِنْ أَنْ أُرَدَّ إِلَى أَرْذَلِ الْعُمُرِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الدُّنْيَا وَعَذَابِ الْقَبْرِ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] ia berkata; telah menceritakan kepada kami [Abu Dawud] ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Abdul Malik bin 'Umair] ia berkata; Aku mendengar [Mush'ab bin Sa'd] ia berkata, [Sa'd] pernah mengajari mereka kalimat-kalimat doa dari Nabi shallallahu 'alaihi wasallam: \"ALLAHUMMA INNI A'UUDZU BIKA MINAL BUKHLI WA A'UUDZU BIKA MINAL JUBNI WA A'UUDZU BIKA MIN AN URADDA ILAA ARDALIL 'UMURI WA A'UUDZU BIKA MIN FITNATID DUNYA WA ADZAABIL QABRI (Ya Allah, aku berlindung kepada-Mu dari kebakhilan, aku berlindung kepada-Mu dari sifat pengecut, aku berlindung kepada-Mu dari kepikunan, dan aku berlindung kepada-Mu dari fitnah dunia dan siksa kubur).\""},"5119":{"ar":"أَخْبَرَنِي هِلَالُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ إِسْرَائِيلَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ مُصْعَبِ بْنِ سَعْدٍ وَعَمْرِو بْنِ مَيْمُونٍ الْأَوْدِيِّ قَالَاكَانَ سَعْدٌ يُعَلِّمُ بَنِيهِ هَؤُلَاءِ الْكَلِمَاتِ كَمَا يُعَلِّمُ الْمُكْتِبُ الْغِلْمَانَ وَيَقُولُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَعَوَّذُ بِهِنَّ فِي دُبُرِ كُلِّ صَلَاةٍ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْبُخْلِ وَأَعُوذُ بِكَ مِنْ الْجُبْنِ وَأَعُوذُ بِكَ مِنْ أَنْ أُرَدَّ إِلَى أَرْذَلِ الْعُمُرِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الدُّنْيَا وَعَذَابِ الْقَبْرِ","id":"Telah mengabarkan kepadaku [Hilal Ibnul 'Ala] ia berkata; telah menceritakan kepada kami [Bapakku] ia berkata; telah menceritakan kepada kami [Ubaidullah] dari [Isra'il] dari [Abdul Malik bin Umair] dari [Mush'ab bin Sa'd] dan ['Amru bin Maimun Al Audi] keduanya berkata; [Sa'd] pernah mengajarkan kalimat-kalimat tersebut kepada anak-anaknya sebagaimana seorang tuan mengajarkan kepada budak-budaknya, ia berkata; \"Rasulullah shallallahu 'alaihi wasallam selalu berlindung dengan kalimat-kalimat terbuat setiap selesai shalat: \"ALLAHUMMA INNI A'UUDZU BIKA MINAL BUKHLI WA A'UUDZU BIKA MINAL JUBNI WA A'UUDZU BIKA MIN AN URADDA ILAA ARDALIL 'UMURI WA A'UUDZU BIKA MIN FITNATID DUNYA WA ADZAABIL QABRI (Ya Allah, aku berlindung kepada-Mu dari kebakhilan, aku berlindung kepada-Mu dari sifat pengecut, aku berlindung kepada-Mu dari kepikunan, dan aku berlindung kepada-Mu dari fitnah dunia dan siksa kubur).\""},"5120":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ فَضَالَةَ عَنْ عُبَيْدِ اللَّهِ قَالَ أَنْبَأَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَقَ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَعَوَّذُ مِنْ الْجُبْنِ وَالْبُخْلِ وَسُوءِ الْعُمُرِ وَفِتْنَةِ الصَّدْرِ وَعَذَابِ الْقَبْرِ","id":"Telah mengabarkan kepada kami [Ahmad bin Fadlalah] dari ['Ubaidullah] ia berkata; telah memberitakan kepada kami [Isra'il] dari [Abu Ishaq] dari ['Amru bin Maimun] dari [Umar] ia berkata; \"Nabi shallallahu 'alaihi wasallam berlindung dari sifat pengecut, kikir, kehidupan yang buruk, mati sebelum bertaubat dan siksa kubur.\""},"5121":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ سَلْمٍ الْبَلْخِيُّ هُوَ أَبُو دَاوُدَ الْمُصَاحِفِيُّ قَالَ أَنْبَأَنَا النَّضْرُ قَالَ أَنْبَأَنَا يُونُسُ عَنْ أَبِي إِسْحَقَ عَنْ عَمْرِو بْنِ مَيْمُونٍ قَالَ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَعَوَّذُ مِنْ خَمْسٍ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْجُبْنِ وَالْبُخْلِ وَسُوءِ الْعُمُرِ وَفِتْنَةِ الصَّدْرِ وَعَذَابِ الْقَبْرِ","id":"Telah mengabarkan kepada kami [Sulaiman bin Salm Al Balkhi yaitu Abu Dawud Al Mushahifi] ia berkata; telah memberitakan kepada kami [An Nadlr] ia berkata; telah memberitakan kepada kami [Yunus] dari [Abu Ishaq] dari ['Amru bin Maimun] ia berkata; \"Aku mendengar [Umar Ibnul Khaththab] berkata; \"Rasulullah shallallahu 'alaihi wasallam berlindung dari lima perkara: \"ALLAHUMMA INNI A'UUDZU BIKA MINAL JUBNI WAL BUKHLI WA SUU`IL 'UMURI WA FITNATILSH SHADR WA 'ADZAABIL QABRI (Ya Allah, aku berlindung kepada-Mu dari sifat pengecut, kikir, kehidupan yang buruk, mati sebelum taubat dan siksa kubur).\""},"5122":{"ar":"أَخْبَرَنِي هِلَالُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا حُسَيْنٌ قَالَ حَدَّثَنَا زُهَيْرٌ قَالَ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ عَمْرِو بْنِ مَيْمُونٍ قَالَ حَدَّثَنِي أَصْحَابُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَعَوَّذُ مِنْ الشُّحِّ وَالْجُبْنِ وَفِتْنَةِ الصَّدْرِ وَعَذَابِ الْقَبْرِ","id":"Telah mengabarkan kepadaku [Hilal Ibnu Al 'Ala`] ia berkata; telah menceritakan kepada kami [Husain] ia berkata; telah menceritakan kepada kami [Zuhair] ia berkata; telah menceritakan kepada kami [Abu Ishaq] dari ['Amru bin Maimun] ia berkata; telah menceritakan kepadaku [Sahabat-sahabat Muhammad] shallallahu 'alaihi wasallam, bahwa Rasulullah shallallahu 'alaihi wasallam berlindung dari sifat kikir, sifat pengecut, mati sebelum taubat dan siksa kubur.\""},"5123":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا أَبُو دَاوُدَ عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَقَ عَنْ عَمْرِو بْنِ مَيْمُونٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَعَوَّذُمُرْسَلٌ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] ia berkata; telah menceritakan kepada kami [Abu Dawud] dari [Sufyan] dari [Abu Ishaq] dari ['Amru bin Maimun] ia berkata; \"Nabi shallallahu 'alaihi wasallam biasa meminta perlindungan.\" Hadits ini mursal."},"5124":{"ar":"أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ وَكِيعٍ قَالَ حَدَّثَنَا أَبِي عَنْ سَعْدِ بْنِ أَبِي أَوْسٍ عَنْ بِلَالِ بْنِ يَحْيَى عَنْ شُتَيْرِ بْنِ شَكَلِ بْنِ حُمَيْدٍ عَنْ أَبِيهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ عَلِّمْنِي دُعَاءً أَنْتَفِعُ بِهِ قَالَ قُلْ اللَّهُمَّ عَافِنِي مِنْ شَرِّ سَمْعِي وَبَصَرِي وَلِسَانِي وَقَلْبِي وَشَرِّ مَنِيِّي يَعْنِي ذَكَرَهُ","id":"Telah mengabarkan kepadaku [Ubaidullah bin Waki'] ia berkata; telah menceritakan kepada kami [Ayahku] dari [Sa'd bin Abu Aus] dari [Bilal bin Yahya] dari [Syutair bin Syakal bin Humaid] dari [Ayahnya] ia berkata; \"Aku berkata; \"Wahai Rasulullah, ajarkanlah kepadaku sebuah doa yang bisa aku ambil manfaatnya.\" Beliau bersabda: \"Ucapkanlah: ALLAHUMMA 'AAFINI MIN SYARRI SAM'I WA BASHARI WA LISANI WA QALBI WA SYARRI MANIYYI (Ya Allah, selamatkanlah aku dari keburukkan pendengaranku, penglihatan, lisan dan hatiku. Dan dari keburukkan maniku -yakni kelamaluannya-).\""},"5125":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي سَالِمُ بْنُ غَيْلَانَ عَنْ دَرَّاجٍ أَبِي السَّمْحِ عَنْ أَبِي الْهَيْثَمِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْكُفْرِ وَالْفَقْرِ فَقَالَ رَجُلٌ وَيَعْدِلَانِ قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Ahmad bin 'Amru bin As Sarh] ia berkata; telah menceritakan kepada kami [Ibnu Wahb] ia berkata; telah mengabarkan kepadaku [Salim bin Ghailan] dari [Darraj Abu As Samh] dari [Abu Al Haitsam] dari [Abu Sa'id Al khudri] dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau berdoa: \"Ya Allah, aku berlindung kepada-Mu dari kekufuran dan kefakiran.\" Seorang laki-laki bertanya; \"Apakah sama? ' beliau menjawab: \"Ya.\""},"5126":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ قُدَامَةَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ الشَّعْبِيِّ عَنْ أُمِّ سَلَمَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا خَرَجَ مِنْ بَيْتِهِ قَالَ بِسْمِ اللَّهِ رَبِّ أَعُوذُ بِكَ مِنْ أَنْ أَزِلَّ أَوْ أَضِلَّ أَوْ أَظْلِمَ أَوْ أُظْلَمَ أَوْ أَجْهَلَ أَوْ يُجْهَلَ عَلَيَّ","id":"Telah mengabarkan kepadaku [Muhammad bin Qudamah] ia berkata; telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Asy Sya'bi] dari [Ummu Salamah] berkata; \"Jika Nabi shallallahu 'alaihi wasallam ingin keluar rumah, beliau selalu mengucapkan: \"BISMILLAHI RABBI A'UUDZU BIKA MIN AN AZILLA AU ADILLA AU AZHLIMA AU UZHLAMA AU AJHALA AU YUJHALA 'ALAYYA (Dengan menyebut nama Allah! Ya Allah, aku berlindung kepada-Mu dari berbuat kesalahan, atau kesesatan, atau berbuat zhalim, atau dizhalimi, berbuat bodoh atau dibodohi).\""},"5127":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ قَالَ حَدَّثَنِي ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي حُيَيُّ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي أَبُو عَبْدِ الرَّحْمَنِ الْحُبُلِيُّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْعُو بِهَؤُلَاءِ الْكَلِمَاتِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ غَلَبَةِ الدَّيْنِ وَغَلَبَةِ الْعَدُوِّ وَشَمَاتَةِ الْأَعْدَاءِ","id":"Telah mengabarkan kepada kami [Ahmad bin 'Amru bin As Sarh] ia berkata; telah menceritakan kepadaku [Ibnu Wahb] ia berkata; telah mengabarkan kepadaku [Huyay bin Abdullah] ia berkata; telah menceritakan kepadaku [Abu 'Abdurrahman Al Hubuli] dari [Abdullah bin Amru bin Al 'Ash] berkata; \"Rasulullah shallallahu 'alaihi wasallam biasa berdoa dengan kalimat-kalimat seperti ini: \"ALLAHUMMA INNI A'UUDZU BIKA MIN GHALABATID DAINI WA GHALABATID 'ADUWWI WA SYAMAATATIL A'DA (Ya Allah, aku berlindung kepada-Mu dari lilitan hutang, penindasan musuh dan kehabagiaan musuh).\""},"5128":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ قَالَ حُيَيٌّ حَدَّثَنِي أَبُو عَبْدِ الرَّحْمَنِ الْحُبُلِيُّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْعُو بِهَؤُلَاءِ الْكَلِمَاتِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ غَلَبَةِ الدَّيْنِ وَشَمَاتَةِ الْأَعْدَاءِ","id":"Telah mengabarkan kepada kami [Yunus bin Abdul A'la] ia berkata; telah memberitakan kepada kami [Ibnu Wahb] ia berkata; [Huyay] berkata; telah mencertakan kepadaku [Abu 'Abdurrahman Al Hubuli] dari [Abdullah bin 'Amru] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam biasa berdoa dengan kalimat-kalimat tersebut: \"ALLAHUMMA INNI A'UUDZU BIKA MIN GHALABATID DAINI WA GHALABATID 'ADUWWI WA SYAMAATATIL A'DA (Ya Allah, aku berlindung kepada-Mu dari lilitan hutang, penindasan musuh dan kehabagiaan musuh).\""},"5129":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا حَمَّادُ بْنُ مَسْعَدَةَ عَنْ هَارُونَ بْنِ إِبْرَاهِيمَ عَنْ مُحَمَّدٍ عَنْ عُثْمَانَ بْنِ أَبِي الْعَاصِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْعُو بِهَذِهِ الدَّعَوَاتِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْكَسَلِ وَالْهَرَمِ وَالْجُبْنِ وَالْعَجْزِ وَمِنْ فِتْنَةِ الْمَحْيَا وَالْمَمَاتِ","id":"Telah mengabarkan kepada kami [Abdullah bin Muhammad bin 'Abdurrahman] ia berkata; telah menceritakan kepada kami [Hammad bin Mas'adah] dari [Harun bin Ibrahim] dari [Muhammad] dari [Utsman bin Abu Al 'Ash] ia berkata; \"Nabi shallallahu 'alaihi wasallam biasa berdoa dengan doa-doa ini: \"ALLAHUMMA INNI A'UUDZU BIKA MINAL KASALI WAL HARAMI WAL JUBNI WAL 'AJZI WA MIN FITNATIL MAHYAA WAL MAMAATI (Ya Allah, aku berlindung kepada-Mu dari kemalasan, pikun, sifar pengecut dan kelemahan. Serta dari fitnah kehidupan dan kematian).\""},"5130":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْحَكَمِ عَنْ شُعَيْبٍ عَنْ اللَّيْثِ عَنْ يَزِيدَ بْنِ الْهَادِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْكَسَلِ وَالْهَرَمِ وَالْمَغْرَمِ وَالْمَأْثَمِ وَأَعُوذُ بِكَ مِنْ شَرِّ الْمَسِيحِ الدَّجَّالِ وَأَعُوذُ بِكَ مِنْ عَذَابِ الْقَبْرِ وَأَعُوذُ بِكَ مِنْ عَذَابِ النَّارِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul Karim] dari [Syu'aib] dari [Al laits] dari [Yazid Ibnu Al Had] dari [Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] ia berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam mengucapkan: \"ALLAHUMMA INNI A'UUDZU BIKA MINAL KASALI WAL HARAMI WAL MAGHRAMI WA MA`TSAMI WA A'UUDZU BIKA MIN SYARRIL MASIIHID DAJJAL WA A'UUDZU BIKA MIN ADZAABIL QABRI WA A'UUDZU BIKA MIN ADZAABIN NAAR (Ya Allah, aku berlindung kepada-Mu dari kemalasan, pikun, hutang yang tidak terbayar, sebab yang mendatangkan dosa. Aku berlindung kepada-Mu dari Al Masih Dajjal. Aku berlindung kepada-Mu dari siksa kubur. Dan aku juga berlindung kepada-Mu dari siksa neraka).\""},"5131":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا سُفْيَانُ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ إِنْ شَاءَ اللَّهُ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَعَوَّذُ مِنْ هَذِهِ الثَّلَاثَةِ مِنْ دَرَكِ الشَّقَاءِ وَشَمَاتَةِ الْأَعْدَاءِ وَسُوءِ الْقَضَاءِ وَجَهْدِ الْبَلَاءِقَالَ سُفْيَانُ هُوَ ثَلَاثَةٌ فَذَكَرْتُ أَرْبَعَةً لِأَنِّي لَا أَحْفَظُ الْوَاحِدَ الَّذِي لَيْسَ فِيهِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Sufyan] dari [Sumay] dari [Abu Shalih] Insyaallah dari [Abu Hurairah] ia berkata; \"Nabi shallallahu 'alaihi wasallam berlindung dari tiga hal ini, yaitu; mendapati kesulitan (su`ul Khatimah), kebahagiaan musuh, qadla yang buruk dan bencana yang dahsyat.\" Sufyan berkata; \"Dalam hadits itu ada tiga hal, namun aku menyebutkan empat perkara karena aku tidak hafal salah satu yang tidak termasuk di dalamnya.\""},"5132":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَسْتَعِيذُ مِنْ سُوءِ الْقَضَاءِ وَشَمَاتَةِ الْأَعْدَاءِ وَدَرَكِ الشَّقَاءِ وَجَهْدِ الْبَلَاءِ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Sufyan] dari [Sumay] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; \"Nabi shallallahu 'alaihi wasallam berlindung dari ketetapan yang jelek, kebahagiaan musuh, su`ul khatimah dan bencana yang dahsyat.\""},"5133":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْجُنُونِ وَالْجُذَامِ وَالْبَرَصِ وَسَيِّئِ الْأَسْقَامِ","id":"Telah mengabarkan kepada kami [Muhammad Ibnu Al Mutsanna] ia berkata; telah menceritakan kepada kami [Abu Dawud] ia berkata; telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Anas] ia berkata; \"Nabi shallallahu 'alaihi wasallam mengucapkan: \"ALLAHUMMA INNI A'UUDZU BIKA MINAL JUNUUNI WAL JUDZAAMI WAL BARASHI WA SAYYI`IL ASQAAM (Ya Allah, aku berlindung kepada-Mu dari penyakit gila, lepra, kusta dan penyakit yang ganas).\""},"5134":{"ar":"أَخْبَرَنَا هِلَالُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا سَعِيدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا عَبَّادٌ عَنْ الْجُرَيْرِيِّ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَعَوَّذُ مِنْ عَيْنِ الْجَانِّ وَعَيْنِ الْإِنْسِ فَلَمَّا نَزَلَتْ الْمُعَوِّذَتَانِ أَخَذَ بِهِمَا وَتَرَكَ مَا سِوَى ذَلِكَ","id":"Telah mengabarkan kepada kami [Hillal bin Al 'Ala] ia berkata; telah menceritakan kepada kami [Sa'id bin Sulaiman] ia berkata; telah menceritakan kepada kami ['Abbad] dari [Al Jurairi] dari [Abu Nadlrah] dari [Abu Sa'id] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam biasa berlindung dari tatapan mata jahat bangsa jin dan manusia. Maka saat turun surat Mu'awwidzatain (surat Al falaq dan surat An Naas) beliau membaca keduanya dan meninggalkan selain itu.\""},"5135":{"ar":"أَخْبَرَنَا مُوسَى بْنُ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا حُسَيْنٌ عَنْ زَائِدَةَ عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَعَوَّذُ بِهَؤُلَاءِ الْكَلِمَاتِ كَانَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْكَسَلِ وَالْهَرَمِ وَالْجُبْنِ وَالْبُخْلِ وَسُوءِ الْكِبَرِ وَفِتْنَةِ الدَّجَّالِ وَعَذَابِ الْقَبْرِ","id":"Telah mengabarkan kepada kami [Musa bin 'Abdurrahman] ia berkata; telah menceritakan kepada kami [Husain] dari [Zaidah] dari [Humaid] dari [Anas] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam biasa berlindung dari kalimat-kalimat seperti ini: \"ALLAHUMMA INNI A'UUDZU BIKA MINAL KASALI WAL HARAMI WAL JUBNI WAL BUKHLI WA SUU`IL KIBRI WA FITNATID DAJJAL WA ADZAABIL QABRI (Ya Allah, aku berlindung kepada-Mu dari kemalasan, pikun, sifat pengecut, kikir, keburukan takabur, fitnah dajjal dan siksa kubur).\""},"5136":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ عَنْ شُعْبَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ قَالَ سَمِعْتُ مُصْعَبَ بْنَ سَعْدٍ عَنْ أَبِيهِ قَالَكَانَ يُعَلِّمُنَا خَمْسًا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْعُو بِهِنَّ وَيَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْبُخْلِ وَأَعُوذُ بِكَ مِنْ الْجُبْنِ وَأَعُوذُ بِكَ مِنْ أَنْ أُرَدَّ إِلَى أَرْذَلِ الْعُمُرِ وَأَعُوذُ بِكَ مِنْ عَذَابِ الْقَبْرِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] ia berkata; telah menceritakan kepada kami [Khalid] dari [Syu'bah] dari [Abdul Malik bin Umair] ia berkata; Aku mendengar [Mush'ab bin Sa'd] dari [Ayahnya] ia berkata; \"(Rasulullah) mengajarkan kepada kami lima perkara, dan Rasulullah shallallahu 'alaihi wasallam biasa berdoa dengannya: \"ALLHUMMA INNI A'UUDZU BIKA MINAL BUKHLI WA A'UUDZU BIKA MINAL JUBNI WA A'UUDZU BIKA MIN AN URADDA ILAA ARDZALIL UMURI WA A'UUDZU BIKA MIN ADZAABIL QABRI (Ya Allah, aku berlindung kepada-Mu dari kebakhilan. Aku berlindung kepada-Mu dari sifat pengecut. Aku berlindung kepada-mu dari kepikunan dan aku berlindung kepada-Mu dari siksa kubur).\""},"5137":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ بَكَّارٍ قَالَ حَدَّثَنَا أَحْمَدُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا يُونُسُ عَنْ أَبِي إِسْحَقَ يَعْنِي أَبَاهُ عَنْ عَمْرِو بْنِ مَيْمُونٍ قَالَحَجَجْتُ مَعَ عُمَرَ فَسَمِعْتُهُ يَقُولُ بِجَمْعٍ أَلَا إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَعَوَّذُ مِنْ خَمْسٍ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْبُخْلِ وَالْجُبْنِ وَأَعُوذُ بِكَ مِنْ سُوءِ الْعُمُرِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الصَّدْرِ وَأَعُوذُ بِكَ مِنْ عَذَابِ الْقَبْرِ","id":"Telah mengabarkan kepada kami [Imran bin Bakar] ia berkata; telah menceritakan kepada kami [Ahmad bin Khalid] ia berkata; telah menceritakan kepada kami [Yunus] dari [Abu Ishaq] -yaitu bapaknya- dari ['Amru bin Maimun] ia berkata; \"Aku pernah melaksanakan haji bersama [Umar], lalu aku mendengar dia berkata kepada sekelompok orang; \"Ketahuilah, sesungguhnya Nabi shallallahu 'alaihi wasallam selalu berlindung dari lima perkara; 'ALLAHUMMA INNI A'UUDZU BIKA MINAL BUKHLI WAL JUBNI WA A'UUDZU BIKA MIN SUU`IL UMURI WA A'UUDZU BIKA MIN FITNATISH SHADRI WA A'UUDZU BIKA MIN ADZAABIL QABRI (Ya Allah, aku berlindung kepada-Mu dari kebakhilan dan sifat pengecut. Aku berlindung kepada-Mu dari kehidupan yang buruk. Aku berlindung kepada-Mu dari kamatian sebelum taubat. Dan aku berlindung kepada-Mu dari siksa kubur).\""},"5138":{"ar":"أَخْبَرَنَا أَزْهَرُ بْنُ جَمِيلٍ قَالَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَاصِمٍ عَنْ عَبْدِ اللَّهِ بْنِ سَرْجِسَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا سَافَرَ قَالَ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ وَعْثَاءِ السَّفَرِ وَكَآبَةِ الْمُنْقَلَبِ وَالْحَوْرِ بَعْدَ الْكَوْرِ وَدَعْوَةِ الْمَظْلُومِ وَسُوءِ الْمَنْظَرِ فِي الْأَهْلِ وَالْمَالِ","id":"Telah mengabarkan kepada kami [Azhar bin Jamil] ia berkata; telah menceritakan kepada kami [Khalid Ibnul Harits] ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Ashim] dari [Abdullah bin Sarjis] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam jika ingin bepergian mengucapkan: \"ALLAHUMMA INNI A'UUDZU BIKA MIN WA'STAA`IS SAFAR WA KAABATIL MUNQALABI WAL HAURI BA'DAL KAURI WA DA'WATIL MALZHLUUMI WA SUU`IL MANZHARI FIL AHLI WAL MAALI (Ya Allah, aku berlindung kepada-Mu dari kelelahan di perjalanan, kesedihan saat kembali, kekurangan setelah kecukupan, doa orang yang terzhalimi dan pemandangan yang buruk pada keluarga dan harta).\""},"5139":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ عَاصِمٍ عَنْ عَبْدِ اللَّهِ بْنِ سَرْجِسَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا سَافَرَ قَالَ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ وَعْثَاءِ السَّفَرِ وَكَآبَةِ الْمُنْقَلَبِ وَالْحَوْرِ بَعْدَ الْكَوْرِ وَدَعْوَةِ الْمَظْلُومِ وَسُوءِ الْمَنْظَرِ فِي الْأَهْلِ وَالْمَالِ وَالْوَلَدِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah menceritakan kepada kami [Jarir] dari ['Ashim] dari [Abdullah bin Sarjis] ia berkata; \"Jika Rasulullah shallallahu 'alaihi wasallam hendak safar, beliau mengucapkan: \"ALLAHUMMA INNI A'UUDZU BIKA MIN WA'STAA`IS SAFAR WA KAABATIL MUNQALABI WAL HAURI BA'DAL KAURI WA DA'WATIL MALZHLUUMI WA SUU`IL MANZHARI FIL AHLI WAL MAALI WAL WALADI (Ya Allah, aku berlindung kepada-Mu dari kelelahan di perjalanan, kesedihan saat kembali, kekurangan setelah kecukupan, doa orang yang terzhalimi dan pemandangan yang buruk pada keluarga, harta dan anak).\""},"5140":{"ar":"أَخْبَرَنَا يُوسُفُ بْنُ حَمَّادٍ قَالَ حَدَّثَنَا بِشْرُ بْنُ مَنْصُورٍ عَنْ عَاصِمٍ عَنْ عَبْدِ اللَّهِ بْنِ سَرْجِسَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَافَرَ يَتَعَوَّذُ مِنْ وَعْثَاءِ السَّفَرِ وَكَآبَةِ الْمُنْقَلَبِ وَالْحَوْرِ بَعْدَ الْكَوْرِ وَدَعْوَةِ الْمَظْلُومِ وَسُوءِ الْمَنْظَرِ","id":"Telah mengabarkan kepada kami [Yusuf bin Hammad] ia berkata; telah menceritakan kepada kami [Bisyr bin Manshur] dari ['Ashim] dari [Abdullah bin Sarjis] ia berkata; \"Jika Nabi shallallahu 'alaihi wasallam hendak melakukan safar, beliau berlindung dari hambatan di perjalanan, kesedihan saat kembali, kekurangan setelah kecukupan, doa orang yang terzhalimi dan pemandangan yang buruk.\""},"5141":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عُمَرَ بْنِ عَلِيِّ بْنِ مُقَدَّمٍ قَالَ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ عَنْ عَبْدِ اللَّهِ بْنِ بِشْرٍ الْخَثْعَمِيِّ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَافَرَ فَرَكِبَ رَاحِلَتَهُ قَالَ بِإِصْبَعِهِ وَمَدَّ شُعْبَةُ بِإِصْبَعِهِ قَالَ اللَّهُمَّ أَنْتَ الصَّاحِبُ فِي السَّفَرِ وَالْخَلِيفَةُ فِي الْأَهْلِ وَالْمَالِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ وَعْثَاءِ السَّفَرِ وَكَآبَةِ ال��مُنْقَلَبِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Amru bin Umar bin Ali bin Miqdam] ia berkata; telah menceritakan kepada kami [Ibnu Abu Adi] dari [Syu'bah] dari [Abdullah bin Bisyr Al Khasy'ami] dari [Abu Zur'ah] dari [Abu Hurairah] ia berkata; \"Jika Rasulullah shallallahu 'alaihi wasallam hendak safar, beliau naik kendaraannya. Beliau lalu mengisyarakatkan dengan jarinya -Syu'bah kemudian membentangkan jarinya-, beliau mengucapkan: \"ALLAHUMMA ANTA SHAHIBU FISSAFARI WAL KHALIFATU FIL AHLI WAL MAALI ALLAHUMMA INNI A'UUDZU BIKA MIN WA'TSAA`IS SAFARI WA KAABATIL MANZHARI (Ya Allah, Engkau adalah teman dalam perjalanan dan yang mengurusi dalam keluarga dan harta (ku). Ya Allah aku berlindung kepada-Mu dari kelelahan dalam perjalanan dan pemandangan yang menyedihkan).\""},"5142":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عَجْلَانَ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعَوَّذُوا بِاللَّهِ مِنْ جَارِ السَّوْءِ فِي دَارِ الْمُقَامِ فَإِنَّ جَارَ الْبَادِيَةِ يَتَحَوَّلُ عَنْكَ","id":"Telah mengabarkan kepada kami [Amru bin Ali] ia berkata; telah menceritakan kepada kami [Yahya] ia berkata; telah menceritakan kepada kami [Muhammad bin 'Ajlan] dari [Sa'id bin Abu Sa'id Al Maqburi] dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berlindunglah kepada Allah dari tetangga yang jahat di tempat tinggal, sebab tetangga yang nomaden (badui) akan menjauh darimu.\""},"5143":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ قَالَ حَدَّثَنَا عَمْرُو بْنُ أَبِي عَمْرٍو أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَبِي طَلْحَةَ الْتَمِسْ لِي غُلَامًا مِنْ غِلْمَانِكُمْ يَخْدُمُنِي فَخَرَجَ بِي أَبُو طَلْحَةَ يَرْدُفُنِي وَرَاءَهُ فَكُنْتُ أَخْدُمُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلَّمَا نَزَلَ فَكُنْتُ أَسْمَعُهُ يُكْثِرُ أَنْ يَقُولَ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْهَرَمِ وَالْحُزْنِ وَالْعَجْزِ وَالْكَسَلِ وَالْبُخْلِ وَالْجُبْنِ وَضَلَعِ الدَّيْنِ وَغَلَبَةِ الرِّجَالِ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] ia berkata; telah menceritakan kepada kami [Isma'il] ia berkata; telah menceritakan kepada kami ['Amru bin Abu 'Amru] bahwa ia mendengar [Anas bin Malik] berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda kepada Abu Thalhah: \"Carikanlah seorang budak dari budak-budakmu untuk membantuku.\" Maka Abu Thalhah membawaku dalam boncengannya, hingga aku pun membantu Rasulullah shallallahu 'alaihi wasallam. setiap kali beliau singgah dalam suatu tempat, beliau selalu mengucapkan: \"ALLAHUMMA INNI A'UUDZU BIKA MINAL HARAMI WAL HUZNI WAL 'AJZI WAL KASALI WAL BUKHLI WAL JUBNI WA DLALA'ID DAINI WA GHALABATIRRIJAL (Ya Allah, aku berlindung kepada-Mu dari kepikunan, kesedihan, kelemahan, kemalasan, kikir, sifat pengecut, himpitan hutang dan penindasan penguasa).\""},"5144":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ يَحْيَى عَنْ عَمْرَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَسْتَعِيذُ بِاللَّهِ مِنْ عَذَابِ الْقَبْرِ وَمِنْ فِتْنَةِ الدَّجَّالِ قَالَ وَقَالَ إِنَّكُمْ تُفْتَنُونَ فِي قُبُورِكُمْ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Sufyan] dari [Yahya] dari [Amrah] dari ['Aisyah] ia berkata; \"Nabi shallallahu 'alaihi wasallam biasa berlindung kepada Allah dari siksa kubur dan fitnah Dajjal.\" perawai berkata; \"Beliau bersabda: \"Sungguh, kalian akan menghadapi fitnah dalam kubur.\""},"5145":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَفْصِ بْنِ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي إِبْرَاهِيمُ عَنْ مُوسَى بْنِ عُقْبَةَ أَخْبَرَنِي أَبُو الزِّنَادِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ هُرْمُزَ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعُوذُ بِاللَّهِ مِنْ عَذَابِ جَهَنَّمَ وَأَعُوذُ بِاللَّهِ مِنْ عَذَابِ الْقَبْرِ وَأَعُوذُ بِاللَّهِ مِنْ شَرِّ الْمَسِيحِ الدَّجَّالِ وَأَعُوذُ بِاللَّهِ مِنْ شَرِّ فِتْنَةِ الْمَحْيَا وَالْمَمَاتِ","id":"Telah mengabarkan kepada kami [Ahmad bin Hafsh bin Abdullah] ia berkata; telah menceritakan kepadaku [Ayahku] ia berkata; telah menceritakan kepadaku [Ibrahim] dari [Musa bin 'Uqbah] ia berkata; telah mengabarkan kepadaku [Abu Az Zinad] dari [Abdurrahman bin Hurmuz Al A'raj] dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku berlindung kepada Allah dari siksa jahannam, dari siksa kubur, dan dari keburukan Al Masih Dajjal. Dan aku juga berlindung kepada Allah dari fitnah kehidupan dan kematian.\""},"5146":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ دُرُسْتَ قَالَ حَدَّثَنَا أَبُو إِسْمَعِيلَ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ أَنَّ أَبَا سَلَمَةَ حَدَّثَهُ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ عَذَابِ الْقَبْرِ وَأَعُوذُ بِكَ مِنْ عَذَابِ النَّارِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْمَحْيَا وَالْمَمَاتِ وَأَعُوذُ بِكَ مِنْ شَرِّ الْمَسِيحِ الدَّجَّالِ","id":"Telah mengabarkan kepada kami [Yahya bin Durusta] ia berkata; telah menceritakan kepada kami [Abu Isma'il] ia berkata; telah menceritakan kepada kami [Yahya bin Abu Katsir] bahwa [Abu Salamah] menceritakan kepadanya dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau mengucapkan: \"ALLAHUMMA INNI A'UUDZU BIKA MIN ADZAABIL QABRI WA A'UUDZU BIKA MIN ADZAABIN NAARI WA A'UUDZU BIKA MIN FITNATIL MAHYAA WAL MAMAATI WA A'UUDZU BIKA MIN SYARRIL MASIIHID DAJJAL (Ya Allah, aku berlindung kepada-Mu dari siksa kubur, aku berlindung kepada-Mu dari siksa neraka, aku berlindung kepada-Mu dari fitnah kehidupan dan kematian, dan aku berlindung kepada-Mu dari keburukkan Al Masih Dajjal).\""},"5147":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ عَنْ أَبِي عُمَرَ عَنْ عُبَيْدِ بْنِ خَشْخَاشٍ عَنْ أَبِي ذَرٍّ قَالَدَخَلْتُ الْمَسْجِدَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهِ فَجِئْتُ فَجَلَسْتُ إِلَيْهِ فَقَالَ يَا أَبَا ذَرٍّ تَعَوَّذْ بِاللَّهِ مِنْ شَرِّ شَيَاطِينِ الْجِنِّ وَالْإِنْسِ قُلْتُ أَوَ لِلْإِنْسِ شَيَاطِينُ قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] ia berkata; telah menceritakan kepada kami [Ja'far bin 'Aun] ia berkata; telah menceritakan kepada kami [Abdurrahman bin Abdullah] dari [Abu Umar] dari ['Ubaid bin Khasykhasy] dari [Abu Dzar] ia berkata; \"Aku masuk ke dalam masjid sementara Rasulullah shallallahu 'alaihi wasallam sudah berada di dalam. Aku duduk di sisinya, beliau lalu bersabda: \"Wahai Abu Dzar, berlindunglah kepada Allah dari keburukkan setan dari jin dan manusia.\" Aku bertanya; \"Apakah pada jenis manusia juga ada setan?\" beliau menjawab: \"Ya.\""},"5148":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ وَمَالِكٌ قَالَا حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عُوذُوا بِاللَّهِ مِنْ عَذَابِ الْقَبْرِ عُوذُوا بِاللَّهِ مِنْ فِتْنَةِ الْمَحْيَا وَالْمَمَاتِ عُوذُوا بِاللَّهِ مِنْ فِتْنَةِ الْمَسِيحِ الدَّجَّالِ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Sufyan] dan [Malik] keduanya berkata; telah menceritakan kepada kami [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Berlindunglah kepada Allah dari siksa kubur, berlindunglah kepada Allah dari fitnah kehidupan dan kematian. Dan berlindunglah kepada Allah dari fitnah Al Masih Dajjal.\""},"5149":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي يَعْلَى بْنُ عَطَاءٍ قَالَ سَمِعْتُ أَبَا عَلْقَمَةَ يُحَدِّثُ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَعَوَّذُ مِنْ خَمْسٍ يَقُولُ عُوذُوا بِاللَّهِ مِنْ عَذَابِ الْقَبْرِ وَمِنْ عَذَابِ جَهَنَّمَ وَمِنْ فِتْنَةِ الْمَحْيَا وَالْمَمَاتِ وَمِنْ شَرِّ الْمَسِيحِ الدَّجَّالِ","id":"Telah mengabarkan kepada kami [Abdurrahman bin Muhammad] ia berkata; telah menceritakan kepada kami [Abu Dawud] ia berkata; telah menceritakan kepada kami [Syu'bah] ia berkata; telah mengabarkan kepadaku [Ya'la bin 'Atha] ia berkata; Aku mendengar [Abu 'Alqamah] menceritakan dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam biasa berlindung dari lima hal, beliau mengucapkan: \"Berlindunglah kepada Allah dari siksa kubur, dari siksa jahannam, dari fitnah kehidupan dan kematian, serta dari keburukkan Al Masih Dajjal.\""},"5150":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ عَنْ مُحَمَّدٍ وَذَكَرَ كَلِمَةً مَعْنَاهَا حَدَّثَنَا شُعْبَةُ عَنْ يَعْلَى بْنِ عَطَاءٍ قَالَ سَمِعْتُ أَبَا عَلْقَمَةَ الْهَاشِمِيَّ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أَطَاعَنِي فَقَدْ أَطَاعَ اللَّهَ وَمَنْ عَصَانِي فَقَدْ عَصَى اللَّهَ وَكَانَ يَتَعَوَّذُ مِنْ عَذَابِ الْقَبْرِ وَعَذَابِ جَهَنَّمَ وَفِتْنَةِ الْأَحْيَاءِ وَالْأَمْوَاتِ وَفِتْنَةِ الْمَسِيحِ الدَّجَّالِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basyar] dan [Muhammad] -dan ia menyebutkan sebuah kata yang semakna dengannya- ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Ya'la bin 'Atha`] ia berkata; aku mendengar [Abu 'Alqamah Al Hasyimi] berkata; aku mendengar [Abu Hurairah] berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa taat kepadaku maka ia telah taat kepada Allah, barangsiapa bermaksiat kepadaku maka ia telah bermaksiat kepada Allah.\" Dan beliau biasa berlindung dari siksa kubur, siksa jahannam, fitnah kehidupan dan kematian serta fitnah Al Masih Dajjal.\""},"5151":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا أَبُو الْوَلِيدِ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ أَبِيهِ عَنْ أَبِي عَلْقَمَةَ حَدَّثَنِي أَبُو هُرَيْرَةَ مِنْ فِيهِ إِلَى فِيَّ قَالَوَقَالَ يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَعِيذُوا بِاللَّهِ مِنْ خَمْسٍ مِنْ عَذَابِ جَهَنَّمَ وَعَذَابِ الْقَبْرِ وَفِتْنَةِ الْمَحْيَا وَالْمَمَاتِ وَفِتْنَةِ الْمَسِيحِ الدَّجَّالِ","id":"Telah mengabarkan kepada kami [Abu Dawud] ia berkata; telah menceritakan kepada kami [Abu Al Walid] ia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Ya'la bin 'Atha`] dari [Ayahnya] dari [Abu 'Alqamah] ia berkata; telah menceritakan kepadaku [Abu Hurairah] -dari mulutnya ke mulutku- ia berkata; \"Nabi shallallahu 'alaihi wasallam bersabda: \"Mintalah perlindungan kepada Allah dari lima hal; dari siksa jahannam, dari siksa kubur, dari fitnah kehidupan dan kematian dan dari fitnah Al Masih Dajjal.\""},"5152":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ أَبِي الزُّبَيْرِ عَنْ طَاوُسٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُعَلِّمُهُمْ هَذَا الدُّعَاءَ كَمَا يُعَلِّمُ السُّورَةَ مِنْ الْقُرْآنِ قُولُوا اللَّهُمَّ إِنَّا نَعُوذُ بِكَ مِنْ عَذَابِ جَهَنَّمَ وَأَعُوذُ بِكَ مِنْ عَذَابِ الْقَبْرِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْمَسِيحِ الدَّجَّالِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْمَحْيَا وَالْمَمَاتِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Abu Az Zubair] dari [Thawus] dari [Abdullah bin Abbas] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam mengajarkan doa ini kepada mereka sebagaimana beliau mengajarkan surat Al-Qur'an. Beliau mengatakan: \"Ucapkanlah: sesungguhnya kami berlindung kepada-Mu dari siksa jahannam, dan aku berlindung kepada-Mu dari siksa kubur, dan aku berlindung kepada-Mu dari fitnah Al Masih Dajjal, dan aku berlindung kepada-Mu dari fitnah kehidupan dan kematian.\""},"5153":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَيْمُونٍ عَنْ سُفْيَانَ عَنْ عَمْرٍو عَنْ طَاوُسَ عَنْ أَبِي هُرَيْرَةَ وَأَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَ��َعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عُوذُوا بِاللَّهِ عَزَّ وَجَلَّ مِنْ عَذَابِ اللَّهِ عُوذُوا بِاللَّهِ مِنْ فِتْنَةِ الْمَحْيَا وَالْمَمَاتِ وَمِنْ عَذَابِ الْقَبْرِ وَمِنْ فِتْنَةِ الْمَسِيحِ الدَّجَّالِ","id":"Telah mengabarkan kepada kami [Muhammad bin Maimun] dari [Sufyan] dari [Amru] dari [Thawus] dari [Abu Hurairah]. Dan [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Berlindunglah kepada Allah 'azza wajalla dari siksa Allah, berlindunglah kepada Allah dari fitnah kehidupan dan kematian, dari siksa kubur dan dari fitnah Al Masih Dajjal.\""},"5154":{"ar":"قَالَ الْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْعُو يَقُولُ فِي دُعَائِهِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ عَذَابِ جَهَنَّمَ وَأَعُوذُ بِكَ مِنْ عَذَابِ الْقَبْرِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْمَسِيحِ الدَّجَّالِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْمَحْيَا وَالْمَمَاتِ","id":"[Al Harits bin Miskin] berkata dengan membacakannya kepada dia, sementara aku mendengarnya, dari [Ibnu Al Qasim] dari [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam biasa mengucapkan dalam doanya: \"ALLAHUMMA INNI A'UUDZU BIKA MIN ADZAABI JAHANNAMA WA A'UUDZU BIKA MIN ADZAABIL QABRI WA A'UUDZU BIKA MIN FITNATIL MASIIHID DAJJAL WA A'UUDZU BIKA MIN FITNATIL MAHYAA WAL MAMAATI (Ya Allah, aku berlindung kepada-Mu dari siksa jahannam, aku berlindung kepada-Mu dari siksa kubur, aku berlindung kepada-Mu dari fitnah Al Masih Dajjal dan aku berlindung kepada-Mu dari fitnah kehidupan dan kematian.\""},"5155":{"ar":"أَخْبَرَنَا أَبُو عَاصِمٍ قَالَ حَدَّثَنَا الْقَاسِمُ بْنُ كَثِيرٍ الْمُقْرِيُّ عَنْ اللَّيْثِ بْنِ سَعْدٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي دُعَائِهِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ فِتْنَةِ الْقَبْرِ وَفِتْنَةِ الدَّجَّالِ وَفِتْنَةِ الْمَحْيَا وَالْمَمَاتِقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا خَطَأٌ وَالصَّوَابُ سُلَيْمَانُ بْنُ سِنَانٍ","id":"Telah mengabarkan kepada kami [Abu Ashim] ia berkata; telah menceritakan kepada kami [Al Qasim bin Katsir Al Muqri] dari [Al Laits bin Sa'id] dari [Yazid bin Abu Habib] dari [Sulaiman bin Yasar] Bahwasanya ia mendengar [Abu Hurairah] berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam berkata dalam doanya: \"ALLAHUMMA INNI A'UUDZU BIKA MIN FITNATIL QABRI WA FITNATILD DAJJAL WA FITNATIL MAHYAA WAL MAMAATI (Ya Allah, aku berlindung kepada-Mu dari fitnah kubur, fitnah Dajjal, serta dari fitnah kehidupan dan kematian).\" Perawi berkata; \"Abu Abdurrahman ini salah, yang benar adalah Sulaiman bin Sinan."},"5156":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عُوذُوا بِاللَّهِ مِنْ عَذَابِ اللَّهِ عُوذُوا بِاللَّهِ مِنْ عَذَابِ الْقَبْرِ عُوذُوا بِاللَّهِ مِنْ فِتْنَةِ الْمَحْيَا وَالْمَمَاتِ عُوذُوا بِاللَّهِ مِنْ فِتْنَةِ الْمَسِيحِ الدَّجَّالِ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] ia berkata; telah menceritakan kepada kami [Sufyan] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Berlindunglah kepada Allah dari siksa Allah, berlindunglah kepada Allah dari siksa kubur, berlindunglah kepada Allah dari fitnah kehidupan dan kematian. Serta berlindunglah kepada Allah dari fitnah Al Masih Dajjal.\""},"5157":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا أَبُو عَامِرٍ الْعَقَدِيُّ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ بُدَيْلِ بْنِ مَيْسَرَةَ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَعَوَّذُ مِنْ عَذَابِ جَهَنَّمَ وَعَذَابِ الْقَبْرِ وَالْمَسِيحِ الدَّجَّالِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Abu Amir Al 'Aqadi] ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Budail bin Maisarah] dari [Abdullah bin Syaqiq] dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam selalu berlindung dari siksa jahannam, siksa kubur dan dari Al Masih Dajjal.\""},"5158":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا الْوَلِيدُ قَالَ حَدَّثَنَا أَبُو عَمْرٍو عَنْ يَحْيَى أَنَّهُ حَدَّثَهُ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ قَالَ حَدَّثَنِي أَبُو هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعَوَّذُوا بِاللَّهِ مِنْ عَذَابِ النَّارِ وَعَذَابِ الْقَبْرِ وَمِنْ فِتْنَةِ الْمَحْيَا وَالْمَمَاتِ وَمِنْ شَرِّ الْمَسِيحِ الدَّجَّالِ","id":"Telah mengabarkan kepada kami [Mahmud bin Khalid] ia berkata; telah menceritakan kepada kami [Al Walid] ia berkata; telah menceritakan kepada kami [Abu 'Amru] dari [Yahya] bahwa dia menceritakan kepadanya, ia berkata; telah mengabarkan kepadaku [Abu Salamah] ia berkata; telah menceritakan kepadaku [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berlindunglah kepada Allah dari siksa neraka, siksa kubur, fitnah kehidupan dan kematian serta dari keburukkan Al Masih Dajjal.\""},"5159":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَفْصٍ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي إِبْرَاهِيمُ عَنْ سُفْيَانَ بْنِ سَعِيدٍ عَنْ أَبِي حَسَّانَ عَنْ جَسْرَةَ عَنْ عَائِشَةَ أَنَّهَا قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ رَبَّ جِبْرَائِيلَ وَمِيكَائِيلَ وَرَبَّ إِسْرَافِيلَ أَعُوذُ بِكَ مِنْ حَرِّ النَّارِ وَمِنْ عَذَابِ الْقَبْرِ","id":"Telah mengabarkan kepada kami [Ahmad bin Hafsh] ia berkata; telah menceritakan kepadaku [Ayahku] ia berkata; telah menceritakan kepadaku [Ibrahim] dari [Sufyan bin Sa'id] dari [Abu Hassan] dari [Jasrah] dari ['Aisyah] bahwa ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"ALLAHUMMA RABBA JIBRA'IL WA MIKAA'IIL WA RABBA ISRAAFIIL A'UUDZU BIKA MIN HARRIN NAARI WA MIN ADZAABIL QABRI (Ya Allah, Rabb Jibril dan Mika'il, Rabb Israfil, aku berlindung kepada-Mu dari panasnya api neraka dan siksa kubur).\""},"5160":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ سَوَّادٍ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ حَدَّثَنَا عَمْرُو بْنُ الْحَارِثِ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ سُلَيْمَانَ بْنِ سِنَانٍ الْمُزَنِيِّ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُسَمِعْتُ أَبَا الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي صَلَاتِهِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ فِتْنَةِ الْقَبْرِ وَمِنْ فِتْنَةِ الدَّجَّالِ وَمِنْ فِتْنَةِ الْمَحْيَا وَالْمَمَاتِ وَمِنْ حَرِّ جَهَنَّمَقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا الصَّوَابُ","id":"Telah mengabarkan kepada kami [Amru bin Sawwad] ia berkata; telah menceritakan kepada kami [Ibnu Wahb] ia berkata; telah menceritakan kepada kami ['Amru Ibnul Harits] dari [Yazid bin Abu Habib] dari [Sulaiman bin Sinan Al Muzanni] bahwa ia mendengar [Abu Hurairah] berkata; \"Aku mendengar Al Qasim shallallahu 'alaihi wasallam mengucapkan dalam shalatnya: \"ALLAHUMMA INNI A'UUDZU BIKA MIN FITNATIL QABRI WA MIN FITNATID DAJJAL WA MIN FITNATIL MAHYAA WAL MAMAATI WA MIN HARRI JAHANNAMA (Ya Allah, aku berlindung kepada-Mu dari fitnah kubur, fitnah Dajjal, fitnah kehidupan dan kematian, dan dari panasnya api jahannam).\""},"5161":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ بُرَيْدِ بْنِ أَبِي مَرْيَمَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سَأَلَ اللَّهَ الْجَنَّةَ ثَلَاثَ مَرَّاتٍ قَالَتْ الْجَنَّةُ اللَّهُمَّ أَدْخِلْهُ الْجَنَّةَ وَمَنْ اسْتَجَارَ مِنْ النَّارِ ثَلَاثَ مَرَّاتٍ قَالَتْ النَّارُ اللَّهُمَّ أَجِرْهُ مِنْ النَّارِ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Abu Al Ahwash] dari [Abu Ishaq] dari [Buraid bin Abu Maryam] dari [Anas bin Malik] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa minta surga kepada Allah sebanyak tiga kali, maka surga akan berkata; 'Ya Allah, masukkanlah ia ke dalam surga'. Dan barangsiapa minta agar dijauhkan dari neraka sebanyak tiga kali, maka neraka akan berkata; 'Ya Allah, jauhkanlah ia dari neraka'.\""},"5162":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَزِيدُ وَهُوَ ابْنُ زُرَيْعٍ قَالَ حَدَّثَنَا حُسَيْنٌ الْمُعَلِّمُ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ بُشَيْرِ بْنِ كَعْبٍ عَنْ شَدَّادِ بْنِ أَوْسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ سَيِّدَ الِاسْتِغْفَارِ أَنْ يَقُولَ الْعَبْدُ اللَّهُمَّ أَنْتَ رَبِّي لَا إِلَهَ إِلَّا أَنْتَ خَلَقْتَنِي وَأَنَا عَبْدُكَ وَأَنَا عَلَى عَهْدِكَ وَوَعْدِكَ مَا اسْتَطَعْتُ أَعُوذُ بِكَ مِنْ شَرِّ مَا صَنَعْتُ أَبُوءُ لَكَ بِذَنْبِي وَأَبُوءُ لَكَ بِنِعْمَتِكَ عَلَيَّ فَاغْفِرْ لِي فَإِنَّهُ لَا يَغْفِرُ الذُّنُوبَ إِلَّا أَنْتَ فَإِنْ قَالَهَا حِينَ يُصْبِحُ مُوقِنًا بِهَا فَمَاتَ دَخَلَ الْجَنَّةَ وَإِنْ قَالَهَا حِينَ يُمْسِي مُوقِنًا بِهَا دَخَلَ الْجَنَّةَخَالَفَهُ الْوَلِيدُ بْنُ ثَعْلَبَةَ","id":"Telah mengabarkan kepada kami [Amru bin Ali] ia berkata; telah menceritakan kepada kami [Yazid] -yaitu Ibnu Zurai'- ia berkata; telah menceritakan kepada kami [Husain Al Mu'allim] dari [Abdullah bin Buraidah] dari [Busyair bin Ka'b] dari [Syaddad bin Aus] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya istighfar yang paling baik adalah; jika seorang hamba mengucapkan: \"ALLAHUMMA ANTA RABBI LAA ILAAHA ILLA ANTA KHALAQTANI WA ANA 'ABDUKA WA ANA 'ALA 'AHDIKA WA WA'DIKA MASTATHA'TU A'UUDZU BIKA MIN SYARRI MAA SHANA'TU ABUU`U LAKA BIDZANBI WA ABUU`U LAKA BINI'MATIKA 'ALAYYA FAGHFIRLI FA INNAHU LAA YAGHFIRU ADZ DZUNUUBA ILLA ANTA (Ya Allah, Engkau adalah Tuhanku, tidak ada Tuhan yang berhak diibadahi selain Engkau. Engkau telah menciptakanku dan aku adalah hamba-Mu. Aku menetapi perjanjian-Mu dan janji-Mu sesuai dengan kemampuanku. Aku berlindung kepada-Mu dari keburukan perbuatanku, aku mengakui dosaku kepada-Mu dan aku akui nikmat-Mu kepadaku, maka ampunilah aku. Sebab tidak ada yang dapat mengampuni dosa selain-Mu) '. Jika ia mengucapkan di waktu subuh dengan penuh keyakinan lalu meninggal, maka ia akan masuk surga. Dan jika ia membacanya di waktu sore dengan penuh keyakinan lalu meninggal, maka ia akan masuk surga.\" Namun Al Walid bin Tsa'labah menyelisihi riwayat hadits ini."},"5163":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى عَنْ ابْنِ وَهْبٍ قَالَ أَخْبَرَنِي مُوسَى بْنُ شَيْبَةَ عَنْ الْأَوْزَاعِيِّ عَنْ عَبْدَةَ بْنِ أَبِي لُبَابَةَ أَنَّ ابْنَ يَسَافٍ حَدَّثَهُ أَنَّهُ سَأَلَ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَمَا كَانَ أَكْثَرُ مَا يَدْعُو بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْلَ مَوْتِهِ قَالَتْ كَانَ أَكْثَرُ مَا كَانَ يَدْعُو بِهِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ شَرِّ مَا عَمِلْتُ وَمِنْ شَرِّ مَا لَمْ أَعْمَلْ","id":"Telah mengabarkan kepada kami [Yunus bin Abdul A'la] dari [Ibnu Wahb] ia berkata; telah mengabarkan kepadaku [Musa bin Syaibah] dari [Al Auza'i] dari [Abdah bin Abu Lubabah] bahwa [Ibnu Yasaf] menceritakan kepadanya, bahwasanya ia pernah bertanya kepada ['Aisyah] isteri Nabi shallallahu 'alaihi wasallam; 'Apa yang paling sering dibaca oleh Rasulullah shallallahu 'alaihi wasallam dalam doa sebelum beliau wafat? ' 'Aisyah berkata; \"Yang paling sering beliau baca adalah: 'ALLAHUMMA INNI A'UUDZU BIKA MIN SYARRI MAA 'AMILTU WA MIN SYARRI MAA LAM A'MAL (Ya Allah, aku berlindung kepada-Mu dari keburukkan sesuatu yang telah aku lakukan, dan dari keburukkan sesuatu yang belum aku lakukan).\""},"5164":{"ar":"أَخْبَرَنِي عِمْرَانُ بْنُ بَكَّارٍ قَالَ حَدَّثَنَا أَبُو الْمُغِيرَةِ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي عَبْدَةُ قَالَ حَدَّثَنِي ابْنُ يَسَافٍ قَالَ سُئِلَتْ عَائِشَةُمَا كَانَ أَكْثَرُ مَا كَانَ يَدْعُو بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ كَانَ أَكْثَرُ دُعَائِهِ أَنْ يَقُولَ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ شَرِّ مَا عَمِلْتُ وَمِنْ شَرِّ مَا لَمْ أَعْمَلْ بَعْدُ","id":"Telah mengabarkan kepadaku [Imran bin Bakkar] ia berkata; telah menceritakan kepada kami [Abu Al Mughirah] ia berkata; telah menceritakan kepada kami [Al Auza'i] ia berkata; telah menceritakan kepadaku [Abdah] ia berkata; telah menceritakan kepadaku [Ibnu Yasaf] ia berkata; ['Aisyah] pernah ditanya; 'Apa yang paling sering dibaca oleh Nabi shallallahu 'alaihi wasallam? ' 'Aisyah menjawab; \"Doa yang paling sering dibaca oleh beliau adalah; 'ALLAHUMMA INNI A'UUDZU BIKA MIN SYARRI MAA 'AMILTU WA MIN SYARRI MAA LAM A'MAL BA'DU (Ya Allah, aku berlindung kepada-Mu dari keburukkan sesuatu yang telah aku lakukan, dan dari keburukkan sesuatu yang belum aku lakukan).\""},"5165":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ قُدَامَةَ عَنْ جَرِيرٍ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ فَرْوَةَ بْنِ نَوْفَلٍ قَالَ سَأَلْتُ أُمَّ الْمُؤْمِنِينَ عَائِشَةَعَمَّا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْعُو قَالَتْ كَانَ يَقُولُ أَعُوذُ بِكَ مِنْ شَرِّ مَا عَمِلْتُ وَمِنْ شَرِّ مَا لَمْ أَعْمَلْ","id":"Telah mengabarkan kepadaku [Muhammad bin Qudamah] dari [Jarir] dari [Manshur] dari [Hilal] dari [Farwah bin Naufal] ia berkata; \"Aku pernah bertanya Ummul Mukminin ['Aisyah], tentang doa yang biasa dibaca oleh Rasulullah shallallahu 'alaihi wasallam untuk berdoa? ' ia menjawab; \"Beliau membaca 'ALLAHUMMA INNI A'UUDZU BIKA MIN SYARRI MAA 'AMILTU WA MIN SYARRI MAA LAM A'MAL (Ya Allah, aku berlindung kepada-Mu dari keburukkan sesuatu yang telah aku lakukan, dan dari keburukkan sesuatu yang belum aku lakukan).\""},"5166":{"ar":"أَخْبَرَنَا هَنَّادٌ عَنْ أَبِي الْأَحْوَصِ عَنْ حُصَيْنٍ عَنْ هِلَالٍ عَنْ فَرْوَةَ بْنِ نَوْفَلٍ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ شَرِّ مَا عَمِلْتُ وَمِنْ شَرِّ مَا لَمْ أَعْمَلْ","id":"Telah mengabarkan kepada kami [Hannad] dari [Abu Al Ahwash] dari [Hushain] dari [Hilal] dari [Farwah bin Naufal] dari ['Aisyah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"ALLAHUMMA INNI A'UUDZU BIKA MIN SYARRI MAA 'AMILTU WA MIN SYARRI MAA LAM A'MAL (Ya Allah, aku berlindung kepada-Mu dari keburukkan sesuatu yang telah aku lakukan, dan dari keburukkan sesuatu yang belum aku lakukan).\""},"5167":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا الْمُعْتَمِرُ عَنْ أَبِيهِ عَنْ حُصَيْنٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ فَرْوَةَ بْنِ نَوْفَلٍ قَالَ سَأَلْتُ عَائِشَةَ فَقُلْتُحَدِّثِينِي بِشَيْءٍ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْعُو بِهِ قَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ شَرِّ مَا عَمِلْتُ وَمِنْ شَرِّ مَا لَمْ أَعْمَلْ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] ia berkata; telah menceritakan kepada kami [Al Mu'tamir] dari [Ayahnya] dari [Hushain] dari [Hilal bin Yasaf] dari [Farwah bin Naufal] ia berkata; \"Aku bertanya ['Aisyah], \"Aku katakan, 'Ceritakanlah kepadaku sesuatu yang Rasulullah shallallahu 'alaihi wasallam biasa gunakan untuk berdoa?! Ia berkata; \"Rasulullah shallallahu 'alaihi wasallam mengucapkan: \"ALLAHUMMA INNI A'UUDZU BIKA MIN SYARRI MAA 'AMILTU WA MIN SYARRI MAA LAM A'MAL (Ya Allah, aku berlindung kepada-Mu dari keburukkan sesuatu yang telah aku lakukan, dan dari keburukkan sesuatu yang belum aku lakukan).\""},"5168":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ حُصَيْنٍ سَمِعْتُ هِلَالَ بْنَ يَسَافٍ عَنْ فَرْوَةَ بْنِ نَوْفَلٍ قَالَ قُلْتُ لِعَائِشَةَأَخْبِرِينِي بِدُعَاءٍ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْعُو بِهِ قَالَتْ كَانَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ شَرِّ مَا عَمِلْتُ وَمِنْ شَرِّ مَا لَمْ أَعْمَلْ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] ia berkata; telah menceritakan kepada kami [Abu Dawud] ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Hushain] ia berkata; aku mendengar [Hilal bin Yasaf] dari [Farwah bin Naufal] ia berkata; aku berkata kepada ['Aisyah]; \"Kabarkanlah kepadaku doa apa yang biasa dibaca oleh Rasulullah shallallahu 'alaihi wasallam?\" 'Aisyah berkata; \"Beliau membaca: ALLAHUMMA INNI A'UUDZU BIKA MIN SYARRI MAA 'AMILTU WA MIN SYARRI MAA LAM A'MAL (Ya Allah, aku berlindung kepada-Mu dari keburukan sesuatu yang telah aku lakukan, dan dari keburukan sesuatu yang belum aku lakukan).\""},"5169":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا الْفَضْلُ بْنُ دُكَيْنٍ عَنْ عُبَادَةَ بْنِ مُسْلِمٍ قَالَ حَدَّثَنِي جُبَيْرُ بْنُ أَبِي سُلَيْمَانَ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ أَنَّ ابْنَ عُمَرَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِعَظَمَتِكَ أَنْ أُغْتَالَ مِنْ تَحْتِيقَالَ جُبَيْرٌ وَهُوَ الْخَسْفُ قَالَ عُبَادَةُ فَلَا أَدْرِي قَوْلُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ قَوْلُ جُبَيْرٍ","id":"Telah mengabarkan kepada kami ['Amru bin Manshur] ia berkata; telah menceritakan kepada kami [Al Fadll bin Dukain] dari ['Ubadah bin Muslim] ia berkata; telah menceritakan kepadaku [Jubair bin Muth'im] bahwa [Ibnu Umar] berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam membaca: ALLAHUMMA INNI A'UUDZU BIKA BI AZHAMATIKA AN UGHTAALA MIN TAHTII (Ya Allah, aku berlindung dengan keagungan-Mu dari pembunuhan yang dilakukan dengan cara yang tidak diketahui).\" Jubair berkata; \"Yaitu penenggelaman ke dalam dasar bumi.\" 'Ubadah berkata; \"Aku tidak mengetahui, apakah itu sabda Nabi shallallahu 'alaihi wasallam atau ucapan Jubair.\""},"5170":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْخَلِيلِ قَالَ حَدَّثَنَا مَرْوَانُ هُوَ ابْنُ مُعَاوِيَةَ عَنْ عَلِيِّ بْنِ عَبْدِ الْعَزِيزِ عَنْ عُبَادَةَ بْنِ مُسْلِمٍ الْفَزَارِيِّ عَنْ جُبَيْرِ بْنِ أَبِي سُلَيْمَانَ عَنْ ابْنِ عُمَرَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ فَذَكَرَ الدُّعَاءَ وَقَالَ فِي آخِرِهِ أَعُوذُ بِكَ أَنْ أُغْتَالَ مِنْ تَحْتِي يَعْنِي بِذَلِكَ الْخَسْفَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Khalil] ia berkata; telah menceritakan kepada kami [Marwan yaitu Ibnu Mu'awiyah] dari [Ali bin Abdul Aziz] dari ['Ubadah bin Muslim Al Fazari] dari [Jubair bin Abu Sulaiman] dari [Ibnu Umar] ia berkata; \"Nabi shallallahu 'alaihi wasallam berdoa: \"ALLAHUMMA (Ya Allah..), lalu beliau menyebutkan doa tersebut, dan mengucapkan pada akhir doanya: \"A'UUDZU BIKA AN UGHTAALA MIN TAHTII (aku berlindung kepada-Mu dari pembunuhan dengan cara yang tidak diketahui), yaitu penenggelaman ke dalam perut bumi.\""},"5171":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى عَنْ عَبْدِ اللَّهِ بْنِ سَعِيدٍ عَنْ صَيْفِيٍّ مَوْلَى أَبِي أَيُّوبَ عَنْ أَبِي الْيَسَرِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ التَّرَدِّي وَالْهَدْمِ وَالْغَرَقِ وَالْحَرِيقِ وَأَعُوذُ بِكَ أَنْ يَتَخَبَّطَنِي الشَّيْطَانُ عِنْدَ الْمَوْتِ وَأَعُوذُ بِكَ أَنْ أَمُوتَ فِي سَبِيلِكَ مُدْبِرًا وَأَعُوذُ بِكَ أَنْ أَمُوتَ لَدِيغًا","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] ia berkata; telah menceritakan kepada kami [Al fadll bin Musa] dari [Abdullah bin Sa'id] dari [Shaifi] -mantan budak Abu Ayyub- dari [Abu Al Yasaar] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam membaca doa: \"Ya Allah, aku berlindung kepada-Mu dari kematian karena jatuh dari tempat yang tinggi, tertimpa reruntuhan, tenggelam, dan terbakar. Dan aku berlindung kepada-Mu dari bujukan setan saat sakaratul maut, kematian saat lari dari perang di jalan-Mu, serta mati karena sengatan binatang melata.\""},"5172":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ أَخْبَرَنِي أَنَسُ بْنُ عِيَاضٍ عَنْ عَبْدِ اللَّهِ بْنِ سَعِيدٍ عَنْ صَيْفِيٍّ عَنْ أَبِي الْيَسَرِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْعُو فَيَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْهَرَمِ وَالتَّرَدِّي وَالْهَدْمِ وَالْغَمِّ وَالْحَرِيقِ وَالْغَرَقِ وَأَعُوذُ بِكَ أَنْ يَتَخَبَّطَنِي الشَّيْطَانُ عِنْدَ الْمَوْتِ وَأَنْ أُقْتَلَ فِي سَبِيلِكَ مُدْبِرًا وَأَعُوذُ بِكَ أَنْ أَمُوتَ لَدِيغًا","id":"Telah mengabarkan kepada kami [Yunus bin Abdul A'la] ia berkata; telah mengabarkan kepadaku [Anas bin Iyadl] dari [Abdullah bin Sa'id] dari [Shaifi] dari [Abu Al Yasar] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam membaca doa: \"Ya Allah, aku berlindung kepada-Mu dari kematian karena pikun, jatuh dari tempat yang tinggi, tertimpa reruntuhan, kesedihan, kebakaran, dan tenggelam. Dan aku berlindung kepada-Mu dari bujukan setan saat sakaratul maut, kematian saat lari dari perang di jalan-Mu, serta mati karena sengatan binatang melata.\""},"5173":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنِي صَيْفِيٌّ مَوْلَى أَبِي أَيُّوبَ الْأَنْصَارِيُّ عَنْ أَبِي الْأَسْوَدِ السُّلَمِيِّهَكَذَا قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْهَدْمِ وَأَعُوذُ بِكَ مِنْ التَّرَدِّي وَأَعُوذُ بِكَ مِنْ الْغَرَقِ وَالْحَرِيقِ وَأَعُوذُ بِكَ أَنْ يَتَخَبَّطَنِي الشَّيْطَانُ عِنْدَ الْمَوْتِ وَأَعُوذُ بِكَ أَنْ أَمُوتَ فِي سَبِيلِكَ مُدْبِرًا وَأَعُوذُ بِكَ أَنْ أَمُوتَ لَدِيغًا","id":"Telah mengabarkan kepada kami [Muhammad Ibnul Mutsanna] ia berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] ia berkata; telah menceritakan kepada kami [Abdullah bin Sa'id] ia berkata; telah menceritakan kepadaku [Shaifi] -mantan budak Abu Ayyub Al Anshari- dari [Abu Al Aswad As Sulami] berkata; \"Rasulullah shallallahu 'alaihi wasallam membaca doa: \"Ya Allah, aku berlindung kepada-Mu dari kematian karena tertimpa reruntuhan, mati karena jatuh dari ketinggian, mati karena tenggelam dan mati karena kebakaran. Dan aku berlindung kepada-Mu dari bujukan setan saat sakaratul maut kematian saat lari dari perang di jalan-Mu, serta mati karena sengatan binatang melata.\""},"5174":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنِي الْعَلَاءُ بْنُ هِلَالٍ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ زَيْدٍ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ الْقَاسِمِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ مَسْرُوقِ بْنِ الْأَجْدَعِ عَنْ عَائِشَةَ قَالَتْطَلَبْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ فِي فِرَاشِي فَلَمْ أُصِبْهُ فَضَرَبْتُ بِيَدِي عَلَى رَأْسِ الْفِرَاشِ فَوَقَعَتْ يَدِي عَلَى أَخْمَصِ قَدَمَيْهِ فَإِذَا هُوَ سَاجِدٌ يَقُولُ أَعُوذُ بِعَفْوِكَ مِنْ عِقَابِكَ وَأَعُوذُ بِرِضَاكَ مِنْ سَخَطِكَ وَأَعُوذُ بِكَ مِنْكَ","id":"Telah mengabarkan kepada kami [Ibrahim bin Ya'qub] ia berkata; telah menceritakan kepada kami [Al 'Ala bin Hilal] ia berkata; telah menceritakan kepada kami ['Ubaidullah] dari [Zaid] dari ['Amru bin Murrah] dari [Al Qasim bin Abdurrahman] dari [Masruq Al Ajda'] dari ['Aisyah] ia berkata; \"Suatu malam aku mencari-cari Rasulullah shallallahu 'alaihi wasallam dari kasurku namun aku tidak menemukannya. Aku lalu memukulkan tanganku ke pangkal kasur hingga tanganku mengenai telapak kaki beliau, ternyata beliau waktu itu sedang sujud. Beliau membaca: \"A'UUDZU BI 'AFWIKA MIN 'IQAABIKA WA A'UUDZU BI RIDLAAKA MIN SAKHATIKA WA A'UUDZU BIKA MINKA (Aku berlindung dengan ampunan-Mu dari siksa-Mu, dengan ridla-Mu dari murka-Mu dan dengan-Mu dari diri-Mu).\""},"5175":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ أَنَّ مُعَاوِيَةَ بْنَ صَالِحٍ حَدَّثَهُ وَحَدَّثَنِي أَزْهَرُ بْنُ سَعِيدٍ يُقَالُ لَهُ الْحَرَازِيُّ شَامِيٌّ عَزِيز الْحَدِيث عَنْ عَاصِمِ بْنِ حُمَيْدٍ قَالَسَأَلْتُ عَائِشَةَ بِمَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْتَتِحُ قِيَامَ اللَّيْلِ قَالَتْ سَأَلْتَنِي عَنْ شَيْءٍ مَا سَأَلَنِي عَنْهُ أَحَدٌ كَانَ يُكَبِّرُ عَشْرًا وَيُسَبِّحُ عَشْرًا وَيَسْتَغْفِرُ عَشْرًا وَيَقُولُ اللَّهُمَّ اغْفِرْ لِي وَاهْدِنِي وَارْزُقْنِي وَعَافِنِي وَيَتَعَوَّذُ مِنْ ضِيقِ الْمَقَامِ يَوْمَ الْقِيَامَةِ","id":"Telah mengabarkan kepadaku [Ibrahim bin Ya'qub] ia berkata; telah menceritakan kepada kami [Zaid Ibnul Hubab] bahwa [Mu'awiyah bin Shalih] menceritakan kepadanya; telah menceritakan kepadaku [Azhar bin Sa'id] disebut juga dengan Al Harazi, seorang dari wilayah Syam dan bagus dalam hal hadits, dari [Ashim bin Humaid] ia berkata; \"Aku pernah bertanya ['Aisyah] tentang sesuatu yang dilakukan oleh Rasulullah shallallahu 'alaihi wasallam sebelum memulai shalat malam. Maka ia menjawab, \"Engkau bertanya terhadap sesuatu yang pernah ditanyakan oleh seseorang kepadaku. Beliau bertakbir sepuluh kali, bertasbih sepuluh kali, dan beristighfar sepuluh kali. Kemudian beliau membaca: 'ALLAHUMMAGHFIRLI WAAHDINII WARZUQNII (Ya Allah, ampunilah aku, berikan aku petunjuk, karuniakan rizki dan kesehatan kepadaku) '. Dan beliau juga berlindung dari kesempitan pada hari kiamat.\""},"5176":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ آدَمَ عَنْ أَبِي خَالِدٍ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ عِلْمٍ لَا يَنْفَعُ وَمِنْ قَلْبٍ لَا يَخْشَعُ وَمِنْ نَفْسٍ لَا تَشْبَعُ وَمِنْ دُعَاءٍ لَا يُسْمَعُقَالَ أَبُو عَبْد الرَّحْمَنِ سَعِيدٌ لَمْ يَسْمَعْهُ مِنْ أَبِي هُرَيْرَةَ بَلْ سَمِعَهُ مِنْ أَخِيهِ عَنْ أَبِي هُرَيْرَةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Adam] dari [Abu Khalid] dari [Muhammad bin 'Ajlan] dari [Sa'id] dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam mengucapkan: \"ALLAHUMMA INNI A'UUDZU BIKA MIN 'ILMIN LAA YANFA' WA MIN QALBIN LAA YAKHSYA' WA MIN NAFSIN LAA TASYBA' WA MIN DU'AA IN LAA YUSMA' (Ya Allah, aku berlindung kepada-Mu dari ilmu yang tidak bermanfaat, hati yang tidak khusyu', jiwa yang tidak merasa puas dan doa yang tidak didengar).\" Abu Abdurrahman berkata; \"Sa'id belum pernah mendengarnya dari Abu Hurairah, tetapi ia mendengar dari saudaranya, dari Abu Hurairah.\""},"5177":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ فَضَالَةَ بْنِ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا يَحْيَى يَعْنِي ابْنَ يَحْيَى قَالَ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَخِيهِ عَبَّادِ بْنِ أَبِي سَعِيدٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ عِلْمٍ لَا يَنْفَعُ وَمِنْ قَلْبٍ لَا يَخْشَعُ وَمِنْ نَفْسٍ لَا تَشْبَعُ وَمِنْ دُعَاءٍ لَا يُسْمَعُ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Fadlalah bin Ibrahim] ia berkata; telah memberitakan kepada kami [Yahya yaitu Ibnu Yahya] ia berkata; telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Sa'id bin Abu Sa'id] dari saudaranya ['Abbad bin Abu Sa'id] bahwa ia mendengar [Abu Hurairah] berkata; \"Rasulullah shallallahu 'alaihi wasallam biasa mengucapkan: \"ALLAHUMMA INNI A'UUDZU BIKA MIN 'ILMIN LAA YANFA' WA MIN QALBIN LAA YAKHSYA' WA MIN NAFSIN LAA TASYBA' WA MIN DU'AA IN LAA YUSMA' (Ya Allah, aku berlindung kepada-Mu dari ilmu yang tidak bermanfaat, hati yang tidak khusyu', jiwa yang tidak merasa puas dan doa yang tidak didengar).\""},"5178":{"ar":"أَخْبَرَنَا وَاصِلُ بْنُ عَبْدِ الْأَعْلَى عَنْ ابْنِ فُضَيْلٍ عَنْ عَاصِمِ بْنِ سُلَيْمَانَ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ قَالَكَانَ إِذَا قِيلَ لِزَيْدِ بْنِ أَرْقَمَ حَدِّثْنَا مَا سَمِعْتَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا أُحَدِّثُكُمْ إِلَّا مَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنَا بِهِ وَيَأْمُرُنَا أَنْ نَقُولَ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْعَجْزِ وَالْكَسَلِ وَالْبُخْلِ وَالْجُبْنِ وَالْهَرَمِ وَعَذَابِ الْقَبْرِ اللَّهُمَّ آتِ نَفْسِي تَقْوَاهَا وَزَكِّهَا أَنْتَ خَيْرُ مَنْ زَكَّاهَا أَنْتَ وَلِيُّهَا وَمَوْلَاهَا اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ نَفْسٍ لَا تَشْبَعُ وَمِنْ قَلْبٍ لَا يَخْشَعُ وَمِنْ عِلْمٍ لَا يَنْفَعُ وَدَعْوَةٍ لَا تُسْتَجَابُ","id":"Telah mengabarkan kepada kami [Washil bin Abdul A'la] dari [Ibnu Fudlail] dari [Ashim bin Sulaiman] dari [Abdullah Ibnul Harits] ia berkata; Jika dikatakan kepada [Zaid bin Arqam]; \"Ceritakanlah kepada kami hadits yang engkau dengar dari Rasulullah shallallahu 'alaihi wasallam!.\" Maka ia berkata; \"Aku tidak akan menceritakan kepada kalian kecuali sesuatu yang Rasulullah shallallahu 'alaihi wasallam ceritakan dan beliau memerintahkan kepada kami (untuk mengucapkan): \"ALLAHUMMA INNI A'UUDZU BIKA MINAL 'AJZI WAL KASALI WAL BUKHLI WAL JUBNI WAL HARAMI WA 'ADZAABIL QABRI. ALLAHUMMA AATI NAFSII TAQWAAHAA WA ZAKKIHAA ANTA KHAIRU MAN ZAKKAHAA ANTA WALIYYUHAA WA MAULAAHAA. ALLAHUMMA INNI A'UUDZU BIKA MIN NAFSIN LAA TASYBA' WA MIN QALBIN LAA YAKHSYA' WA MIN 'ILMIN LAA YANFA' WA DA'WATIN LAA TUSTAJAABU (Ya Allah, aku berlindung kepada-Mu dari kelemahan, kemalasan, sifat kikir, pengecut, pikun dan siksa kubur. Ya Allah, berilah ketakwaan kepada jiwaku, bersihkanlah ia karena Engkau adalah sebaik-baik yang membersihkannya. Engkau Pengatur dan Pemiliknya. Ya Allah, aku berlindung kepada-Mu dari jiwa yang tidak pernah merasa puas, hati yang tidak khusyu', ilmu yang tidak bermanfaat dan doa yang tidak didengar).\""},"5179":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ الشَّعْبِيِّ عَنْ أُمِّ سَلَمَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا خَرَجَ مِنْ بَيْتِهِ قَالَ بِسْمِ اللَّهِ رَبِّ أَعُوذُ بِكَ مِنْ أَنْ أَزِلَّ أَوْ أَضِلَّ أَوْ أَظْلِمَ أَوْ أُظْلَمَ أَوْ أَجْهَلَ أَوْ يُجْهَلَ عَلَيَّ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] ia berkata; telah menceritakan kepada kami [Abdurrahman] ia berkata; telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Asy Sya'bi] dari [Ummu Salamah] ia berkata; \"Nabi shallallahu 'alaihi wasallam jika ingin keluar rumah membaca: \"BISMILLAHI RABBI A'UUDZU BIKA MIN AN AZILLA AU ADILLA AU AZHLIMA AU IZHLAMA AU AJHALA AU YUJHALA 'ALAYYA (Dengan menyebut nama Allah, ya Tuhanku! Aku berlindung kepada-Mu dari keterpelesetan, tersesat, berlaku zhalim atau terzhalimi, berlaku bodoh atau dibodohi).\""},"5180":{"ar":"أَخْبَرَنَا أَبُو بَكْرٍ أَحْمَدُ بْنُ مُحَمَّدِ بْنِ إِسْحَقَ السُّنِّيُّ قِرَاءَةً عَلَيْهِ فِي بَيْتِهِ قَالَ أَنْبَأَنَا الْإِمَامُ أَبُو عَبْدِ الرَّحْمَنِ أَحْمَدُ بْنُ شُعَيْبٍ النَّسَائِيُّ رَحِمَهُ اللَّهُ تَعَالَى قَالَ أَنْبَأَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى قَالَ أَنْبَأَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي مَيْسَرَةَ عَنْ عُمَرَ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا نَزَلَ تَحْرِيمُ الْخَمْرِ قَالَ عُمَرُ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانًا شَافِيًا فَنَزَلَتْ الْآيَةُ الَّتِي فِي الْبَقَرَةِ فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ عُمَرُ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانًا شَافِيًا فَنَزَلَتْ الْآيَةُ الَّتِي فِي النِّسَاءِ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى }فَكَانَ مُنَادِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَقَامَ الصَّلَاةَ نَادَى لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانًا شَافِيًا فَنَزَلَتْ الْآيَةُ الَّتِي فِي الْمَائِدَةِ فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَلَمَّا بَلَغَ فَهَلْ أَنْتُمْ مُنْتَهُونَ قَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ انْتَهَيْنَا انْتَهَيْنَا","id":"Telah mengabarkan kepada kami Abu Bakr Ahmad bin Muhammad bin Ishaq As Sunni -dengan membaca dihadapannya di rumah miliknya- ia berkata; telah memberitakan kepada kami Imam Abu Abdurrahman Ahmad bin Syu'aib An Nasa`i rahimahullahu Ta'ala, ia berkata; telah memberitakan kepada kami [Abu Dawud] ia berkata; telah menceritakan kepada kami [Ubaidullah bin Musa] ia berkata; telah memberitakan kepada kami [Isra'il] dari [Abu Ishaq] dari [Abu Maisarah] dari [Umar radliallahu 'anhu] ia berkata; \"Ketika turun ayat yang mengharamkan khamer, Umar berdoa; \"Ya Allah, berilah penjelasan kepada kami tentang khamer dengan penjelasan yang memadahi!\" Maka turunlah ayat yang terdapat dalam surat Al Baqarah. Lalu Umar dipanggil dan ayat tersebut dibacakan kepadanya. Umar lalu berdoa lagi; \"Ya Allah, berilah penjelasan kepada kami tentang khamer dengan penjelasan yang memadahi!\" Maka turunlah ayat yang terdapat dalam surat An Nisa`: 'Hai orang-orang yang beriman, janganlah kamu shalat sedang kamu dalam keadaan mabuk…'. Jika waktu shalat tiba, penyeru Rasulullah shallallahu 'alaihi wasallam biasa menyerukan 'Janganlah kamu shalat, sedangkan kami dalam keadaan mabuk'. Lalu Umar dipanggil dan ayat tersebut dibacakan kepadanya. Setelah itu Umar berdoa lagi; \"Ya Allah, berilah penjelasan kepada kami tentang khamer dengan penjelasan yang memadahi!\" Maka turunlah ayat yang terdapat dalam surat Al Maidah. Umar pun dipanggil dan ayat tersebut dibacakan kepadanya, ketika sampai, Maka berhentilah kamu (dari mengerjakan pekerjaan itu, Lantas Umar radliallahu 'anhu berkata; \"Kami berhenti, kami berhenti!.\""},"5181":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ يَعْنِي ابْنَ الْمُبَارَكِ عَنْ سُلَيْمَانَ التَّيْمِيِّ أَنَّ أَنَسَ بْنَ مَالِكٍ أَخْبَرَهُمْ قَالَبَيْنَا أَنَا قَائِمٌ عَلَى الْحَيِّ وَأَنَا أَصْغَرُهُمْ سِنًّا عَلَى عُمُومَتِي إِذْ جَاءَ رَجُلٌ فَقَالَ إِنَّهَا قَدْ حُرِّمَتْ الْخَمْرُ وَأَنَا قَائِمٌ عَلَيْهِمْ أَسْقِيهِمْ مِنْ فَضِيخٍ لَهُمْ فَقَالُوا اكْفَأْهَا فَكَفَأْتُهَا فَقُلْتُ لِأَنَسٍ مَا هُوَ قَالَ الْبُسْرُ وَالتَّمْرُقَالَ أَبُو بَكْرِ بْنُ أَنَسٍ كَانَتْ خَمْرُهُمْ يَوْمَئِذٍ فَلَمْ يُنْكِرْ أَنَسٌ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] ia berkata; telah memberitakan kepada kami [Abdullah yaitu Ibnul Mubarak] dari [Sulaiman At Taimi] bahwa [Anas bin Malik] pernah mengabarkan kepada mereka, ia berkata; \"Ketika aku sedang duduk-duduk di perkampungan pamanku -waktu itu aku adalah yang paling muda di antara mereka-, datanglah seorang laki-laki seraya berkata; \"Khamer telah diharamkan!\" Saat itu aku sedang menuangkan khamer untuk mereka, mereka berkata; \"Tumpahkanlah khamer itu!\" aku pun menumpahkannya.\" Aku bertanya kepada Anas; \"Minuman itu dari apa?\" ia menjawab: \"(Campuran) kurma muda dan kurma masak.\" Abu Bakr bin Anas berkata; \"Dari bahan itulah khamer mereka saat itu, dan Anas tidak mengingkarinya.\""},"5182":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ يَعْنِي ابْنَ الْمُبَارَكِ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَكُنْتُ أَسْقِي أَبَا طَلْحَةَ وَأُبَيَّ بْنَ كَعْبٍ وَأَبَا دُجَانَةَ فِي رَهْطٍ مِنْ الْأَنْصَارِ فَدَخَلَ عَلَيْنَا رَجُلٌ فَقَالَ حَدَثَ خَبْرٌ نَزَلَ تَحْرِيمُ الْخَمْرِ فَكَفَأْنَا قَالَ وَمَا هِيَ يَوْمَئِذٍ إِلَّا الْفَضِيخُ خَلِيطُ الْبُسْرِ وَالتَّمْرِ قَالَ وَقَالَ أَنَسٌ لَقَدْ حُرِّمَتْ الْخَمْرُ وَإِنَّ عَامَّةَ خُمُورِهِمْ يَوْمَئِذٍ الْفَضِيخُ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] ia berkata; telah memberitakan kepada kami [Abdullah yaitu Ibnul Mubarak] dari [Sa'id bin Abu Arubah] dari [Qatadah] dari [Anas] ia berkata; \"Di perkumpulan orang-orang Anshar, aku pernah menuangkan (khamer) untuk Abu Thalhah, Ubay bin Ka'ab dan Abu Dujanah. Tiba-tiba masuklah seorang laki-laki dan berkata; \"Ada kabar bahwa khamer telah diharamkan!\" Maka kami pun menumpahkan khamer tersebut.\" Anas berkata; \"Tidaklah disebut khamer -waktu itu- kecuali minuman yang terbuat dari campuran kurma muda dan kurma masak.\" Qatadah berkata; \"Anas mengatakan; \"Khamer telah diharamkan, dan khamer mereka pada waktu itu terbuat dari campuran kurma muda dan kurma masak.\""},"5183":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَحُرِّمَتْ الْخَمْرُ حِينَ حُرِّمَتْ وَإِنَّهُ لَشَرَابُهُمْ الْبُسْرُ وَالتَّمْرُ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Humaid Ath Thawil] dari [Anas bin Malik] ia berkata; \"Khamer diharamkan saat turun ayat yang mengharamkannya, dan khamer mereka saat itu terbuat dari campuran kurma muda dan kurma masak.\""},"5184":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ شُعْبَةَ عَنْ مُحَارِبِ بْنِ دِثَارٍ عَنْ جَابِرٍ يَعْنِي ابْنَ عَبْدِ اللَّهِ قَالَالْبُسْرُ وَالتَّمْرُ خَمْرٌ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Asy Syu'bah] dari [Muharib bin Ditsar] dari [Jabir yaitu Ibnu Abdullah] ia berkata; \"Kurma muda dan kurma masak adalah khamer.\""},"5185":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ سُفْيَانَ عَنْ مُحَارِبِ بْنِ دِثَارٍ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ قَالَالْبُسْرُ وَالتَّمْرُ خَمْرٌرَفَعَهُ الْأَعْمَشُ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Sufyan] dari [Muharib bin Ditsar] ia berkata; \"Aku mendengar [Jabir bin Abdullah] berkata; \"Kurma muda dan kurma masak adalah khamer.\" Sementara Al A'masy telah memarfu'kannya."},"5186":{"ar":"أَخْبَرَنَا الْقَاسِمُ بْنُ زَكَرِيَّا قَالَ أَنْبَأَنَا عُبَيْدُ اللَّهِ عَنْ شَيْبَانَ عَنْ الْأَعْمَشِ عَنْ مُحَارِبِ بْنِ دِثَارٍ عَنْ جَابِرٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الزَّبِيبُ وَالتَّمْرُ هُوَ الْخَمْرُ","id":"Telah mengabarkan kepada kami [Al Qasim bin Zakariya] ia berkata; telah memberitakan kepada kami [Ubaidullah] dari [Syaiban] dari [Al A'masy] dari [Muharib bin Ditsar] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Anggur dan kurma adalah khamer.\""},"5187":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ أَنْبَأَنَا عَبْدُ الرَّحْمَنِ عَنْ شُعْبَةَ عَنْ الْحَكَمِ عَنْ ابْنِ أَبِي لَيْلَى عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْبَلَحِ وَالتَّمْرِ وَالزَّبِيبِ وَالتَّمْرِ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] ia berkata; telah memberitakan kepada kami [Abdurrahman] dari [Syu'bah] dari [Al Hakam] dari [Ibnu Abu Laila] dari [Seorang laki-laki] sahabat Nabi shallallahu 'alaihi wasallam, ia berkata; \"Nabi shallallahu 'alaihi wasallam melarang mencampur kurma mentah dengan kurma masak, dan anggur dengan kurma masak.\""},"5188":{"ar":"أَخْبَرَنَا وَاصِلُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ حَبِيبِ بْنِ أَبِي عَمْرَةَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الدُّبَّاءِ وَالْحَنْتَمِ وَالْمُزَفَّتِ وَالنَّقِيرِ وَأَنْ يُخْلَطَ الْبَلَحُ وَالزَّهْوُ","id":"Telah mengabarkan kepada kami [Washil bin Abdul A'la] ia berkata; telah menceritakan kepada kami [Ibnu Fudlail] dari [Habib bin Abu Amrah] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang Ad Duba, Al Hantam, Al Muzaffat, An Naqir dan mencampur kurma mentah dengan Az Zahwu (kurma mentah hampir masak).\" "},"5189":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ حَبِيبِ بْنِ أَبِي عَمْرَةَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الدُّبَّاءِ وَالْمُزَفَّتِ وَزَادَ مَرَّةً أُخْرَى وَالنَّقِيرِ وَأَنْ يُخْلَطَ التَّمْرُ بِالزَّبِيبِ وَالزَّهْوُ بِالتَّمْرِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Jarir] dari [Habib bin Abu Amrah] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang dari Ad Duba dan Al Muzaffat.\" Dan dalam riwayat lain ia menambahkan, \"An Naqir, dan mencampur kurma masak dengan anggur, dan Az Zahwu (kurma mentah hampir masak) dengan kurma masak.\" "},"5190":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ مَنْصُورِ بْنِ جَعْفَرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ حَبِيبٍ عَنْ أَبِي أَرْطَاةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الزَّهْوِ وَالتَّمْرِ وَالزَّبِيبِ وَالتَّمْرِ","id":"Telah mengabarkan kepada kami [Al Husain bin Manshur bin Ja'far] ia berkata; telah menceritakan kepada kami [Abdullah bin Numair] ia berkata; telah menceritakan kepada kami [Al A'masy] dari [Habib] dari [Arthah] dari [Abu Sa'id Al Khudri] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang mencampur Az Zahwu (kurma mentah hampir masak) dengan kurma masak, dan anggur dengan kurma masak.\""},"5191":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ الْأَوْزَاعِيِّ قَالَ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي قَتَادَةَ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَجْمَعُوا بَيْنَ التَّمْرِ وَالزَّبِيبِ وَلَا بَيْنَ الزَّهْوِ وَالرُّطَبِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Al Auza'i] ia berkata; telah menceritakan kepadaku [Yahya bin Abu Katsir] ia berkata; telah menceritakan kepadaku [Abdullah bin Abu Qatadah] dari [Ayahnya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Janganlah kalian campur antara kurma masak dengan anggur, dan Az Zahwu (kurma mentah hampir masak) dengan ruthab (kurma segar).\""},"5192":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ قَالَ حَدَّثَنَا عَلِيٌّ وَهُوَ ابْنُ الْمُبَارَكِ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ أَبِي قَتَادَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَنْبِذُوا الزَّهْوَ وَالرُّطَبَ جَمِيعًا وَلَا تَنْبِذُوا الزَّبِيبَ وَالرُّطَبَ جَمِيعًا","id":"Telah mengabarkan kepada kami [Muhammad Ibnul Mutsanna] ia berkata; telah menceritakan kepada kami [Utsman bin Umar] ia berkata; telah menceritakan kepada kami [Ali yaitu Ibnul Mubarak] dari [Yahya] dari [Abu Salamah] dari [Abu Qatadah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian membuat nabidz dengan mencampur Az Zahwu (kurma mentah hampir masak) dengan ruthab (kurma segar) secara bersamaan, dan anggur dengan ruthab (kurma segar) secara bersamaan.\" "},"5193":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَفْصِ بْنِ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي إِبْرَاهِيمُ هُوَ ابْنُ طَهْمَانَ عَنْ عُمَرَ بْنِ سَعِيدٍ عَنْ سُلَيْمَانَ عَنْ مَالِكِ بْنِ الْحَارِثِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُخْلَطَ التَّمْرُ وَالزَّبِيبُ وَأَنْ يُخْلَطَ الزَّهْوُ وَالتَّمْرُ وَالزَّهْوُ وَالْبُسْرُ","id":"Telah mengabarkan kepada kami [Ahmad bin Hafsh bin Abdullah] ia berkata; telah menceritakan kepadaku [Ayahku] ia berkata; telah menceritakan kepadaku [Ibrahim yaitu Ibnu Thahman] dari [Umar bin Sa'id] dari [Sulaiman] dari [Malik bin Al Harits] dari [Abu Sa'id Al Khudri] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang mencampur antara kurma masak dengan anggur, Az Zahwu (kurma mentah hampir masak) dengan kurma masak dan Az Zahwu dengan kurma muda.\""},"5194":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ عَنْ يَحْيَى وَهُوَ ابْنُ سَعِيدٍ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي عَطَاءٌ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ خَلِيطِ التَّمْرِ وَالزَّبِيبِ وَالْبُسْرِ وَالرُّطَبِ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dari [Yahya yaitu bin Sa'id] dari [Ibnu Juraij] ia berkata; telah mengabarkan kepadaku ['Atha`] dari [Jabir] berkata; \"Nabi shallallahu 'alaihi wasallam melarang mencampur antara kurma masak dengan anggur, kurma muda dan kurma segar.\""},"5195":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ عَنْ أَبِي دَاوُدَ قَالَ حَدَّثَنَا بِسْطَامُ قَالَ حَدَّثَنَا مَالِكُ بْنُ دِينَارٍ عَنْ عَطَاءٍ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَخْلِطُوا الزَّبِيبَ وَالتَّمْرَ وَلَا الْبُسْرَ وَالتَّمْرَ","id":"Telah mengabarkan kepada kami [Amru bin Ali] dari [Abu Dawud] ia berkata; telah menceritakan kepada kami [Bistham] berkata, telah menceritakan kepada kami [Malik bin Dinar] dari ['Atha`] dari [Jabir] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian mencampur antara anggur dan kurma masak, kurma muda dan kurma masak.\""},"5196":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ عَطَاءٍ عَنْ جَابِرٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى أَنْ يُنْبَذَ الزَّبِيبُ وَالتَّمْرُ جَمِيعًا وَنَهَى أَنْ يُنْبَذَ الْبُسْرُ وَالتَّمْرُ جَمِيعًا","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Al Laits] dari ['Atha`] dari [Jabir] dari Rasulullah shallallahu 'alaihi wasallam, bahwa Rasulullah shallallahu 'alaihi wasallam melarang membuat khamer dengan mencampur antara anggur dan kurma masak, kurma muda dan kurma masak secara bersamaan.\""},"5197":{"ar":"أَخْبَرَنَا وَاصِلُ بْنُ عَبْدِ الْأَعْلَى عَنْ ابْنِ فُضَيْلٍ عَنْ أَبِي إِسْحَقَ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الدُّبَّاءِ وَالْحَنْتَمِ وَالْمُزَفَّتِ وَالنَّقِيرِ وَعَنْ الْبُسْرِ وَالتَّمْرِ أَنْ يُخْلَطَا وَعَنْ الزَّبِيبِ وَالتَّمْرِ أَنْ يُخْلَطَا وَكَتَبَ إِلَى أَهْلِ هَجَرَ أَنْ لَا تَخْلِطُوا الزَّبِيبَ وَالتَّمْرَ جَمِيعًا","id":"Telah mengabarkan kepada kami [Washil bin Abdul A'la] dari [Ibnu Fudlail] dari [Abu Ishaq] dari [Habib bin Abu Tsabit] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang Ad Duba, Al Hantam, Al Muzaffat, dan An Naqir. Mencampur antara kurma muda dengan kurma masak, dan anggur dengan kurma masak. Beliau juga pernah menulis surat kepada penduduk Hajar: \"Janganlah kalian mencampur antara anggur dengan kurma masak secara bersamaan.\" "},"5198":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا يَزِيدُ قَالَ أَنْبَأَنَا حُمَيْدٌ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَالْبُسْرُ وَحْدَهُ حَرَامٌ وَمَعَ التَّمْرِ حَرَامٌ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] ia berkata; telah menceritakan kepada kami [Yazid] ia berkata; telah memberitakan kepada kami [Humaid] dari [Ikrimah] dari [Ibnu Abbas] ia berkata; \"(rendaman) kurma itu haram, dan mencampurkannya dengan kurma masak juga haram.\""},"5199":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ آدَمَ وَعَلِيُّ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا عَبْدُ الرَّحِيمِ عَنْ حَبِيبِ بْنِ أَبِي عَمْرَةَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ خَلِيطِ التَّمْرِ وَالزَّبِيبِ وَعَنْ التَّمْرِ وَالْبُسْرِ","id":"Telah mengabarkan kepada kami [Muhammad bin Adam] dan [Ali bin Sa'id] keduanya berkata; telah menceritakan kepada kami [Abdurrahim] dari [Habib bin Abu 'Amrah] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang mencampur kurma masak dengan anggur, dan kurma masak dengan kurma muda.\""},"5200":{"ar":"أَخْبَرَنَا قُرَيْشُ بْنُ عَبْدِ الرَّحَمَنِ الْبَاوَرْدِيُّ عَنْ عَلِيِّ بْنِ الْحَسَنِ قَالَ أَنْبَأَنَا الْحُسَيْنُ بْنُ وَاقِدٍ قَالَ حَدَّثَنِي عَمْرُو بْنُ دِينَارٍ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ التَّمْرِ وَالزَّبِيبِ وَنَهَى عَنْ التَّمْرِ وَالْبُسْرِ أَنْ يُنْبَذَا جَمِيعًا","id":"Telah mengabarkan kepada kami [Quraiys bin Abdurrahman Al Bawardi] dari [Ali bin Al Hasan] ia berkata; telah memberitakan kepada kami [Al Husain bin Waqid] ia berkata; telah menceritakan kepadaku ['Amru bin Dinar] ia berkata; Aku mendengar [Jabir bin Abdullah] berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang mencampur kurma masak dengan anggur, dan mencampur kurma masak dengan kurma muda sebagai nabidz secara bersamaan.\" "},"5201":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ هِشَامٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَنْبِذُوا الزَّهْوَ وَالرُّطَبَ وَلَا تَنْبِذُوا الرُّطَبَ وَالزَّبِيبَ جَمِيعًا","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Hisyam] dari [Yahya bin Abu Katsir] dari [Abdullah bin Abu Qatadah] dari [Ayahnya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Janganlah kamu membuat nabidz antara Az Zahwu (kurma mentah hampir masak) dengan ruthab (kurma segar), dan antara ruthab dengan anggur secara bersamaan.\" "},"5202":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى أَنْ يُنْبَذَ الزَّبِيبُ وَالْبُسْرُ جَمِيعًا وَنَهَى أَنْ يُنْبَذَ الْبُسْرُ وَالرُّطَبُ جَمِيعًا","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Al Laits] dari [Abu Az Zubair] dari [Jabir] dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau melarang membuat nabidz dari anggur dengan kurma muda secara bersamaan, dan kurma muda dengan ruthab (kurma segar) secara bersamaan.\" "},"5203":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ وِقَاءِ بْنِ إِيَاسٍ عَنْ الْمُخْتَارِ بْنِ فُلْفُلٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَجْمَعَ شَيْئَيْنِ نَبِيذًا يَبْغِي أَحَدُهُمَا عَلَى صَاحِبِهِ قَالَ وَسَأَلْتُهُ عَنْ الْفَضِيخِ فَنَهَانِي عَنْهُ قَالَ كَانَ يَكْرَهُ الْمُذَنِّبَ مِنْ الْبُسْرِ مَخَافَةَ أَنْ يَكُونَا شَيْئَيْنِ فَكُنَّا نَقْطَعُهُ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Wiqa` bin Iyas] dari [Al Mukhtar bin Fulful] dari [Anas bin Malik] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang mengoplos dua jenis perasan sehingga menjadi arak, satu sama lain saling menguatkan daya mabuknya.\" Anas mengatakan; \"Aku juga bertanya perihal fadlikh (arak dari perasan kurma muda), beliau juga melarangku.\" Anas berkata; \"Beliau tidak menyukai perasan kurma muda, khawatir jangan-jangan itu juga oplosan dari dua perasan sehingga kami menghentikannya."},"5204":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ هِشَامِ بْنِ حَسَّانَ عَنْ أَبِي إِدْرِيسَ قَالَشَهِدْتُ أَنَسَ بْنَ مَالِكٍ أُتِيَ بِبُسْرٍ مُذَنِّبٍ فَجَعَلَ يَقْطَعُهُ مِنْهُ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Hisyam bin Hassan] dari [Abu Idris] ia berkata; \"Aku melihat [Anas bin Malik] diberi perasan kurma muda, lalu ia menghindarinya.\""},"5205":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ قَالَ قَتَادَةُكَانَ أَنَسٌ يَأْمُرُ بِالتَّذْنُوبِ فَيُقْرَضُ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Sa'id bin Abu Arubah] berkata; [Qatadah] berkata; \" [Anas] pernah menyuruh membuat minuman perasan, lalu ia menghindarinya.\""},"5206":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ حُمَيْدٍ عَنْ أَنَسٍأَنَّهُ كَانَ لَا يَدَعُ شَيْئًا قَدْ أَرْطَبَ إِلَّا عَزَلَهُ عَنْ فَضِيخِهِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Humaid] dari [Anas], bahwa tidaklah ia meninggalkan (kurma) yang sudah matang kecuali meninggalkan pula perasannya.\""},"5207":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ يَعْنِي ابْنَ الْحَارِثِ قَالَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِي قَتَادَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَنْبِذُوا الزَّهْوَ وَالرُّطَبَ جَمِيعًا وَلَا الْبُسْرَ وَالزَّبِيبَ جَمِيعًا وَانْبِذُوا كُلَّ وَاحِدٍ مِنْهُمَا عَلَى حِدَتِهِ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] ia berkata; telah menceritakan kepada kami [Khalid yaitu Ibnul Harits] ia berkata; telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Abdullah bin Abu Qatadah] dari [Abu Qatadah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian membuat nabidz dari Az Zahwu (kurma mentah hampir masak) dan ruthab (kurma segar) secara bersamaan, dan kurma muda dengan anggur secara bersamaan. Namun buatlah setiap masing-masing itu secara terpisah.\""},"5208":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ دُرُسْتَ قَالَ حَدَّثَنَا أَبُو إِسْمَعِيلَ قَالَ حَدَّثَنَا يَحْيَى أَنَّ عَبْدَ اللَّهِ بْنَ أَبِي قَتَادَةَ حَدَّثَهُ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ خَلِيطِ الزَّهْوِ وَالتَّمْرِ وَخَلِيطِ الْبُسْرِ وَالتَّمْرِ وَقَالَ لِتَنْبِذُوا كُلَّ وَاحِدٍ مِنْهُمَا عَلَى حِدَةٍ فِي الْأَسْقِيَةِ الَّتِي يُلَاثُ عَلَى أَفْوَاهِهَا","id":"Telah mengabarkan kepada kami [Yahya bin Durusta] ia berkata; telah menceritakan kepada kami [Abu Ishaq] ia berkata; telah menceritakan kepada kami [Yahya] bahwa [Abdullah bin Abu Qatadah] menceritakan kepadanya dari [Bapaknya] bahwa Nabi shallallahu 'alaihi wasallam melarang mencampur Az Zahwu (kurma mentah hampir masak) dengan kurma masak, dan kurma muda dengan kurma masak.\" Beliau bersabda: \"Hendaklah kalian membuat nabidz dari keduanya dengan sendiri-sendiri (terpisah) dalam wadah kulit yang diikat lubangnya.\""},"5209":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ إِسْمَعِيلَ بْنِ مُسْلِمٍ الْعَبْدِيِّ قَالَ حَدَّثَنَا أَبُو الْمُتَوَكِّلِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُخْلَطَ بُسْرٌ بِتَمْرٍ أَوْ زَبِيبٌ بِتَمْرٍ أَوْ زَبِيبٌ بِبُسْرٍ وَقَالَ مَنْ شَرِبَهُ مِنْكُمْ فَلْيَشْرَبْ كُلَّ وَاحِدٍ مِنْهُ فَرْدًا تَمْرًا فَرْدًا أَوْ بُسْرًا فَرْدًا أَوْ زَبِيبًا فَرْدًا","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Isma'il bin Muslim Al 'Abdi] ia berkata; telah menceritakan kepada kami [Abu Al Mutawakkil] dari [Abu Sa'id Al Khudri] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang mencampur kurma muda dengan kurma masak, atau anggur dengan kurma, atau anggur dengan kurma muda.\" Beliau bersabda: \"Barangsiapa dari kalian ingin meminumnya hendaklah ia meminum masing-masing darinya secara sendiri-sendiri (terpisah), perasan kurma masak sendiri, perasan kurma muda sendiri, atau perasan anggur sendiri.\""},"5210":{"ar":"أَخْبَرَنِي أَحْمَدُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا شُعَيْبُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ بْنُ مُسْلِمٍ قَالَ حَدَّثَنَا أَبُو الْمُتَوَكِّلِ النَّاجِي قَالَ حَدَّثَنِي أَبُو سَعِيدٍ الْخُدْرِيُّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يُخْلَطَ بُسْرًا بِتَمْرٍ أَوْ زَبِيبًا بِتَمْرٍ أَوْ زَبِيبًا بِبُسْرٍ وَقَالَ مَنْ شَرِبَ مِنْكُمْ فَلْيَشْرَبْ كُلَّ وَاحِدٍ مِنْهُ فَرْدًاقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا أَبُو الْمُتَوَكِّلِ اسْمُهُ عَلِيُّ بْنُ دَاوُدَ","id":"Telah mengabarkan kepadaku [Ahmad bin Khalid] ia berkata; telah menceritakan kepada kami [Syu'aib bin Harb] ia berkata; telah menceritakan kepada kami [Isma'il bin Muslim] ia berkata; telah menceritakan kepada kami [Abu Al Mutawakkil An Naji] ia berkata; telah menceritakan kepadaku [Abu Sa'id Al Khudri] bahwa Nabi shallallahu 'alaihi wasallam melarang mencampur kurma muda dengan kurma masak, atau anggur dengan kurma masak, atau anggur dengan kurma muda.\" Beliau bersabda: \"Barangsiapa salah seorang dari kalian ingin meminumnya, hendaklah ia minum setiap masing-masing darinya dengan sendiri (terpisah).\"' Abdurrahman berkata; \"Abu Al Mutawakkil namanya adalah Ali bin Dawud.\""},"5211":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ عِكْرِمَةَ بْنِ عَمَّارٍ قَالَ حَدَّثَنَا أَبُو كَثِيرٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُخْلَطَ الْبُسْرُ وَالزَّبِيبُ وَالْبُسْرُ وَالتَّمْرُ وَقَالَ انْبِذُوا كُلَّ وَاحِدٍ مِنْهُمَا عَلَى حِدَةٍ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Ikrimah bin Ammar] ia berkata; telah menceritakan kepada kami [Abu Katsir] ia berkata; Aku mendengar [Abu Hurairah] berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang mencampur kurma muda dengan anggur dan kurma muda dengan kurma masak.\" Beliau bersabda: \"Buatlah nabidz (arak) setiap dari keduanya dengan sendiri-sendiri (terpisah).\""},"5212":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَمَّارٍ قَالَ حَدَّثَنَا الْمُعَافَى يَعْنِي ابْنَ عِمْرَانَ عَنْ إِسْمَعِيلَ بْنِ مُسْلِمٍ عَنْ أَبِي الْمُتَوَكِّلِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يُنْبَذَ التَّمْرُ وَالزَّبِيبُ وَالتَّمْرُ وَالْبُسْرُ وَقَالَ انْتَبِذُوا الزَّبِيبَ فَرْدًا وَالتَّمْرَ فَرْدًا وَالْبُسْرَ فَرْدًاقَالَ أَبُو عَبْد الرَّحْمَنِ أَبُو كَثِيرٍ اسْمُهُ يَزِيدُ بْنُ عَبْدِ الرَّحْمَنِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Ammar] ia berkata; telah menceritakan kepada kami [Al Mu'afa] -yakni Ibnu Imran- dari [Isma'il bin Muslim] dari [Abu Al Mutawakkil] dari [Abu Sa'id Al Khudri] berkata; \"Nabi shallallahu 'alaihi wasallam melarang untuk mencampur antara kurma masak dengan anggur dan kurma masak dengan kurma muda.\" Beliau bersabda: \"Peraslah anggur sendiri, kurma masak sendiri dan kurma muda secara sendiri.\" Abdurrahman berkata; \"Abu Katsir namanya adalah Yazid bin Abdurrahman.\""},"5213":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ الْأَوْزَاعِيِّ قَالَ حَدَّثَنِي أَبُو كَثِيرٍ ح وَأَنْبَأَنَا حُمَيْدُ بْنُ مَسْعَدَةَ عَنْ سُفْيَانَ بْنِ حَبِيبٍ عَنْ الْأَوْزَاعِيِّ حَدَّثَنَا أَبُو كَثِيرٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْخَمْرُ مِنْ هَاتَيْنِ وَقَالَ سُوَيْدٌ فِي هَاتَيْنِ الشَّجَرَتَيْنِ النَّخْلَةُ وَالْعِنَبَةُ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Al Auza'i] ia berkata; telah menceritakan kepadaku [Abu Katsir]. (dalam jalur lain disebutkan) Telah memberitakan kepada kami [Humaid bin Mas'adah] dari [Sufyan bin Habib] dari [Al Auza'i] berkata; telah menceritakan kepada kami [Abu Katsir] ia berkata; aku mendengar [Abu Hurairah] berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Khamer itu dari dua ini, \" Suwaid menyebutkan, \"pada dua pohon ini; kurma dan anggur.\""},"5214":{"ar":"أَخْبَرَنَا زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا ابْنُ عُلَيَّةَ قَالَ حَدَّثَنَا الْحَجَّاجُ الصَّوَّافُ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي أَبُو كَثِيرٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْخَمْرُ مِنْ هَاتَيْنِ الشَّجَرَتَيْنِ النَّخْلَةُ وَالْعِنَبَةُ","id":"Telah mengabarkan kepada kami [Ziyad bin Ayyub] ia berkata; telah menceritakan kepada kami [Ibnu Ulayyah] ia berkata; telah menceritakan kepada kami [Al Hajjaj Ash Shawwaf] dari [Yahya bin Abu Katsir] ia berkata; telah menceritakan kepadaku [Abu Katsir] dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Khamer itu dari dua pohon ini; kurma dan anggur\"."},"5215":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ عَنْ شَرِيكٍ عَنْ مُغِيرَةَ عَنْ إِبْرَاهِيمَ وَالشَّعْبِيِّ قَالَاالسَّكَرُ خَمْرٌ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] ia berkata; telah mengabarkan kepada kami [Abdullah] dari [Syarik] dari [Mughirah] dari [Ibrahim] dan [Asy Sya'bi] keduanya berkata; \"Minuman yang memabukkan adalah khamer.\""},"5216":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ سُفْيَانَ عَنْ حَبِيبِ بْنِ أَبِي عَمْرَةَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَالسَّكَرُ خَمْرٌ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Sufyan] dari [Habib bin Abu Amrah] dari [Sa'id bin Jubair] ia berkata; \"Minuman yang memabukkan adalah khamer.\""},"5217":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ حَبِيبٍ وَهُوَ ابْنُ أَبِي عَمْرَةَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَالسَّكَرُ خَمْرٌ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Jarir] dari [Habib yaitu bin Amrah] dari [Sa'id bin Jubair] ia berkata; \"Minuman yang memabukkan adalah khamer.\""},"5218":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ سُفْيَانَ عَنْ أَبِي حَصِينٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَالسَّكَرُ حَرَامٌ وَالرِّزْقُ الْحَسَنُ حَلَالٌ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Sufyan] dari [Abu Hushain] dari [Sa'id bin Jubair] ia berkata; \"Minuman yang memabukkan adalah haram dan rizki yang halal adalah halal.\""},"5219":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا ابْنُ عُلَيَّةَ قَالَ حَدَّثَنَا أَبُو حَيَّانَ قَالَ حَدَّثَنَا الشَّعْبِيُّ عَنْ ابْنِ عُمَرَ قَالَسَمِعْتُ عُمَرَ رَضِيَ اللَّهُ عَنْهُ يَخْطُبُ عَلَى مِنْبَرِ الْمَدِينَةِ فَقَالَ أَيُّهَا النَّاسُ أَلَا إِنَّهُ نَزَلَ تَحْرِيمُ الْخَمْرِ يَوْمَ نَزَلَ وَهِيَ مِنْ خَمْسَةٍ مِنْ الْعِنَبِ وَالتَّمْرِ وَالْعَسَلِ وَالْحِنْطَةِ وَالشَّعِيرِ وَالْخَمْرُ مَا خَامَرَ الْعَقْلَ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] ia berkata; telah menceritakan kepada kami [Ibnu Ulayyah] ia berkata; telah menceritakan kepada kami [Abu Hayyan] ia berkata; telah menceritakan kepada kami [Asy Sya'bi] dari [Ibnu Umar] ia berkata; \"Aku mendengar [Umar radliallahu 'anhu] berkhutbah di atas mimbar masjid Madinah, ia mengatakan, \"Wahai manusia! Ketahuilah, sesungguhnya khamer telah diharamkan pada hari diharamkannya. Dan ia terbuat dari lima macam (buah); anggur, kurma masak, madu, jewawut dan gandum. Khamer adalah sesuatu yang menutupi akal.\""},"5220":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ أَنْبَأَنَا ابْنُ إِدْرِيسَ عَنْ زَكَرِيَّا وَأَبِي حَيَّانَ عَنْ الشَّعْبِيِّ عَنْ ابْنِ عُمَرَ قَالَسَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ عَلَى مِنْبَرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَمَّا بَعْدُ فَإِنَّ الْخَمْرَ نَزَلَ تَحْرِيمُهَا وَهِيَ مِنْ خَمْسَةٍ مِنْ الْعِنَبِ وَالْحِنْطَةِ وَالشَّعِيرِ وَالتَّمْرِ وَالْعَسَلِ","id":"Telah mengabarkan kepada kami [Muhammad Ibnul 'Ala] ia berkata; telah memberitakan kepada kami [Ibnu Idris] dari [Zakariya] dan [Abu Hayyan] dari [Asy Sya'bi] dari [Ibnu Umar] ia berkata; \"Aku mendengar [Umar Ibnul Khaththab radliallahu 'anhu] menyampaikan di atas mimbar Rasulullah shallallahu 'alaihi wasallam: \"Amma ba'du; Sesungguhnya khamer telah diharamkan, dan ia berasal dari lima macam perasan; anggur, jemawut, gandum, kurma dan madu.\""},"5221":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ إِسْرَائِيلَ عَنْ أَبِي حَصِينٍ عَنْ عَامِرٍ عَنْ ابْنِ عُمَرَ قَالَالْخَمْرُ مِنْ خَمْسَةٍ مِنْ التَّمْرِ وَالْحِنْطَةِ وَالشَّعِيرِ وَالْعَسَلِ وَالْعِنَبِ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] ia berkata; telah menceritakan kepada kami [Ubaidullah] dari [Isra'il] dari [Abu Hashin] dari [Amir] dari [Ibnu Umar] ia berkata; \"Khamer itu dari lima macam perasan; kurma masak, jemawut, gandum, madu dan anggur.\""},"5222":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ ابْنِ عَوْنٍ عَنْ ابْنِ سِيرِينَ قَالَجَاءَ رَجُلٌ إِلَى ابْنِ عُمَرَ فَقَالَ إِنَّ أَهْلَنَا يَنْبِذُونَ لَنَا شَرَابًا عَشِيًّا فَإِذَا أَصْبَحْنَا شَرِبْنَا قَالَ أَنْهَاكَ عَنْ الْمُسْكِرِ قَلِيلِهِ وَكَثِيرِهِ وَأُشْهِدُ اللَّهَ عَلَيْكَ أَنْهَاكَ عَنْ الْمُسْكِرِ قَلِيلِهِ وَكَثِيرِهِ وَأُشْهِدُ اللَّهَ عَلَيْكَ إِنَّ أَهْلَ خَيْبَرَ يَنْتَبِذُونَ شَرَابًا مِنْ كَذَا وَكَذَا وَيُسَمُّونَهُ كَذَا وَكَذَا وَهِيَ الْخَمْرُ وَإِنَّ أَهْلَ فَدَكٍ يَنْتَبِذُونَ شَرَابًا مِنْ كَذَا وَكَذَا يُسَمُّونَهُ كَذَا وَكَذَا وَهِيَ الْخَمْرُ حَتَّى عَدَّ أَشْرِبَةً أَرْبَعَةً أَحَدُهَا الْعَسَلُ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] ia berkata; telah menceritakan kepada kami [Abdullah] dari [Ibnu Aun] dari [Ibnu Sirin] ia berkata; \"Seorang laki-laki datang menemui [Ibnu Umar] dan berkata; \"Keluarga kami membuat perasan sebagai minuman, lalu pada pagi harinya kami meminumnya?\" Ibnu Umar berkata; \"Engkau telah dilarang untuk minum sesuatu yang memabukkan, baik sedikit ataupun banyak. Aku bersaksi kepada Allah atas kamu, sesungguhnya engkau telah dilarang untuk minum sesuatu yang memabukkan; baik sedikit ataupun banyak. Dan aku juga bersaksi kepada Allah atas kamu, bahwa penduduk Khaibar pernah membuat perasan dari seperti ini dan seperti ini, lalu mereka menamakannya dengan seperti ini dan seperti ini, dan itu adalah khamer. Dan sesungguhnya penduduk Fadak pernah membuat perasan dari seperti ini dan seperti ini, lalu mereka menamakannya dengan seperti ini dan seperti ini, dan itu adalah khamer.\" Sehingga Ibnu Umar menyebutkan empat jenis minuman yang salah satunya adalah madu.\""},"5223":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ عَنْ حَمَّادِ بْنِ زَيْدٍ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّ مُسْكِرٍ حَرَامٌ وَكُلُّ مُسْكِرٍ خَمْرٌ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] ia berkata; telah mengabarkan kepada kami [Abdullah] dari [Hammad bin Zaid] ia berkata; telah menceritakan kepada kami [Ayyub] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Setiap yang memabukkan adalah haram, dan setiap yang memabukkan adalah khamer.\""},"5224":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ مَنْصُورِ بْنِ جَعْفَرٍ قَالَ حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ قَالَ حَدّ��ثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ مُسْكِرٍ حَرَامٌ وَكُلُّ مُسْكِرٍ خَمْرٌقَالَ الْحُسَيْنُ قَالَ أَحْمَدُ وَهَذَا حَدِيثٌ صَحِيحٌ","id":"Telah mengabarkan kepada kami [Al Husain bin Masnhur bin Ja'far] ia berkata; telah menceritakan kepada kami [Ahmad bin Hanbal] ia berkata; telah menceritakan kepada kami [Abdurrahman bin Mahdi] ia berkata; telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap yang memabukkan adalah haram, dan setiap yang memabukkan adalah khamer.\" Abdurrahman berkata; \"Ahmad menyebutkan bahwa hadits ini derajatnya shahih.\""},"5225":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ دُرُسْتَ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ مُسْكِرٍ خَمْرٌ","id":"Telah mengabarkan kepada kami [Yahya bin Durusta] ia berkata; telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap yang memabukkan adalah khamer.\""},"5226":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ مَيْمُونٍ قَالَ حَدَّثَنَا ابْنُ أَبِي رَوَّادٍ قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ مُسْكِرٍ خَمْرٌ وَكُلُّ مُسْكِرٍ حَرَامٌ","id":"Telah mengabarkan kepada kami [Ali bin Maimun] ia berkata; telah menceritakan kepada kami [Ibnu Abu Rawwad] ia berkata; telah menceritakan kepada kami [Ibnu Juraij] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap yang memabukkan adalah khamer dan setiap yang memabukkan adalah haram.\""},"5227":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّ مُسْكِرٍ حَرَامٌ وَكُلُّ مُسْكِرٍ خَمْرٌ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah mengabarkan kepada kami [Abdullah] dari [Muhammad bin 'Ajlan] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Setiap yang memabukkan adalah haram, dan setiap yang memabukkan adalah khamer.\""},"5228":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ مُسْكِرٍ حَرَامٌ","id":"Telah mengabarkan kepada kami [Muhammad Ibnul Mutsanna] ia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Muhammad bin Amru] dari [Abu Salamah] dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap yang memabukkan adalah haram.\""},"5229":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ عَنْ إِسْمَعِيلَ عَنْ مُحَمَّدٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يُنْبَذَ فِي الدُّبَّاءِ وَالْمُزَفَّتِ وَالنَّقِيرِ وَالْحَنْتَمِ وَكُلُّ مُسْكِرٍ حَرَامٌ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] dari [Isma'il] dari [Muhammad] dari [Abu Salamah] dari [Abu Hurairah] berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang membuat arak dalam Ad Duba, Al Muzaffat, An Naqir dan Al Hantam. Dan setiap yang memabukkan adalah haram.\" "},"5230":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَقُتَيْبَةُ عَنْ سُفْيَانَ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ شَرَابٍ أَسْكَرَ فَهُوَ حَرَامٌ قَالَ قُتَيْبَةُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dan [Qutaibah] dari [Sufyan] dari [Az Zuhri] dari [Abu Salamah] dari ['Aisyah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap minuman yang memabukkan adalah haram.\" Qutaibah menyebutkan dari Nabi shallallahu 'alaihi wasallam."},"5231":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ ح وَأَنْبَأَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ الْبِتْعِ فَقَالَ كُلُّ شَرَابٍ أَسْكَرَ حَرَامٌاللَّفْظُ لِسُوَيْدٍ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik]. (dalam jalur lain disebutkan) Telah memberitakan kepada kami [Suwaid bin Nashr] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Malik] dari [Ibnu Syihab] dari [Abu Salamah] dari ['Aisyah radliallahu 'anha] berkata; \"Rasulullah shallallahu 'alaihi wasallam ditanya tentang Al bit'u (minuman dari perasan madu), lalu beliau menjawab: \"Setiap minuman yang memabukkan adalah haram.\" Ini adalah lafadz Suwaid."},"5232":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ الْبِتْعِ فَقَالَ كُلُّ شَرَابٍ أَسْكَرَ فَهُوَ حَرَامٌ وَالْبِتْعُ مِنْ الْعَسَلِ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Ma'mar] dari [Az Zuhri] dari [Abu Salamah] dari ['Aisyah radliallahu 'anha] berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah ditanya tentang Al bit'u, lalu beliau menjawab: \"Setiap minuman yang memabukkan adalah haram, dan Al bit'u terbuat dari madu.\""},"5233":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ سُوَيْدِ بْنِ مَنْجُوفٍ وَعَبْدُ اللَّهِ بْنُ الْهَيْثَمِ عَنْ أَبِي دَاوُدَ عَنْ شُعْبَةَ عَنْ سَعِيدِ بْنِ أَبِي بُرْدَةَ عَنْ أَبِيهِ عَنْ أَبِي مُوسَى قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ مُسْكِرٍ حَرَامٌ","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah bin Suwaid bin Manjuf] dan [Abdullah bin Al Haitsam] dari [Abu Dawud] dari [Syu'bah] dari [Sa'id bin Abu Burdah] dari [Saudaranya] dari [Abu Musa] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap yang memabukkan adalah haram.\""},"5234":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي بُرْدَةَ عَنْ أَبِيهِ قَالَبَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا وَمُعَاذٌ إِلَى الْيَمَنِ فَقَالَ مُعَاذٌ إِنَّكَ تَبْعَثُنَا إِلَى أَرْضٍ كَثِيرٌ شَرَابُ أَهْلِهَا فَمَا أَشْرَبُ قَالَ اشْرَبْ وَلَا تَشْرَبْ مُسْكِرًا","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah bin Ali] ia berkata; telah menceritakan kepada kami ['Abdurrahman] dari [Isra'il] dari [Abu Ishaq] dari [Abu Burdah] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengutus aku dan Mu'adz ke Yaman, lalu Mu'adz berkata, \"Engkau mengutus kami ke suatu wilayah yang penduduknya banyak membuat minuman (khamer), maka minuman apa yang boleh untuk saya minum?\" beliau menjawab: \"Minumlah, dan jangan minum sesuatu yang memabukkan.\""},"5235":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ قَالَ أَنْبَأَنَا الْأَسْوَدُ بْنُ شَيْبَانَ السَّدُوسِيُّ قَالَ سَمِعْتُ عَطَاءًسَأَلَهُ رَجُلٌ فَقَالَ إِنَّا نَرْكَبُ أَسْفَارًا فَتُبْرَزُ لَنَا الْأَشْرِبَةُ فِي الْأَسْوَاقِ لَا نَدْرِي أَوْعِيَتَهَا فَقَالَ كُلُّ مُسْكِرٍ حَرَامٌ فَذَهَبَ يُعِيدُ فَقَالَ كُلُّ مُسْكِرٍ حَرَامٌ فَذَهَبَ يُعِيدُ فَقَالَ هُوَ مَا أَقُولُ لَكَ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] ia berkata; telah memberitakan kepada kami [Al Aswad bin Syaiban As Sadusi] ia berkata; Aku mendengar ['Atha] ditanya oleh seorang laki-laki, ia mengatakan, \"Kami sedang dalam berkendaraan dalam suatu perjalanan, lalu kami ditawari beberapa minuman pada suatu pasar yang kami tidak tahu apa wadahnya?\" 'Atha menjawab, \"Setiap yang memabukkan adalah haram.\" Laki-laki itu kemudian pergi dan kembali lagi, 'Atha berkata lagi, \"Setiap yang memabukkan adalah haram.\" Laki-laki itu kemudian pergi dan kembali lagi, 'Atha lalu berkata, \"Itu yang aku katakan kepadamu.\""},"5236":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ هَارُونَ بْنِ إِبْرَاهِيمَ عَنْ ابْنِ سِيرِينَ قَالَكُلُّ مُسْكِرٍ حَرَامٌ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Harun bin Ibrahim] dari [Ibnu Sirin] ia berkata, \"Setiap yang memabukkan adalah haram.\""},"5237":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ عَبْدِ الْمَلِكِ بْنِ الطُّفَيْلِ الْجَزَرِيِّ قَالَ كَتَبَ إِلَيْنَا عُمَرُ بْنُ عَبْدِ الْعَزِيزِلَا تَشْرَبُوا مِنْ الطِّلَاءِ حَتَّى يَذْهَبَ ثُلُثَاهُ وَيَبْقَى ثُلُثَهُ وَكُلُّ مُسْكِرٍ حَرَامٌ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Abdul Malik bin Ath Thufail Al Jazari] ia berkata, \" [Umar bin Abdul Aziz] pernah menulis surat kepada kami, 'Janganlah kalian meminum perasan hingga menguap dua pertiganya dan tersisa sepertiganya, dan setiap yang memabukkan adalah haram'.\""},"5238":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ الْأَجْلَحِ قَالَ حَدَّثَنِي أَبُو بَكْرِ بْنُ أَبِي مُوسَى عَنْ أَبِيهِ قَالَبَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْيَمَنِ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ بِهَا أَشْرِبَةً فَمَا أَشْرَبُ وَمَا أَدَعُ قَالَ وَمَا هِيَ قُلْتُ الْبِتْعُ وَالْمِزْرُ قَالَ وَمَا الْبِتْعُ وَالْمِزْرُ قُلْتُ أَمَّا الْبِتْعُ فَنَبِيذُ الْعَسَلِ وَأَمَّا الْمِزْرُ فَنَبِيذُ الذُّرَةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَشْرَبْ مُسْكِرًا فَإِنِّي حَرَّمْتُ كُلَّ مُسْكِرٍ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Al Ajlah] ia berkata; telah menceritakan kepadaku [Abu Bakr bin Abu Musa] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengutusku ke Yaman, lalu aku bertanya kepada beliau, \"Di sana banyak minuman (khamer), maka mana yang boleh aku minum dan mana yang tidak?\" beliau beliau balik bertanya: \"Minuman apa saja itu?\" Aku menjawab, \"Al Bit'u dan Al Mizr.\" Beliau bertanya lagi: \"Apa itu Al Bit'u dan Al Mizr?\" aku menjawab: \"Al Bit'u adalah minuman yang terbuat dari perasan madu, sedangkan Al Mizr adalah minuman yang terbuat dari perasan jagung.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kamu minum sesuatu yang memabukkan, karena aku telah mengharamkan setiap minuman yang memabukkan.\""},"5239":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ آدَمَ بْنِ سُلَيْمَانَ عَنْ ابْنِ فُضَيْلٍ عَنْ الشَّيْبَانِيِّ عَنْ أَبِي بُرْدَةَ عَنْ أَبِيهِ قَالَبَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْيَمَنِ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ بِهَا أَشْرِبَةً يُقَالُ لَهَا الْبِتْعُ وَالْمِزْرُ قَالَ وَمَا الْبِتْعُ وَالْمِزْرِ قُلْتُ شَرَابٌ يَكُونُ مِنْ الْعَسَلِ وَالْمِزْرُ يَكُونُ مِنْ الشَّعِيرِ قَالَ كُلُّ مُسْكِرٍ حَرَامٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Adam bin Sulaiman] dari [Ibnu Fudlail] dari [Asy Syaibani] dari [Abu Burdah] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengutusku ke Yaman, lalu aku bertanya kepada beliau: \"Wahai Rasulullah, di sana banyak terdapat minuman yang disebut Al Bit'u dan Al Mizr?\" beliau balik bertanya: \"Apa itu Al Bit'u dan Al Mizr?\" Aku menjawab, \"Al Bit'u adalah minuman yang terbuat dari madu, sementara Al Mizr adalah minuman yang terbuat dari gandum.\" Beliau lantas bersabda: \"Setiap yang memabukkan adalah haram.\""},"5240":{"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ قَالَ أَخْبَرَنِي أَبِي قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ نَافِعٍ عَنْ ابْن�� طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ قَالَخَطَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ آيَةَ الْخَمْرِ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَرَأَيْتَ الْمِزْرَ قَالَ وَمَا الْمِزْرُ قَالَ حَبَّةٌ تُصْنَعُ بِالْيَمَنِ فَقَالَ تُسْكِرُ قَالَ نَعَمْ قَالَ كُلُّ مُسْكِرٍ حَرَامٌ","id":"Telah mengabarkan kepada kami [Abu Bakr bin Ali] ia berkata; telah menceritakan kepada kami [Nashr bin Ali] ia berkata; telah mengabarkan kepadaku [Bapakku] ia berkata; telah menceritakan kepada kami [Ibrahim bin Nafi'] dari [Ibnu Thawus] dari [Bapaknya] dari [Ibnu Umar], ia berkata, \"Rasulullah shallallahu 'alaihi wasallam berkhutbah dan menyebut tentang ayat khamer, lalu seorang laki-laki bertanya, \"Wahai Rasulullah, apa pendapatmu dengan Al Mizr?\" beliau balik bertanya: \"Apa itu Al Mizr?\" laki-laki itu menjawab, \"Perasan biji-bijian yang dibuat di Yaman.\" Beliau bertanya lagi: \"Apakah ia memabukkan?\" laki-laki itu menjawab, \"Ya.\" Beliau bersabda: \"Setiap yang memabukkan adalah haram.\""},"5241":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي الْجُوَيْرِيَةِ قَالَسَمِعْتُ ابْنَ عَبَّاسٍ وَسُئِلَ فَقِيلَ لَهُ أَفْتِنَا فِي الْبَاذَقِ فَقَالَ سَبَقَ مُحَمَّدٌ الْبَاذَقَ وَمَا أَسْكَرَ فَهُوَ حَرَامٌ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Abu Awanah] dari [Abu Al Juwairiyah] ia berkata; aku mendengar [Ibnu Abbas] ditanya, dikatakan kepadanya, \"Berilah fatwa kepada kami tentang hukum Al Badzaq (khamer persia)?\" Ibnu Abbas menjawab, \"Telah lama Muhammad menetapkan hukum Al Badzaq, apa-apa yang memabukkan adalah haram.\""},"5242":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى يَعْنِي ابْنَ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنَا عَمْرُو بْنُ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا أَسْكَرَ كَثِيرُهُ فَقَلِيلُهُ حَرَامٌ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Sa'id] ia berkata; telah menceritakan kepada kami [Yahya] -yaitu Ibnu Sa'id- dari [Ubaidullah] ia berkata; telah menceritakan kepada kami [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesuatu yang banyaknya memabukkan, maka sedikitnya juga memabukkan.\""},"5243":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَخْلَدٍ قَالَ حَدَّثَنَا سَعِيدُ بْنُ الْحَكَمِ قَالَ أَنْبَأَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنِي الضَّحَّاكُ بْنُ عُثْمَانَ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ عَامِرِ بْنِ سَعْدٍ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَنْهَاكُمْ عَنْ قَلِيلِ مَا أَسْكَرَ كَثِيرُهُ","id":"Telah mengabarkan kepada kami [Humaid bin Makhlad] ia berkata; telah menceritakan kepada kami [Sa'id Ibnul Hakam] ia berkata; telah memberitakan kepada kami [Muhammad bin Ja'far] ia berkata; telah menceritakan kepadaku [Adl Dlahhak bin Utsman] dari [Bukair bin Abdullah bin Al Asyaj] dari [Amir bin Sa'd] dari [Bapaknya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Aku melarang kalian dari sedikitnya sesuatu jika banyaknya memabukkan.\""},"5244":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَمَّارٍ قَالَ حَدَّثَنَا الْوَلِيدُ بْنُ كَثِيرٍ عَنْ الضَّحَّاكِ بْنِ عُثْمَانَ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ عَامِرِ بْنِ سَعْدٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ قَلِيلِ مَا أَسْكَرَ كَثِيرُهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Ammar] ia berkata; telah menceritakan kepada kami [Al Walid bin Katsir] dari [Adl Dlahhak bin Utsman] dari [Bukair bin Abdullah bin Al Asyaj] dari [Amir bin Sa'd] dari [Bapaknya] berkata, \"Nabi shallallahu 'alaihi wasallam melarang dari sesuatu yang sedikit jika banyaknya memabukkan.\""},"5245":{"ar":"أَخْبَرَنَا هِشَامُ بْنُ عَمَّارٍ قَالَ حَدَّثَنَا صَدَقَةُ بْنَ خَالِدٍ عَنْ زَيْدِ بْنِ وَاقِدٍ أَخْبَرَنِي خَالِدُ بْنُ عَبْدِ اللَّهِ بْنِ حُسَيْنٍ عَنْ أَبِي هُرَيْرَةَ قَالَعَلِمْتُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَصُومُ فَتَحَيَّنْتُ فِطْرَهُ بِنَبِيذٍ صَنَعْتُهُ لَهُ فِي دُبَّاءٍ فَجِئْتُهُ بِهِ فَقَالَ أَدْنِهِ فَأَدْنَيْتُهُ مِنْهُ فَإِذَا هُوَ يَنِشُّ فَقَالَ اضْرِبْ بِهَذَا الْحَائِطَ فَإِنَّ هَذَا شَرَابُ مَنْ لَا يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِقَالَ أَبُو عَبْد الرَّحْمَنِ وَفِي هَذَا دَلِيلٌ عَلَى تَحْرِيمِ السَّكَرِ قَلِيلِهِ وَكَثِيرِهِ وَلَيْسَ كَمَا يَقُولُ الْمُخَادِعُونَ لِأَنْفُسِهِمْ بِتَحْرِيمِهِمْ آخِرِ الشَّرْبَةِ وَتَحْلِيلِهِمْ مَا تَقَدَّمَهَا الَّذِي يُشْرَبُ فِي الْفَرَقِ قَبْلَهَا وَلَا خِلَافَ بَيْنَ أَهْلِ الْعِلْمِ أَنَّ السُّكْرَ بِكُلِّيَّتِهِ لَا يَحْدُثُ عَلَى الشَّرْبَةِ الْآخِرَةِ دُونَ الْأُولَى وَالثَّانِيَةِ بَعْدَهَا وَبِاللَّهِ التَّوْفِيقُ","id":"Telah mengabarkan kepada kami [Hisyam bin Ammar] ia berkata; telah menceritakan kepada kami [Shadaqah bin Khalid] dari [Zaid bin Waqid] berkata, telah mengabarkan kepadaku [Khalid bin Abdullah bin Husain] dari [Abu Hurairah] ia berkata, \"Aku tahu bahwa Rasulullah shallallahu 'alaihi wasallam biasa melakukan puasa, maka aku menyiapkan buka puasanya dengan arak yang aku buat dalam wadah Ad Duba, wadah itu lantas aku bawa kepada beliau. Beliau bersabda: \"Dekatkanlah wadah itu kepadaku, \" maka aku dekatkan wadah tersebut kepadanya, dan ternyata arak tersebut sedang menguap (seperti air mendidih). Beliau lalu bersabda: \"Buanglah minuman ini ke dinding, sebab ia untuk orang-orang yang tidak beriman kepada Allah dan hari kiamat.\" Abu 'Abdurrahman berkata, \"Dalam hadits ini terdapat dalil atas haramnya sesuatu yang memabukkan, baik sedikit atau banyaknya. Dan bukan sebagaimana yang dikatakan oleh orang-orang yang menipu diri mereka sendiri, bahwa keharaman itu hanya terdapat pada tegukan terakhir, sedang pada tegukan pertama atau sebelumnya adalah halal. Tidak ada perselisihan di antara para ahli ilmu bahwa keharamannya itu mencakup keseluruhannya, sebab mabuk tidak akan terjadi hanya pada tegukan terakhir tanpa adanya yang pertama, kedua dan seterusnya. Hanya kepada Allah tempat memohon pertolongan.\" "},"5246":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا عَمَّارُ بْنُ رُزَيْقٍ عَنْ أَبِي إِسْحَقَ عَنْ صَعْصَعَةَ بْنِ صُوحَانَ عَنْ عَلِيٍّ كَرَّمَ اللَّهُ وَجْهَهُ قَالَنَهَانِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ حَلْقَةِ الذَّهَبِ وَالْقَسِّيِّ وَالْمِيثَرَةِ وَالْجِعَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Al Mubarak] ia berkata; telah menceritakan kepada kami [Yahya bin Adam] ia berkata; telah menceritakan kepada kami [Ammar bin Zuraiq] dari [Abu Ishaq] dari [Sha'sha'ah bin Shuhan] dari [Ali] -semoga Allah memuliakan wajahnya- ia berkata, \"Nabi shallallahu 'alaihi wasallam melarangku memakai cincin emas, kain yang bersulam sutera, alas pelana yang terbuat dari sutera dan arak yang terbuat dari perahan gandum.\""},"5247":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا عَبْدُ الْوَاحِدِ عَنْ إِسْمَعِيلَ وَهُوَ ابْنُ سُمَيْعٍ قَالَ حَدَّثَنِي مَالِكُ بْنُ عُمَيْرٍ قَالَقَالَ صَعْصَعَةُ لِعَلِيِّ بْنِ أَبِي طَالِبٍ كَرَّمَ اللَّهُ وَجْهَهُ انْهَنَا يَا أَمِيرَ الْمُؤْمِنِينَ عَمَّا نَهَاكَ عَنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَهَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الدُّبَّاءِ وَالْحَنْتَمِ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Abdul Wahid] dari [Isma'il] -yaitu Ibnu Sumai'- ia berkata; telah menceritakan kepadaku [Malik bin Umair] ia berkata; Sha'sha'ah berkata kepada [Ali bin Abu Thalib] -semoga Allah memuliakan wajahnya-, \"Wahai Amirul Mukminin, laranglah kami dari sesuatu yang Rasulullah shallallahu 'alaihi wasallam telah melarangnya darimu!\" Ali bin Abu Thalib berkata, \"Rasulullah shallallahu 'alaihi wasallam melarangku dari Ad Duba dan Al Hantam.\" "},"5248":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُنْبَذُ لَهُ فِي تَوْرٍ مِنْ حِجَارَةٍ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Abu Awanah] dari [Abu Az Zubair] dari [Jabir] berkata, \"Nabi shallallahu 'alaihi wasallam biasa dibuatkan perasan dalam wadah besar yang terbuat dari batu.\""},"5249":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ طَاوُسٍ قَالَقَالَ رَجُلٌ لِابْنِ عُمَرَ أَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ نَبِيذِ الْجَرِّ قَالَ نَعَمْقَالَ طَاوُسٌ وَاللَّهِ إِنِّي سَمِعْتُهُ مِنْهُ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Sulaiman At Taimi] dari [Thawus] ia berkata, \"Seorang laki-laki bertanya [Ibnu Umar], \"Apakah Rasulullah shallallahu 'alaihi wasallam melarang membuat perasan dalam guci (tembikar)?\" ia menjawab, \"Benar\". Thawus berkata, \"Demi Allah, aku mendengarnya dari dia.\""},"5250":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ زَيْدِ بْنِ يَزِيدَ بْنِ أَبِي الزَّرْقَاءِ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ التَّيْمِيِّ وَإِبْرَاهِيمَ بْنِ مَيْسَرَةَ قَالَا سَمِعْنَا طَاوُسًا يَقُولُجَاءَ رَجُلٌ إِلَى ابْنِ عُمَرَ قَالَ أَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ نَبِيذِ الْجَرِّ قَالَ نَعَمْ زَادَ إِبْرَاهِيمُ فِي حَدِيثِهِ وَالدُّبَّاءِ","id":"Telah mengabarkan kepada kami [Harun bin Zaid bin Yazid bin Abu Az Zarqa] ia berkata; telah menceritakan kepadaku [Bapakku] ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Sulaiman At Taimi] dan [Ibrahim bin Maisarah] keduanya berkata; Kami mendengar [Thawus] berkata, \"Seorang laki-laki datang kepada [Ibnu Umar] dan bertanya, \"Apakah Rasulullah shallallahu 'alaihi wasallam melarang membuat perasan dalam guci (tembikar)?\" ia menjawab, \"Benar.\" Ibrahim menambahkan dalam haditsnya, \"Dan Ad Duba.\""},"5251":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ عُيَيْنَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ قَالَ قَالَ ابْنُ عَبَّاسٍنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ نَبِيذِ الْجَرِّ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah menceritakan kepada kami [Abdullah] dari [Uyainah bin 'Abdurrahman] dari [Bapaknya] ia berkata; [Ibnu Abbas] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang perasan dalam guci (tembikar).\""},"5252":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ الْحُسَيْنِ قَالَ حَدَّثَنَا أُمَيَّةُ عَنْ شُعْبَةَ عَنْ جَبَلَةَ بْنِ سُحَيْمٍ عَنْ ابْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْحَنْتَمِقُلْتُ مَا الْحَنْتَمُ قَالَ الْجَرُّ","id":"Telah mengabarkan kepada kami [Ali bin Al Husain] ia berkata; telah menceritakan kepada kami [Umayyah] dari [Syu'bah] dari [Jabalah bin Suhaim] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang dari Al Hantam.\" Aku bertanya, \"Al hantam itu apa? ' ia menjawab, \"Guci dari tembikar.\""},"5253":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي مَسْلَمَةَ قَالَ سَمِعْتُ عَبْدَ الْعَزِيزِ يَعْنِي ابْنَ أَسِيدٍ الطَّاحِيَّ بَصْرِيٌّ يَقُولُسُئِلَ ابْنُ الزُّبَيْرِ عَنْ نَبِيذِ الْجَرِّ قَالَ نَهَانَا عَنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] ia berkata; telah menceritakan kepada kami [Khalid] ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu Salamah] ia berkata; Aku mendengar [Abdul Aziz] -yaitu Asid Ath Thahi seorang dari Bashrah- ia berkata, \" [Ibnu Zubair] pernah ditanya tentang perasan yang dibuat dalam guci tembikar, ia menjawab, \"Rasulullah shallallahu 'alaihi wasallam telah melarang kami darinya.\""},"5254":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ عَلِيِّ بْنِ سُوَيْدِ بْنِ مَنْجُوفٍ قَالَ حَدَّثَنَا عَبْدُ الر��َحْمَنِ بْنُ مَهْدِيٍّ عَنْ هِشَامِ بْنِ أَبِي عَبْدِ اللَّهِ عَنْ أَيُّوبَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَسَأَلْنَا ابْنَ عُمَرَ عَنْ نَبِيذِ الْجَرِّ فَقَالَ حَرَّمَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَفَأَتَيْتُ ابْنَ عَبَّاسٍ فَقُلْتُ سَمِعْتُ الْيَوْمَ شَيْئًا عَجِبْتُ مِنْهُ قَالَ مَا هُوَ قُلْتُ سَأَلْتُ ابْنَ عُمَرَ عَنْ نَبِيذِ الْجَرِّ فَقَالَ حَرَّمَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ صَدَقَ ابْنُ عُمَرَ قُلْتُ مَا الْجَرُّ قَالَ كُلُّ شَيْءٍ مِنْ مَدَرٍ","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah bin Ali bin Suwaid bin Manjuf] ia berkata; telah menceritakan kepada kami ['Abdurrahman bin Mahdi] dari [Hisyam bin Abu Abdullah] dari [Ayyub] dari [Sa'id bin Jubair] ia berkata, \"Kami bertanya [Ibnu Umar] tentang perasan yang dibuat dalam guci tembikar, ia menjawab, \"Rasulullah shallallahu 'alaihi wasallam telah melarangnya.\" Lalu aku datangi [Ibnu Abbas] dan berkata, \"Hari ini aku telah mendengar sesuatu yang membuatku kaget!\" Ibnu Abbas bertanya, \"Apa itu?\" Aku menjawab, \"Aku bertanya Ibnu Umar tentang perasan yang dibuat dalam guci tembikar, lalu ia menjawab bahwa Rasulullah shallallahu 'alaihi wasallam telah melarangnya.\" Ibnu Abbas berkata, \"Ibnu Umar benar.\" Aku bertanya, \"Guci tembikar itu apa?\" Ibnu Abbas menjawab, \"Segala sesuatu yang dibuat dari tanah liat.\""},"5255":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ زُرَارَةَ أَنْبَأَنَا إِسْمَعِيلُ عَنْ أَيُّوبَ عَنْ رَجُلٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَكُنْتُ عِنْدَ ابْنِ عُمَرَ فَسُئِلَ عَنْ نَبِيذِ الْجَرِّ فَقَالَ حَرَّمَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَوَشَقَّ عَلَيَّ لَمَّا سَمِعْتُهُ فَأَتَيْتُ ابْنَ عَبَّاسٍ فَقُلْتُ أَنَّ ابْنَ عُمَرَ سُئِلَ عَنْ شَيْءٍ فَجَعَلْتُ أُعَظِّمُهُ قَالَ مَا هُوَ قُلْتُ سُئِلَ عَنْ نَبِيذِ الْجَرِّ فَقَالَ صَدَقَ حَرَّمَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ وَمَا الْجَرُّ قَالَ كُلُّ شَيْءٍ صُنِعَ مِنْ مَدَرٍ","id":"Telah mengabarkan kepada kami [Amru bin Zurarah] berkata, telah memberitakan kepada kami [Isma'il] dari [Ayyub] dari [Seorang laki-laki] dari [Sa'id bin Jubair] ia berkata, \"Aku pernah di sisi [Ibnu Umar], lalu ia ditanya tentang perasan yang dibuat dalam guci tembikar. Ibnu Umar lalu menjawab, 'Rasulullah shallallahu 'alaihi wasallam telah melarangnya.' Aku agak keberatan saat mendengar jawaban itu, maka aku mendatangi [Ibnu Abbas] dan aku katakan kepadanya bahwa Ibnu Umar pernah ditanya tentang sesuatu, dan aku menganggapnya sebagai masalah yang besar. Ibnu Abbas bertanya, \"Apa sesuatu itu?\" Aku menjawab, \"Ia pernah ditanya tentang perasan dalam guci tembikar.\" Ibnu Abbas berkata, \"Ia benar, Rasulullah shallallahu 'alaihi wasallam telah melarangnya.\" Aku bertanya, \"Guci tembikar itu apa?\" Ia menjawab, \"Segala sesuatu yang dibuat dari tanah liat.\""},"5256":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ الشَّيْبَانِيِّ قَالَ سَمِعْتُ ابْنَ أَبِي أَوْفَى يَقُولُنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ نَبِيذِ الْجَرِّ الْأَخْضَرِقُلْتُ فَالْأَبْيَضُ قَالَ لَا أَدْرِي","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] ia berkata; telah menceritakan kepada kami [Abu Dawud] ia berkata; telah memberitakan kepada kami [Syu'bah] dari [Asy Syaibani] ia berkata; Aku mendengar [Ibnu Abu Aufa] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang perasan (yang dibuat dalam) guci tembikar yang berwarna hijau.\" Aku bertanya, \"Bagaimana dengan yang berwarna putih?\" ia menjawab, \"Aku tidak tahu.\""},"5257":{"ar":"أَخْبَرَنَا أَبُو عَبْد الرَّحْمَنِ قَالَ أَنْبَأَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا أَبُو إِسْحَقَ الشَّيْبَانِيُّ قَالَ سَمِعْتُ ابْنَ أَبِي أَوْفَى يَقُولُنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ نَبِيذِ الْجَرِّ الْأَخْضَرِ وَالْأَبْيَضِ","id":"Telah mengabarkan kepada kami Abu 'Abdurrahman ia berkata; telah memberitakan kepada kami [Muhammad bin Manshur] ia berkata; telah menceritakan kepada kami [Sufyan] ia berkata; telah menceritakan kepada kami [Abu Ishaq Asy Syaibani] ia berkata; Aku mendengar [Ibnu Abu Aufa] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang perasan yang dibuat dalam guci tembikar yang berwarna hijau dan putih.\""},"5258":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي رَجَاءٍ قَالَسَأَلْتُ الْحَسَنَ عَنْ نَبِيذِ الْجَرِّ أَحَرَامٌ هُوَ قَالَ حَرَامٌ قَدْ حَدَّثَنَا مَنْ لَمْ يَكْذِبْ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ نَبِيذِ الْحَنْتَمِ وَالدُّبَّاءِ وَالْمُزَفَّتِ وَالنَّقِيرِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] ia berkata; telah menceritakan kepada kami [Muhammad] berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu Raja] ia berkata; Aku bertanya [Al Hasan] tentang perasan yang dibuat dalam guci tembikar, apakah ia haram?\" ia menjawab, \"Ia haram. Hal ini telah diceritakan oleh [seseorang yang tidak berbohong], bahwa Rasulullah shallallahu 'alaihi wasallam telah melarang perasan dalam Al hantam, Ad Duba, Al Muzaffat dan An Naqir.\" "},"5259":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ إِبْرَاهِيمَ بْنِ مَيْسَرَةَ عَنْ طَاوُسٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الدُّبَّاءِ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] ia berkata; telah menceritakan kepada kami [Abu Dawud] ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Ibrahim bin Maisarah] dari [Thawus] dari [Ibnu Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang dari Ad Duba (bejana yang terbuat dari buah labu).\""},"5260":{"ar":"أَخْبَرَنَا جَعْفَرُ بْنُ مُسَافِرٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ حسَّانَ قَالَ حَدَّثَنَا وُهَيْبٌ قَالَ حَدَّثَنَا ابْنُ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الدُّبَّاءِ","id":"Telah mengabarkan kepada kami [Ja'far bin Musafir] ia berkata; telah menceritakan kepada kami [Yahya bin Hassan] ia berkata; telah menceritakan kepada kami [Wuhaib] ia berkata; telah menceritakan kepada kami [Ibnu Thawus] dari [Bapaknya] dari [Ibnu Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang dari Ad Duba (bejana yang terbuat dari buah labu).\""},"5261":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ وَحَمَّادٌ وَسُلَيْمَان�� عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الدُّبَّاءِ وَالْمُزَفَّتِ","id":"Telah mengabarkan kepada kami [Muhammad Ibnul Mutsanna] ia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] ia berkata; telah menceritakan kepada kami [Sufyan] dari [Manshur] dan [Hammad] dan [Sulaiman] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang Ad Duba dan Al Muzaffat.\" "},"5262":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ عَنْ سُلَيْمَانَ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ الْحَارِثِ بْنِ سُوَيْدٍ عَنْ عَلِيٍّ كَرَّمَ اللَّهُ وَجْهَهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى عَنْ الدُّبَّاءِ وَالْمُزَفَّتِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] ia berkata; telah menceritakan kepada kami [Yahya] dari [Sufyan] dari [Sulaiman] dari [Ibrahim At Taimi] dari [Al Harits bin Suwaid] dari [Ali] -semoga Allah memuliakan wajahnya-, dari nabi shallallahu 'alaihi wasallam, bahwasanya beliau melarang Ad Duba dan Al Muzaffat.\" "},"5263":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ أَبَانَ قَالَ حَدَّثَنَا شَبَابَةُ بْنُ سَوَّارٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ بُكَيْرِ بْنِ عَطَاءٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَعْمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الدُّبَّاءِ وَالْمُزَفَّتِ","id":"Telah mengabarkan kepada kami [Muhammad bin Aban] ia berkata; telah menceritakan kepada kami [Syababah bin Sawwar] ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Bukair bin 'Atha] dari ['Abdurrahman bin Ya'mar] dari Nabi shallallahu 'alaihi wasallam, bahwasanya beliau melarang Ad Duba dan Al Muzaffat.\" "},"5264":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّهُ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الدُّبَّاءِ وَالْمُزَفَّتِ أَنْ يُنْبَذَ فِيهِمَا","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari [Anas bin Malik], bahwasanya ia mengabarkan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam melarang membuat perasan dalam Ad Duba dan Al Muzaffat.\" "},"5265":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا الزُّهْرِيُّ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الدُّبَّاءِ وَالْمُزَفَّتِ أَنْ يُنْبَذَ فِيهِمَا","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] ia berkata; telah menceritakan kepada kami [Sufyan] ia berkata; telah menceritakan kepada kami [Az Zuhri] ia berkata; telah mengabarkan kepadaku [Abu Salamah] bahwasanya ia mendengar [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang membuat perasaan dalam Ad Duba dan Al Muzaffat.\" "},"5266":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ أَخْبَرَنِي نَافِعٌ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْمُزَفَّتِ وَالْقَرْعِ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Sa'id] ia berkata; telah menceritakan kepada kami [Yahya] dari [Ubaidullah] ia berkata; telah mengabarkan kepadaku [Nafi'] dari [Ibnu Umar], bahwa Rasulullah shallallahu 'alaihi wasallam melarang Al Muzaffat dab Qar' (sejenis labu).\" "},"5267":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ الْحَكَمِ بْنِ فَرْوَةَ يُقَالُ لَهُ ابْنُ كُرْدِيٍّ بَصْرِيٌّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْخَالِقِ الشَّيْبَانِيِّ قَالَ سَمِعْتُ سَعِيدًا يُحَدِّثُ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الدُّبَّاءِ وَالْحَنْتَمِ وَالنَّقِيرِ","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah bin Al Hakam bin Farwah] -di dipanggil dengan nama Ibnu Kurdi, seorang dari Bashrah- ia berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Abdul Khaliq Asy Syaibani] ia berkata, \"Aku mendengar [Sa'id] menceritakan dari [Ibnu Umar], bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari Ad Duba, Al Hantam dan An Naqir.\" "},"5268":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ الْمُثَنَّى بْنِ سَعِيدٍ عَنْ أَبِي الْمُتَوَكِّلِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الشُّرْبِ فِي الْحَنْتَمِ وَالدُّبَّاءِ وَالنَّقِيرِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Al Mutsanna bin Sa'id] dari [Abu Al Mutawakkil] dari [Abu Sa'id Al Khudri] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang minuman dalam Al hantam, Ad Duba dan An Naqir.\" "},"5269":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ شُعْبَةَ عَنْ مُحَارِبٍ قَالَ سَمِعْتُ ابْنَ عُمَرَ يَقُولُنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الدُّبَّاءِ وَالْحَنْتَمِ وَالْمُزَفَّتِ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Syu'bah] dari [Muharib] ia berkata; Aku mendengar [Ibnu Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang dari Ad Duba, Al Hantam dan Al Muzaffat.\" "},"5270":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ الْأَوْزَاعِيِّ قَالَ حَدَّثَنِي يَحْيَى حَدَّثَنِي أَبُو سَلَمَةَ قَالَ حَدَّثَنِي أَبُو هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْجِرَارِ وَالدُّبَّاءِ وَالظُّرُوفِ الْمُزَفَّتَةِ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Al Auza'i] ia berkata; telah menceritakan kepadaku [Yahya] berkata, telah menceritakan kepadaku [Abu Salamah] ia berkata; telah menceritakan kepadaku [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang dari guci tembikar, Ad Duba dan wadah Al Muzaffat.\" "},"5271":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ عَوْنِ بْنِ صَالِحٍ الْبَارِقيِّ عَنْ زَيْنَبَ بِنْتِ نَصْرٍ وَجُمَيْلَةَ بِنْتِ عَبَّادٍ أَنَّهُمَا سَمِعَتَا عَائِشَةَ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْ شَرَابٍ صُنِعَ فِي دُبَّاءٍ أَوْ حَنْتَمٍ أَوْ مُزَفَّتٍ لَا يَكُونُ زَيْتًا أَوْ خَلًّا","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Aun bin Shalih Al Baqi] dari [Zainab binti Nahsr] dan [Jumailah binti Abbad] bahwa keduanya mendengar ['Aisyah] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam melarang minuman yang dibuat dalam Ad Duba, atau Al Hantam, atau Al Muzaffat; yang tidak menjadi minyak atau cuka.\" "},"5272":{"ar":"أَخْبَرَنَا قُرَيْشُ بْنُ عَبْدِ الرَّحْمَنِ قَالَ أَنْبَأَنَا عَلِيُّ بْنُ الْحَسَنِ قَالَ أَنْبَأَنَا الْحُسَيْنُ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ زِيَادٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الدُّبَّاءِ وَالْحَنْتَمِ وَالنَّقِيرِ وَالْمُزَفَّتِ","id":"Telah mengabarkan kepada kami [Quraiys bin 'Abdurrahman] ia berkata; telah memberitakan kepada kami [Ali bin Al Hasan] ia berkata; telah memberitakan kepada kami [Al Husain] ia berkata; telah menceritakan kepadaku [Muhammad bin Ziyad] ia berkata; Aku mendengar [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang Ad Duba, Al Hantam, An Naqir dan Al Muzaffat.\" "},"5273":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ الْقَاسِمِ بْنِ الْفَضْلِ قَالَ حَدَّثَنَا ثُمَامَةُ بْنُ حَزْنٍ الْقُشَيْرِيُّ قَالَلَقِيتُ عَائِشَةَ فَسَأَلْتُهَا عَنْ النَّبِيذِ فَقَالَتْ قَدِمَ وَفْدُ عَبْدِ الْقَيْسِ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلُوهُ فِيمَا يَنْبِذُونَ فَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَنْبِذُوا فِي الدُّبَّاءِ وَالنَّقِيرِ وَالْمُقَيَّرِ وَالْحَنْتَمِ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Al Qasim bin Al Fadll] ia berkata; telah menceritakan kepada kami [Tsumamah bin Hazn Al Qurasyi] ia berkata, \"Aku pernah bertemu ['Aisyah] lalu aku tanyakan kepadanya tentang perasan nabidz (arak). Ia lantas berkata, \"Utusan Abdu Qais pernah datang menemui Rasulullah shallallahu 'alaihi wasallam, mereka bertanya beliau tentang perasan nabidz yang mereka buat, lalu Nabi shallallahu 'alaihi wasallam melarang mereka untuk membuatnya dalam Ad Duba, An Naqir, Al Muqayyar dan Al Hantam.\" "},"5274":{"ar":"أَخْبَرَنَا زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا ابْنُ عُلَيَّةَ قَالَ حَدَّثَنَا إِسْحَقُ بْنُ سُوَيْدٍ عَنْ مُعَاذَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْنَهَى عَنْ الدُّبَّاءِ بِذَاتِهِ","id":"Telah mengabarkan kepada kami [Ziyad bin Ayyub] ia berkata; telah menceritakan kepada kami [Ibnu Ulayyah] ia berkata; telah menceritakan kepada kami [Ishaq bin Suwaid] dari [Mu'adzah] dari ['Aisyah? radliallahu 'anhuma] ia berkata, \"Beliau murni melarang Ad Duba.\" "},"5275":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ إِسْحَقَ وَهُوَ ابْنُ سُوَيْدٍ يَقُولُ حَدَّثَتْنِي مُعَاذَةُ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ نَبِيذِ النَّقِيرِ وَالْمُقَيَّرِ وَالدُّبَّاءِ وَالْحَنْتَمِفِي حَدِيثِ ابْنِ عُلَيَّةَ قَالَ إِسْحَقُ وَذَكَرَتْ هُنَيْدَةُ عَنْ عَائِشَةَ مِثْلَ حَدِيثِ مُعَاذَةَ وَسَمَّتْ الْجِرَارَ قُلْتُ لِهُنَيْدَةَ أَنْتِ سَمِعْتِيهَا سَمَّتْ الْجِرَارَ قَالَتْ نَعَمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] ia berkata; telah menceritakan kepada kami [Al Mu'tamir] ia berkata; aku mendengar [Ishaq] -yaitu Ibnu Suwaid- ia berkata; telah menceritakan kepadaku [Mu'adzah] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang perasan nabidz yang dibuat dalam An Naqir, Al Muqayyar, Ad Duba dan Al Hantam.\" Dalam hadits [Ibnu Ulayyah], [Ishaq] berkata, \" [Hunaidah] menyebutkan dari ['Aisyah] seperti dalam hadits Mu'adzah, dan ia menyebutnya dengan lafadz Al Jirar.\" Aku bertanya kepada Hunaidah, \"Apakah engkau mendengarnya ('Aisyah) menyebut Al Jirar (Guci tembikar)?\" ia menjawab, \"Ya.\""},"5276":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ طَوْدِ بْنِ عَبْدِ الْمَلِكِ الْقَيْسِيِّ بَصْرِيٌّ قَالَ حَدَّثَنِي أَبِي عَنْ هُنَيْدَةَ بِنْتِ شَرِيكِ بْنِ أَبَانَ قَالَتْلَقِيتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا بِالْخُرَيْبَةِ فَسَأَلْتُهَا عَنْ الْعَكَرِ فَنَهَتْنِي عَنْهُ وَقَالَتْ انْبِذِي عَشِيَّةً وَاشْرَبِيهِ غُدْوَةً وَأَوْكِي عَلَيْهِ وَنَهَتْنِي عَنْ الدُّبَّاءِ وَالنَّقِيرِ وَالْمُزَفَّتِ وَالْحَنْتَمِ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Thaud bin Abdul Malik Al Qaisi] seorang yang berasal dari Bashrah, ia berkata; telah menceritakan kepadaku [Bapakku] dari [Hunaidah binti Syarik bin Aban] ia berkata, \"Aku bertemu ['Aisyah]? radliallahu 'anhuma di Khuraibah, lalu aku bertanya kepadanya tentang Al 'Akar (sisa-sisa khamer dalam guci), ia lalu melarangku darinya. Kemudian ia berkata, 'Peraslah di malam hari, lalu minumlah di pagi menjelang siang, serta tutuplah mulut gucinya.' Dan ia melarang kami dari Ad Duba, An Naqir, Al Muzaffat dan Al Hantam.\" "},"5277":{"ar":"أَخْبَرَنَا زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا ابْنُ إِدْرِيسَ قَالَ سَمِعْتُ الْمُخْتَارَ بْنَ فُلْفُلٍ عَنْ أَنَسٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الظُّرُوفِ الْمُزَفَّتَةِ","id":"Telah mengabarkan kepada kami [Ziyad bin Ayyub] ia berkata; telah menceritakan kepada kami [Ibnu Idris] ia berkata; aku mendengar [Al Mukhtar bin Fulful] dari [Anas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang dari wadah Al Muzaffat (bejana yang dicat dengan ter).\""},"5278":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ حَدَّثَنَا مَنْصُورُ بْنُ حَيَّانَ سَمِعَ سَعِيدَ بْنَ جُبَيْرٍ يُحَدِّثُ أَنَّهُ سَمِعَ ابْنَ عُمَرَ وَابْنَ عَبَّاسٍأَنَّهُمَا شَهِدَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى عَنْ الدُّبَّاءِ وَالْحَنْتَمِ وَالْمُزَفَّتِ وَالنَّقِيرِ ثُمَّ تَلَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذِهِ الْآيَةَ{ وَمَا آتَاكُمْ الرَّسُولُ فَخُذُوهُ وَمَا نَهَاكُمْ عَنْهُ فَانْتَهُوا }","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] ia berkata; telah menceritakan kepada kami [Yazid bin Harun] ia berkata; telah menceritakan kepada kami [Manshur bin Hayyan] ia mendengar [Sa'id bin Jubair] menceritakan bahwasanya ia mendengar [Ibnu Umar] dan [Ibnu Abbas] bersaksi atas Rasulullah shallallahu 'alaihi wasallam, bahwa beliau melarang dari Ad Duba, Al Hantam, Al Muzaffat dan An Naqir. Kemudian Rasulullah shallallahu 'alaihi wasallam membaca ayat berikut ini: '(Apa yang diberikan Rasul kepadamu maka terimalah dia. Dan apa yang dilarangnya bagimu maka tinggalkanlah..) ' (Qs. Al Hasyr: 7).\" "},"5279":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَ عَنْ ابْنِ عَمٍّ لَهَا يُقَالُ لَهُ أَنَسٌ قَالَ قَالَ ابْنُ عَبَّاسٍأَلَمْ يَقُلْ اللَّهُ عَزَّ وَجَلَّ{ مَا آتَاكُمْ الرَّسُولُ فَخُذُوهُ وَمَا نَهَاكُمْ عَنْهُ فَانْتَهُوا }قُلْتُ بَلَى قَالَ أَلَمْ يَقُلْ اللَّهُ{ وَمَا كَانَ لِمُؤْمِنٍ وَلَا مُؤْمِنَةٍ إِذَا قَضَى اللَّهُ وَرَسُولُهُ أَمْرًا أَنْ يَكُونَ لَهُمْ الْخِيَرَةُ مِنْ أَمْرِهِمْ }قُلْتُ بَلَى قَالَ فَإِنِّي أَشْهَدُ أَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ النَّقِيرِ وَالْمُقَيَّرِ وَالدُّبَّاءِ وَالْحَنْتَمِ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Sulaiman At Taimi] dari [Asma binti Yazid] dari anak pamannya yang dipanggil [Anas] ia berkata; [Ibnu Abbas] berkata, \"Bukankah Allah telah mengatakan: '(Apa yang diberikan Rasul kepadamu maka terimalah dia. Dan apa yang dilarangnya bagimu maka tinggalkanlah..) '? (Qs. Al Hasyr: 7), aku menjawab, \"Benar.\" Ibnu Abbas berkata lagi, \"Bukankah Allah telah mengatakan: '(Dan tidaklah patut bagi laki-laki yang Mukmin dan tidak (pula) bagi perempuan yang Mukmin, apabila Allah dan Rasul-Nya telah menetapkan suatu ketetapan, akan ada bagi mereka pilihan (yang lain) tentang urusan mereka..)? (Qs. Al Hasyr: 36), aku menjawab, \"Benar.\" Ibnu Abbas lantas berkata, \"Sesungguhnya aku bersaksi bahwa Nabi Allah shallallahu 'alaihi wasallam melarang An Naqir, Al Muqayyar, Ad Duba dan Al Hantam.\" "},"5280":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ يَزِيدَ قَالَ حَدَّثَنَا بَهْزُ بْنُ أَسَدٍ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي عَمْرُو بْنُ مُرَّةَ قَالَ سَمِعْتُ زَاذَانَ قَالَ سَأَلْتُ عَبْدَ اللَّهِ بْنَ عُمَرَقُلْتُ حَدِّثْنِي بِشَيْءٍ سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْأَوْعِيَةِ وَفَسِّرْهُ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْحَنْتَمِ وَهُوَ الَّذِي تُسَمُّونَهُ أَنْتُمْ الْجَرَّةَ وَنَهَى عَنْ الدُّبَّاءِ وَهُوَ الَّذِي تُسَمُّونَهُ أَنْتُمْ الْقَرْعَ وَنَهَى عَنْ النَّقِيرِ وَهِيَ النَّخْلَةُ يَنْقُرُونَهَا وَنَهَى عَنْ الْمُزَفَّتِ وَهُوَ الْمُقَيَّرُ","id":"Telah mengabarkan kepada kami [Amru bin Yazid] ia berkata; telah menceritakan kepada kami [Bahz bin Asad] berkata, telah menceritakan kepada kami [Syu'bah] ia berkata; telah mengabarkan kepadaku [Amru bin Murrah] ia berkata; Aku mendengar [Zadzan] berkata; Aku bertanya [Abdullah bin Umar], aku katakan, \"Ceritakan dan jelaskanlah kepadaku tentang sesuatu yang pernah engkau dengar dari Rasulullah shallallahu 'alaihi wasallam mengenai perkakas?! Abdullah bin Umar menjawab, \"Rasulullah shallallahu 'alaihi wasallam melarang Al hantam, yakni wadah yang kalian sebut dengan Al Jarrah (guci dari tembikar); melarang Ad Duba, yakni wadah yang kalian sebut dengan Al Qar'u (wadah dari buah labu); melarang An Naqir, yaitu batang kurma yang biasa kalian lubangi bagian tengahnya. Dan beliau juga melarang dari Al Muzaffat, yakni Al Muqayyar (bejana yang dibuat dicat dengan ter).\""},"5281":{"ar":"أَخْبَرَنَا سَوَّارُ بْنُ عَبْدِ اللَّهِ بْنِ سَوَّارٍ قَالَ حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنِ عَبْدِ الْمَجِيدِ عَنْ هِشَامٍ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفْدَ عَبْدِ الْقَيْسِ حِينَ قَدِمُوا عَلَيْهِ عَنْ الدُّبَّاءِ وَعَنْ النَّقِيرِ وَعَنْ الْمُزَفَّتِ وَالْمَزَادَةِ الْمَجْبُوبَةِ وَقَالَ انْتَبِذْ فِي سِقَائِكَ أَوْكِهِ وَاشْرَبْهُ حُلْوًا قَالَ بَعْضُهُمْ ائْذَنْ لِي يَا رَسُولَ اللَّهِ فِي مِثْلِ هَذَا قَالَ إِذًا تَجْعَلَهَا مِثْلَ هَذِهِ وَأَشَارَ بِيَدِهِ يَصِفُ ذَلِكَ","id":"Telah mengabarkan kepada kami [Sawwar bin Abdullah bin Sawwar] ia berkata; telah menceritakan kepada kami [Abdul Wahhab bin Abdul Majid] dari [Hisyam] dari [Muhammad] dari [Abu Hurairah] ia berkata, \"Ketika utusan Abdu Qais datang menemui Rasulullah shallallahu 'alaihi wasallam, beliau melarang mereka dari Ad Duba, An Naqir, Al Muzaffat dan Muzadah Al Majbubah (semacam gentong yang tidak ada tutupnya).\" Beliau mengatakan: \"Buatlah perasan dalam wadah air minum kalian, ikat bagian atasnya dan minumlah saat masih manis.\" Sebagian sahabat berkata, \"Wahai Rasulullah, izinkanlah kami membuat perasan dalam wadah seperti itu!\" beliau bersabda: \"Kalau begitu buatlah seperti itu, \" seraya memberi isyarat kepada mereka.\" "},"5282":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ ابْنِ جُرَيْجٍ قِرَاءَةً قَالَ وَقَالَ أَبُو الزُّبَيْرِ سَمِعْتُ جَابِرًا يَقُولُنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْجَرِّ وَالْمُزَفَّتِ وَالدُّبَّاءِ وَالنَّقِيرِ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا لَمْ يَجِدْ سِقَاءً يُنْبَذْ لَهُ فِيهِ نُبِذَ لَهُ فِي تَوْرٍ مِنْ حِجَارَةٍ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Ibnu Juraij] secara bacaan, ia berkata; [Abu Az Zubair] berkata; Aku mendengar [Jabir] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang Al Jarr (guci tembikar), Al Muzaffat, Ad Duba dan An Naqir. Dan jika Nabi shallallahu 'alaihi wasallam tidak mendapatkan wadah air minum yang bisa digunakan untuk membuat perasan, beliau membuatlah dalam wadah dari batu.\" "},"5283":{"ar":"أَخْبَرَنِي أَحْمَدُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا إِسْحَقُ يَعْنِي الْأَزْرَقَ قَالَ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ أَبِي سُلَيْمَانَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُنْبَذُ لَهُ فِي سِقَاءٍ فَإِذَا لَمْ يَكُنْ لَهُ سِقَاءٌ نَنْبِذُ لَهُ فِي تَوْرِ بِرَامٍ قَالَ وَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الدُّبَّاءِ وَالنَّقِيرِ وَالْمُزَفَّتِ","id":"Telah mengabarkan kepadaku [Ahmad bin Khalid] ia berkata; telah menceritakan kepada kami [Ishaq] -yaitu Al Azraq- ia berkata; telah menceritakan kepada kami [Abdul Malik bin Abu Sulaiman] dari [Abu Az Zubair] dari [Jabir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam biasa dibuatkan perasan nabidz dalam wadah air minum, jika kami tidak mendapatkan wadah air minum, kami membuatkannya dalam wadah dari batu.\" Jabir berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang Ad Duba, An Naqir dan Al Muzaffat.\" "},"5284":{"ar":"أَخْبَرَنَا سَوَّارُ بْنُ عَبْدِ اللَّهِ بْنِ سَوَّارٍ قَالَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ قَالَ حَدَّثَنَا عَبْدُ الْمَلِكِ قَالَ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الدُّبَّاءِ وَالنَّقِيرِ وَالْجَرِّ وَالْمُزَفَّتِ","id":"Telah mengabarkan kepada kami [Sawwar bin Abdullah bin Sawwar] ia berkata; telah menceritakan kepada kami [Khalid Ibnul Harits] ia berkata; telah menceritakan kepada kami [Abdul Malik] ia berkata; telah menceritakan kepada kami [Abu Az Zubair] dari [Jabir? radliallahu 'anhu] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang Ad duba, An Naqir, Al Jarr dan Al Muzaffat.\" "},"5285":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا سُلَيْمَانُ الْأَحْوَلُ عَنْ مُجَاهِدٍ عَنْ أَبِي عِيَاضٍ عَنْ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ فِي الْجَرِّ غَيْرَ مُزَفَّتٍ","id":"Telah mengabarkan kepada kami [Ibrahim bin Sa'id] ia berkata; telah menceritakan kepada kami [Sufyan] ia berkata; telah menceritakan kepada kami [Sulaiman Al Ahwal] dari [Mujahid] dari [Abu Iyadl] dari [Abdullah], bahwa Nabi shallallahu 'alaihi wasallam memberi keringanan untuk menggunakan Al Jarr (guci dari tembikar), bukan Muzaffat.\" "},"5286":{"ar":"أَخْبَرَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ عَنْ الْأَحْوَصِ بْنِ جَوَّابٍ عَنْ عَمَّارِ بْنِ رُزَيْقٍ أَنَّهُ حَدَّثَهُمْ عَنْ أَبِي إِسْحَقَ عَنْ الزُّبَيْرِ بْنِ عَدِيٍّ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي كُنْتُ نَهَيْتُكُمْ عَنْ لُحُومِ الْأَضَاحِيِّ فَتَزَوَّدُوا وَادَّخِرُوا وَمَنْ أَرَادَ زِيَارَةَ الْقُبُورِ فَإِنَّهَا تُذَكِّرُ الْآخِرَةَ وَاشْرَبُوا وَاتَّقُوا كُلَّ مُسْكِرٍ","id":"Telah mengabarkan kepada kami [Al Abbas bin Abdul Azhim] dari [Al Ahwash bin Jawwab] dari [Ammar bin Zuraiq] bahwasanya ia menceritakan kepada mereka dari [Ishaq] dari [Az Zubair bin Adi] dari [Ibnu Buraidah] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dahulu aku melarang kalian makan daging sembilahan (Adlha), sekarang berbekal dan simpanlah. Siapa ingin menziarahi kubur, maka itu akan mengingatkan kepada hari akhirat. Minumlah, dan jauhilah segala sesuatu yang memabukkan.\""},"5287":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ آدَمَ بْنِ سُلَيْمَانَ عَنْ ابْنِ فُضَيْلٍ عَنْ أَبِي سِنَانٍ عَنْ مُحَارِبِ بْنِ دِثَارٍ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي كُنْتُ نَهَيْتُكُمْ عَنْ زِيَارَةِ الْقُبُورِ فَزُورُوهَا وَنَهَيْتُكُمْ عَنْ لُحُومِ الْأَضَاحِيِّ فَوْقَ ثَلَاثَةِ أَيَّامٍ فَأَمْسِكُوا مَا بَدَا لَكُمْ وَنَهَيْتُكُمْ عَنْ النَّبِيذِ إِلَّا فِي سِقَاءٍ فَاشْرَبُوا فِي الْأَسْقِيَةِ كُلِّهَا وَلَا تَشْرَبُوا مُسْكِرًا","id":"Telah mengabarkan kepadaku [Muhammad bin Adam bin Sulaiman] dari [Ibnu Fudlail] dari [Abu Sinan] dari [Muharib bin Ditsar] dari [Abdullah bin Buraidah] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dahulu aku melarang kalian dari ziarah kubur, sekarang berziarahlah. Aku juga pernah melarang kalian dari memakan daging sembelihan (Adlha) lebih dari tiga hari, maka simpanlah yang tampak oleh kalian. Aku juga pernah melarang kalian dari perasan nabidz kecuali dalam wadah air minuman, maka minumlah dari setiap wadah apapun, serta jauhilah sesuatu yang memabukkan.\""},"5288":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْدَانَ بْنِ عِيسَى بْنِ مَعْدَانَ الْحَرَّانِيُّ قَالَ حَدَّثَنَا الْحَسَنُ بْنُ أَعْيَنَ قَالَ حَدَّثَنَا زُهَيْرٌ قَالَ حَدَّثَنَا زُبَيْدٌ عَنْ مُحَارِبٍ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي كُنْتُ نَهَيْتُكُمْ عَنْ ثَلَاثٍ زِيَارَةِ الْقُبُورِ فَزُورُوهَا وَلْتَزِدْكُمْ زِيَارَتُهَا خَيْرًا وَنَهَيْتُكُمْ عَنْ لُحُومِ الْأَضَاحِيِّ بَعْدَ ثَلَاثٍ فَكُلُوا مِنْهَا مَا شِئْتُمْ وَنَهَيْتُكُمْ عَنْ الْأَشْرِبَةِ فِي الْأَوْعِيَةِ فَاشْرَبُوا فِي أَيِّ وِعَاءٍ شِئْتُمْ وَلَا تَشْرَبُوا مُسْكِرًا","id":"Telah mengabarkan kepada kami [Muhammad bin Ma'dan bin Isa bin Ma'dan Al Harrani] ia berkata; telah menceritakan kepada kami [Al Hasan bin A'yun] ia berkata; telah menceritakan kepada kami [Zuhair] ia berkata; telah menceritakan kepada kami [Zubaid] dari [Muharib] dari [Ibnu Buraidah] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku pernah melarang kalian dari tiga hal; ziarah kubur, sekarang berziarahlah, semoga dengan berziarah akan menambah kebaikan. Aku pernah melarang kalian dari memakan daging sembelihan (Adlha) lebih dari tiga hari, sekarang makanlah sesukamu. Dan aku juga pernah melarang kalian dari beberapa minuman dalam beberapa bejana, sekarang minumlah dalam bejana mana saja sesuka kalian, dan jangan minum sesuatu yang memabukkan.\""},"5289":{"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنِ عَلِيٍّ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْحَجَّاجِ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ حَمَّادِ بْنِ أَبِي سُلَيْمَانَ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُنْتُ نَهَيْتُكُمْ عَنْ الْأَوْعِيَةِ فَانْتَبِذُوا فِيمَا بَدَا لَكُمْ وَإِيَّاكُمْ وَكُلَّ مُسْكِرٍ","id":"Telah mengabarkan kepada kami [Abu Bakr bin Ali] ia berkata; telah menceritakan kepada kami [Ibrahim bin Al Hajjaj] ia berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Hammad bin Abu Sulaiman] dari [Abdullah bin Buraidah] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku pernah melarang kalian dari beberapa bejana, sekarang buatlah perasan nabidz pada bejana yang ada pada kalian, dan jauhilah segala sesuatu yang memabukkan.\""},"5290":{"ar":"أَخْبَرَنَا أَبُو عَلِيٍّ مُحَمَّدُ بْنُ يَحْيَى بْنِ أَيُّوبَ مَرْوَزِيٌّ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُثْمَانَ قَالَ حَدَّثَنَا عِيسَى بْنُ عُبَيْدٍ الْكِنْدِيُّ خُرَاسَانِيٌّ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ بُرَيْدَةَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَا هُوَ يَسِيرُ إِذْ حَلَّ بِقَوْمٍ فَسَمِعَ لَهُمْ لَغَطًا فَقَالَ مَا هَذَا الصَّوْتُ قَالُوا يَا نَبِيَّ اللَّهِ لَهُمْ شَرَابٌ يَشْرَبُونَهُ فَبَعَثَ إِلَى الْقَوْمِ فَدَعَاهُمْ فَقَالَ فِي أَيِّ شَيْءٍ تَنْتَبِذُونَ قَالُوا نَنْتَبِذُ فِي النَّقِيرِ وَالدُّبَّاءِ وَلَيْسَ لَنَا ظُرُوفٌ فَقَالَ لَا تَشْرَبُوا إِلَّا فِيمَا أَوْكَيْتُمْ عَلَيْهِ قَالَ فَلَبِثَ بِذَلِكَ مَا شَاءَ اللَّهُ أَنْ يَلْبَثَ ثُمَّ رَجَعَ عَلَيْهِمْ فَإِذَا هُمْ قَدْ أَصَابَهُمْ وَبَاءٌ وَاصْفَرُّوا قَالَ مَا لِي أَرَاكُمْ قَدْ هَلَكْتُمْ قَالُوا يَا نَبِيَّ اللَّهِ أَرْضُنَا وَبِيئَةٌ وَحَرَّمْتَ عَلَيْنَا إِلَّا مَا أَوْكَيْنَا عَلَيْهِ قَالَ اشْرَبُوا وَكُلُّ مُسْكِرٍ حَرَامٌ","id":"Telah mengabarkan kepada kami [Abu Ali Muhammad bin Yahya bin Ayyub Marwazi] ia berkata; telah menceritakan kepada kami [Abdullah bin Utsman] ia berkata; telah menceritakan kepada kami [Isa bin Ubaid Al Kindi Khurasani] ia berkata; aku mendengar [Abdullah bin Buraidah] dari [Bapaknya] berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam sedang berjalan dan melintasi suatu kaum, beliau mendengar kegaduhan mereka. Beliau bertanya: \"Suara apa itu?\" mereka menjawab, \"Wahai Nabi Allah, mereka mempunyai minuman yang biasa mereka minum!\" maka beliau pun mengutus seseorang dan memanggil mereka, beliau lantas bertanya: \"Dalam wadah apa kalian membuat perasan nabidz?\" mereka menjawab, \"Kami membuat perasan nabidz dalam An Naqir dan Ad Duba, sebab kami tidak memiliki tempat lain.\" Beliau bersabda: \"Janganlah kalian minum kecuali pada wadah yang kalian ikat pada tutupnya.\" Buraidah berkata, \"Kemudian pemakaian wadah itu ditinggalkan dalam jangka waktu yang cukup lama, dan ketika beliau datang lagi, mereka telah terjangkit penyakit yang menular hingga wajah mereka tampak pucat. Beliau bersabda: \"Kenapa aku melihat kalian mendapat musibah itu?\" mereka menjawab, \"Wahai Nabi Allah, tanah dan lingkungan kami, dan engkau juga telah mengharamkan atas kami kecuali wadah yang ada tutupnya.\" Beliau bersabda: \"Minumlah, dan setiap minuman yang memabukkan adalah haram.\""},"5291":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا أَبُو دَاوُدَ الْحَفَرِيُّ وَأَبُو أَحْمَدَ الزُّبَيْرِيُّ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ سَالِمٍ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا نَهَى عَنْ الظُّرُوفِ شَكَتْ الْأَنْصَارُ فَقَالَتْ يَا رَسُولَ اللَّهِ لَيْسَ لَنَا وِعَاءٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا إِذًا","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] ia berkata; telah menceritakan kepada kami [Abu Dawud Al Hafari] dan [Abu Ahmad Az Zubairi] dari [Sufyan] dari [Manshur] dari [Salim] dari [Jabir] ia berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam melarang pemakaian beberapa bejana, orang-orang Anshar mengeluh. Mereka berkata, \"Wahai Rasulullah, kami tidak memiliki bejana!\" Nabi shallallahu 'alaihi wasallam kemudian bersabda: \"Kalau begitu tidak apa-apa.\""},"5292":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةَ أُسْرِيَ بِهِ بِقَدَحَيْنِ مِنْ خَمْرٍ وَلَبَنٍ فَنَظَرَ إِلَيْهِمَا فَأَخَذَ اللَّبَنَ فَقَالَ لَهُ جِبْرِيلُ عَلَيْهِ السَّلَام الْحَمْدُ لِلَّهِ الَّذِي هَدَاكَ لِلْفِطْرَةِ لَوْ أَخَذْتَ الْخَمْرَ غَوَتْ أُمَّتُكَ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Yunus] dari [Az Zuhri] dari [Sa'id Ibnul Musayyab] dari [Abu Hurairah] ia berkata, \"Pada malam Rasulullah shallallahu 'alaihi wasallam diisra'kan, dihidangkan kepada beliau dua bejana; khamer dan susu. Lalu beliau memandangi keduanya seraya mengambil bejana yang berisi susu. Jibril 'Alaihis Salam pun berkata, \"Segala puji bagi Allah yang telah menunjukimu kepada fitrah, sekiranya engkau mengambil khamer maka engkau telah menyesatkan umatmu.\""},"5293":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى عَنْ خَالِدٍ وَهُوَ ابْنُ الْحَارِثِ عَنْ شُعْبَةَ قَالَ سَمِعْتُ أَبَا بَكْرِ بْنَ حَفْصٍ يَقُولُ سَمِعْتُ ابْنَ مُحَيْرِيزٍ يُحَدِّثُ عَنْ رَجُلٍ مَنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَشْرَبُ نَاسٌ مِنْ أُمَّتِي الْخَمْرَ يُسَمُّونَهَا بِغَيْرِ اسْمِهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] dari [Khalid] -yaitu Ibnul Harits- dari [Syu'bah] ia berkata; Aku mendengar [Abu Bakr bin Hafsh] berkata; Aku mendengar [Ibnu Muhairiz] menceritakan dari [seorang laki-laki] sahabat Nabi shallallahu 'alaihi wasallam, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Akan ada orang-orang dari umatku yang minum khamer, mereka akan menamainya dengan selain namanya.\""},"5294":{"ar":"أَخْبَرَنَا عِيسَى بْنُ حَمَّادٍ قَالَ أَنْبَأَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَزْنِي الزَّانِي حِينَ يَزْنِي وَهُوَ مُؤْمِنٌ وَلَا يَشْرَبُ الْخَمْرَ شَارِبُهَا حِينَ يَشْرَبُهَا وَهُوَ مُؤْمِنٌ وَلَا يَسْرِقُ السَّارِقُ حِينَ يَسْرِقُ وَهُوَ مُؤْمِنٌ وَلَا يَنْتَهِبُ نُهْبَةً يَرْفَعُ النَّاسُ إِلَيْهِ فِيهَا أَبْصَارَهُمْ حِينَ يَنْتَهِبُهَا وَهُوَ مُؤْمِنٌ","id":"Telah mengabarkan kepada kami [Isa bin Hammad] ia berkata; telah memberitakan kepada kami [Al Laits] dari [Uqail] dari [Ibnu Syihab] dari [Abu Bakr bin 'Abdurrahman Ibnul Harits] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang mukmin tidak disebut mukmin saat ia berzina, seorang mukmin tidak disebut mukmin saat ia minum khamer, seorang mukmin tidak disebut mukmin saat ia mencuri, dan seorang mukmin tidak disebut mukmin saat ia merampas hak orang lain hingga orang-orang memasang pandangan mata mereka saat merampas.\""},"5295":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي سَعِيدُ بْنُ الْمُسَيَّبِ وَأَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ وَأَبُو بَكْرِ بْنُ عَبْدِ الرَّحْمَنِ كُلُّهُمْ حَدَّثُونِي عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَزْنِي الزَّانِي حِينَ يَزْنِي وَهُوَ مُؤْمِنٌ وَلَا يَسْرِقُ السَّارِقُ حِينَ يَسْرِقُ وَهُوَ مُؤْمِنٌ وَلَا يَشْرَبُ الْخَمْرَ حِينَ يَشْرَبُهَا وَهُوَ مُؤْمِنٌ وَلَا يَنْتَهِبُ نُهْبَةً ذَاتَ شَرَفٍ يَرْفَعُ الْمُسْلِمُونَ إِلَيْهِ أَبْصَارَهُمْ وَهُوَ مُؤْمِنٌ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah menceritakan kepada kami [Al Walid bin Muslim] dari [Al Auza'i] dari [Az Zuhri] ia berkata; telah menceritakan kepadaku [Sa'id Ibnul Musayyab] dan [Abu Salamah bin 'Abdurrahman] dan [Abu Bakr bin 'Abdurrahman] semuanya menceritakan kepadaku dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Seorang mukmin tidak disebut mukmin saat ia berzina, seorang mukmin tidak disebut mukmin saat ia mencuri, seorang mukmin tidak disebut mukmin saat ia minum khamer, dan seorang mukmin tidak disebut mukmin saat ia merampas hak orang lain hingga orang-orang memasang pandangan mata mereka saat merampas.\""},"5296":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ مُغِيرَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي نُعْمٍ عَنْ ابْنِ عُمَرَ وَنَفَرٍ مِنْ أَصْحَابِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالُواقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ شَرِبَ الْخَمْرَ فَاجْلِدُوهُ ثُمَّ إِنْ شَرِبَ فَاجْلِدُوهُ ثُمَّ إِنْ شَرِبَ فَاجْلِدُوهُ ثُمَّ إِنْ شَرِبَ فَاقْتُلُوهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Jarir] dari [Mughirah] dari ['Abdurrahman bin Abu Nu'm] dari [Ibnu Umar] dan sekelompok sahabat Muhammad shallallahu 'alaihi wasallam, mereka berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa minum khamer maka cambuklah dia, jika minum lagi maka cambuklah dia, jika minum lagi maka cambuklah dia, dan jika minum lagi maka bunuhlah dia.\""},"5297":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا شَبَابَةُ قَالَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ خَالِهِ الْحَارِثِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا سَكِرَ فَاجْلِدُوهُ ثُمَّ إِنْ سَكِرَ فَاجْلِدُوهُ ثُمَّ إِنْ سَكِرَ فَاجْلِدُوهُ ثُمَّ قَالَ فِي الرَّابِعَةِ فَاضْرِبُوا عُنُقَهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah menceritakan kepada kami [Syababah] ia berkata; telah menceritakan kepada kami [Ibnu Abu Dzi`b] dari pamannya [Al Harits bin 'Abdurrahman] dari [Abu Salamah] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Jika ia mabuk maka cambuklah, kemudian jika ia mabuk lagi maka cambuklah, kemudian jika ia mabuk lagi maka cambuklah.\" Kemudian pada kali keempatnya beliau bersabda: \"Maka bunuhlah ia.\""},"5298":{"ar":"أَخْبَرَنَا وَاصِلُ بْنُ عَبْدِ الْأَعْلَى عَنْ ابْنِ فُضَيْلٍ عَنْ وَائِلِ بْنِ بَكْرٍ عَنْ أَبِي بُرْدَةَ بْنِ أَبِي مُوسَى عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُأَنَّهُ كَانَ يَقُولُ مَا أُبَالِي شَرِبْتُ الْخَمْرَ أَوْ عَبَدْتُ هَذِهِ السَّارِيَةَ مِنْ دُونِ اللَّهِ عَزَّ وَجَلَّ","id":"Telah mengabarkan kepada kami [Washil bin Abdul A'la] dari [Ibnu Fudlail] dari [Wail bin Bakr] dari [Abu Burdah bin Abu Musa] dari [Bapaknya]? radliallahu 'anhu, bahwasanya ia berkata, \"Aku tidak peduli, apakah aku minum khamer atau aku menyembah tiang ini selain Allah 'azza wajalla.\""},"5299":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا عُثْمَانُ بْنُ حِصْنِ بْنِ عَلَّاقٍ دِمَشْقِيٌّ قَالَ حَدَّثَنَا عُرْوَةُ بْنُ رُوَيْمٍ أَنَّ ابْنَ الدَّيْلَمِيِّرَكِبَ يَطْلُبُ عَبْدَ اللَّهِ بْنَ عَمْرِو بْنِ الْعَاصِ قَالَ ابْنُ الدَّيْلَمِيِّ فَدَخَلْتُ عَلَيْهِ فَقُلْتُ هَلْ سَمِعْتَ يَا عَبْدَ اللَّهِ بْنَ عَمْرٍو رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَرَ شَأْنَ الْخَمْرِ بِشَيْءٍ فَقَالَ نَعَمْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَشْرَبُ الْخَمْرَ رَجُلٌ مِنْ أُمَّتِي فَيَقْبَلُ اللَّهُ مِنْهُ صَلَاةً أَرْبَعِينَ يَوْمًا","id":"Telah mengabarkan kepada kami [Ali bin Hujr] ia berkata; telah memberitakan kepada kami [Utsman bin Hishn bin Allaq Dimasyqi] ia berkata; telah menceritakan kepada kami [Urwah bin Ruwaim] berkata, \"Ibnu Ad Dailami berkendaraan mencari Abdullah bin Amru bin Al Ash. [Ibnu Ad Dailami] berkata, \"Aku masuk menemui [Abdullah bin Amru bin Ash], lalu aku bertanya kepadanya, \"Wahai Abdullah bin Amru, apakah engkau mendengar Rasulullah shallallahu 'alaihi wasallam menyebutkan sesuatu tentang khamer?\" ia menjawab, \"Benar. Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang laki-laki dari umatku minum khamer, lalu Allah menerima shalatnya selama empat puluh hari.\""},"5300":{"ar":"أَخْبَرَنَا قُتَيْبَةُ وَعَلِيُّ بْنُ حُجْرٍ قَالَا حَدَّثَنَا خَلَفٌ يَعْنِي ابْنَ خَلِيفَةَ عَنْ مَنْصُورِ بْنِ زَاذَانَ عَنْ الْحَكَمِ بْنِ عُتَيْبَةَ عَنْ أَبِي وَائِلٍ عَنْ مَسْرُوقٍ قَالَالْقَاضِي إِذَا أَكَلَ الْهَدِيَّةَ فَقَدْ أَكَلَ السُّحْتَ وَإِذَا قَبِلَ الرِّشْوَةَ بَلَغَتْ بِهِ الْكُفْرَ وَقَالَ مَسْرُوقٌ مَنْ شَرِبَ الْخَمْرَ فَقَدْ كَفَرَ وَكُفْرُهُ أَنْ لَيْسَ لَهُ صَلَاةٌ","id":"Telah mengabarkan kepada kami [Qutaibah] dan [Ali bin Hujr] keduanya berkata; telah menceritakan kepada kami [Khalaf] -yaitu Ibnu Khalifah- dari [Manshur bin Zadzan] dari [Al Hakam bin Utaibah] dari [Abu Wail] dari [Masruq] ia berkata, \"Jika seorang hakim makan barang yang dihadiahkan maka ia telah makan kemurkaan, dan jika menerima suap maka itu akan menariknya kepada kakufuran.\" [Masruq] menyebutkan, \"Barangsiapa minum khamer maka ia telah kafir, dan kekafirannya adalah tidak diterimanya ibadah shalatnya.\""},"5301":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ عَنْ أَبِيهِ قَالَ سَمِعْتُ عُثْمَانَ رَضِيَ اللَّهُ عَنْهُ يَقُولُاجْتَنِبُوا الْخَمْرَ فَإِنَّهَا أُمُّ الْخَبَائِثِ إِنَّهُ كَانَ رَجُلٌ مِمَّنْ خَلَا قَبْلَكُمْ تَعَبَّدَ فَعَلِقَتْهُ امْرَأَةٌ غَوِيَّةٌ فَأَرْسَلَتْ إِلَيْهِ جَارِيَتَهَا فَقَالَتْ لَهُ إِنَّا نَدْعُوكَ لِلشَّهَادَةِ فَانْطَلَقَ مَعَ جَارِيَتِهَا فَطَفِقَتْ كُلَّمَا دَخَلَ بَابًا أَغْلَقَتْهُ دُونَهُ حَتَّى أَفْضَى إِلَى امْرَأَةٍ وَضِيئَةٍ عِنْدَهَا غُلَامٌ وَبَاطِيَةُ خَمْرٍ فَقَالَتْ إِنِّي وَاللَّهِ مَا دَعَوْتُكَ لِلشَّهَادَةِ وَلَكِنْ دَعَوْتُكَ لِتَقَعَ عَلَيَّ أَوْ تَشْرَبَ مِنْ هَذِهِ الْخَمْرَةِ كَأْسًا أَوْ تَقْتُلَ هَذَا الْغُلَامَ قَالَ فَاسْقِينِي مِنْ هَذَا الْخَمْرِ كَأْسًا فَسَقَتْهُ كَأْسًا قَالَ زِيدُونِي فَلَمْ يَرِمْ حَتَّى وَقَعَ عَلَيْهَا وَقَتَلَ النَّفْسَ فَاجْتَنِبُوا الْخَمْرَ فَإِنَّهَا وَاللَّهِ لَا يَجْتَمِعُ الْإِيمَانُ وَإِدْمَانُ الْخَمْرِ إِلَّا لَيُوشِكُ أَنْ يُخْرِجَ أَحَدُهُمَا صَاحِبَهُأَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ يَعْنِي ابْنَ الْمُبَارَكِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي أَبُو بَكْرِ بْنُ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ أَنَّ أَبَاهُ قَالَ سَمِعْتُ عُثْمَانَ يَقُولُ اجْتَنِبُوا الْخَمْرَ فَإِنَّهَا أُمُّ الْخَبَائِثِ فَإِنَّهُ كَانَ رَجُلٌ مِمَّنْ خَلَا قَبْلَكُمْ يَتَعَبَّدُ وَيَعْتَزِلُ النَّاسَ فَذَكَرَ مِثْلَهُ قَالَ فَاجْتَنِبُوا الْخَمْرَ فَإِنَّهُ وَاللَّهِ لَا يَجْتَمِعُ وَالْإِيمَانُ أَبَدًا إِلَّا يُوشِكَ أَحَدُهُمَا أَنْ يُخْرِجَ صَاحِبَهُ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Ma'mar] dari [Az Zuhri] dari [Abu Bakr bin 'Abdurrahman bin Al Harits] dari [Bapaknya] ia berkata; Aku mendengar [Utsman? radliallahu 'anhu] berkata, \"Jauhilah oleh kalian minum khamer sebab ia adalah pangkal semua dosa. Ada seorang laki-laki sebelum kalian yang taat beribadah disukai oleh seorang wanita pelacur. Wanita itu lalu mengutus budak wanitanya agar mengatakan, 'Sesungguhnya aku memanggilmu untuk bersaksi.' Maka berangkatlah laki-laki itu bersama budak wanita tersebut, sementara ia sendiri bersiap-siap hingga ketika laki-laki itu masuk ia mengunci pintu rumah tanpa ada orang selain dia. Sehingga laki-laki itu berhadapan dengan seorang wanita cantik yang di sisinya terdapat seorang anak kecil dan botol khamer. Wanita itu lantas berkata, \"Demi Allah, aku memanggilmu bukan untuk bersaksi, tetapi aku memanggilmu untuk bersetubuh denganku, atau meneguk segelas khamer, atau membunuh anak kecil ini!\" laki-laki itu berkata, \"Berikan saja aku segelas khamer.\" Maka wanita itu memberikan satu gelas khamer kepadanya. Laki-laki itu lalu berkata, \"Tambahkanlah untukku.\" Laki-laki itu tetap saja minum hingga ia menzinai wanita itu dan membunuh seorang jiwa (anak kecil). Maka jauhilah minum khamer, karena -demi Allah- tidak akan pernah berkumpul antara iman dan kebiasaan minum khamer kecuali salah satunya akan mengeluarkan yang lain.\" Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] -yaitu Ibnul Mubarak- dari [Yunus] dari [Az Zuhri] ia berkata; telah menceritakan kepadaku [Abu Bakr bin 'Abdurrahman bin Al Harits] bahwa [Bapaknya] berkata; aku mendengar [Utsman] berkata, \"Jauhilah oleh kalian minum khamer sebab ia adalah pangkal semua dosa. Pernah ada seorang laki-laki yang menyepi dari kehidupan manusia untuk beribadah....lalu ia menyebutkan sebagaimana dalam hadits. Ia berkata, \"Jauhilah oleh kalian minum khamer, karena -demi Allah- selamanya tidak akan berkumpul antara iman dan kebiasaan minum khamer kecuali salah satunya akan mengeluarkan yang lain.\""},"5302":{"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا سُرَيْجُ بْنُ يُونُسَ قَالَ حَدَّثَنَا يَحْيَى بْنُ عَبْدِ الْمَلِكِ عَنْ الْعَلَاءِ وَهُوَ ابْنُ الْمُسَيَّبِ عَنْ فُضَيْلٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عُمَرَ قَالَمَنْ شَرِبَ الْخَمْرَ فَلَمْ يَنْتَشِ لَمْ تُقْبَلْ لَهُ صَلَاةٌ مَا دَامَ فِي جَوْفِهِ أَوْ عُرُوقِهِ مِنْهَا شَيْءٌ وَإِنْ مَاتَ مَاتَ كَافِرًا وَإِنْ انْتَشَى لَمْ تُقْبَلْ لَهُ صَلَاةٌ أَرْبَعِينَ لَيْلَةً وَإِنْ مَاتَ فِيهَا مَاتَ كَافِرًاخَالَفَهُ يَزِيدُ بْنُ أَبِي زِيَادٍ","id":"Telah mengabarkan kepada kami [Abu Bakr bin Ali] ia berkata; telah menceritakan kepada kami [Suraij bin Yunus] ia berkata; telah menceritakan kepada kami [Yahya bin Abdul Malik] dari [Al 'Ala] -yaitu Ibnul Musayyab- dari [Fudlail] dari [Mujahid] dari [Ibnu Umar] ia berkata, \"Barangsiapa minum khamer dan belum sampai mabuk, maka shalatnya tidak akan diterima selama di dalam perut atau urat-uratnya masih terdapat sesuatu darinya. Jika mati maka ia mati dalam keadaan kafir. Dan barangsiapa minum khamer hingga mabuk, maka shalatnya tidak akan diterima selama empat puluh malam. Dan jika ia mati karena minum khamer, maka ia mati dalam keadaan kafir.\" Namun riwayat ini diselisihi oleh Yazid bin Abu Ziyad.\""},"5303":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ آدَمَ بْنِ سُلَيْمَانَ عَنْ عَبْدِ الرَّحِيمِ عَنْ يَزِيدَ ح وَأَنْبَأَنَا وَاصِلُ بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ مُجَاهِدٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ مُحَمَّدُ بْنُ آدَمَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ شَرِبَ الْخَمْرَ فَجَعَلَهَا فِي بَطْنِهِ لَمْ يَقْبَلْ اللَّهُ مِنْهُ صَلَاةً سَبْعًا إِنْ مَاتَ فِيهَا وَقَالَ ابْنُ آدَمَ فِيهِنَّ مَاتَ كَافِرًا فَإِنْ أَذْهَبَتْ عَقْلَهُ عَنْ شَيْءٍ مِنْ الْفَرَائِضِ وَقَالَ ابْنُ آدَمَ الْقُرْآنِ لَمْ تُقْبَلْ لَهُ صَلَاةٌ أَرْبَعِينَ يَوْمًا إِنْ مَاتَ فِيهَا وَقَالَ ابْنُ آدَمَ فِيهِنَّ مَاتَ كَافِرًا","id":"Telah mengabarkan kepadaku [Muhammad bin Adam bin Sulaiman] dari [Abdurrahim] dari [Yazid]. (dalam jalur lain disebutkan) Telah memberitakan kepada kami [Washil bin Abdul A'la] berkata, telah menceritakan kepada kami [Ibnu Fudlail] dari [Yazid bin Abu Ziyad] dari [Mujahid] dari [Abdullah bin Amru] dari Nabi shallallahu 'alaihi wasallam, dan [Muhammad bin Adam] menyebutkan, \"Dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa minum khamer hingga masuk ke dalam perutnya, maka shalatnya tidak akan diterima selama tujuh hari. Jika ia mati di dalamnya, Ibnu Adam menyebutkan, 'pada hari-hari itu, maka ia mati sebagai seorang kafir. Jika khamer itu menjadikan akalnya hilang dari sesuatu kewajiban, Ibnu Adam menyebutkan, 'Al-Qur'an, maka shalatnya tidak akan diterima selama empat puluh hari. Jika ia mati di dalamnya, Ibnu Adam menyebutkan, 'pada hari-hari itu, maka ia mati sebagai seorang kafir.\""},"5304":{"ar":"أَخْبَرَنَا الْقَاسِمُ بْنُ زَكَرِيَّا بْنِ دِينَارٍ قَالَ حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو حَدَّثَنَا أَبُو إِسْحَقَ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي رَبِيعَةُ بْنُ يَزِيدَ ح و أَخْبَرَنِي عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدٍ عَنْ بَقِيَّةَ عَنْ أَبِي عَمْرٍو وَهُوَ الْأَوْزَاعِيُّ عَنْ رَبِيعَةَ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ بْنِ الدَّيْلَمِيِّ قَالَدَخَلْتُ عَلَى عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِ وَهُوَ فِي حَائِطٍ لَهُ بِالطَّائِفِ يُقَالُ لَهُ الْوَهْطُ وَهُوَ مُخَاصِرٌ فَتًى مِنْ قُرَيْشٍ يُزَنُّ ذَلِكَ الْفَتَى بِشُرْبِ الْخَمْرِ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ شَرِبَ الْخَمْرَ شَرْبَةً لَمْ تُقْبَلْ لَهُ تَوْبَةٌ أَرْبَعِينَ صَبَاحًا فَإِنْ تَابَ تَابَ اللَّهُ عَلَيْهِ فَإِنْ عَادَ لَمْ تُقْبَلْ تَوْبَتُهُ أَرْبَعِينَ صَبَاحًا فَإِنْ تَابَ تَابَ اللَّهُ عَلَيْهِ فَإِنْ عَادَ كَانَ حَقًّا عَلَى اللَّهِ أَنْ يَسْقِيَهُ مِنْ طِينَةِ الْخَبَالِ يَوْمَ الْقِيَامَةِاللَّفْظُ لِعَمْرٍو","id":"Telah mengabarkan kepada kami [Al Qasim bin Zakaria bin Dinar] ia berkata; telah menceritakan kepada kami [Mu'awiyah bin Amru] berkata, telah menceritakan kepada kami [Abu Ishaq] ia berkata; telah menceritakan kepada kami [Al Auza'i] ia berkata; telah menceritakan kepadaku [Rabi'ah bin Yazid]. (dalam jalur lain disebutkan) Telah mengabarkan kepadaku [Amru bin Utsman bin Sa'id] dari [Baqiyyah] dari [Abu Amru] -yaitu Al Auza'i- dari [Rabi'ah bin Yazid] dari [Abdullah bin Ad Dailami] ia berkata, \"Aku menemui [Abdullah bin Amru bin Al Ash] di kebun miliknya yang disebut Al Wahth, di wilayah Thaif. Pada waktu itu ia sedang menggandeng tangan seorang laki-laki Quraisy yang dituduh minum khamer. Lalu ia berkata, \"Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa minum khamer sekali saja, maka tidak akan diterima taubatnya selama empat puluh hari. Jika ia bertaubat maka akan diterima oleh Allah, namun jika ia mengulanginya maka tidak akan diterima taubatnya selama empat puluh hari. Jika ia bertaubat maka akan Allah terima taubatnya, dan jika ia mengulanginya lagi maka telah menjadi hak bagi Allah untuk memberinya minum dari keringat kotor penduduk neraka pada hari kiamat.\" Lafadz ini dari Amru."},"5305":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ شَرِبَ الْخَمْرَ فِي الدُّنْيَا ثُمَّ لَمْ يَتُبْ مِنْهَا حُرِمَهَا فِي الْآخِرَةِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dan [Al Harits bin Miskin] dengan membaca di hadapannya -aku pun mendengarnya, dan ini adalah lafadz darinya- dari [Ibnul Qasim] ia berkata; telah menceritakan kepadaku [Malik] dari [Nafi'] dari [Ibnu Umar], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa minum khamer di dunia dan belum sempat bertaubat darinya, maka Allah akan mengharamkannya di akhirat.\""},"5306":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ عَنْ مُحَمَّدٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ نُبَيْطٍ عَنْ جَابَانَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَدْخُلُ الْجَنَّةَ مَنَّانٌ وَلَا عَاقٌّ وَلَا مُدْمِنُ خَمْرٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dari [Muhammad] ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Manshur] dari [Salim bin Abu Al Ju'd] dari [Nubaith] dari [Jaban] dari [Abdullah bin Amru] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak akan masuk surga seorang yang mengungkit-ungkit pemberian, orang yang durhaka (kepada orang tua) dan pecandu khamer.\""},"5307":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ حَمَّادِ بْنِ زَيْدٍ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ شَرِبَ الْخَمْرَ فِي الدُّنْيَا فَمَاتَ وَهُوَ يُدْمِنُهَا لَمْ يَتُبْ مِنْهَا لَمْ يَشْرَبْهَا فِي الْآخِرَةِ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Hammad bin Zaid] ia berkata; telah menceritakan kepada kami [Ayyub] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa minum khamer di dunia, lalu ia meninggal dalam keadaan mencandu dan belum bertaubat darinya, maka ia tidak akan meminumnya di akhirat.\""},"5308":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ دُرُسْتَ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ شَرِبَ الْخَمْرَ فِي الدُّنْيَا فَمَاتَ وَهُوَ يُدْمِنُهَا لَمْ يَشْرَبْهَا فِي الْآخِرَةِ","id":"Telah mengabarkan kepada kami [Yahya bin Durusta] ia berkata; telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar? radliallahu 'anhuma] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa minum khamer di dunia, lalu ia meninggal dalam keadaan mencandunya maka ia tidak akan meminumnya di akhirat.\""},"5309":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ الْحَسَنِ بْنِ يَحْيَى عَنْ الضَّحَّاكِ قَالَمَنْ مَاتَ مُدْمِنًا لِلْخَمْرِ نُضِحَ فِي وَجْهِهِ بِالْحَمِيمِ حِينَ يُفَارِقُ الدُّنْيَا","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Al Hasan bin Yahya] dari [Adl Dlahhak] ia berkata, \"Barangsiapa kecanduan minum khamer, maka akan dipercikkan air panas pada mukanya saat ia meninggal dunia.\""},"5310":{"ar":"أَخْبَرَنَا زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ حَمَّادٍ قَالَ حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنِي عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ قَالَغَرَّبَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ رَبِيعَةَ بْنَ أُمَيَّةَ فِي الْخَمْرِ إِلَى خَيْبَرَ فَلَحِقَ بِهِرَقْلَ فَتَنَصَّرَ فَقَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ لَا أُغَرِّبُ بَعْدَهُ مُسْلِمًا","id":"Telah mengabarkan kepada kami [Zakaria bin Yahya] ia berkata; telah menceritakan kepada kami [Abdul A'la bin Hammad] ia berkata; telah menceritakan kepada kami [Mu'tamir bin Sulaiman] ia berkata; telah menceritakan kepadaku [Abdurrazaq] dari [Ma'mar] dari [Az Zuhri] dari [Sa'id Ibnul Musayyab] ia berkata, \" [Umar]? radliallahu 'anhu mengasingkan Rabi'ah bin Umayyah ke Khaibar karena minum khamer, lalu Rabi'ah bertemu Hiraqlius dan masuk kristen. Maka Umar? radliallahu 'anhu pun berkata, \"Demi Allah, aku tidak akan mengasingkan seorang muslim pun setelahnya.\""},"5311":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ أَبِي الْأَحْوَصِ عَنْ سِمَاكٍ عَنْ الْقَاسِمِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي بُرْدَةَ بْنِ نِيَارٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اشْرَبُوا فِي الظُّرُوفِ وَلَا تَسْكَرُواقَالَ أَبُو عَبْد الرَّحْمَنِ وَهَذَا حَدِيثٌ مُنْكَرٌ غَلِطَ فِيهِ أَبُو الْأَحْوَصِ سَلَّامُ بْنُ سُلَيْمٍ لَا نَعْلَمُ أَنَّ أَحَدًا تَابَعَهُ عَلَيْهِ مِنْ أَصْحَابِ سِمَاكِ بْنِ حَرْبٍ وَسِمَاكٌ لَيْسَ بِالْقَوِيِّ وَكَانَ يَقْبَلُ التَّلْقِينَ قَالَ أَحْمَدُ بْنُ حَنْبَلٍ كَانَ أَبُو الْأَحْوَصِ يُخْطِئُ فِي هَذَا الْحَدِيثِ خَالَفَهُ شَرِيكٌ فِي إِسْنَادِهِ وَفِي لَفْظِهِ","id":"Telah mengabarkan kepada kami [Hannad bin As Sari] dari [Abu Al Ahwash] dari [Simak] dari [Al Qasim bin 'Abdurrahman] dari [Bapaknya] dari [Abu Burdah bin Niyar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Minumlah kalian dalam wadah-wadah dari kulit dan janganlah kalian mabuk.\" 'Abdurrahman berkata, \"Ini adalah hadits munkar, Abul Ahwash Salam bin Sulaim keliru dalam hadits tersebut, dan kami tidak mengetahui seorang pun dari sahabat-sahabat Simak bin Harb yang menguatkan haditsnya. Sementara Simak sendiri bukanlah seorang yang kuat (dalam hal hadits).\" Ahmad bin Hanbal berkata, \"Abul Ahwash salah dalam hadits ini, dan Syarik menyelisihinya dalam hal sanad dan lafadznya.\""},"5312":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ قَالَ حَدَّثَنَا يَزِيدُ قَالَ أَنْبَأَنَا شَرِيكٌ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الدُّبَّاءِ وَالْحَنْتَمِ وَالنَّقِيرِ وَالْمُزَفَّتِخَالَفَهُ أَبُو عَوَانَةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Isma'il] ia berkata; telah menceritakan kepada kami [Yazid] ia berkata; telah memberitakan kepada kami [Syarik] dari [Simak bin Harb] dari [Ibnu Buraidah] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang Ad Duba, Al Hantam, An Naqir dan Al Muzaffat.\" Abu Awanah menyelisihi riwayatnya. "},"5313":{"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنُ عَلِيٍّ قَالَ أَنْبَأَنَا إِبْرَاهِيمُ بْنُ حَجَّاجٍ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ سِمَاكٍ عَنْ قِرْصَافَةَ امْرَأَةٍ مِنْهُمْ عَنْ عَائِشَةَ قَالَتْاشْرَبُوا وَلَا تَسْكَرُواقَالَ أَبُو عَبْد الرَّحْمَنِ وَهَذَا أَيْضًا غَيْرُ ثَابِتٍ وَقِرْصَافَةُ هَذِهِ لَا نَدْرِي مَنْ هِيَ وَالْمَشْهُورُ عَنْ عَائِشَةَ خِلَافُ مَا رَوَتْ عَنْهَا قِرْصَافَةُ","id":"Telah mengabarkan kepada kami [Abu Bakr bin Ali] ia berkata; telah memberitakan kepada kami [Ibrahim bin Hajjaj] ia berkata; telah menceritakan kepada kami [Abu Awanah] dari [Simak] dari [Qirshafah] -isteri salah seorang dari mereka- dari ['Aisyah] ia berkata, \"Minumlah kalian dan jangan mabuk.\" Abu 'Abdurrahman berkata, \"Hadits ini juga tidak kuat, sementara Qirshafah sendiri kami juga tidak mengetahuinya. Namun yang masyhur dari 'Aisyah, riwayatnya bertentangan dengan apa yang diriwayatkan oleh Qirshafah darinya.\""},"5314":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ عَلِيِّ بْنِ الْمُبَارَكِ قَالَ حَدَّثَتْنَا كَرِيمَةُ بِنْتُ هَمَّامٍ أَنَّهَا سَمِعَتْ عَائِشَةَ أُمَّ الْمُؤْمِنِينَ تَقُولُنُهِيتُمْ عَنْ الدُّبَّاءِ نُهِيتُمْ عَنْ الْحَنْتَمِ نُهِيتُمْ عَنْ الْمُزَفَّتِ ثُمَّ أَقْبَلَتْ عَلَى النِّسَاءِ فَقَالَتْ إِيَّاكُنَّ وَالْجَرَّ الْأَخْضَرَ وَإِنْ أَسْكَرَكُنَّ مَاءُ حُبِّكُنَّ فَلَا تَشْرَبْنَهُ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Ali Ibnul Mubarak] ia berkata; telah menceritakan kepada kami [Karimah binti Hamma] bahwasanya ia mendengar ['Aisyah Ummul Mukminin] berkata, \"Kalian telah dilarang dari Ad Duba, Al Hantam, dan Al Muzaffat.\" Lalu ia menghadap ke arah para wanita dan berkata, \"Jauhilah oleh kalian guci tembikar yang berwarna hijau, dan jika perasaan biji-biji kalian memabukkan kalian maka janganlah kalian minum.\" "},"5315":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا أَبَانُ بْنُ صَمْعَةَ قَالَ حَدَّثَتْنِي وَالِدَتِي عَنْ عَائِشَةَأَنَّهَا سُئِلَتْ عَنْ الْأَشْرِبَةِ فَقَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْ كُلِّ مُسْكِرٍوَاعْتَلُّوا بِحَدِيثِ عَبْدِ اللَّهِ بْنِ شَدَّادٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] ia berkata; telah menceritakan kepada kami [Khalid] ia berkata; telah menceritakan kepada kami [Aban bin Sham'ah] ia berkata; telah menceritakan kepadaku [Ibuku] dari ['Aisyah], bahwasanya ia pernah ditanya tentang beberapa minuman. Lalu 'Aisyah menjawab, 'Rasulullah shallallahu 'alaihi wasallam melarang dari setiap minuman yang memabukkan.' Mereka lalu beralasan dengan hadits Abdullah bin Syaddad dari hadits Abdullah bin Abbas.\""},"5316":{"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا سُرَيْجُ بْنُ يُونُسَ قَالَ حَدَّثَنَا هُشَيْمٌ عَنْ ابْنِ شُبْرُمَةَ قَالَ حَدَّثَنِي الثِّقَةُ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادٍ عَنْ ابْنِ عَبَّاسٍ قَالَحُرِّمَتْ الْخَمْرُ بِعَيْنِهَا قَلِيلُهَا وَكَثِيرُهَا وَالسَّكْرُ مِنْ كُلِّ شَرَابٍخَالَفَهُ أَبُو عَوْنٍ مُحَمَّدُ بْنُ عُبَيْدِ اللَّهِ الثَّقَفِيُّ","id":"Telah mengabarkan kepada kami [Abu Bakr bin Ali] ia berkata; telah menceritakan kepada kami [Suraij bin Yunus] ia berkata; telah menceritakan kepada kami [Husyaim] dari [Ibnu Syubrumah] ia berkata; telah menceritakan kepadaku [seseorang yang tsiqah] dari [Abdullah bin Syaddad] dari [Ibnu Abbas] ia berkata, \"Khamer telah diharamkan karena dzatnya, sedikitnya atau banyaknya, dan yang memabukkan dari setiap minuman.\" Abu Aun Muhammad bin Ubaidullah Ats Tsaqafi menyelisihinya."},"5317":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ الْحَكَمِ قَالَ حَدَّثَنَا مُحَمَّدٌ ح وَأَنْبَأَنَا الْحُسَيْنُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مِسْعَرٍ عَنْ أَبِي عَوْنٍ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادٍ عَنْ ابْنِ عَبَّاسٍ قَالَحُرِّمَتْ الْخَمْرُ بِعَيْنِهَا قَلِيلُهَا وَكَثِيرُهَا وَالسُّكْرُ مِنْ كُلِّ شَرَابٍ لَمْ يَذْكُرْ ابْنُ الْحَكَمِ قَلِيلُهَا وَكَثِيرُهَا","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah bin Al Hakam] ia berkata; telah menceritakan kepada kami [Muhammad]. (dalam jalur lain disebutkan) Telah memberitakan kepada kami [Al Husain bin Manshur] ia berkata; telah menceritakan kepada kami [Ahmad bin Hanbal] ia berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Mis'ar] dari [Abu Aun] dari [Abdullah bin Syaddad] dari [Ibnu Abbas] ia berkata, \"Khamer telah diharamkan karena dzatnya; sedikitnya atau banyaknya, dan yang memabukkan dari setiap minuman.\" Tetapi [Ibnu Al Hakam] tidak menyebutkan lafadz, \"Sedikitnya atau banyaknya.\""},"5318":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ أَبِي الْعَبَّاسِ قَالَ حَدَّثَنَا شَرِيكٌ عَنْ عَبَّاسِ بْنِ ذَرِيحٍ عَنْ أَبِي عَوْنٍ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادٍ عَنْ ابْنِ عَبَّاسٍ قَالَحُرِّمَتْ الْخَمْرُ قَلِيلُهَا وَكَثِيرُهَا وَمَا أَسْكَرَ مِنْ كُلِّ شَرَابٍقَالَ أَبُو عَبْد الرَّحْمَنِ وَهَذَا أَوْلَى بِالصَّوَابِ مِنْ حَدِيثِ ابْنِ شُبْرُمَةَ وَهُشَيْمُ بْنُ بَشِيرٍ كَانَ يُدَلِّسُ وَلَيْسَ فِي حَدِيثِهِ ذِكْرُ السَّمَاعِ مِنْ ابْنِ شُبْرُمَةَ وَرِوَايَةُ أَبِي عَوْنٍ أَشْبَهُ بِمَا رَوَاهُ الثِّقَاتُ عَنْ ابْنِ عَبَّاسٍ","id":"Telah mengabarkan kepada kami [Al Husain bin Manshur] ia berkata; telah menceritakan kepada kami [Ahmad bin Hanbal] ia berkata; telah menceritakan kepada kami [Ibrahim bin Abul Abbas] ia berkata; telah menceritakan kepada kami [Syarik] dari [Ibnu Abbas bin Dzarih] dari [Abu Aun] dari [Abdullah bin Syaddad] dari [Ibnu Abbas] ia berkata, \"Khamer telah diharamkan; sedikitnya atau banyaknya, dan yang memabukkan dari setiap minuman.\" Abu 'Abdurrahman berkata, \"Hadits ini lebih benar dari hadits Ibnu Syubrumah. Husyaim bin Basyir adalah seorang mudallis (penipu dalam hadits), dalam hadits riwayatnya tidak disebutkan bahwa ia mendengar dari Ibnu Syubrumah. Sedangkan riwayat Abu Aun mirip dengan hadits yang diriwayatkan oleh para ahli hadits yang tsiqah (terpercaya), dari Ibnu Abbas.\""},"5319":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا أَبُو عَامِرٍ وَالنَّضْرُ بْنُ شُمَيْلٍ وَوَهْبُ بْنُ جَرِيرٍ قَالُوا حَدَّثَنَا شُعْبَةُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ قَالَ سَمِعْتُ أَبَا الْحَكَمِ يُحَدِّثُ قَالَ ابْنُ عَبَّاسٍمَنْ سَرَّهُ أَنْ يُحَرِّمَ إِنْ كَانَ مُحَرِّمًا مَا حَرَّمَ اللَّهُ وَرَسُولُهُ فَلْيُحَرِّمْ النَّبِيذَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Abu Amir] dan [An Nadlr bin Syumail] dan [Wahb bin Jurair] mereka berkata; telah menceritakan kepada kami [Syu'bah] dari [Salamah bin Kuhail] ia berkata; Aku mendengar [Abu Al Hakam] menceritakan bahwa [Ibnu Abbas] berkata, \"Barangsiapa suka mengharamkan sesuatu yang telah Allah haramkan, maka hendaklah ia haramkan perasan nabidz.\""},"5320":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ عُيَيْنَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ قَالَقَالَ رَجُلٌ لِابْنِ عَبَّاسٍ إِنِّي امْرُؤٌ مِنْ أَهْلِ خُرَاسَانَ وَإِنَّ أَرْضَنَا أَرْضٌ بَارِدَةٌ وَإِنَّا نَتَّخِذُ شَرَابًا نَشْرَبُهُ مِنْ الزَّبِيبِ وَالْعِنَبِ وَغَيْرِهِ وَقَدْ أُشْكِلَ عَلَيَّ فَذَكَرَ لَهُ ضُرُوبًا مِنْ الْأَشْرِبَةِ فَأَكْثَرَ حَتَّى ظَنَنْتُ أَنَّهُ لَمْ يَفْهَمْهُ فَقَالَ لَهُ ابْنُ عَبَّاسٍ إِنَّكَ قَدْ أَكْثَرْتَ عَلَيَّ اجْتَنِبْ مَا أَسْكَرَ مِنْ تَمْرٍ أَوْ زَبِيبٍ أَوْ غَيْرِهِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Uyainah bin 'Abdurrahman] dari [Bapaknya] ia berkata, \"Seorang laki-laki berkata kepada [Ibnu Abbas], \"Aku adalah salah seorang dari penduduk Khurasan, dan negeriku sangat dingin. Maka kami membuat minuman untuk kami minum dari buah kismis, anggur dan selainnya -dan aku susah untuk menghafalnya, lalu ia menyebutkan beberapa contoh minuman yang sangat banyak hingga aku mengira jika Ibnu Abbas tidak akan memaminya-. Setelah itu Ibnu Abbas berkata kepada laki-laki itu, \"Banyak sekali engkau sebutkan model minuman kepadaku, jauhilah minuman yang memabukkan, baik itu dari perasan kurma, kismis (anggur kering) atau selainnya.\""},"5321":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ عَنْ عُمَارَةَ بْنِ غَزِيَّةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ رَجُلًا مِنْ جَيْشَانَ وَجَيْشَانُ مِنْ الْيَمَنِ قَدِمَ فَسَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ شَرَابٍ يَشْرَبُونَهُ بِأَرْضِهِمْ مِنْ الذُّرَةِ يُقَالُ لَهُ الْمِزْرُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمُسْكِرٌ هُوَ قَالَ نَعَمْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ مُسْكِرٍ حَرَامٌ إِنَّ اللَّهَ عَزَّ وَجَلَّ عَهِدَ لِمَنْ شَرِبَ الْمُسْكِرَ أَنْ يَسْقِيَهُ مِنْ طِينَةِ الْخَبَالِ قَالُوا يَا رَسُولَ اللَّهِ وَمَا طِينَةُ الْخَبَالِ قَالَ عَرَقُ أَهْلِ النَّارِ أَوْ قَالَ عُصَارَةُ أَهْلِ النَّارِ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Abdul Aziz] dari [Umarah bin Ghaziyah] dari [Abu Az Zubair] dari [Jabir] berkata, \"Seorang laki-laki dari Jaisyan -Jaisyan adalah sebuah wilayah di Yaman- datang dan bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang minuman dari perasan jagung yang mereka sebut Al Mizr, mereka biasa meminumnya di wilayah mereka. Nabi shallallahu 'alaihi wasallam lalu bertanya: \"Apakah itu memabukkan?\" ia menjawab, \"Ya.\" Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Setiap yang memabukkan adalah haram. Sesungguhnya Allah Azza Wa Jalla telah membuat perjanjian bahwa siapa yang minum sesuatu yang memabukkan, Allah akan memberinya minum tinatul khabal.\" Para sahabat bertanya, \"Wahai Rasulullah, tinatul Khabal itu apa?\" beliau menjawab: \"Keringat penduduk neraka, atau beliau mengatakan, \"Perasan keringat penduduk neraka.\""},"5322":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ عَنْ يَزِيدَ وَهُوَ ابْنُ زُرَيْعٍ عَنْ ابْنِ عَوْنٍ عَنْ الشَّعْبِيِّ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ الْحَلَالَ بَيِّنٌ وَإِنَّ الْحَرَامَ بَيِّنٌ وَإِنَّ بَيْنَ ذَلِكَ أُمُورًا مُشْتَبِهَاتٍ وَرُبَّمَا قَالَ وَإِنَّ بَيْنَ ذَلِكَ أُمُورًا مُشْتَبِهَةً وَسَأَضْرِبُ فِي ذَلِكَ مَثَلًا إِنَّ اللَّهَ عَزَّ وَجَلَّ حَمَى حِمًى وَإِنَّ حِمَى اللَّهِ مَا حَرَّمَ وَإِنَّهُ مَنْ يَرْعَ حَوْلَ الْحِمَى يُوشِكُ أَنْ يُخَالِطَ الْحِمَى وَرُبَّمَا قَالَ يُوشِكُ أَنْ يَرْتَعَ وَإِنَّ مَنْ خَالَطَ الرِّيبَةَ يُوشِكُ أَنْ يَجْسُرَ","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] dari [Yazid] -yaitu Ibnu Zurai'- dari [Ibnu Aun] dari [Asy Sya'bi] dari [An Nu'man bin Basyir] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perkara yang halal itu telah jelas dan yang haram juga telah jelas, sedangkan antara keduanya ada perkara yang samar-samar, dan mungkin saja beliau mengatakan, 'sesungguhnya antara keduanya terdapat perkara-perkara yang musytabihah (samar). Dan akan aku beri contoh tentang hal itu; sesungguhnya Allah mempunyai pembatas, dan batasan Allah adalah apa-apa yang telah Ia haramkan-Nya. Orang yang mengembala di sekitar pembatas, maka dikawatirkan akan masuk ke dalam pagar pembatas, dan barangkali beliau mengatakan, 'dikawatirkan ternaknya akan masuk. Sesungguhnya orang yang mendekati perkara yang meragukan dikhawatirkan akan menyeberang (memasuki perkara yang tidak dibolehkan).\""},"5323":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ أَبَانَ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ بُرَيْدِ بْنِ أَبِي مَرْيَمَ عَنْ أَبِي الْحَوْرَاءِ السَّعْديِّ قَالَ قُلْ��ُ لِلْحَسَنِ بْنِ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُمَا مَا حَفِظْتَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ حَفِظْتُ مِنْهُ دَعْ مَا يَرِيبُكَ إِلَى مَا لَا يَرِيبُكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Aban] ia berkata; telah menceritakan kepada kami [Abdullah bin Idris] ia berkata; telah memberitakan kepada kami [Syu'bah] dari [Buraid bin Abu Maryam] dari [Abu Al Haura As Sa'di] ia berkata, \"Aku berkata kepada? [Al Hasan bin Ali]? radliallahu 'anhuma, \"Apa yang engkau hafal dari Rasulullah shallallahu 'alaihi wasallam?\" ia menjawab, \"Aku menghafal dari beliau: \"Tinggalkanlah apa yang meragukan kamu dan lakukan apa yang tidak meragukan kamu.\""},"5324":{"ar":"أَخْبَرَنَا الْجَارُودُ بْنُ مُعَاذٍ هُوَ بَاوَرْدِيُّ قَالَ حَدَّثَنَا أَبُو سُفْيَانَ مُحَمَّدُ بْنُ حُمَيْدٍ عَنْ مَعْمَرٍ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِأَنَّهُ كَانَ يَكْرَهُ أَنْ يَبِيعَ الزَّبِيبَ لِمَنْ يَتَّخِذُهُ نَبِيذًا","id":"Telah mengabarkan kepada kami [Al Jarud bin Mu'adz] -yaitu Bawardi- ia berkata; telah menceritakan kepada kami [Abu Sufyan Muhammad bin Humaid] dari [Ma'mar] dari [Ibnu Thawus] dari [Bapaknya], bahwasanya ia tidak menyukai menjual anggur kepada seseorang yang akan menjadikannya sebagai perasan nabidz.\""},"5325":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ سُفْيَانَ بْنِ دِينَارٍ عَنْ مُصْعَبِ بْنِ سَعْدٍ قَالَكَانَ لِسَعْدٍ كُرُومٌ وَأَعْنَابٌ كَثِيرَةٌ وَكَانَ لَهُ فِيهَا أَمِينٌ فَحَمَلَتْ عِنَبًا كَثِيرًا فَكَتَبَ إِلَيْهِ إِنِّي أَخَافُ عَلَى الْأَعْنَابِ الضَّيْعَةَ فَإِنْ رَأَيْتَ أَنْ أَعْصُرَهُ عَصَرْتُهُ فَكَتَبَ إِلَيْهِ سَعْدٌ إِذَا جَاءَكَ كِتَابِي هَذَا فَاعْتَزِلْ ضَيْعَتِي فَوَاللَّهِ لَا أَئْتَمِنُكَ عَلَى شَيْءٍ بَعْدَهُ أَبَدًا فَعَزَلَهُ عَنْ ضَيْعَتِهِ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Sufyan bin Dinar] dari [Mush'ab bin Sa'd] ia berkata, \" [Sa'd] mempunyai kebun anggur yang buahnya sangat banyak, dan ia juga mempunyai seseorang yang menjaga kebunnya. Buah anggur tersebut lalu diangkut dalam jumlah yang besar, maka penjaga itu pun menulis surat kepadanya, \"Aku khawatir anggur-anggur itu akan rusak, jika engkau menginginkannya, maka aku akan membuatnya perasan (arak).\" Sa'd pun menulis surat balasan kepadanya, \"Jika suratku ini telah tiba kepadamu, maka buanglah anggurku yang telah rusak. Demi Allah, setelah ini aku tidak akan mempercayakan kamu untuk mengurusinya selama-lamanya.\" Kemudian penjaga kebun itu pun membuang buah anggur yang telah rusak.\""},"5326":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ هَارُونَ بْنِ إِبْرَاهِيمَ عَنْ ابْنِ سِيرِينَ قَالَبِعْهُ عَصِيرًا مِمَّنْ يَتَّخِذُهُ طِلَاءً وَلَا يَتَّخِذُهُ خَمْرًا","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Harun bin Ibrahim] dari [Ibnu Sirin] ia berkata, \"Juallah buah anggur yang telah menjadi perasan kepada orang yang akan membuatnya sebagai minuman yang dimasak, bukan sebagai khamer.\""},"5327":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ مَنْصُورًا عَنْ إِبْرَاهِيمَ عَنْ نُبَاتَةَ عَنْ سُوَيْدِ بْنِ غَفَلَةَ قَالَكَتَبَ عُمَرُ بْنُ الْخَطَّابِ إِلَى بَعْضِ عُمَّالِهِ أَنْ ارْزُقْ الْمُسْلِمِينَ مِنْ الطِّلَاءِ مَا ذَهَبَ ثُلُثَاهُ وَبَقِيَ ثُلُثُهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] ia berkata; telah menceritakan kepada kami [Al Mu'tamir] ia berkata; Aku mendengar [Manshur] dari [Ibrahim] dari [Nubatah] dari [Suwaid bin Ghafalah] ia berkata, \"[Umar Ibnul Khaththab] menulis surat kepada sebagian pekerjanya, \"Berilah kaum muslimin Ath Thila (nabidz yang telah dimasak hingga menjadi gula), yang telah hilang dua pertiganya dan tersisa sepertiganya.\""},"5328":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ هِشَامٍ عَنْ ابْنِ سِيرِينَ أَنَّ عَبْدَ اللَّهِ بْنَ يَزِيدَ الْخَطْمِيَّ قَالَكَتَبَ إِلَيْنَا عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ أَمَّا بَعْدُ فَاطْبُخُوا شَرَابَكُمْ حَتَّى يَذْهَبَ مِنْهُ نَصِيبُ الشَّيْطَانِ فَإِنَّ لَهُ اثْنَيْنِ وَلَكُمْ وَاحِدٌ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Hisyam] dari [Ibnu Sirin] bahwa [Abdullah bin Yazid Al Khathmi] berkata, \"[Umar Ibnul Khaththab] menulis surat kepada kami, \"Amma ba'du; Masaklah minuman kalian hingga hilang bagian setan. Sesungguhnya baginya adalah dua bagian dan untuk kalian satu bagian.\""},"5329":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ جَرِيرٍ عَنْ مُغِيرَةَ عَنْ الشَّعْبِيِّ قَالَكَانَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُ يَرْزُقُ النَّاسَ الطِّلَاءَ يَقَعُ فِيهِ الذُّبَابُ وَلَا يَسْتَطِيعُ أَنْ يَخْرُجَ مِنْهُ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Jarir] dari [Mughirah] dari [Asy Sya'bi] ia berkata, \" [Ali] memberikan minuman perasan nabidz kepada orang-orang, yang jika ada lalat jatuh dan masuk ke dalamnya maka tidak akan bisa keluar lagi.\""},"5330":{"ar":"أَخْبَرَنَا زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا عَبْدُ الْأَعْلَى قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ دَاوُدَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِأَنَّ أَبَا الدَّرْدَاءِ كَانَ يَشْرَبُ مَا ذَهَبَ ثُلُثَاهُ وَبَقِيَ ثُلُثُهُ","id":"Telah mengabarkan kepada kami [Zakaria bin Yahya] ia berkata; telah menceritakan kepada kami [Abdul A'la] ia berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Dawud] dari [Sa'id Ibnul Musayyab] berkata, \" [Abu Darda] biasa minum perasan yang telah hilang dua pertiga dan tersisa sepertiganya.\""},"5331":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ هُشَيْمٍ قَالَ أَنْبَأَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّأَنَّهُ كَانَ يَشْرَبُ مِنْ الطِّلَاءِ مَا ذَهَبَ ثُلُثَاهُ وَبَقِيَ ثُلُثُهُ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Husyaim] ia berkata; telah memberitakan kepada kami [Isma'il bin Abu Khalid] dari [Qais bin Abu Hazim] dari [Abu Musa Al Asy'ari], bahwasanya ia minum perasan yang telah dimasak, yang telah hilang dua pertiga dan tersisa sepertiganya.\""},"5332":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ سُفْيَانَ عَنْ يَعْلَى بْنِ عَطَاءٍ قَالَ سَمِعْتُ سَعِيدَ بْنَ الْمُسَيَّبِوَسَأَلَهُ أَعْرَابِيٌّ عَنْ شَرَابٍ يُطْبَخُ عَلَى النِّصْفِ فَقَالَ لَا حَتَّى يَذْهَبَ ثُلُثَاهُ وَيَبْقَى الثُّلُثُ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Sufyan] dari [Ya'la bin Atha] ia berkata, \"Aku mendengar [Sa'id Ibnul Musayyab] ditanya oleh seorang arab dusun tentang perasan yang dimasak hingga hilang setengahnya. Lalu ia menjawab, \"Tidak boleh (diminum), hingga hilang dua pertiga dan tersisa sepertiganya.\""},"5333":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ يَزِيدَ بْنِ زُرَيْعٍ قَالَ حَدَّثَنَا أَبُو رَجَاءٍ قَالَسَأَلْتُ الْحَسَنَ عَنْ الطِّلَاءِ الْمُنَصَّفِ فَقَالَ لَا تَشْرَبْهُ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Yazid bin Zurai'] ia berkata; telah menceritakan kepada kami [Abu Raja] ia berkata, \"Aku bertanya? [Al Hasan] tentang perasan yang dimasak hingga tinggal setengahnya, maka ia menjawab, \"Jangan engkau minum.\""},"5334":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ بَشِيرِ بْنِ الْمُهَاجِرِ قَالَسَأَلْتُ الْحَسَنَ عَمَّا يُطْبَخُ مِنْ الْعَصِيرِ قَالَ مَا تَطْبُخُهُ حَتَّى يَذْهَبَ الثُّلُثَانِ وَيَبْقَى الثُّلُثُ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Basyir Ibnul Muhajir] ia berkata, \"Aku bertanya? [Al Hasan] tentang perasan yang dimasak, ia lalu menjawab: \"(Engkau boleh minum) perasan yang engkau masak hingga hilang dua pertiga dan hanya tersisa sepertiganya.\""},"5335":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ عَبْدِ الْمَلِكِ بْنِ طُفَيْلٍ الْجَزَرِيِّ قَالَ كَتَبَ إِلَيْنَا عُمَرُ بْنُ عَبْدِ الْعَزِيزِأَنْ لَا تَشْرَبُوا مِنْ الطِّلَاءِ حَتَّى يَذْهَبَ ثُلُثَاهُ وَيَبْقَى ثُلُثُهُ وَكُلُّ مُسْكِرٍ حَرَامٌ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Abdul Malik bin Thufail Al Jazari] ia berkata, \" [Umar bin Abdul Aziz] menulis surat kepada kami, 'Janganlah kalian minum perasan yang dimasak hingga hilang dua pertiga dan tersisa sepertiganya. Dan setiap yang memabukkan adalah haram'.\""},"5336":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا الْمُعْتَمِرُ عَنْ بُرْدٍ عَنْ مَكْحُولٍ قَالَكُلُّ مُسْكِرٍ حَرَامٌ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah menceritakan kepada kami [Al Mu'tamir] dari [Burd] dari [Makhul] ia berkata, \"Setiap yang memabukkan adalah haram.\""},"5337":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ أَبِي يَعْفُورٍ السُّلَمِيِّ عَنْ أَبِي ثَابِتٍ الثَّعْلَبِيِّ قَالَكُنْتُ عِنْدَ ابْنِ عَبَّاسٍ فَجَاءَهُ رَجُلٌ فَسَأَلَهُ عَنْ الْعَصِيرِ فَقَالَ اشْرَبْهُ مَا كَانَ طَرِيًّا قَالَ إِنِّي طَبَخْتُ شَرَابًا وَفِي نَفْسِي مِنْهُ قَالَ أَكُنْتَ شَارِبَهُ قَبْلَ أَنْ تَطْبُخَهُ قَالَ لَا قَالَ فَإِنَّ النَّارَ لَا تُحِلُّ شَيْئًا قَدْ حَرُمَ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Abu Ya'fur As Sulami] dari [Abu Tsabit Ast Tsa'labi] ia berkata, \"Saat aku ada di sisi [Ibnu Abbas], seorang laki-laki datang kepadanya dan bertanya tentang perasan?\" Ibnu Abbas menjawab, \"Minumlah perasan tersebut selama masih baru.\" Abu Ayyub berkata, \"Aku memasak perasan tersebut dan menyimpannya untuk diriku.\" Ibnu Abbas bertanya, \"Apakah kamu meminumnya sebelum engkau masak?\" Abu Ayyub menjawab, \"Tidak.\" Ibnu Abbas berkata, \"Sesungguhnya api tidak bisa menghalalkan sesuatu yang telah diharamkan.\""},"5338":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ ابْنِ جُرَيْجٍ قِرَاءَةً أَخْبَرَنِي عَطَاءٌ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ يَقُولُوَاللَّهِ مَا تُحِلُّ النَّارُ شَيْئًا وَلَا تُحَرِّمُهُقَالَ ثُمَّ فَسَّرَ لِي قَوْلَهُ لَا تُحِلُّ شَيْئًا لِقَوْلِهِمْ فِي الطِّلَاءِ وَلَا تُحَرِّمُهُ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Ibnu Juraij] -secara bacaan- ia berkata; telah mengabarkan kepadaku [Atha] ia berkata, \"Aku mendengar [Ibnu Abbas] berkata, \"Demi Allah, api tidak dapat menghalalkan atau mengharamkan sesuatu.\" Atha berkata, \"Kemudian Ibnu Abbas menjelaskan kepadaku tentang perkataannya 'Tidak dapat menghalalkan sesuatu -berkenaan dengan ucapan mereka tentang perasan- atau mengharamkannya'.\""},"5339":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ حَيْوَةَ بْنِ شُرَيْحٍ قَالَ أَخْبَرَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ قَالَاشْرَبْ الْعَصِيرَ مَا لَمْ يُزْبِدْ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Haiwah bin Syuraih] ia berkata; telah memberitakan kepadaku [Uqail] dari [Ibnu Syihab] dari [Sa'id Ibnul Musayyab] ia berkata, \"Minumlah perasan anggur selama belum berbuih.\""},"5340":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ هِشَامِ بْنِ عَائِذٍ الْأَسَدِيِّ قَالَسَأَلْتُ إِبْرَاهِيمَ عَنْ الْعَصِيرِ قَالَ اشْرَبْهُ حَتَّى يَغْلِيَ مَا لَمْ يَتَغَيَّرْ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Hisyam bin 'Aidz Al Asadi] ia berkata, \"Aku bertanya [Ibrahim] tentang perasan, ia menjawab, \"Minumlah ia hingga mendidih dan belum berubah.\""},"5341":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ عَبْدِ الْمَلِكِ عَنْ عَطَاءٍفِي الْعَصِيرِ قَالَ اشْرَبْهُ حَتَّى يَغْلِيَ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Abdul Malik] dari [Atha] tentang perasan buah, \"Ia menjawab, \"Minumlah hingga ia mendidih (mengalami fermentasi).\""},"5342":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ دَاوُدَ عَنْ الشَّعْبِيِّ قَالَاشْرَبْهُ ثَلَاثَةَ أَيَّامٍ إِلَّا أَنْ يَغْلِيَ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Hammad bin Salamah] dari [Dawud] dari [Asy Sya'bi] ia berkata, \"Minumlah ia selama tiga hari, kecuali jika ia telah mendidih (mengalami fermentasi).\" "},"5343":{"ar":"أَخْبَرَنِي عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرٍ قَالَ حَدَّثَنَا بَقِيَّةُ قَالَ حَدَّثَنِي الْأَوْزَاعِيُّ عَنْ يَحْيَى بْنِ أَبِي عَمْرٍو عَنْ عَبْدِ اللَّهِ بْنِ الدَّيْلَمِيِّ عَنْ أَبِيهِ فَيْرُوزَ قَالَقَدِمْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّا أَصْحَابُ كَرْمٍ وَقَدْ أَنْزَلَ اللَّهُ عَزَّ وَجَلَّ تَحْرِيمَ الْخَمْرِ فَمَاذَا نَصْنَعُ قَالَ تَتَّخِذُونَهُ زَبِيبًا قُلْتُ فَنَصْنَعُ بِالزَّبِيبِ مَاذَا قَالَ تُنْقِعُونَهُ عَلَى غَدَائِكُمْ وَتَشْرَبُونَهُ عَلَى عَشَائِكُمْ وَتُنْقِعُونَهُ عَلَى عَشَائِكُمْ وَتَشْرَبُونَهُ عَلَى غَدَائِكُمْ قُلْتُ أَفَلَا نُؤَخِّرُهُ حَتَّى يَشْتَدَّ قَالَ لَا تَجْعَلُوهُ فِي الْقُلَلِ وَاجْعَلُوهُ فِي الشِّنَانِ فَإِنَّهُ إِنْ تَأَخَّرَ صَارَ خَلًّا","id":"Telah mengabarkan kepadaku [Amru bin Utsman bin Sa'id bin Katsir] ia berkata; telah menceritakan kepada kami [Baqiyyah] ia berkata; telah menceritakan kepadaku [Al Auza'i] dari [Yahya bin Abu Amru] dari [Abdullah bin Ad Dailami] dari bapaknya [Fairuz] ia berkata, \"Aku datang menemui Rasulullah shallallahu 'alaihi wasallam dan bertanya, \"Wahai Rasulullah, kami adalah para pemilik kebun anggur, sedangkan Allah Azza Wa Jalla telah menurunkan keharaman khamer, lalu apa yang harus kami lakukan?\" beliau menjawab: \"Jadikanlah zabib (anggur kering).\" Aku bertanya, \"Lalu apa yang harus aku lakukan dengan zabib?\" beliau menjawab: \"Engkau rendam di waktu pagi lalu engkau minum di waktu sore. Engkau rendam di waktu sore lalu engkau minum di waktu pagi.\" Aku bertanya, \"Tidak baikkah jika kami akhirkan hingga ia menjadi keras?\" beliau bersabda: \"Janganlah kamu merendamnya dalam Qulal (guci besar dari tembikar), tapi rendamlah dalam guci kecil sebab jika ditangguhkan ia akan menjadi cuka.\""},"5344":{"ar":"أَخْبَرَنَا عِيسَى بْنُ مُحَمَّدٍ أَبُو عُمَيْرِ بْنِ النَّحَّاسِ عَنْ ضَمْرَةَ عَنْ الشَّيْبَانِيِّ عَنْ ابْنِ الدَّيْلَمِيِّ عَنْ أَبِيهِ قَالَقُلْنَا يَا رَسُولَ اللَّهِ إِنَّ لَنَا أَعْنَابًا فَمَاذَا نَصْنَعُ بِهَا قَالَ زَبِّبُوهَا قُلْنَا فَمَا نَصْنَعُ بِالزَّبِيبِ قَالَ انْبِذُوهُ عَلَى غَدَائِكُمْ وَاشْرَبُوهُ عَلَى عَشَائِكُمْ وَانْبِذُوهُ عَلَى عَشَائِكُمْ وَاشْرَبُوهُ عَلَى غَدَائِكُمْ وَانْبِذُوهُ فِي الشِّنَانِ وَلَا تَنْبِذُوهُ فِي الْقِلَالِ فَإِنَّهُ إِنْ تَأَخَّرَ صَارَ خَلًّا","id":"Telah mengabarkan kepada kami [Isa bin Muhammad Abu Umair bin An Nuhhas] dari [Dlamrah] dari [Asy Syaibani] dari [Ibnu Ad Dailami] dari [Bapaknya] ia berkata, \"Kami bertanya, \"Wahai Rasulullah, kami mempunyai banyak anggur, lantas apa yang harus kami lakukan?\" beliau menjawab: \"Jadikanlah sebagai zabib (anggur kering).\" Kami bertanya lagi, \"Lalu apa yang harus kami lakukan dengan zabib?\" beliau menjawab: \"Buatlah perasan di pagi hari lalu minumlah di sore hari kalian. Dan buatlah perasan di sore hari lalu minumlah di pagi hari kalian. Buatlah perasan nabidz itu pada guci kecil dan jangan pada Qulal (guci besar dari tembikar), sebab jika ditangguhkan ia akan menjadi cuka.\""},"5345":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ الْحَرَّانِيُّ قَالَ حَدَّثَنَا يَعْلَى بْنُ عُبَيْدٍ قَالَ حَدَّثَنَا مُطِيعٌ عَنْ أَبِي عُثْمَانَ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ يُنْبَذُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَشْرَبُهُ مِنْ الْغَدِ وَمِنْ بَعْدِ الْغَدِ فَإِذَا كَانَ مَسَاءُ الثَّالِثَةِ فَإِنْ بَقِيَ فِي الْإِنَاءِ شَيْءٌ لَمْ يَشْرَبُوهُ أُهَرِيقَ","id":"Telah mengabarkan kepada kami [Abu Dawud Al Harrani] ia berkata; telah menceritakan kepada kami [Ya'la bin Ubaid] ia berkata; telah menceritakan kepada kami [Muthi'] dari [Abu Utsman] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam biasa dibuatkan minuman dari perasan, lalu beliau meminumnya pada keesokan hari dan lusa. Jika pada hari ketiga masih ada sisa di dalam wadah, beliau tidak meminumnya, tetapi menumpahkannya.\""},"5346":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا شَرِيكٌ عَنْ أَبِي إِسْحَقَ عَنْ يَحْيَى بْنِ عُبَيْدٍ الْبَهْرَانِيِّ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُنْقَعُ لَهُ الزَّبِيبُ فَيَشْرَبُهُ يَوْمَهُ وَالْغَدَ وَبَعْدَ الْغَدِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah menceritakan kepada kami [Yahya bin Adam] ia berkata; telah menceritakan kepada kami [Syarik] dari [Abu Ishaq] dari [Yahya bin Ubaid Al Bahrani] dari [Ibnu Abbas] berkata, \"Pernah Rasulullah shallallahu 'alaihi wasallam direndamkan perasan anggur, lalu beliau meminumnya pada hari tersebut, keesokan harinya dan lusa.\""},"5347":{"ar":"أَخْبَرَنَا وَاصِلُ بْنُ عَبْدِ الْأَعْلَى عَنْ ابْنِ فُضَيْلٍ عَنْ الْأَعْمَشِ عَنْ يَحْيَى بْنِ أَبِي عُمَرَ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُنْبَذُ لَهُ نَبِيذُ الزَّبِيبِ مِنْ اللَّيْلِ فَيَجْعَلُهُ فِي سِقَاءٍ فَيَشْرَبُهُ يَوْمَهُ ذَلِكَ وَالْغَدَ وَبَعْدَ الْغَدِ فَإِذَا كَانَ مِنْ آخِرِ الثَّالِثَةِ سَقَاهُ أَوْ شَرِبَهُ فَإِنْ أَصْبَحَ مِنْهُ شَيْءٌ أَهْرَاقَهُ","id":"Telah mengabarkan kepada kami [Washil bin Abdul A'la] dari [Ibnu Fudlail] dari [Al A'masy] dari [Yahya bin Abu Umar] dari [Ibnu Abbas] ia berkata, \"Pernah Rasulullah shallallahu 'alaihi wasallam dibuatkan perasan buah anggur dalam wadah air minum, lalu beliau meminumnya pada hari tersebut, keesokan harinya dan lusa. Pada sore hari di hari ketiga, beliau meminumnya. Dan jika di pagi hari masih ada sesuatu yang tersisa beliau menumpahkannya.\""},"5348":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ بَسَّامٍ قَالَسَأَلْتُ أَبَا جَعْفَرٍ عَنْ النَّبِيذِ قَالَ كَانَ عَلِيُّ بْنُ حُسَيْنٍ رَضِيَ اللَّهُ عَنْهُ يُنْبَذُ لَهُ مِنْ اللَّيْلِ فَيَشْرَبُهُ غُدْوَةً وَيُنْبَذُ لَهُ غُدْوَةً فَيَشْرَبُهُ مِنْ اللَّيْلِ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Bassam] ia berkata, \"Aku bertanya [Abu Ja'far] tentang perasan nabidz, ia lalu menjawab, \"Pernah [Ali bin Husain]? radliallahu 'anhu dibuatkan perasan nabidz pada malam hari lalu meminumnya pada pagi hari, dan dibuatkan pada pagi hari lalu meminumnya pada malam hari.\""},"5349":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْد�� اللَّهِ قَالَ سَمِعْتُ سُفْيَانَسُئِلَ عَنْ النَّبِيذِ قَالَ انْتَبِذْ عَشِيًّا وَاشْرَبْهُ غُدْوَةً","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] ia berkata, \"Aku mendengar [Sufyan] ditanya tentang perasan nabidz, ia lalu menjawab, \"Buatlah di malam hari lalu minumlah di pagi hari.\""},"5350":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ مَعْمَرٍ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِأَنَّهُ كَانَ يَكْرَهُ أَنْ يَجْعَلَ نَطْلَ النَّبِيذِ فِي النَّبِيذِ لِيَشْتَدَّ بِالنَّطْلِ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Ma'mar] dari [Qatadah] dari [Sa'id Ibnul Musayyab], bahwasanya ia membenci jika endapan nabidz disatukan dalam perasan nabidz supaya endapan itu menjadi keras (hasiatnya).\""},"5351":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ سُفْيَانَ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِأَنَّهُ قَالَ فِي النَّبِيذِ خَمْرُهُ دُرْدِيُّهُ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Sufyan] dari [Dawud bin Abu Hind] dari [Sa'id Ibnul Musayyab], bahwa ia pernah berkata tentang perasan nabidz, \"Khamernya itu terletak pada ampasnya.\""},"5352":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ قَالَإِنَّمَا سُمِّيَتْ الْخَمْرُ لِأَنَّهَا تُرِكَتْ حَتَّى مَضَى صَفْوُهَا وَبَقِيَ كَدَرُهَا وَكَانَ يَكْرَهُ كُلَّ شَيْءٍ يُنْبَذُ عَلَى عَكَرٍ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Syu'bah] dari [Qatadah] dari [Sa'id Ibnul Musayyab] ia berkata, \"Dinamakan khamer karena ia dibiarkan hingga kemurniannya hilang dan tersisa endapannya. Dan dia memakruhkan setiap sesuatu yang dibuat perasan hingga mengendap.\""},"5353":{"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا الْقَوَارِيرِيُّ قَالَ حَدَّثَنَا ابْنُ أَبِي زَائِدَةَ قَالَ حَدَّثَنَا حَسَنُ بْنُ عَمْرٍو عَنْ فُضَيْلِ بْنِ عَمْرٍو عَنْ إِبْرَاهِيمَ قَالَكَانُوا يَرَوْنَ أَنَّ مَنْ شَرِبَ شَرَابًا فَسَكِرَ مِنْهُ لَمْ يَصْلُحْ لَهُ أَنْ يَعُودَ فِيهِ","id":"Telah mengabarkan kepada kami [Abu Bakr bin Ali] ia berkata; telah menceritakan kepada kami [Al Qawariri] ia berkata; telah menceritakan kepada kami [Ibnu Abu Zaidah] ia berkata; telah menceritakan kepada kami [Hasan bin Amru] dari [Fudlail bin Amru] dari [Ibrahim] ia berkata, \"Mereka berpandangan bahwa siapa yang meminum perasan kemudian mabuk, maka tidak boleh untuk mengulanginya lagi.\""},"5354":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ سُفْيَانَ عَنْ مُغِيرَةَ عَنْ أَبِي مَعْشَرٍ عَنْ إِبْرَاهِيمَ قَالَلَا بَأْسَ بِنَبِيذِ الْبُخْتُجِ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Sufyan] dari [Mughirah] dari [Abu Ma'syar] dari [Ibrahim] ia berkata, \"Tidak apa-apa minum perasan nabidz yang telah dimasak.\""},"5355":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ أَبِي عَوَانَةَ عَنْ أَبِي مِسْكِينٍ قَالَ سَأَلْتُ إِبْرَاهِيمَقُلْتُ إِنَّا نَأْخُذُ دُرْدِيَّ الْخَمْرِ أَوْ الطِّلَاءِ فَنُنَظِّفُهُ ثُمَّ نَنْقَعُ فِيهِ الزَّبِيبَ ثَلَاثًا ثُمَّ نُصَفِّيهِ ثُمَّ نَدَعُهُ حَتَّى يَبْلُغَ فَنَشْرَبُهُ قَالَ يُكْرَهُ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Abu Arubah] dari [Abu Miskin] ia berkata, \"Aku bertanya kepada [Ibrahim], aku katakan, \"Kami mengambil ambas (endapan) khamer, atau perasan nabidz yang telah dimasak. Kemudian kami membersihkan bekasnya memasukkan ke dalamnya tiga butir kismis. Setelah itu kami membersihkannya kembali dan membiarkannya hingga matang, lalu kami meminumnya?\" Ibrahim menjawab, \"Itu dimakruhkan.\""},"5356":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ ابْنِ شُبْرُمَةَ قَالَرَحِمَ اللَّهُ إِبْرَاهِيمَ شَدَّدَ النَّاسُ فِي النَّبِيذِ وَرَخَّصَ فِيهِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Jarir] dari [Ibnu Syubrumah] ia berkata, \"Semoga Allah merahmati [Ibrahim], orang-orang berlaku keras dalam masalah perasan nabidz, namun ia justeru memberi kemudahan.\""},"5357":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ عَنْ أَبِي أُسَامَةَ قَالَ سَمِعْتُ ابْنَ الْمُبَارَكِ يَقُولُمَا وَجَدْتُ الرُّخْصَةَ فِي الْمُسْكِرِ عَنْ أَحَدٍ صَحِيحًا إِلَّا عَنْ إِبْرَاهِيمَ","id":"Telah menceritakan kepada kami [Ubaidullah bin Sa'id] dari [Abu Usamah] ia berkata, \"Aku mendengar [Ibnul Mubarak] berkata, \"Aku tidak pernah mendapatkan riwayat yang shahih dari seorang pun yang memberikan keringanan dalam masalah minuman yang memabukkan, selain dari Ibrahim.\""},"5358":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ سَمِعْتُ أَبَا أُسَامَةَ يَقُولُمَا رَأَيْتُ رَجُلًا أَطْلَبَ لِلْعِلْمِ مِنْ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ الشَّامَاتِ وَمِصْرَ وَالْيَمَنَ وَالْحِجَازَ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Sa'id] ia berkata; aku mendengar [Abu Usamah] berkata, \"Aku tidak pernah melihat seseorang yang tekun dalam menuntut ilmu selain Abdullah Ibnul Mubarak, ia pernah pergi ke Syamat, Mesir, Yaman dan Hijaz.\""},"5359":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا أَسَدُ بْنُ مُوسَى قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ لِأُمِّ سُلَيْمٍ قَدَحٌ مِنْ عَيْدَانٍ فَقَالَتْ سَقَيْتُ فِيهِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلَّ الشَّرَابِ الْمَاءَ وَالْعَسَلَ وَاللَّبَنَ وَالنَّبِيذَ","id":"Telah mengabarkan kepada kami [Ar Rabi' bin Sulaiman] ia berkata; telah menceritakan kepada kami [Asad bin Musa] ia berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas]? radliallahu 'anhu, ia berkata, \" [Ummu Sulaim] mempunyai gelas yang terbuat dari 'Aidan (batang pohon kurma), ia berkata, \"Aku pernah memberi minuman kepada Rasulullah shallallahu 'alaihi wasallam dengan gelas itu, baik air, madu, susu atau perasan nabidz.\""},"5360":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ سُفْيَانَ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ ذَرِّ بْنِ عَبْدِ اللَّهِ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِ قَالَسَأَلْتُ أُبَيَّ بْنَ كَعْبٍ عَنْ النَّبِيذِ فَقَالَ اشْرَبْ الْمَاءَ وَاشْرَبْ الْعَسَلَ وَاشْرَبْ السَّوِيقَ وَاشْرَبْ اللَّبَنَ الَّذِي نُجِعْتَ بِهِ فَعَاوَدْتُهُ فَقَالَ الْخَمْرَ تُرِيدُ الْخَمْرَ تُرِيدُ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Sufyan] dari [Salamah bin Kuhail] dari [Dzar bin Abdullah] dari [Sa'id bin 'Abdurrahman bin Abza] dari [Bapaknya] ia berkata, \"Aku pernah bertanya [Ubay bin Ka'b] tentang perasan nabidz, lalu ia menjawab, \"Minumlah air, madu, perasan jewawut, atau susu yang lebih berguna bagimu.\" Aku tetap saja mengulangi pertanyaan itu kepadanya hingga ia pun berkata, \"Apakah kamu mau khamer, apakah kamu mau khamer!\""},"5361":{"ar":"أَخْبَرَنِي أَحْمَدُ بْنُ عَلِيِّ بْنِ سَعِيدِ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا الْقَوَارِيرِيُّ قَالَ حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ أَبِيهِ عَنْ مُحَمَّدٍ عَنْ عَبِيدَةَ عَنْ ابْنِ مَسْعُودٍ قَالَأَحْدَثَ النَّاسُ أَشْرِبَةً مَا أَدْرِي مَا هِيَ فَمَا لِي شَرَابٌ مُنْذُ عِشْرِينَ سَنَةً أَوْ قَالَ أَرْبَعِينَ سَنَةً إِلَّا الْمَاءُ وَالسَّوِيقُ غَيْرَ أَنَّهُ لَمْ يَذْكُرْ النَّبِيذَ","id":"Telah mengabarkan kepadaku [Ahmad bin Ali bin Sa'id bin Ibrahim] ia berkata; telah menceritakan kepada kami [Al Qawariri] ia berkata; telah menceritakan kepada kami [Mu'tamir bin Sulaiman] dari [Bapaknya] dari [Muhammad] dari [Abidah] dari [Ibnu Mas'ud] ia berkata, \"Orang-orang banyak membuat bermacam-macam minuman, aku tidak mengetahui minuman apa itu. Dan aku tidak mengenal minuman sejak dua puluh tahun, atau ia mengatakan, 'empat puluh tahun, selain air dan perasan jewawut.\" Hanya saja Ibnu Mas'ud tidak menyebutkan perasan nabidz."},"5362":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ ابْنِ عَوْنٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ عَبِيدَةَ قَالَأَحْدَثَ النَّاسُ أَشْرِبَةً مَا أَدْرِي مَا هِيَ وَمَا لِي شَرَابٌ مُنْذُ عِشْرِينَ سَنَةً إِلَّا الْمَاءُ وَاللَّبَنُ وَالْعَسَلُ","id":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Ibnu Aun] dari [Muhammad bin Sirin] dari [Abidah] ia berkata, \"Orang-orang banyak membuat bermacam-macam minuman, aku tidak mengetahui minuman apa itu. Sementara aku sendiri tidak mengenal minuman sejak dua puluh tahun lalu selain air, susu dan madu.\""},"5363":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ ابْنِ شُبْرُمَةَ قَالَقَالَ طَلْحَةُ لِأَهْلِ الْكُوفَةِ فِي النَّبِيذِ فِتْنَةٌ يَرْبُو فِيهَا الصَّغِيرُ وَيَهْرَمُ فِيهَا الْكَبِيرُ قَالَ وَكَانَ إِذَا كَانَ فِيهِمْ عُرْسٌ كَانَ طَلْحَةُ وَزُبَيْدٌ يَسْقِيَانِ اللَّبَنَ وَالْعَسَلَ فَقِيلَ لِطَلْحَةَ أَلَا تَسْقِيهِمُ النَّبِيذَ قَالَ إِنِّي أَكْرَهُ أَنْ يَسْكَرَ مُسْلِمٍ فِي سَبَبِي","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Jarir] dari [Ibnu Syubrumah] ia berkata, \" [Thalhah] berkata kepada penduduk Kufah, \"Pada perasan nabidz terdapat fitnah; ia akan membuat orang yang muda tampak tua, dan membuat orang yang tua tampah renta.\" Ibnu Syubrumah berkata, \"Jika di antara mereka mengadakan pesta pernikahan, maka Thalhah dan Zubaid hanya menuang susu dan madu. Lalu dikatakan kepada Thalhah, \"Kenapa engkau tidak menuang perasan nabidz untuk mereka?\" ia menjawab, \"Aku tidak ingin seorang muslim mabuk karena aku.\""},"5364":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ قَالَكَانَ ابْنُ شُب��رُمَةَ لَا يَشْرَبُ إِلَّا الْمَاءَ وَاللَّبَنَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Jarir] ia berkata, \" [Ibnu Syubrumah] tidak minum kecuali air atau susu.\""}};
